                    ReadAlongSentence(text: "But Texans didn’t bury their heads in shame.", start: 1046.62, end: 1048.86),
                    ReadAlongSentence(text: "They shouted, \"Remember the Alamo!\" and used that failure as the fuel to win their independence.", start: 1049.46, end: 1055.52),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He contrasts this with the \"Chicken Littles\" of the world—the cynics who run around yelling, \"The sky is falling!\" whenever there is a rumor of a recession.", start: 1056.02, end: 1063.48),
                    ReadAlongSentence(text: "He explains that cynics criticize, but winners analyze.", start: 1063.7, end: 1067.24),
                    ReadAlongSentence(text: "Criticism blinds you; analysis opens your eyes.", start: 1067.54, end: 1070.78),
                    ReadAlongSentence(text: "He tells the story of finding a great real estate deal, only to have a \"smart\" friend talk him out of it because \"prices might drop.\"", start: 1071.28, end: 1078.08),
                    ReadAlongSentence(text: "The prices went up, and the friend stayed poor.", start: 1078.58, end: 1081.08),
                    ReadAlongSentence(text: "The lesson?", start: 1081.58, end: 1082.1),
                    ReadAlongSentence(text: "\"Don't let the noise of the world drown out the whisper of opportunity.\"", start: 1082.6, end: 1086.1),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Algorithmic Doomer", start: 1086.84, end: 1087.96),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In 2026, the \"Chicken Littles\" have a megaphone.", start: 1088.46, end: 1092.0),
                    ReadAlongSentence(text: "They are the algorithmic feeds on your phone, optimized to keep you terrified because fear drives engagement.", start: 1092.46, end: 1098.94),
                    ReadAlongSentence(text: "The \"Inner Saboteur\" is now powered by AI-generated deepfakes and 24/7 \"Crash Coming Soon\" YouTube thumbnails.", start: 1099.72, end: 1108.64),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Laziness has also evolved.", start: 1109.42, end: 1110.88),
                    ReadAlongSentence(text: "Today, laziness doesn't look like sleeping on the couch; it looks like \"busyness.\"", start: 1111.3, end: 1116.12),
                    ReadAlongSentence(text: "You are too busy answering emails, checking Slack, and \"researching\" (watching tutorials) to actually do anything.", start: 1116.8, end: 1123.0),
                    ReadAlongSentence(text: "This is \"productive procrastination.\"", start: 1123.58, end: 1125.76),
                    ReadAlongSentence(text: "The modern winner ignores the comment section.", start: 1126.3, end: 1128.58),
                    ReadAlongSentence(text: "They realize that if an investment feels \"safe\" to the herd, it’s already too late.", start: 1129.04, end: 1133.69),
                    ReadAlongSentence(text: "The Saboteur tells you to wait for certainty.", start: 1134.43, end: 1136.55),
                    ReadAlongSentence(text: "The Wiser investor knows certainty is expensive.", start: 1137.17, end: 1141.17),
                ]),
            ],
            7: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Knowledge Coma", start: 1191.31, end: 1192.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the final, most dangerous trap: You are smarter now.", start: 1192.93, end: 1196.75),
                    ReadAlongSentence(text: "You have read the Cores.", start: 1197.41, end: 1198.59),
                    ReadAlongSentence(text: "You understand the math.", start: 1199.09, end: 1200.21),
                    ReadAlongSentence(text: "And yet, tomorrow morning, you will likely wake up and do exactly what you did today.", start: 1200.71, end: 1204.93),
                    ReadAlongSentence(text: "This is the \"Knowledge Coma.\"", start: 1205.71, end: 1207.15),
                    ReadAlongSentence(text: "The friction isn't ignorance anymore; it is inertia.", start: 1208.07, end: 1210.89),
                    ReadAlongSentence(text: "Most people collect financial advice like baseball cards—they categorize it, admire it, and show it off, but they never play the game.", start: 1211.67, end: 1218.95),
                    ReadAlongSentence(text: "They are waiting for the \"perfect time\" or the \"perfect deal,\" unaware that perfection is just procrastination in a tuxedo.", start: 1219.51, end: 1226.19),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Power of \"I Don't Want\"", start: 1226.77, end: 1228.43),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author shatters this paralysis not with a spreadsheet, but with a piece of paper.", start: 1228.95, end: 1233.21),
                    ReadAlongSentence(text: "He tells the story of how he found his \"Why\"—the fuel that outlasted his fear.", start: 1233.79, end: 1238.35),
                    ReadAlongSentence(text: "He didn't start by writing down \"I want to be rich.\"", start: 1238.91, end: 1241.75),
                    ReadAlongSentence(text: "That was too vague.", start: 1242.11, end: 1243.15),
                    ReadAlongSentence(text: "Instead, he sat down and ruthlessly listed what he didn't want.", start: 1243.53, end: 1247.31),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "\"I don't want to work for someone else for the rest of my life.\"", start: 1247.95, end: 1250.29),
                    ReadAlongSentence(text: "\"I don't want to be told when I can go on vacation.\"", start: 1250.79, end: 1252.87),
                    ReadAlongSentence(text: "\"I don't want to miss my child’s soccer game because of a conference call.\"", start: 1253.49, end: 1256.61),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He explains that this \"List of Don'ts\" created a pressure cooker of emotion.", start: 1257.33, end: 1261.47),
                    ReadAlongSentence(text: "It wasn't just a wish; it was a rejection of mediocrity.", start: 1262.21, end: 1265.09),
                    ReadAlongSentence(text: "This deep-seated emotional leverage—the \"Power of Spirit\"—is the only force strong enough to push you through the inevitable obstacles of the first 90 days.", start: 1265.67, end: 1275.33),
                    ReadAlongSentence(text: "Without a burning \"Why,\" the \"How\" is useless.", start: 1275.73, end: 1278.77),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The 2026 \"Micro-Step\" Revolution", start: 1279.43, end: 1282.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In 2026, the barrier to entry has collapsed.", start: 1283.22, end: 1286.72),
                    ReadAlongSentence(text: "You don't need $50,000 for a down payment or a license to trade.", start: 1287.1, end: 1290.5),
                    ReadAlongSentence(text: "The \"Launchpad\" today is built on micro-actions.", start: 1291.06, end: 1293.76),
                    ReadAlongSentence(text: "The author couldn't buy 0.0001% of a building in 1997.", start: 1294.14, end: 1297.82),
                    ReadAlongSentence(text: "Today, you can.", start: 1299.3, end: 1300.66),
                    ReadAlongSentence(text: "You can buy fractional shares of real estate, tokenized gold, or a slice of a startup for the price of a latte.", start: 1301.12, end: 1307.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern error is thinking you need to \"launch\" a massive enterprise.", start: 1307.78, end: 1312.96),
                    ReadAlongSentence(text: "You don't.", start: 1313.28, end: 1313.72),
                    ReadAlongSentence(text: "You need to launch a habit.", start: 1314.06, end: 1315.34),
                    ReadAlongSentence(text: "The \"Wiser\" approach uses automation to bypass your willpower entirely.", start: 1315.86, end: 1320.58),
                    ReadAlongSentence(text: "You don't \"decide\" to invest; you set up a smart contract or an auto-debit that invests for you before you even wake up.", start: 1321.4, end: 1329.02),
                    ReadAlongSentence(text: "You build the wealth architecture once, and then you let the machine run.", start: 1329.62, end: 1333.88),
                ]),
            ],
        ],
        2: [
            1: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Illusion of Competence", start: 7.94, end: 9.4),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the uncomfortable truth: 90% of people who think they are \"investing\" are actually just gambling with better odds.", start: 9.86, end: 17.64),
                    ReadAlongSentence(text: "The friction in your financial life usually stems from a single category error.", start: 18.32, end: 22.74),
                    ReadAlongSentence(text: "You treat the stock market like a casino where the chips are expensive and the rules are vague.", start: 23.38, end: 28.06),
                    ReadAlongSentence(text: "You assume that because you bought a stock and held it for a year, you are an investor.", start: 28.54, end: 32.5),
                    ReadAlongSentence(text: "You aren't.", start: 32.98, end: 33.64),
                    ReadAlongSentence(text: "If you bought it based on a feeling, a tip, or a chart pattern, you are speculating.", start: 34.24, end: 38.82),
                    ReadAlongSentence(text: "And the market loves to punish speculators who believe they are investors.", start: 39.28, end: 43.22),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Trinity of Safety", start: 43.76, end: 45.03),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author solves this by demanding we sign a mental contract before spending a dime.", start: 45.79, end: 50.39),
                    ReadAlongSentence(text: "He strips away the noise and offers a ruthless definition.", start: 50.87, end: 54.61),
                    ReadAlongSentence(text: "An operation is only an investment if it meets three specific criteria upon thorough analysis:", start: 55.33, end: 61.07),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Safety of Principal: You are reasonably sure you won't lose your initial cash.", start: 61.85, end: 66.13),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Adequate Return: You aren't looking for a lottery ticket; you are looking for a fair rent on your money.", start: 66.61, end: 71.89),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Thorough Analysis: You have done the math on the underlying business, not just the stock price.", start: 72.49, end: 78.13),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine a man betting on a horse race.", start: 78.63, end: 80.75),
                    ReadAlongSentence(text: "He studies the track record, the jockey, and the weather.", start: 81.23, end: 83.95),
                    ReadAlongSentence(text: "He is informed, but he is still gambling because he has no safety of principal—if the horse loses, his money vanishes.", start: 84.45, end: 91.35),
                    ReadAlongSentence(text: "The \"Intelligent Investor\" refuses to bet on the horse; he buys the racetrack.", start: 91.79, end: 97.13),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Gamification Trap", start: 97.51, end: 98.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, this distinction is harder to see because the casino has moved into your pocket.", start: 99.35, end: 104.57),
                    ReadAlongSentence(text: "Trading apps shower you with digital confetti when you execute a trade, conditioning you to crave action over analysis.", start: 105.57, end: 112.79),
                    ReadAlongSentence(text: "We see this in the \"Crypto Craze\" or the \"AI Gold Rush.\"", start: 113.41, end: 116.83),
                    ReadAlongSentence(text: "Buying a digital token because you hope a billionaire tweets about it is not investing; it is the \"Greater Fool Theory\"—hoping someone else will pay more for your mistake.", start: 117.83, end: 126.71),
                    ReadAlongSentence(text: "The danger today isn't just market volatility; it’s the user interface of your life designed to make speculation feel like strategy.", start: 127.63, end: 135.06),
                    ReadAlongSentence(text: "If your asset relies entirely on hype to succeed, you aren't investing in a business; you're investing in a narrative.", start: 135.84, end: 143.28),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Safety Paradox", start: 181.66, end: 182.74),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The greatest trick the financial industry ever pulled was convincing you that cash is \"safe.\"", start: 183.48, end: 188.72),
                    ReadAlongSentence(text: "You look at your bank account, and the number stays the same or grows slightly.", start: 189.46, end: 193.08),
                    ReadAlongSentence(text: "You feel a warm sense of security.", start: 193.74, end: 195.48),
                    ReadAlongSentence(text: "You sleep well.", start: 196.0, end: 196.8),
                    ReadAlongSentence(text: "But this is a hallucination.", start: 197.14, end: 198.42),
                    ReadAlongSentence(text: "In the physical world, if you left a car in a garage for twenty years, you’d expect it to rust.", start: 198.88, end: 204.2),
                    ReadAlongSentence(text: "Money is no different, yet we treat it as if it’s immune to decay.", start: 204.68, end: 208.32),
                    ReadAlongSentence(text: "The friction here is psychological: we are wired to fear the volatility of the stock market (where prices bounce up and down visibly), so we run into the arms of a guaranteed loss.", start: 209.04, end: 218.98),
                    ReadAlongSentence(text: "We choose the slow bleed over the bumpy ride.", start: 219.5, end: 221.65),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Yardstick That Shrank", start: 221.97, end: 223.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author illustrates this with a brutal reality check from the first half of the 20th century.", start: 223.91, end: 228.81),
                    ReadAlongSentence(text: "He tells the story of the \"Conservative Investor\" who, traumatized by market crashes, put 100% of his wealth into high-grade bonds.", start: 229.45, end: 238.03),
                    ReadAlongSentence(text: "This man felt prudent.", start: 238.61, end: 239.89),
                    ReadAlongSentence(text: "He collected his fixed interest checks like clockwork.", start: 240.47, end: 243.27),
                    ReadAlongSentence(text: "But while he was staring at the stable numbers on his statements, the world around him changed.", start: 243.69, end: 248.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The price of bread, housing, and energy doubled.", start: 248.81, end: 251.83),
                    ReadAlongSentence(text: "The \"yardstick\" of money had shrunk.", start: 252.35, end: 254.05),
                    ReadAlongSentence(text: "The author points out that by the time this investor needed to spend his principal, it had lost half its purchasing power.", start: 254.59, end: 260.79),
                    ReadAlongSentence(text: "The man hadn't lost dollars; he had lost lifestyle.", start: 261.55, end: 264.25),
                    ReadAlongSentence(text: "The \"safe\" investment was actually a trap that guaranteed he would be poorer at the end than when he started.", start: 264.77, end: 271.43),
                    ReadAlongSentence(text: "The author’s lesson is stark: Inflation is a thief that works in the dark, and keeping all your money in \"safe\" cash is not prudence—it is a decision to let the thief empty your house while you watch.", start: 272.11, end: 283.37),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The High-Yield Hallucination", start: 283.87, end: 285.21),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, this enemy is even more deceptive.", start: 285.57, end: 288.63),
                    ReadAlongSentence(text: "You open a High-Yield Savings Account (HYSA) offering 5% and think you are winning.", start: 289.17, end: 294.81),
                    ReadAlongSentence(text: "You aren’t.", start: 295.39, end: 295.99),
                    ReadAlongSentence(text: "You are barely treading water.", start: 296.47, end: 297.89),
                    ReadAlongSentence(text: "If inflation is running at 3.5% and the tax man takes another 1.5% of your gains, your real return is zero.", start: 298.47, end: 305.85),
                    ReadAlongSentence(text: "You are running on a financial treadmill just to stay in the same place.", start: 306.41, end: 309.72),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Furthermore, the \"basket of goods\" has changed.", start: 310.28, end: 312.9),
                    ReadAlongSentence(text: "The author worried about the price of milk; you need to worry about the cost of healthcare, college tuition, and prime real estate, which often inflate significantly faster than the government's official CPI numbers.", start: 313.5, end: 325.66),
                    ReadAlongSentence(text: "If you are paying 1% to a financial advisor to manage a portfolio of cash and bonds that yields 4%, you are essentially paying someone to manage your slow bankruptcy.", start: 326.3, end: 336.1),
                    ReadAlongSentence(text: "In a world of unlimited fiat currency printing, holding cash is like holding a melting ice cube.", start: 336.7, end: 342.46),
                    ReadAlongSentence(text: "You cannot save your way to wealth in a currency that is designed to depreciate.", start: 342.92, end: 347.28),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Price Tag Panic", start: 354.62, end: 355.78),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine you own a house you love.", start: 356.36, end: 358.34),
                    ReadAlongSentence(text: "You know its value: good roof, solid foundation, great neighborhood.", start: 358.88, end: 362.66),
                    ReadAlongSentence(text: "Now imagine a stranger stands on your lawn every single morning yelling a different price at you.", start: 363.28, end: 367.74),
                    ReadAlongSentence(text: "Monday he screams, \"I'll give you $500,000!\"", start: 368.52, end: 370.36),
                    ReadAlongSentence(text: "Tuesday he whispers, \"The market is crashing!", start: 372.28, end: 374.92),
                    ReadAlongSentence(text: "I'll only give you $150,000!\"", start: 375.48, end: 376.06),
                    ReadAlongSentence(text: "Wednesday he is euphoric again and offers $900,000.", start: 377.88, end: 380.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most people would close the blinds and ignore him.", start: 381.92, end: 384.7),
                    ReadAlongSentence(text: "But in the stock market, you do the opposite.", start: 385.12, end: 387.48),
                    ReadAlongSentence(text: "You let this stranger dictate your emotional state.", start: 387.94, end: 390.64),
                    ReadAlongSentence(text: "When he yells a low price, you panic and sell your house cheap.", start: 391.22, end: 394.74),
                    ReadAlongSentence(text: "When he yells a high price, you feel rich and buy more houses.", start: 395.24, end: 398.88),
                    ReadAlongSentence(text: "This is the friction: you confuse the price on the screen with the value of the business.", start: 399.44, end: 403.73),
                    ReadAlongSentence(text: "You let the fluctuating price tag determine your worth, rather than the quality of the merchandise.", start: 404.25, end: 409.33),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Partner You Can't Fire", start: 409.83, end: 412.09),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author introduces us to this stranger.", start: 412.65, end: 415.05),
                    ReadAlongSentence(text: "His name is \"Mr.", start: 415.65, end: 416.65),
                    ReadAlongSentence(text: "Market.\"", start: 417.13, end: 417.53),
                    ReadAlongSentence(text: "He is your business partner in a private company.", start: 418.03, end: 420.37),
                    ReadAlongSentence(text: "Mr.", start: 421.25, end: 421.59),
                    ReadAlongSentence(text: "Market is obliging but emotionally unstable.", start: 422.07, end: 424.51),
                    ReadAlongSentence(text: "Every day, without fail, he names a price at which he will either buy your interest or sell you his.", start: 425.11, end: 431.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The catch?", start: 431.57, end: 432.13),
                    ReadAlongSentence(text: "His price has nothing to do with the business's actual performance.", start: 432.55, end: 436.75),
                    ReadAlongSentence(text: "It is based entirely on his mood.", start: 437.11, end: 439.01),
                    ReadAlongSentence(text: "When he is manic (optimistic), he sees only sunshine and names a high price.", start: 439.55, end: 444.81),
                    ReadAlongSentence(text: "When he is depressed (pessimistic), he sees only trouble and names a low price.", start: 445.49, end: 450.57),
                    ReadAlongSentence(text: "The author’s solution is a mindset shift: Mr.", start: 451.01, end: 453.81),
                    ReadAlongSentence(text: "Market is there to serve you, not to guide you.", start: 454.93, end: 457.65),
                    ReadAlongSentence(text: "You are not forced to deal with him.", start: 458.13, end: 459.75),
                    ReadAlongSentence(text: "If his offer is ridiculous, you ignore him.", start: 460.35, end: 463.09),
                    ReadAlongSentence(text: "If his offer is a bargain, you buy.", start: 463.65, end: 465.55),
                    ReadAlongSentence(text: "If his offer is absurdly high, you sell.", start: 466.09, end: 468.83),
                    ReadAlongSentence(text: "You are the adult in the room; he is the hysterical child.", start: 469.27, end: 472.33),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Algorithm of Anxiety", start: 472.89, end: 474.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, Mr.", start: 475.15, end: 477.17),
                    ReadAlongSentence(text: "Market isn't just a guy on your lawn; he is in your pocket, buzzing every 15 minutes.", start: 477.67, end: 482.35),
                    ReadAlongSentence(text: "He is the notification on your phone saying \"Bitcoin is down 10%\" or \"Nvidia hits all-time high.\"", start: 482.85, end: 489.09),
                    ReadAlongSentence(text: "The modern Mr.", start: 489.61, end: 491.07),
                    ReadAlongSentence(text: "Market is amplified by algorithms designed to trigger your dopamine and cortisol.", start: 491.81, end: 496.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the \"Flash Crash\" or the meme-stock frenzy.", start: 497.39, end: 500.69),
                    ReadAlongSentence(text: "These are Mr.", start: 501.27, end: 502.11),
                    ReadAlongSentence(text: "Market on steroids—millions of people reacting to a viral sentiment rather than business fundamentals.", start: 502.49, end: 508.44),
                    ReadAlongSentence(text: "If you own an S&P 500 ETF, you own the 500 biggest companies in America.", start: 508.84, end: 514.38),
                    ReadAlongSentence(text: "Did the value of Coca-Cola or Microsoft actually drop 20% in a week because of a geopolitical rumor?", start: 515.16, end: 521.58),
                    ReadAlongSentence(text: "No.", start: 522.08, end: 522.18),
                    ReadAlongSentence(text: "Their factories didn't burn down.", start: 522.88, end: 524.44),
                    ReadAlongSentence(text: "Their customers didn't vanish.", start: 524.9, end: 526.56),
                    ReadAlongSentence(text: "Only the price tag changed.", start: 527.1, end: 528.64),
                    ReadAlongSentence(text: "If you react to the notification, you are letting the algorithm trade against you.", start: 529.14, end: 533.52),
                    ReadAlongSentence(text: "You must view volatility not as risk, but as the fee you pay for higher returns.", start: 534.02, end: 539.14),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Myth of the Mastermind", start: 563.0, end: 564.76),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a persistent lie in finance that \"effort equals return.\"", start: 565.18, end: 569.22),
                    ReadAlongSentence(text: "In your job, if you work 80 hours a week, you get a promotion.", start: 570.04, end: 573.56),
                    ReadAlongSentence(text: "In the stock market, if you work 80 hours a week analyzing charts, reading news, and tweaking your portfolio, you will likely underperform a dead person.", start: 574.1, end: 582.3),
                    ReadAlongSentence(text: "The friction here is ego.", start: 582.76, end: 584.18),
                    ReadAlongSentence(text: "You believe you are smarter than the market.", start: 584.92, end: 586.78),
                    ReadAlongSentence(text: "You believe you can time the top and the bottom.", start: 587.46, end: 590.16),
                    ReadAlongSentence(text: "You believe that \"doing nothing\" is lazy.", start: 590.72, end: 592.98),
                    ReadAlongSentence(text: "But in investing, activity is the enemy of returns.", start: 593.66, end: 597.38),
                    ReadAlongSentence(text: "The more you touch your portfolio, the more you incur fees, taxes, and emotional errors.", start: 598.08, end: 603.62),
                    ReadAlongSentence(text: "The goal of the Fortress is to protect you from your own desire to be clever.", start: 604.12, end: 607.77),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The 50/50 Split", start: 608.25, end: 609.47),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author solves this by creating a specific category for people who want to get rich without making investing their second job: the \"Defensive Investor.\"", start: 609.85, end: 618.99),
                    ReadAlongSentence(text: "He proposes a radical simplicity.", start: 619.55, end: 621.61),
                    ReadAlongSentence(text: "Imagine a portfolio that is a perfect balance scale.", start: 622.21, end: 625.07),
                    ReadAlongSentence(text: "On one side, you have high-grade bonds (lending money to stable governments or corporations).", start: 625.61, end: 631.29),
                    ReadAlongSentence(text: "On the other side, you have a diversified list of leading common stocks (owning a piece of the economy).", start: 631.91, end: 637.37),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author suggests a baseline split of 50% stocks and 50% bonds.", start: 637.91, end: 643.75),
                    ReadAlongSentence(text: "This is your \"Fortress.\"", start: 644.51, end: 645.97),
                    ReadAlongSentence(text: "When the stock market crashes and people are jumping out of windows, your bonds hold their value, and your portfolio only drops half as much as the market.", start: 646.65, end: 654.55),
                    ReadAlongSentence(text: "You sleep well.", start: 655.05, end: 655.75),
                    ReadAlongSentence(text: "When the market booms and your neighbor is bragging about his gains, your stocks participate in the rally.", start: 656.33, end: 662.35),
                    ReadAlongSentence(text: "You never fully lose, and you never miss out.", start: 662.77, end: 665.39),
                    ReadAlongSentence(text: "The genius is in the maintenance: if stocks go up and become 60% of your portfolio, you simply sell some stocks and buy bonds to get back to 50/50.", start: 665.79, end: 673.87),
                    ReadAlongSentence(text: "This forces you to do the one thing everyone fails at: sell high and buy low, automatically.", start: 675.49, end: 681.45),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Autopilot Advantage", start: 682.11, end: 683.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, building this Fortress is easier than the author could have ever dreamed.", start: 684.17, end: 688.51),
                    ReadAlongSentence(text: "In his day, you had to buy individual bonds and pick 20 different stocks.", start: 689.33, end: 694.63),
                    ReadAlongSentence(text: "Today, you can build the entire Fortress with two clicks using low-cost Index Funds or ETFs (Exchange Traded Funds).", start: 695.31, end: 703.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Instead of picking \"winners\" (which is hard), you buy the entire S&P 500 or a Total World Stock ETF.", start: 703.86, end: 710.66),
                    ReadAlongSentence(text: "You own Apple, Microsoft, Amazon, and 4,000 other companies.", start: 711.32, end: 715.76),
                    ReadAlongSentence(text: "If one goes bankrupt, you don't even notice.", start: 716.32, end: 718.7),
                    ReadAlongSentence(text: "If a new AI giant emerges, you automatically own it.", start: 719.2, end: 722.34),
                    ReadAlongSentence(text: "This is the \"Boglehead\" philosophy (named after Jack Bogle, who popularized index funds), which is the modern spiritual successor to Graham’s Defensive strategy.", start: 723.02, end: 732.48),
                    ReadAlongSentence(text: "It accepts that you cannot predict the future, so you simply own the entire economy.", start: 733.06, end: 737.98),
                    ReadAlongSentence(text: "It turns investing from a stress-inducing hunt for \"the next Bitcoin\" into a boring, reliable utility bill that pays you.", start: 738.66, end: 745.46),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Hero Complex", start: 752.58, end: 753.64),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the seduction: You believe that if you are smarter, faster, and read more news than your neighbor, you will make more money.", start: 754.14, end: 762.22),
                    ReadAlongSentence(text: "You view the stock market as a test of your intelligence.", start: 762.82, end: 766.0),
                    ReadAlongSentence(text: "This is the \"Hero Complex,\" and it is the fastest way to underperform.", start: 766.52, end: 770.96),
                    ReadAlongSentence(text: "The friction is simple: you are not competing against your neighbor.", start: 771.5, end: 774.52),
                    ReadAlongSentence(text: "You are competing against institutional algorithms that read every news headline in milliseconds and price it in before you’ve even unlocked your phone.", start: 775.28, end: 783.86),
                    ReadAlongSentence(text: "If you try to \"win\" by buying the same popular, high-growth companies everyone else loves, you are paying a premium for a consensus view.", start: 784.66, end: 792.78),
                    ReadAlongSentence(text: "You are buying a Ferrari at full sticker price and hoping to sell it for a profit.", start: 793.22, end: 797.33),
                    ReadAlongSentence(text: "That isn't investing; that's wishful thinking.", start: 797.95, end: 800.69),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Negative Art", start: 801.29, end: 802.35),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author solves this by redefining what it means to be \"Enterprising.\"", start: 802.85, end: 806.59),
                    ReadAlongSentence(text: "He clarifies that being an Enterprising Investor is not about taking more risk; it is about doing more work.", start: 807.37, end: 813.97),
                    ReadAlongSentence(text: "It is a job description, not a personality type.", start: 814.65, end: 817.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author warns against the siren song of \"Growth Stocks\"—the companies that everyone knows are the future.", start: 818.65, end: 824.95),
                    ReadAlongSentence(text: "He tells the story of the investor who buys the great companies of the era (like the radio or airline pioneers) and loses everything because the price was already bid up to perfection.", start: 825.49, end: 836.05),
                    ReadAlongSentence(text: "Instead, the Enterprising Investor practices a \"negative art.\"", start: 836.55, end: 840.29),
                    ReadAlongSentence(text: "They avoid the popular.", start: 840.79, end: 841.97),
                    ReadAlongSentence(text: "They hunt in the scrap heap.", start: 842.57, end: 844.03),
                    ReadAlongSentence(text: "They look for \"bargain issues\"—stocks selling for less than their working capital.", start: 844.63, end: 849.79),
                    ReadAlongSentence(text: "They buy when the news is bad, the outlook is gloomy, and the crowd is selling.", start: 850.33, end: 854.43),
                    ReadAlongSentence(text: "The Enterprising Investor makes their money not by predicting the future, but by correcting the market's mistakes in the present.", start: 854.81, end: 861.05),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Edge of Discomfort", start: 861.53, end: 863.09),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, the \"easy\" information is gone.", start: 863.59, end: 866.33),
                    ReadAlongSentence(text: "You cannot find a bargain just by looking at a P/E ratio on Yahoo Finance because a million other people have seen it too.", start: 866.61, end: 873.77),
                    ReadAlongSentence(text: "Today, the \"Enterprising\" edge is almost entirely psychological.", start: 874.33, end: 878.07),
                    ReadAlongSentence(text: "It is the ability to endure social pain.", start: 878.63, end: 880.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Think about the collapse of Meta (Facebook) in 2022 or the energy sector when oil prices went negative in 2020.", start: 881.31, end: 888.73),
                    ReadAlongSentence(text: "The \"Enterprising\" move wasn't to buy Nvidia when it was on every magazine cover; it was to buy the unloved, \"boring,\" or \"dead\" sectors when everyone else was chasing AI hype.", start: 890.29, end: 900.84),
                    ReadAlongSentence(text: "If you are buying a stock that makes you feel smart at a dinner party, you are likely overpaying.", start: 901.5, end: 906.3),
                    ReadAlongSentence(text: "The modern Enterprising strategy often involves \"Deep Value\" or \"Special Situations\"—spinoffs, distressed assets, or small-cap companies too small for the big funds to touch.", start: 907.02, end: 917.6),
                    ReadAlongSentence(text: "You are looking for the \"ick factor\"—assets that are fundamentally sound but temporarily hated.", start: 918.04, end: 923.5),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Protocol", start: 924.14, end: 924.78),
                ]),
            ],
            6: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Croupier's Cut", start: 947.38, end: 948.32),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The financial industry is built on a single, powerful myth: \"Investing is too complicated for you to do alone; you need an expert.\"", start: 949.02, end: 956.58),
                    ReadAlongSentence(text: "So, you hand your money to a mutual fund manager—a \"star\" in a suit who promises to navigate the market's storms.", start: 957.36, end: 964.08),
                    ReadAlongSentence(text: "You pay them a 1% or 2% fee every year, regardless of whether they make you money or lose it.", start: 964.56, end: 970.9),
                    ReadAlongSentence(text: "The friction here is mathematical, not emotional.", start: 971.62, end: 974.28),
                    ReadAlongSentence(text: "That 2% fee sounds small, but over 30 years, it can consume up to 40% of your total wealth.", start: 975.1, end: 982.08),
                    ReadAlongSentence(text: "You are taking 100% of the risk, providing 100% of the capital, and giving away nearly half the upside to a manager who, statistically, will fail to beat the market anyway.", start: 982.84, end: 994.27),
                    ReadAlongSentence(text: "You aren't hiring a guide; you're carrying a parasite.", start: 995.05, end: 997.61),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Rearview Mirror Trap", start: 998.09, end: 999.51),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author saw this coming decades ago.", start: 999.83, end: 1001.81),
                    ReadAlongSentence(text: "He identified the fatal flaw in how mutual funds are sold: Performance Chasing.", start: 1002.21, end: 1006.81),
                    ReadAlongSentence(text: "He describes the \"Hot Hand\" fallacy—the investor who looks at a list of funds, picks the one that went up 50% last year, and assumes it will do the same next year.", start: 1007.31, end: 1017.03),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Graham warns that \"past performance is not a guarantee of future results\" isn't just a legal disclaimer; it is an iron law.", start: 1017.49, end: 1025.55),
                    ReadAlongSentence(text: "He observed that funds with spectacular returns usually achieved them by taking spectacular risks or getting lucky in a specific sector.", start: 1026.15, end: 1034.47),
                    ReadAlongSentence(text: "Once that sector cools off, the \"genius\" manager looks like a fool, and the investor who bought in at the top suffers the crash.", start: 1035.03, end: 1042.13),
                    ReadAlongSentence(text: "The author’s solution was brutal honesty: most funds are just expensive marketing machines designed to gather assets, not to generate alpha.", start: 1042.67, end: 1050.69),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Index Revolution", start: 1051.43, end: 1052.63),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the trap is even more subtle.", start: 1053.07, end: 1055.07),
                    ReadAlongSentence(text: "We have \"Thematic ETFs\"—funds dedicated to AI, Cannabis, or Space Travel.", start: 1055.71, end: 1061.63),
                    ReadAlongSentence(text: "These are the modern version of the \"hot\" mutual funds Graham warned about.", start: 1062.43, end: 1066.83),
                    ReadAlongSentence(text: "They package a compelling narrative (e.g., \"Robots are the future!\") and charge you a premium to own a basket of hype.", start: 1067.33, end: 1074.12),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Wiser\" analysis, championed by Graham’s disciple John Bogle, is that you should stop looking for the needle in the haystack and just buy the haystack.", start: 1074.6, end: 1083.06),
                    ReadAlongSentence(text: "The modern S&P 500 Index Fund allows you to fire the manager.", start: 1083.48, end: 1087.24),
                    ReadAlongSentence(text: "Instead of paying 1.5% for a human to guess which stocks will go up, you pay 0.03% to a computer to own all the stocks.", start: 1087.72, end: 1096.6),
                    ReadAlongSentence(text: "In a world where information is instant, the \"edge\" that active managers used to have is gone.", start: 1097.08, end: 1103.16),
                    ReadAlongSentence(text: "By indexing, you guarantee you will outperform 90% of professional investors simply by refusing to pay their salaries.", start: 1103.78, end: 1111.06),
                ]),
            ],
            7: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The greatest lie on Wall Street is a single number: \"EPS\" (Earnings Per Share).", start: 1117.3, end: 1122.26),
                    ReadAlongSentence(text: "The friction is that you are trained to treat this number as a hard fact.", start: 1122.92, end: 1126.58),
                    ReadAlongSentence(text: "When a company \"beats earnings estimates,\" the stock pops, and you feel safe.", start: 1127.16, end: 1132.12),
                    ReadAlongSentence(text: "But in reality, \"Net Income\" is often an opinion—a flexible figure massaged by accountants to make management look good.", start: 1132.64, end: 1140.1),
                    ReadAlongSentence(text: "Cash, on the other hand, is a fact.", start: 1140.76, end: 1142.88),
                    ReadAlongSentence(text: "Most investors fail because they buy a company based on the headline profit number without realizing the business is actually bleeding cash to keep the lights on.", start: 1143.38, end: 1151.8),
                    ReadAlongSentence(text: "They are buying a beautifully painted car with no engine.", start: 1152.6, end: 1155.58),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Kitchen Sink Trap", start: 1156.0, end: 1157.08),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author exposes this by taking us into the dark room of corporate accounting.", start: 1157.92, end: 1161.75),
                    ReadAlongSentence(text: "He tells the story of the \"Big Bath\"—a trick where a new CEO arrives and immediately writes off every possible bad investment, lawsuit, and mistake in a single quarter.", start: 1162.17, end: 1171.89),
                    ReadAlongSentence(text: "This makes the company look terrible for three months (which the CEO blames on the previous guy), but it clears the decks so that future earnings look artificially explosive.", start: 1172.39, end: 1181.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Graham warns us to ignore \"Pro Forma\" earnings—earnings that exclude \"bad stuff.\"", start: 1181.95, end: 1187.05),
                    ReadAlongSentence(text: "He likens it to a man saying he saved $1,000 this month, provided you ignore the $5,000 he spent on gambling because that was a \"one-time event.\"", start: 1187.85, end: 1196.55),
                    ReadAlongSentence(text: "The author’s solution is to distrust the Income Statement and focus on the Balance Sheet and the dividend record.", start: 1197.65, end: 1203.57),
                    ReadAlongSentence(text: "If a company says it is making millions but isn't paying dividends or building up cash, the author asks: \"Where is the money?\"", start: 1204.35, end: 1211.97),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The EBITDA Alibi", start: 1212.69, end: 1214.23),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, this manipulation has evolved into \"Adjusted EBITDA\" (Earnings Before Interest, Taxes, Depreciation, and Amortization).", start: 1215.07, end: 1224.47),
                    ReadAlongSentence(text: "This is a metric often used by high-growth Tech and AI companies to pretend they are profitable when they are not.", start: 1225.09, end: 1231.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the WeWork debacle, where the company used \"Community Adjusted EBITDA\" to hide massive losses.", start: 1232.21, end: 1239.11),
                    ReadAlongSentence(text: "Or look at modern software companies that pay their employees in millions of dollars of Stock-Based Compensation (SBC).", start: 1240.03, end: 1247.14),
                    ReadAlongSentence(text: "They claim to be \"profitable\" on an adjusted basis because they treat that stock issuance as free money.", start: 1248.12, end: 1254.26),
                    ReadAlongSentence(text: "But it isn't free—it dilutes you.", start: 1254.82, end: 1257.16),
                    ReadAlongSentence(text: "It slices the pizza into more pieces, making your slice smaller.", start: 1257.7, end: 1261.64),
                    ReadAlongSentence(text: "If you only look at the \"Non-GAAP\" earnings promoted in the press release, you are being legally lied to.", start: 1262.24, end: 1267.9),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Protocol", start: 1268.38, end: 1270.16),
                ]),
            ],
            8: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Vacuum Trap", start: 1293.9, end: 1294.88),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The biggest mistake you make is falling in love with a stock in isolation.", start: 1295.54, end: 1299.4),
                    ReadAlongSentence(text: "You see a company—let's say a popular coffee chain—and you think, \"I love their coffee, the line is always out the door, this must be a great investment.\"", start: 1300.26, end: 1308.82),
                    ReadAlongSentence(text: "You buy it because the story feels good.", start: 1309.4, end: 1311.56),
                    ReadAlongSentence(text: "This is the \"Vacuum Trap.\"", start: 1312.48, end: 1313.96),
                    ReadAlongSentence(text: "You are judging an asset without a benchmark.", start: 1314.5, end: 1317.0),
                    ReadAlongSentence(text: "It is like buying a house for $1 million without checking if the identical house next door just sold for $500,000.", start: 1317.36, end: 1323.0),
                    ReadAlongSentence(text: "Friction arises because you are judging the quality of the product rather than the value of the business.", start: 1324.52, end: 1329.76),
                    ReadAlongSentence(text: "A great company can be a terrible investment if you pay the wrong price.", start: 1330.3, end: 1334.38),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Tale of Two Companies", start: 1334.82, end: 1336.48),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author shatters this illusion by playing a game of \"Spot the Difference.\"", start: 1336.9, end: 1340.59),
                    ReadAlongSentence(text: "He takes two companies in the same industry—often a popular \"glamour\" stock and an unloved \"boring\" stock—and places their financials side-by-side, stripping away their names.", start: 1341.43, end: 1351.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of Company A (the darling) which trades at 40 times its earnings, and Company B (the outcast) which trades at 10 times its earnings.", start: 1352.25, end: 1361.53),
                    ReadAlongSentence(text: "Company A has a great story, but its balance sheet is loaded with debt.", start: 1362.11, end: 1365.81),
                    ReadAlongSentence(text: "Company B is boring, but it has zero debt and twice the cash reserves.", start: 1366.33, end: 1371.23),
                    ReadAlongSentence(text: "The author reveals that to justify its price, Company A would have to grow at a miraculous rate for a decade, while Company B just has to stay alive to make you money.", start: 1371.71, end: 1381.33),
                    ReadAlongSentence(text: "By forcing a head-to-head comparison, the \"obvious\" choice often flips.", start: 1382.15, end: 1386.29),
                    ReadAlongSentence(text: "The glamour stock is revealed as a speculation; the boring stock is revealed as the investment.", start: 1386.91, end: 1392.65),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Tesla\" Premium", start: 1393.17, end: 1394.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, this disparity has exploded.", start: 1395.35, end: 1398.05),
                    ReadAlongSentence(text: "We see it in the \"Magnificent Seven\" versus the rest of the market.", start: 1398.53, end: 1402.03),
                    ReadAlongSentence(text: "You might look at a high-flying EV maker or an AI chip designer trading at 80x earnings and think it's the only game in town.", start: 1402.65, end: 1410.11),
                    ReadAlongSentence(text: "But if you run the \"Comparison Test\" against a legacy competitor—say, a boring semiconductor firm or an established auto manufacturer—you often find that the \"old\" company has higher profit margins, better dividends, and a valuation that is 80% cheaper.", start: 1410.75, end: 1426.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern market pays a massive premium for \"narrative.\"", start: 1427.05, end: 1430.03),
                    ReadAlongSentence(text: "It overvalues the disruptor and undervalues the incumbent.", start: 1430.47, end: 1433.69),
                    ReadAlongSentence(text: "The Wiser Analysis isn't that you should never buy the growth stock; it’s that you must quantify exactly how much \"optimism\" you are paying for.", start: 1434.33, end: 1442.68),
                    ReadAlongSentence(text: "If you are paying 5x more for a dollar of earnings from Company X than from Company Y, you better be certain Company X is five times better.", start: 1443.38, end: 1452.46),
                    ReadAlongSentence(text: "Usually, it isn't.", start: 1453.22, end: 1454.34),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Protocol", start: 1454.8, end: 1455.5),
                ]),
            ],
            9: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Junk Food Portfolio", start: 1491.7, end: 1492.94),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most investors suffer from financial obesity.", start: 1493.54, end: 1496.42),
                    ReadAlongSentence(text: "You fill your portfolio with \"empty calories\"—companies that have great stories but zero nutritional value.", start: 1497.18, end: 1503.52),
                    ReadAlongSentence(text: "You buy the hot EV startup that hasn't sold a car, or the biotech firm with no revenue, because you are hungry for growth.", start: 1504.14, end: 1511.1),
                    ReadAlongSentence(text: "The friction is that in a bull market, junk rises just like quality.", start: 1511.84, end: 1515.78),
                    ReadAlongSentence(text: "You feel smart holding these fragile companies.", start: 1516.4, end: 1518.76),
                    ReadAlongSentence(text: "But when the market turns, the junk crashes 90% and never recovers, while the quality stocks just go on a diet.", start: 1519.4, end: 1526.0),
                    ReadAlongSentence(text: "You fail because you have no standards; you let any stock into your house just because it knocked on the door.", start: 1526.74, end: 1532.53),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Seven-Point Bouncer", start: 1533.09, end: 1534.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author solves this by hiring a ruthless bouncer for your portfolio.", start: 1535.27, end: 1538.99),
                    ReadAlongSentence(text: "He creates a specific \"Defensive Screen\"—a checklist of seven strict requirements that a company must meet before you even consider buying it.", start: 1539.75, end: 1547.91),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author tells us that a Defensive Investor is not a talent scout looking for the next big thing; he is a quality control inspector.", start: 1548.35, end: 1556.23),
                    ReadAlongSentence(text: "He demands:", start: 1556.65, end: 1557.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Adequate Size: No small, risky companies.", start: 1557.79, end: 1560.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Strong Financials: Current assets must be at least twice current liabilities.", start: 1561.39, end: 1566.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Earnings Stability: Positive earnings for the last 10 years.", start: 1566.77, end: 1570.47),
                    ReadAlongSentence(text: "No losses allowed.", start: 1570.97, end: 1572.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Dividend Record: Uninterrupted payments for 20 years.", start: 1572.65, end: 1575.61),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Earnings Growth: A minimum increase of 33% over the last 10 years.", start: 1576.11, end: 1581.37),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Moderate P/E: The price should not be more than 15 times average earnings.", start: 1581.81, end: 1586.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Moderate Price-to-Book: The price should not be more than 1.5 times the book value.", start: 1586.65, end: 1591.93),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If a stock fails even one of these tests, the bouncer throws it out.", start: 1592.41, end: 1596.27),
                    ReadAlongSentence(text: "It doesn't matter if it's the \"future of technology\"; if it doesn't have the numbers, it doesn't get in.", start: 1596.85, end: 1602.07),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Zombie Apocalypse", start: 1602.61, end: 1603.99),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, this screen is your only defense against \"Zombie Companies\"—firms that don't earn enough profit to cover the interest on their debt.", start: 1604.51, end: 1611.93),
                    ReadAlongSentence(text: "In the last decade of near-zero interest rates, thousands of these zombies have survived by borrowing cheap money.", start: 1612.43, end: 1618.92),
                    ReadAlongSentence(text: "They are the SPACs, the unprofitable tech IPOs, and the \"disruptors\" that bleed cash.", start: 1619.54, end: 1625.12),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You can apply Graham’s screen to filter out the noise of the modern tech bubble.", start: 1625.7, end: 1630.18),
                    ReadAlongSentence(text: "While you might relax the P/E ratio slightly for high-quality tech giants (who have asset-light models), the core principle remains: Profits matter.", start: 1630.62, end: 1639.4),
                    ReadAlongSentence(text: "Dividends matter.", start: 1640.0, end: 1641.02),
                    ReadAlongSentence(text: "A company like Uber or Airbnb in their early years would have been rejected by this screen—and Graham would be fine with that.", start: 1641.64, end: 1648.16),
                    ReadAlongSentence(text: "He would rather miss a Google than suffer a WeWork.", start: 1648.6, end: 1651.32),
                    ReadAlongSentence(text: "Today, you can automate this by looking at \"Dividend Aristocrats\" or \"Quality Factor\" ETFs, which effectively run this code for you.", start: 1651.76, end: 1659.98),
                ]),
            ],
            10: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Dumpster Diver's Dilemma", start: 1668.06, end: 1669.46),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "To be an Enterprising Investor, you must be willing to do something that feels physically repulsive: you must buy what others are throwing away.", start: 1670.06, end: 1677.7),
                    ReadAlongSentence(text: "The friction here is intense social pressure.", start: 1678.64, end: 1680.86),
                    ReadAlongSentence(text: "When a company is failing, the headlines are screaming \"Bankruptcy!\" and your friends are laughing at it.", start: 1681.34, end: 1686.4),
                    ReadAlongSentence(text: "To buy it then requires a stomach of steel.", start: 1686.86, end: 1689.2),
                    ReadAlongSentence(text: "Most people fail at this because they crave the safety of the herd.", start: 1689.68, end: 1693.22),
                    ReadAlongSentence(text: "They want to buy \"good\" companies that are winning.", start: 1693.78, end: 1697.08),
                    ReadAlongSentence(text: "But the Enterprising Investor knows a secret: a \"bad\" company at a dirt-cheap price is a better investment than a \"good\" company at an exorbitant price.", start: 1697.56, end: 1706.34),
                    ReadAlongSentence(text: "You aren't looking for quality; you are looking for a mispricing so severe that the market is practically handing you free money.", start: 1706.82, end: 1713.11),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Cigar Butt Strategy", start: 1713.79, end: 1715.01),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The author famously formalized this with the concept of the \"Net-Net.\"", start: 1715.55, end: 1719.75),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of a specific type of bargain that was once common: a company trading for less than its liquidation value.", start: 1720.31, end: 1727.09),
                    ReadAlongSentence(text: "Imagine a company that has $10 million in cash and inventory, owes $2 million in debt, and has a market cap of only $5 million.", start: 1727.63, end: 1735.55),
                    ReadAlongSentence(text: "Even if the business shuts down tomorrow, sells the inventory, and pays off the debt, there is $8 million left.", start: 1736.15, end: 1742.05),
                    ReadAlongSentence(text: "If you buy the whole company for $5 million, you make an instant $3 million profit.", start: 1742.73, end: 1747.07),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This is the \"Cigar Butt\" approach.", start: 1747.65, end: 1749.23),
                    ReadAlongSentence(text: "You find a discarded cigar on the street that is soggy and gross, but it has one good puff left in it.", start: 1749.85, end: 1755.07),
                    ReadAlongSentence(text: "It’s free, so that puff is pure profit.", start: 1755.63, end: 1758.27),
                    ReadAlongSentence(text: "The author’s solution for the Enterprising Investor is to hunt for these statistical anomalies—companies worth more dead than alive—and buy a basket of them.", start: 1759.01, end: 1767.41),
                    ReadAlongSentence(text: "You don't care about their future; you care that you bought a dollar bill for 50 cents.", start: 1768.13, end: 1772.25),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Hidden Assets of the Digital Age", start: 1772.81, end: 1775.15),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern market, true \"Net-Nets\" are rare because computers find them instantly.", start: 1775.67, end: 1780.47),
                    ReadAlongSentence(text: "However, the principle remains the most powerful tool in deep value investing.", start: 1781.15, end: 1785.71),
                    ReadAlongSentence(text: "Today, the \"hidden assets\" aren't factories or piles of coal; they are intellectual property, user bases, or even Bitcoin treasuries.", start: 1786.51, end: 1796.13),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider a legacy tech company that everyone thinks is a dinosaur.", start: 1796.85, end: 1800.63),
                    ReadAlongSentence(text: "The stock is crushed.", start: 1801.15, end: 1802.57),
                    ReadAlongSentence(text: "But on its balance sheet, it owns a massive portfolio of patents or a stake in a hot AI startup that the market has forgotten about.", start: 1802.95, end: 1810.46),
                    ReadAlongSentence(text: "Or consider a retail chain that owns its own real estate.", start: 1810.92, end: 1814.54),
                    ReadAlongSentence(text: "The market values the business at zero because \"retail is dead,\" but the land under the stores is worth more than the stock price.", start: 1814.98, end: 1822.2),
                    ReadAlongSentence(text: "This is the modern \"sum-of-the-parts\" trade.", start: 1822.68, end: 1825.12),
                    ReadAlongSentence(text: "You are looking for \"Special Situations\" where the market is so focused on the dying business that it ignores the valuable assets locked inside.", start: 1825.96, end: 1833.92),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Protocol", start: 1834.48, end: 1835.24),
                ]),
            ],
            11: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Optimism Blindfold", start: 1860.46, end: 1862.3),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The most dangerous defect in the human brain is the ability to ignore data that contradicts a happy story.", start: 1862.9, end: 1868.92),
                    ReadAlongSentence(text: "You buy a stock because the CEO is charismatic and the vision is \"world-changing.\"", start: 1869.58, end: 1874.24),
                    ReadAlongSentence(text: "When the footnotes in the financial report show massive debt or insider selling, you gloss over them.", start: 1874.88, end: 1879.96),
                    ReadAlongSentence(text: "\"They're just investing for growth,\" you tell yourself.", start: 1880.48, end: 1883.08),
                    ReadAlongSentence(text: "The friction is that you are analyzing the narrative, not the structure.", start: 1883.64, end: 1887.04),
                    ReadAlongSentence(text: "You are admiring the paint job on a house while termites are eating the foundation.", start: 1887.72, end: 1891.52),
                    ReadAlongSentence(text: "By the time the floor collapses, it is too late.", start: 1892.04, end: 1894.74),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Conglomerate House of Cards", start: 1895.28, end: 1897.34),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author masterfully exposes this by taking us back to the \"Conglomerate Boom.\"", start: 1897.88, end: 1902.05),
                    ReadAlongSentence(text: "He tells the story of companies that stopped inventing products and started inventing accounting tricks.", start: 1902.49, end: 1907.53),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine a boring company that decides to become \"exciting\" by buying up random businesses—a steel mill, an airline, a rental car agency.", start: 1907.93, end: 1917.69),
                    ReadAlongSentence(text: "On paper, their revenue explodes.", start: 1918.37, end: 1920.53),
                    ReadAlongSentence(text: "The CEO looks like a genius.", start: 1920.97, end: 1922.61),
                    ReadAlongSentence(text: "But the author peels back the curtain to reveal the rot: they paid for these acquisitions with overpriced stock and massive debt.", start: 1923.31, end: 1930.97),
                    ReadAlongSentence(text: "The \"growth\" was an illusion created by merging sloppy businesses together.", start: 1931.85, end: 1936.15),
                    ReadAlongSentence(text: "The \"Synergy\" they promised never happened.", start: 1936.75, end: 1939.63),
                    ReadAlongSentence(text: "When the economy slowed down, the debt remained, but the cash flow vanished.", start: 1940.13, end: 1943.85),
                    ReadAlongSentence(text: "The stock, once a darling of Wall Street, went to zero.", start: 1944.27, end: 1947.37),
                    ReadAlongSentence(text: "The lesson?", start: 1947.77, end: 1948.25),
                    ReadAlongSentence(text: "Complexity is often a mask for fraud.", start: 1948.63, end: 1951.27),
                    ReadAlongSentence(text: "If you cannot understand how a company makes money in two sentences, it probably doesn't.", start: 1951.79, end: 1956.55),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Community Adjusted\" Reality", start: 1956.91, end: 1958.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the red flags are hidden in plain sight under the guise of \"Innovation.\"", start: 1959.27, end: 1963.79),
                    ReadAlongSentence(text: "The modern equivalent of the Conglomerate trick is the \"Pivot.\"", start: 1964.37, end: 1967.99),
                    ReadAlongSentence(text: "When a crypto exchange collapses, or an \"AI\" startup implodes, the signs were always there.", start: 1968.59, end: 1973.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the recent \"SPAC\" (Special Purpose Acquisition Company) mania.", start: 1974.23, end: 1978.91),
                    ReadAlongSentence(text: "Companies with zero revenue were taken public based on PowerPoint slides projecting trillions in future profit.", start: 1979.79, end: 1985.91),
                    ReadAlongSentence(text: "Or look at the \"WeWork\" disaster, where the company invented a metric called \"Community Adjusted EBITDA\" to pretend that renting desks at a loss was actually profitable.", start: 1986.47, end: 1996.48),
                    ReadAlongSentence(text: "They removed the \"bad\" costs (like rent and marketing) to show a \"good\" number.", start: 1997.2, end: 2001.28),
                    ReadAlongSentence(text: "This is not accounting; it is fiction.", start: 2001.94, end: 2004.3),
                    ReadAlongSentence(text: "If a company pivots its entire business model to the latest buzzword (like adding \"Blockchain\" in 2017 or \"AI\" in 2024) without a working product, run.", start: 2004.94, end: 2015.48),
                    ReadAlongSentence(text: "They are selling you stock, not software.", start: 2016.04, end: 2018.1),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Protocol", start: 2018.74, end: 2019.5),
                ]),
            ],
            12: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Perfectionist's Fallacy", start: 2038.84, end: 2040.56),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The biggest lie you tell yourself is that you can predict the future.", start: 2041.24, end: 2044.88),
                    ReadAlongSentence(text: "You build complex spreadsheets projecting revenue for the next ten years.", start: 2045.42, end: 2049.28),
                    ReadAlongSentence(text: "You tell yourself, \"If they grow at 15% and margins stay at 20%, the stock is worth exactly $142.50.\"", start: 2049.8, end: 2055.78),
                    ReadAlongSentence(text: "The friction here is arrogance.", start: 2057.56, end: 2060.26),
                    ReadAlongSentence(text: "The world is chaotic.", start: 2060.76, end: 2062.28),
                    ReadAlongSentence(text: "Pandemics happen.", start: 2062.86, end: 2063.9),
                    ReadAlongSentence(text: "Wars start.", start: 2064.4, end: 2065.3),
                    ReadAlongSentence(text: "CEOs get fired.", start: 2065.72, end: 2067.1),
                    ReadAlongSentence(text: "If your investment only works when everything goes perfectly, you are not investing; you are walking a tightrope without a net.", start: 2067.66, end: 2074.58),
                    ReadAlongSentence(text: "One gust of wind, and you are dead.", start: 2075.1, end: 2077.2),
                    ReadAlongSentence(text: "Most people fail because they pay a price that demands perfection.", start: 2077.58, end: 2081.3),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Engineering Secret", start: 2081.92, end: 2083.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author boils down the secret of investment success into three words: Margin of Safety.", start: 2083.7, end: 2089.05),
                    ReadAlongSentence(text: "To explain it, he leaves the world of finance and enters the world of engineering.", start: 2089.81, end: 2093.77),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of building a bridge.", start: 2094.19, end: 2096.21),
                    ReadAlongSentence(text: "If you need a bridge to support a 10,000-pound truck, do you build it to hold exactly 10,000 pounds?", start: 2097.03, end: 2104.07),
                    ReadAlongSentence(text: "No.", start: 2104.77, end: 2104.87),
                    ReadAlongSentence(text: "If the truck is slightly heavier or the steel is slightly weaker, the bridge collapses.", start: 2105.57, end: 2110.13),
                    ReadAlongSentence(text: "You build it to hold 30,000 pounds.", start: 2110.63, end: 2112.99),
                    ReadAlongSentence(text: "That extra 20,000 pounds of capacity is your \"Margin of Safety.\"", start: 2113.51, end: 2117.87),
                    ReadAlongSentence(text: "It is the buffer that allows for rust, bad weather, and human error.", start: 2118.39, end: 2122.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In investing, this means if you calculate a business is worth $100 a share (its \"intrinsic value\"), you do not pay $100.", start: 2122.77, end: 2130.43),
                    ReadAlongSentence(text: "You pay $60.", start: 2131.89, end: 2132.27),
                    ReadAlongSentence(text: "That $40 gap is your protection.", start: 2133.61, end: 2135.55),
                    ReadAlongSentence(text: "It means the company can have a bad year, the economy can tank, or your math can be wrong, and you still won't lose money.", start: 2136.01, end: 2142.97),
                    ReadAlongSentence(text: "If things go right, you make a fortune.", start: 2143.65, end: 2145.63),
                    ReadAlongSentence(text: "If things go wrong, you break even.", start: 2146.17, end: 2148.19),
                    ReadAlongSentence(text: "You win by refusing to pay full price for value.", start: 2148.81, end: 2151.91),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Buffer Against Chaos", start: 2152.39, end: 2153.89),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern world, this concept is the only thing standing between you and total ruin.", start: 2154.43, end: 2159.29),
                    ReadAlongSentence(text: "We live in an era of \"Black Swans\"—unpredictable events like COVID-19 or the 2008 Financial Crisis that shatter standard economic models.", start: 2159.83, end: 2169.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the investors who bought \"safe\" tech stocks at 100 times earnings in 2021 because \"rates will stay low forever.\"", start: 2170.19, end: 2177.79),
                    ReadAlongSentence(text: "They had zero Margin of Safety.", start: 2178.51, end: 2180.15),
                    ReadAlongSentence(text: "When rates rose, their portfolios fell 70%.", start: 2180.75, end: 2182.93),
                    ReadAlongSentence(text: "Contrast this with the investor who bought energy stocks when oil was negative in 2020.", start: 2184.35, end: 2188.79),
                    ReadAlongSentence(text: "They bought assets for pennies on the dollar.", start: 2190.23, end: 2192.21),
                    ReadAlongSentence(text: "Even if the transition to green energy happens faster than expected, they bought so cheaply that they can't lose.", start: 2193.0, end: 2199.0),
                    ReadAlongSentence(text: "In a world of algorithms and AI trading, the Margin of Safety is your humility.", start: 2199.66, end: 2204.66),
                    ReadAlongSentence(text: "It is the admission that you don't know what will happen next, so you demand a discount to compensate for your ignorance.", start: 2205.22, end: 2211.2),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Protocol", start: 2211.58, end: 2212.18),
                ]),
            ],
        ],
        3: [
            1: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Have you ever noticed how the smartest people in the room often make the most disastrous financial decisions?", start: 6.88, end: 12.16),
                    ReadAlongSentence(text: "The friction comes from a fundamental misunderstanding: we treat finance like it is physics.", start: 12.84, end: 17.26),
                    ReadAlongSentence(text: "We believe it operates on immutable laws, formulas, and perfectly rational answers.", start: 17.76, end: 23.1),
                    ReadAlongSentence(text: "We assume that if we just build a complex enough system—perhaps engineering intricate data architecture to process market trends and chart the future—we can perfectly conquer the market.", start: 23.84, end: 33.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But human beings aren't code.", start: 33.94, end: 35.34),
                    ReadAlongSentence(text: "We fail because we optimize for a spreadsheet instead of optimizing for a peaceful night's sleep.", start: 35.76, end: 40.52),
                    ReadAlongSentence(text: "When you design a flawless financial plan on a quiet Sunday afternoon, you are acting rationally.", start: 41.18, end: 45.68),
                    ReadAlongSentence(text: "When the market drops 15% on a Tuesday morning and your heart starts pounding, rationality evaporates.", start: 46.38, end: 52.58),
                    ReadAlongSentence(text: "The perfectly calculated plan shatters against the reality of human emotion.", start: 53.36, end: 57.32),
                    ReadAlongSentence(text: "The secret the industry tries to hide is that trying to be completely, coldly rational is actually a trap.", start: 57.76, end: 63.6),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Fever of the Era", start: 64.13, end: 65.25),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author tells a compelling story about how our personal history dictates our financial reality.", start: 65.93, end: 71.11),
                    ReadAlongSentence(text: "Imagine two different people.", start: 71.87, end: 73.13),
                    ReadAlongSentence(text: "One was born in 1950 and watched the stock market go essentially nowhere during their formative years in the 1970s.", start: 73.63, end: 79.77),
                    ReadAlongSentence(text: "The other was born in 1970 and came of age during the unstoppable roaring bull market of the 1990s.", start: 80.29, end: 85.97),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If you ask both of them about risk, you will get two entirely opposite answers.", start: 86.59, end: 90.75),
                    ReadAlongSentence(text: "And the fascinating part?", start: 91.41, end: 92.41),
                    ReadAlongSentence(text: "No one is crazy.", start: 92.91, end: 93.95),
                    ReadAlongSentence(text: "The author points out that every financial decision makes perfect sense to the person making it at that exact moment, heavily filtered through the tiny sliver of economic history they personally experienced.", start: 94.39, end: 104.11),
                    ReadAlongSentence(text: "We are all viewing money through a highly distorted, individualized lens.", start: 104.49, end: 108.21),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Because our lenses are so biased, the author argues that aiming for strict rationality is a vulnerability.", start: 108.93, end: 114.29),
                    ReadAlongSentence(text: "A purely rational investor might look at historical data and decide to leverage themselves to the absolute limit because the expected return is mathematically positive.", start: 114.79, end: 122.63),
                    ReadAlongSentence(text: "But a reasonable investor knows that if a sudden dip causes a margin call, or simply triggers enough anxiety to force a panic exit, the math is entirely useless.", start: 123.25, end: 131.45),
                    ReadAlongSentence(text: "You must aim for a strategy that is reasonable enough to let you stay in the game long-term, even if it isn't flawlessly rational on paper.", start: 132.35, end: 139.87),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Trading the Algorithm for the Human", start: 140.53, end: 142.01),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s drag this into the reality of right now.", start: 142.47, end: 144.31),
                    ReadAlongSentence(text: "We are living in an era of overwhelming technological acceleration.", start: 144.91, end: 148.93),
                    ReadAlongSentence(text: "AI infrastructure is booming, data centers are eating massive amounts of capital, and markets swing wildly based on geopolitical murmurs or the sudden movement of a single crypto whale.", start: 149.69, end: 160.57),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, you hold an unprecedented amount of analytical power right in your pocket.", start: 161.29, end: 166.19),
                    ReadAlongSentence(text: "You can deploy an autonomous Deep Research Agent to parse a decade of dense 10-K filings in minutes, and it might tell you exactly what you need to know about a company.", start: 166.81, end: 175.07),
                    ReadAlongSentence(text: "The AI feels no fear.", start: 175.47, end: 176.65),
                    ReadAlongSentence(text: "It doesn't sweat.", start: 176.99, end: 177.59),
                    ReadAlongSentence(text: "It only sees pure expected value and cold, hard rationality.", start: 178.15, end: 182.01),
                    ReadAlongSentence(text: "But you are the one who has to stare at the screen when a sudden supply chain shock causes those exact companies to plummet 20% in a week.", start: 182.73, end: 189.21),
                    ReadAlongSentence(text: "When you look at your phone and see those red numbers flashing across your live widget, the psychological pain immediately overrides the AI's logical blueprint.", start: 189.77, end: 197.32),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In today's world of frictionless, hyper-fast mobile finance, the ultimate edge isn't just having the most sophisticated data or the fastest alert system.", start: 197.74, end: 206.5),
                    ReadAlongSentence(text: "It is building a strategy that actively accommodates your own human flaws.", start: 207.18, end: 210.98),
                    ReadAlongSentence(text: "If maintaining a theoretically \"perfect\" portfolio keeps you staring at the ceiling at 2 AM, it is a catastrophic strategy for you.", start: 211.46, end: 218.02),
                    ReadAlongSentence(text: "Wealth isn't built by the person with the smartest data; it is built by the person who creates a framework reasonable enough to survive their own worst impulses.", start: 218.68, end: 229.16),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Listen closely.", start: 260.16, end: 260.76),
                    ReadAlongSentence(text: "The financial world is obsessed with the myth of the self-made visionary.", start: 261.3, end: 264.96),
                    ReadAlongSentence(text: "When we see someone accumulate massive wealth, our immediate instinct is to dissect their morning routine, their work ethic, and their precise execution.", start: 265.4, end: 272.78),
                    ReadAlongSentence(text: "We assume their success is a direct, one-to-one output of their intelligence.", start: 273.42, end: 277.08),
                    ReadAlongSentence(text: "Conversely, when we fail, we beat ourselves up, assuming we just weren't smart enough or didn't grind hard enough.", start: 277.78, end: 283.48),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This is the friction that breaks most investors.", start: 284.06, end: 286.3),
                    ReadAlongSentence(text: "We completely ignore the massive, invisible forces constantly acting upon our lives and our portfolios.", start: 286.92, end: 293.02),
                    ReadAlongSentence(text: "We look at the winners and try to perfectly replicate their exact steps, completely forgetting that it is impossible to replicate their exact circumstances.", start: 293.5, end: 301.46),
                    ReadAlongSentence(text: "When you believe you are in complete control of the outcome, every loss destroys your confidence, and every win inflates your ego to dangerous levels.", start: 302.0, end: 309.3),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Tragic Flip of the Coin", start: 309.86, end: 311.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author illustrates this profound truth with the story of Bill Gates and his high school friend, Kent Evans.", start: 311.61, end: 316.31),
                    ReadAlongSentence(text: "In 1968, Bill Gates attended Lakeside School, which happened to be one of the only high schools in the entire world with access to a computer.", start: 317.07, end: 324.37),
                    ReadAlongSentence(text: "The odds of a teenager having access to that kind of computing power at that time were roughly one in a million.", start: 325.11, end: 329.91),
                    ReadAlongSentence(text: "That extraordinary stroke of luck set the stage for the creation of Microsoft.", start: 330.39, end: 334.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But there is a darker half to this story.", start: 335.29, end: 337.13),
                    ReadAlongSentence(text: "Gates had a best friend named Kent Evans.", start: 337.75, end: 339.81),
                    ReadAlongSentence(text: "Kent was just as brilliant as Gates, just as obsessed with coding, and shared the exact same world-changing ambition.", start: 340.27, end: 346.29),
                    ReadAlongSentence(text: "But before they even graduated, Kent died in a tragic mountaineering accident.", start: 346.89, end: 351.25),
                    ReadAlongSentence(text: "The odds of a high school student dying on a mountain are also about one in a million.", start: 351.95, end: 355.63),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Gates experienced a one-in-a-million stroke of positive variance.", start: 356.01, end: 359.51),
                    ReadAlongSentence(text: "That is luck.", start: 359.95, end: 360.89),
                    ReadAlongSentence(text: "Kent experienced a one-in-a-million stroke of negative variance.", start: 361.61, end: 364.99),
                    ReadAlongSentence(text: "That is risk.", start: 365.41, end: 366.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Luck and risk are siblings; they are doppelgängers.", start: 366.71, end: 369.85),
                    ReadAlongSentence(text: "The author reveals that outcomes are rarely just the result of individual effort.", start: 370.35, end: 374.43),
                    ReadAlongSentence(text: "Furthermore, the vast majority of massive financial success is driven by \"tails\"—extreme, rare outlier events.", start: 375.07, end: 382.87),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In finance, as in business, you can be completely wrong half the time and still make a fortune, provided your few successful ventures catch a massive tailwind.", start: 383.77, end: 392.23),
                    ReadAlongSentence(text: "You don't need to be right every time.", start: 392.87, end: 394.55),
                    ReadAlongSentence(text: "You just need to survive long enough to catch the right wave.", start: 394.89, end: 397.17),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Catching the Algorithmic Tailwind", start: 397.79, end: 399.21),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let's drag this into the reality of the modern market.", start: 399.61, end: 401.79),
                    ReadAlongSentence(text: "Think about the explosive rise of AI and data center infrastructure over the last few years.", start: 402.19, end: 407.37),
                    ReadAlongSentence(text: "Someone who heavily allocated capital into specific GPU manufacturers five years ago might be parading around as a visionary genius today.", start: 408.09, end: 415.93),
                    ReadAlongSentence(text: "But were they truly predicting the exact trajectory of generative AI, or did they happen to be standing in the right sector right before a massive, unpredictable technological boom reshaped the global economy?", start: 416.63, end: 426.4),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If you try to flawlessly replicate their specific strategy now, assuming it was pure skill, you might end up swallowing the \"risk\" side of the coin just as the market cycle shifts.", start: 426.88, end: 436.2),
                    ReadAlongSentence(text: "In today’s hyper-connected environment—where a single regulatory shift in Clean Energy, a sudden breakthrough in decentralized networks, or an overnight geopolitical trade war can erase billions in value—you cannot accurately predict the future.", start: 437.02, end: 450.88),
                    ReadAlongSentence(text: "The variables are too dense.", start: 451.54, end: 452.72),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Your objective is not to be a flawless oracle.", start: 453.2, end: 455.24),
                    ReadAlongSentence(text: "Your objective is endurance.", start: 455.7, end: 457.64),
                    ReadAlongSentence(text: "You must construct a system robust enough to weather the 99 terrible or mediocre days so that your capital is still sitting at the table when that 1 extraordinary day of massive returns finally arrives.", start: 458.32, end: 469.46),
                    ReadAlongSentence(text: "The secret isn't predicting the tails; it's surviving the wait.", start: 470.16, end: 473.66),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Have you ever noticed that hitting your financial targets rarely feels as good as you thought it would?", start: 480.24, end: 484.3),
                    ReadAlongSentence(text: "You hustle, you scrape, you finally hit that magic number in your portfolio—and within forty-eight hours, the satisfaction evaporates.", start: 484.74, end: 491.88),
                    ReadAlongSentence(text: "You immediately set a new, higher target.", start: 492.38, end: 494.54),
                    ReadAlongSentence(text: "The friction here is that most people believe wealth is a numbers game, but it is actually a psychology game.", start: 494.92, end: 500.44),
                    ReadAlongSentence(text: "We fail at this because we allow our ego to scale linearly with our net worth.", start: 500.96, end: 504.98),
                    ReadAlongSentence(text: "We step onto a hedonic treadmill, convinced that if we just get a little bit more, we will finally arrive.", start: 505.48, end: 511.04),
                    ReadAlongSentence(text: "But the goalpost has wheels.", start: 511.72, end: 513.12),
                    ReadAlongSentence(text: "People destroy perfectly good financial plans, taking catastrophic risks, simply because they are playing a game of comparison they can never win.", start: 513.72, end: 521.12),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Phantom in the Ferrari", start: 522.12, end: 523.22),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author crystalizes this trap through a brilliant concept called the \"Man in the Car Paradox.\"", start: 523.76, end: 528.42),
                    ReadAlongSentence(text: "Imagine you are walking down the street and a sleek, roaring $200,000 Ferrari pulls up to the stoplight.", start: 529.24, end: 534.53),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "What goes through your mind?", start: 534.91, end: 535.79),
                    ReadAlongSentence(text: "You almost never look at the driver and think, \"Wow, the guy driving that car is incredibly cool and successful.", start: 536.49, end: 542.43),
                    ReadAlongSentence(text: "I admire him.\"", start: 543.33, end: 544.01),
                    ReadAlongSentence(text: "Instead, you look at the car and think, \"If I had that car, people would think I am cool.\"", start: 544.65, end: 549.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Do you see the tragic irony?", start: 550.49, end: 551.69),
                    ReadAlongSentence(text: "The driver purchased the Ferrari explicitly to signal their wealth and command your admiration.", start: 552.25, end: 556.33),
                    ReadAlongSentence(text: "But you bypass the driver entirely, using their expensive possession as a mirror to reflect your own desires for status.", start: 556.97, end: 563.05),
                    ReadAlongSentence(text: "Nobody is as impressed with your stuff as you are.", start: 563.75, end: 566.09),
                    ReadAlongSentence(text: "The author also notes the tragic trajectory of incredibly wealthy executives—people who already had hundreds of millions of dollars—who committed financial crimes just to get a little bit more.", start: 566.75, end: 576.11),
                    ReadAlongSentence(text: "They risked something they had and needed (their freedom and reputation) for something they didn't have and didn't need (a higher ranking on a billionaire's list).", start: 576.77, end: 584.79),
                    ReadAlongSentence(text: "They completely forgot how to define the word \"enough.\"", start: 585.33, end: 587.79),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Flexing in the Digital Colosseum", start: 588.33, end: 590.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let's pull this into the hyper-connected reality of today.", start: 590.61, end: 593.31),
                    ReadAlongSentence(text: "The \"Man in the Car\" is no longer just a guy at a stoplight; he is everywhere.", start: 593.73, end: 597.73),
                    ReadAlongSentence(text: "The ego trap has gone digital, frictionless, and infinite.", start: 598.31, end: 601.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Fifteen years ago, you only had to compare your financial success to your immediate neighbors.", start: 602.51, end: 607.07),
                    ReadAlongSentence(text: "Today, because of social media, remote work digital nomads, and viral trading communities, you are forced to compare your portfolio to the top 0.001% of the global internet.", start: 607.67, end: 618.17),
                    ReadAlongSentence(text: "You might execute a brilliant, disciplined strategy, securing a solid, sustainable return on a clean energy ETF or a well-researched AI infrastructure play.", start: 618.97, end: 628.01),
                    ReadAlongSentence(text: "You should be thrilled.", start: 628.43, end: 631.03),
                    ReadAlongSentence(text: "But then you open your phone and see a 19-year-old who turned a stimulus check into millions by gambling on a decentralized crypto token.", start: 631.43, end: 638.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Instantly, your very reasonable success feels like a failure.", start: 638.71, end: 641.89),
                    ReadAlongSentence(text: "Your ego screams that you are falling behind.", start: 642.33, end: 644.29),
                    ReadAlongSentence(text: "In the modern market, the ultimate scarcity isn't capital or data; it is the psychological armor required to ignore what everyone else is doing.", start: 645.13, end: 653.3),
                    ReadAlongSentence(text: "If you let the viral screenshots of overnight tech millionaires dictate your baseline for success, you will eventually take uncharacteristic risks that blow up your entire life's work.", start: 654.0, end: 663.32),
                    ReadAlongSentence(text: "You have to realize that comparing your behind-the-scenes reality to someone else's curated highlight reel is a rigged game.", start: 664.1, end: 670.42),
                    ReadAlongSentence(text: "The only way to win is to refuse to play.", start: 670.86, end: 672.96),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Curse of the Maximum Yield", start: 708.92, end: 710.38),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is a secret that the loudest voices in the financial media desperately want you to ignore: hunting for the highest possible return is usually what destroys your wealth.", start: 711.0, end: 719.6),
                    ReadAlongSentence(text: "The friction here is rooted in our impatience.", start: 720.26, end: 722.48),
                    ReadAlongSentence(text: "We treat investing like a drag race, constantly scanning the horizon for the fastest-moving vehicle.", start: 722.86, end: 727.9),
                    ReadAlongSentence(text: "If one asset is up 20% and ours is only up 8%, we feel like we are losing.", start: 728.42, end: 732.82),
                    ReadAlongSentence(text: "So, we switch lanes.", start: 733.32, end: 734.6),
                    ReadAlongSentence(text: "We pivot.", start: 734.92, end: 735.32),
                    ReadAlongSentence(text: "We interrupt the process.", start: 735.74, end: 736.84),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But wealth creation isn't a drag race; it is a glacier.", start: 737.58, end: 740.46),
                    ReadAlongSentence(text: "Most people fail because they misunderstand the fundamental math of compounding.", start: 741.16, end: 745.3),
                    ReadAlongSentence(text: "They think compounding is about earning massive percentages every single year.", start: 745.98, end: 750.68),
                    ReadAlongSentence(text: "It isn't.", start: 751.32, end: 751.76),
                    ReadAlongSentence(text: "Compounding is a stubborn, slow-moving machine that only requires one input to work its magic: unbroken, continuous time.", start: 752.26, end: 759.91),
                    ReadAlongSentence(text: "Every time you panic, chase a new trend, or try to dodge a market dip, you unplug the machine and reset the clock to zero.", start: 760.63, end: 767.17),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The $81 Billion Birthday and the Price of Admission", start: 767.67, end: 770.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author shatters this illusion by pointing to the most famous investor alive: Warren Buffett.", start: 771.05, end: 775.53),
                    ReadAlongSentence(text: "We attribute Buffett’s fortune to supreme stock-picking intelligence.", start: 775.99, end: 779.49),
                    ReadAlongSentence(text: "But the author reveals a staggering mathematical reality: of Buffett's roughly $84.5 billion net worth (at the time the book was written), $81.5 billion of it came after his 65th birthday.", start: 780.21, end: 790.07),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Buffett isn't the greatest investor of all time because he had the highest annual returns.", start: 790.59, end: 794.53),
                    ReadAlongSentence(text: "In fact, there are quantitative fund managers who boast significantly higher average annual returns than him.", start: 795.11, end: 800.07),
                    ReadAlongSentence(text: "Buffett's secret is simply that he has been achieving good returns uninterrupted for three-quarters of a century.", start: 800.53, end: 805.21),
                    ReadAlongSentence(text: "He never stopped the engine.", start: 805.97, end: 807.03),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But how do you keep the engine running when the market collapses?", start: 808.15, end: 810.71),
                    ReadAlongSentence(text: "The author explains this through the metaphor of a \"fee versus a fine.\"", start: 811.19, end: 814.81),
                    ReadAlongSentence(text: "When you get a speeding ticket, that is a fine.", start: 815.33, end: 817.43),
                    ReadAlongSentence(text: "It means you did something wrong; you are being punished and you should change your behavior.", start: 817.85, end: 821.95),
                    ReadAlongSentence(text: "But when you pay $150 to get into Disneyland, that is a fee.", start: 822.35, end: 825.81),
                    ReadAlongSentence(text: "It is simply the price of admission to experience something great.", start: 826.37, end: 829.75),
                    ReadAlongSentence(text: "Market volatility—the agonizing 20% or 30% drops—is not a fine.", start: 830.55, end: 835.95),
                    ReadAlongSentence(text: "It does not mean you made a mistake.", start: 836.49, end: 837.83),
                    ReadAlongSentence(text: "It is the unavoidable fee you must pay to access the theme park of long-term compounding.", start: 838.29, end: 843.27),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Weathering the AI Super-Cycle", start: 843.77, end: 845.41),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s contextualize this for the modern market.", start: 845.91, end: 848.05),
                    ReadAlongSentence(text: "We are currently watching a massive structural shift regarding artificial intelligence, autonomous networks, and global data center expansion.", start: 848.63, end: 855.83),
                    ReadAlongSentence(text: "The long-term trajectory of these technologies is incredibly profound.", start: 856.43, end: 859.96),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "However, the day-to-day reality of participating in this super-cycle is brutal.", start: 860.62, end: 865.04),
                    ReadAlongSentence(text: "A sudden semiconductor export restriction, a minor trade war whisper, or an unexpected shift in remote-work enterprise spending can send a perfectly healthy AI infrastructure company plummeting 35% in a single month.", start: 865.5, end: 877.8),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "When modern investors see that flash crash on their screens, their instinct is to view it as a speeding ticket.", start: 878.26, end: 883.44),
                    ReadAlongSentence(text: "They think, “I made a mistake, I need to exit immediately to stop the pain.”", start: 884.08, end: 887.28),
                    ReadAlongSentence(text: "But if you truly understand the underlying thesis of the asset, that 35% drop is just the admission fee.", start: 888.16, end: 893.64),
                    ReadAlongSentence(text: "If you refuse to pay the fee of modern market volatility, you will never be allowed to stay on the ride long enough to let the compounding engine do its actual work.", start: 894.16, end: 902.14),
                    ReadAlongSentence(text: "You cannot get a multi-decade technological tailwind for free.", start: 902.64, end: 905.84),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Getting wealthy is glamorous; staying wealthy is agonizingly dull.", start: 911.16, end: 914.54),
                    ReadAlongSentence(text: "The financial world glorifies the ascent.", start: 915.16, end: 917.24),
                    ReadAlongSentence(text: "We obsess over the visionaries who see what no one else sees, the risk-takers who put everything on the line, and the bold optimists who look at a skeptical market and confidently declare, \"I am right, and everyone else is wrong.\"", start: 917.78, end: 929.64),
                    ReadAlongSentence(text: "Getting money absolutely demands this aggressive, forward-leaning posture.", start: 930.82, end: 934.48),
                    ReadAlongSentence(text: "You must be optimistic enough to believe that the future will be larger and more profitable than the past.", start: 935.2, end: 940.0),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But here is the brutal friction that shatters most portfolios: the very psychological traits required to make money are the exact traits that will mathematically guarantee you lose it.", start: 940.46, end: 948.9),
                    ReadAlongSentence(text: "People fail because they treat wealth generation and wealth preservation as the exact same discipline.", start: 949.52, end: 954.7),
                    ReadAlongSentence(text: "They are not just different skills; they are polar opposites.", start: 955.24, end: 958.04),
                    ReadAlongSentence(text: "To keep your wealth, you must undergo a complete psychological inversion.", start: 958.6, end: 962.4),
                    ReadAlongSentence(text: "You have to trade your visionary optimism for a creeping, constant paranoia.", start: 963.2, end: 968.4),
                    ReadAlongSentence(text: "You must assume that your past success was largely a byproduct of a temporary tailwind, and that tomorrow's market is actively conspiring to take it all back.", start: 969.2, end: 978.26),
                    ReadAlongSentence(text: "When you refuse to shift gears—when you keep your foot slammed on the accelerator of optimism after you have already won the race—you eventually drive your portfolio straight off a cliff.", start: 979.02, end: 988.28),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Ghost of Jesse Livermore and the Mechanics of Survival", start: 988.96, end: 991.8),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author illustrates this catastrophic failure to shift gears through the haunting story of Jesse Livermore.", start: 992.4, end: 997.49),
                    ReadAlongSentence(text: "In the early 20th century, Livermore was arguably the greatest stock trader alive.", start: 998.13, end: 1002.17),
                    ReadAlongSentence(text: "When the catastrophic market crash of 1929 hit, wiping out a generation of wealth and plunging the nation into the Great Depression, Livermore’s wife locked their doors, assuming they were completely ruined like everyone else in their social circle.", start: 1002.83, end: 1014.23),
                    ReadAlongSentence(text: "But Livermore returned home with unbelievable news: he had aggressively shorted the market.", start: 1014.61, end: 1018.81),
                    ReadAlongSentence(text: "While the world burned, Livermore made the modern equivalent of over three billion dollars in a single week.", start: 1019.39, end: 1024.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He had achieved the ultimate financial victory.", start: 1025.37, end: 1027.41),
                    ReadAlongSentence(text: "He was invincible.", start: 1027.95, end: 1029.07),
                    ReadAlongSentence(text: "But Livermore could not turn off the risk-taking engine that made him a billionaire.", start: 1029.67, end: 1033.25),
                    ReadAlongSentence(text: "He kept placing massive, highly leveraged, wildly optimistic bets on the market, assuming his own genius was a permanent shield.", start: 1033.79, end: 1040.79),
                    ReadAlongSentence(text: "He lacked the paranoia required to protect what he had built.", start: 1041.51, end: 1044.31),
                    ReadAlongSentence(text: "Four years later, Livermore had lost absolutely everything, culminating in tragedy.", start: 1045.13, end: 1049.83),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This story perfectly highlights the author’s concept of \"Room for Error,\" often called the margin of safety.", start: 1050.59, end: 1055.97),
                    ReadAlongSentence(text: "Room for error is the unspoken, unglamorous secret of the world's most enduring investors.", start: 1056.65, end: 1061.75),
                    ReadAlongSentence(text: "It is the understanding that your predictive models will eventually be wrong.", start: 1064.37, end: 1068.05),
                    ReadAlongSentence(text: "If your financial plan requires the market to perform exactly as you predicted in order for you to survive, you are playing Russian roulette.", start: 1068.85, end: 1076.15),
                    ReadAlongSentence(text: "Building an unbreakable defense means engineering a life and a portfolio that can endure a reality where your assumptions are completely shattered.", start: 1076.49, end: 1083.83),
                    ReadAlongSentence(text: "It is the realization that survival is not just one of the strategies; survival is the only foundation upon which compounding can actually work.", start: 1084.61, end: 1092.11),
                    ReadAlongSentence(text: "If you are forced out of the game during a downturn, your past brilliance is entirely erased.", start: 1092.61, end: 1097.21),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Surviving the Algorithmic Meat Grinder", start: 1097.81, end: 1099.87),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Fast forward to our current reality.", start: 1100.39, end: 1101.85),
                    ReadAlongSentence(text: "The velocity of money and the sheer speed of information have violently accelerated.", start: 1102.39, end: 1106.65),
                    ReadAlongSentence(text: "We are navigating an era of unprecedented leverage and hyperspeed narrative-driven markets.", start: 1107.09, end: 1111.89),
                    ReadAlongSentence(text: "Consider the billions of dollars currently flowing into AI infrastructure and massive data centers, the wild swings of clean energy ETFs reacting to a single regulatory rumor, or the chaotic, 24/7 global casino of cryptocurrency.", start: 1112.67, end: 1126.35),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In this hyper-connected environment, the illusion of safety is a dangerous and intoxicating trap.", start: 1126.91, end: 1132.83),
                    ReadAlongSentence(text: "People build complex, highly optimized portfolios that work flawlessly—right up until a sudden geopolitical trade war severs a critical semiconductor supply chain, or an unforeseen algorithmic shift triggers a cascading flash crash across the network.", start: 1133.31, end: 1147.41),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, having room for error isn't just about keeping a percentage of your portfolio in cash.", start: 1148.13, end: 1152.89),
                    ReadAlongSentence(text: "It is about structural, psychological defense.", start: 1153.49, end: 1156.45),
                    ReadAlongSentence(text: "It means asking yourself what happens if the remote work trend completely reverses, commercial real estate collapses, and the specific tech sector you are heavily exposed to experiences a decade-long winter.", start: 1157.31, end: 1167.78),
                    ReadAlongSentence(text: "A modern margin of safety means recognizing that the unprecedented will happen.", start: 1168.58, end: 1173.04),
                    ReadAlongSentence(text: "If you have leveraged yourself to the absolute maximum to capture the upside of the current AI super-cycle, you have left yourself zero room for error when the inevitable, unpredictable macro-shock arrives, that lack of a safety net will force you to liquidate your positions at the absolute worst time just to survive.", start: 1173.84, end: 1191.26),
                    ReadAlongSentence(text: "You must be skeptical enough to build a massive financial moat today, precisely so you can afford to be optimistic about the decades to come.", start: 1191.94, end: 1197.92),
                ]),
            ],
            6: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is a reality most people completely misunderstand about capital: we are conditioned to view money strictly as a medium of exchange for physical goods.", start: 1254.84, end: 1263.56),
                    ReadAlongSentence(text: "You earn money to exchange it for a car, a house, a vacation, or a watch.", start: 1264.24, end: 1268.42),
                    ReadAlongSentence(text: "The friction that traps almost every investor is the belief that if you are not actively spending your money on something tangible, that money is sitting idle and useless.", start: 1268.98, end: 1277.44),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Because of this, people only save with a specific purchase in mind.", start: 1278.16, end: 1281.66),
                    ReadAlongSentence(text: "They save for a down payment.", start: 1282.18, end: 1283.48),
                    ReadAlongSentence(text: "They save for a wedding.", start: 1283.9, end: 1284.98),
                    ReadAlongSentence(text: "But when you only view money as a ticket to acquire things, you inevitably fall victim to lifestyle creep.", start: 1285.46, end: 1291.08),
                    ReadAlongSentence(text: "The moment your income increases, your desires stretch to match it.", start: 1291.54, end: 1294.9),
                    ReadAlongSentence(text: "You upgrade your apartment, you upgrade your car, and suddenly your new, massive income is entirely spoken for.", start: 1295.46, end: 1301.76),
                    ReadAlongSentence(text: "You feel wealthy because you are surrounded by expensive items, but you are actually chained to a higher burn rate.", start: 1302.48, end: 1307.92),
                    ReadAlongSentence(text: "You are forced to work harder, take on more stress, and answer to more people just to maintain the baseline.", start: 1308.54, end: 1313.91),
                    ReadAlongSentence(text: "You have succeeded in acquiring money, but you have failed to acquire the one thing money is actually designed to buy.", start: 1314.37, end: 1320.45),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Highest Dividend", start: 1321.13, end: 1321.93),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author shatters this consumption mindset by revealing what he considers the single greatest intrinsic value of a dollar.", start: 1322.37, end: 1329.11),
                    ReadAlongSentence(text: "He argues that the absolute highest dividend money can possibly pay is the ability to control your own time.", start: 1329.77, end: 1334.93),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "To illustrate this, the author points to a massive, multi-decade study of elderly populations.", start: 1335.33, end: 1340.95),
                    ReadAlongSentence(text: "When researchers asked thousands of elderly people what the secret to a happy life was, almost none of them said \"working hard to make enough money to buy things.\"", start: 1341.47, end: 1349.11),
                    ReadAlongSentence(text: "None of them cared about the size of their former houses or the prestige of their titles.", start: 1349.65, end: 1353.39),
                    ReadAlongSentence(text: "The overwhelmingly common denominator for happiness was having quality time, strong relationships, and the autonomy to dictate their own schedules.", start: 1354.15, end: 1361.37),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author explains that the most powerful form of saving is saving for absolutely nothing at all.", start: 1361.99, end: 1366.91),
                    ReadAlongSentence(text: "You do not need a specific reason to save.", start: 1367.23, end: 1369.25),
                    ReadAlongSentence(text: "When you save without a goal, you are no longer saving to buy a product; you are saving to buy options.", start: 1369.99, end: 1375.25),
                    ReadAlongSentence(text: "You are purchasing a hedge against life's inevitable unpredictability.", start: 1376.03, end: 1379.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Every unspent dollar in your bank account represents a tiny piece of your future that you own outright.", start: 1379.57, end: 1384.53),
                    ReadAlongSentence(text: "It represents the ability to take a lower-paying job that you actually love, the ability to walk away from a toxic boss, or the ability to take a six-month sabbatical without your life falling apart.", start: 1385.03, end: 1396.39),
                    ReadAlongSentence(text: "True wealth is waking up in the morning and saying, \"I can do whatever I want today.\"", start: 1396.95, end: 1400.75),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Digital Sweatshop", start: 1401.49, end: 1402.47),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s translate this into the hyper-accelerated modern era.", start: 1403.01, end: 1405.81),
                    ReadAlongSentence(text: "Look around at the current boom in tech, remote work, and the frantic race to capitalize on artificial intelligence.", start: 1406.59, end: 1411.99),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "We now have a generation of highly paid \"digital nomads\" and tech executives making staggering amounts of money.", start: 1412.61, end: 1418.63),
                    ReadAlongSentence(text: "But look closely at their lives.", start: 1419.09, end: 1420.53),
                    ReadAlongSentence(text: "A remote worker might be pulling in $300,000 a year, but if they are terrified of being replaced by the latest generative AI model, and are chained to their Slack notifications 24/7 to prove their productivity, they are not free.", start: 1421.21, end: 1432.73),
                    ReadAlongSentence(text: "They have a massive income, but they are living in a digital sweatshop.", start: 1433.51, end: 1436.91),
                    ReadAlongSentence(text: "They have zero autonomy over their Tuesday afternoon.", start: 1437.4, end: 1439.88),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Conversely, consider someone who built a modest, unglamorous portfolio—perhaps a steady accumulation of basic index funds or stable tech mainstays—but purposely kept their living expenses incredibly low.", start: 1440.42, end: 1451.86),
                    ReadAlongSentence(text: "They don't have the income to charter a private jet, but they have accumulated enough unspent capital to insulate themselves from the AI panic.", start: 1452.58, end: 1459.66),
                    ReadAlongSentence(text: "If their industry shifts or a global pandemic reshapes the economy, they don't have to scramble.", start: 1460.22, end: 1464.84),
                    ReadAlongSentence(text: "They have the flexibility to pause, pivot, and retrain at their own pace.", start: 1465.5, end: 1469.5),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In today's world, where algorithms can execute trades in milliseconds and remote work blurs the line between the office and the bedroom, your time is under constant siege.", start: 1469.98, end: 1478.96),
                    ReadAlongSentence(text: "If you are using your portfolio just to fund a more expensive lifestyle, you are missing his point.", start: 1479.62, end: 1484.34),
                    ReadAlongSentence(text: "You should be using your portfolio to buy yourself out of the modern grind.", start: 1484.78, end: 1487.84),
                    ReadAlongSentence(text: "Your wealth is measured not by what you can purchase, but by how many months you can truly \"live\" without asking anyone for permission!", start: 1488.52, end: 1495.56),
                ]),
            ],
            7: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is a psychological trap that almost everyone falls into: we rely on visual cues to measure success.", start: 1501.3, end: 1507.04),
                    ReadAlongSentence(text: "If you want to know if someone is physically fit, you look at them.", start: 1507.76, end: 1511.32),
                    ReadAlongSentence(text: "If you want to know if someone is a good public speaker, you listen to them.", start: 1511.86, end: 1514.82),
                    ReadAlongSentence(text: "So, logically, if you want to know if someone is doing well financially, you look at their lifestyle.", start: 1515.54, end: 1520.34),
                    ReadAlongSentence(text: "You look at the car they drive, the zip code they live in, and the photos they post.", start: 1520.76, end: 1524.64),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The friction arises because this logic is entirely backwards when it comes to finance.", start: 1525.06, end: 1529.62),
                    ReadAlongSentence(text: "The only definitive thing you know about someone driving a $100,000 car is that they have $100,000 less in the bank than they did yesterday—or worse, they are drowning in $100,000 of debt.", start: 1530.16, end: 1539.34),
                    ReadAlongSentence(text: "People completely fail at building long-term security because they are trying to emulate the spending patterns of the rich, completely misunderstanding that true wealth is exactly what you cannot see.", start: 1539.74, end: 1550.64),
                    ReadAlongSentence(text: "When you use your money to signal to the world how much money you have, you are actively destroying the very thing you are trying to display.", start: 1551.42, end: 1557.59),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Price of the Unbought", start: 1558.31, end: 1559.43),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author delivers a masterclass on this distinction by brutally separating two words society uses interchangeably: \"Rich\" and \"Wealthy.\"", start: 1559.89, end: 1567.47),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Rich is a current income.", start: 1568.19, end: 1569.59),
                    ReadAlongSentence(text: "It is highly visible.", start: 1570.01, end: 1570.93),
                    ReadAlongSentence(text: "Even someone drowning in debt can be \"rich\" if their monthly cash flow is high enough to cover the interest payments on their massive mansion and sports car.", start: 1571.43, end: 1579.13),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Wealth, however, is hidden.", start: 1579.81, end: 1581.29),
                    ReadAlongSentence(text: "Wealth is the income not spent.", start: 1581.95, end: 1583.67),
                    ReadAlongSentence(text: "The author tells the story of the singer Rihanna, who nearly went bankrupt and sued her financial advisor.", start: 1584.25, end: 1589.37),
                    ReadAlongSentence(text: "The advisor’s defense was a profound, almost sarcastic truth: \"Was it really necessary to tell her that if you spend money on things, you will end up with the things and not the money?\"", start: 1590.07, end: 1598.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author confesses that his own personal financial strategy isn't about maximizing every single yield or driving a spectacular car.", start: 1599.45, end: 1607.01),
                    ReadAlongSentence(text: "He and his family purposefully live a quiet, unglamorous lifestyle with a massive savings rate.", start: 1607.69, end: 1612.85),
                    ReadAlongSentence(text: "Why?", start: 1613.39, end: 1613.67),
                    ReadAlongSentence(text: "Because wealth is the luxury car not purchased.", start: 1614.25, end: 1617.11),
                    ReadAlongSentence(text: "It is the big diamond ring not bought.", start: 1617.55, end: 1619.43),
                    ReadAlongSentence(text: "It is the first-class upgrade declined.", start: 1619.93, end: 1621.79),
                    ReadAlongSentence(text: "Wealth is financial assets that have not yet been converted into the stuff you see.", start: 1622.47, end: 1626.31),
                    ReadAlongSentence(text: "It is a quiet, hidden ledger of options, flexibility, and unspent potential.", start: 1627.07, end: 1631.59),
                    ReadAlongSentence(text: "If you cannot embrace the agonizingly boring act of leaving money alone, you will never build wealth; you will only ever build a facade.", start: 1632.27, end: 1639.25),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Digital Flex Economy", start: 1639.85, end: 1641.25),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s pull this into the hyper-visible reality of the present moment.", start: 1641.99, end: 1645.59),
                    ReadAlongSentence(text: "The pressure to look rich has exponentially mutated.", start: 1646.25, end: 1648.89),
                    ReadAlongSentence(text: "It is no longer just the guy in your neighborhood showing off a new lawnmower; it is a global, 24/7 digital colosseum.", start: 1649.43, end: 1656.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Look at the modern crypto ecosystem, or the explosive wealth narratives surrounding early AI infrastructure investments.", start: 1656.63, end: 1662.69),
                    ReadAlongSentence(text: "Every single day, you are bombarded with screenshots of massive decentralized wallet balances, tech founders flashing their lavish remote-work setups in Bali, or traders showcasing massive overnight gains from an obscure Data Center REIT.", start: 1663.51, end: 1676.22),
                    ReadAlongSentence(text: "This is the modern flex.", start: 1677.0, end: 1678.48),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But remember the rule of the unseen: you are only seeing the highlight reel.", start: 1679.0, end: 1682.58),
                    ReadAlongSentence(text: "What that viral screenshot does not show you is the crippling margin debt holding that portfolio together.", start: 1683.0, end: 1688.26),
                    ReadAlongSentence(text: "It does not show you the catastrophic tax liability waiting at the end of the year.", start: 1689.06, end: 1692.48),
                    ReadAlongSentence(text: "It does not show you the insomnia.", start: 1692.98, end: 1694.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In an era where everyone can instantly broadcast their perceived success, the desire to convert your unspent capital into visible status is overwhelming.", start: 1694.98, end: 1702.36),
                    ReadAlongSentence(text: "If you acquire a solid, life-changing return from a clean energy ETF, your ego will scream at you to immediately upgrade your lifestyle so the world knows you succeeded.", start: 1703.02, end: 1712.38),
                    ReadAlongSentence(text: "You have to fight this modern instinct with everything you have.", start: 1712.92, end: 1715.48),
                    ReadAlongSentence(text: "The ultimate flex in today's digital economy is having an unassailable, deeply secure financial foundation that absolutely no one on the internet knows about.", start: 1716.04, end: 1724.86),
                    ReadAlongSentence(text: "True wealth is silent.", start: 1725.64, end: 1727.4),
                ]),
            ],
            8: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the most dangerous assumption embedded in modern finance: the belief that the past is a perfect blueprint for the future.", start: 1734.26, end: 1741.6),
                    ReadAlongSentence(text: "We are conditioned to treat financial history like a hard science.", start: 1742.34, end: 1745.0),
                    ReadAlongSentence(text: "We look at past recessions, past technological revolutions, and past market crashes, and we build elaborate, hyper-detailed models to predict exactly what will happen next.", start: 1745.34, end: 1754.7),
                    ReadAlongSentence(text: "The friction that destroys so many portfolios is the misplaced confidence that if you just study enough historical data, you can eliminate uncertainty.", start: 1755.24, end: 1763.16),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But people fail because they are studying a world that no longer exists.", start: 1763.74, end: 1767.4),
                    ReadAlongSentence(text: "They build highly rigid, decades-long financial plans assuming two things will remain absolutely static: the macroeconomic environment, and their own personal desires.", start: 1767.84, end: 1777.94),
                    ReadAlongSentence(text: "Both of these assumptions are fatal.", start: 1778.7, end: 1780.18),
                    ReadAlongSentence(text: "When you lock yourself into a rigid, mathematically optimized master plan, you are completely defenseless when the world inevitably does something it has never done before.", start: 1780.82, end: 1789.0),
                    ReadAlongSentence(text: "Even worse, you are trapped when you wake up a decade later and realize the person you are today no longer wants the things the person you were ten years ago was saving for.", start: 1789.64, end: 1798.92),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Prophet’s Fallacy and the Stranger in the Mirror", start: 1799.64, end: 1801.58),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author dismantles this rigid thinking by exposing two profound psychological blind spots.", start: 1802.0, end: 1807.63),
                    ReadAlongSentence(text: "First, he addresses the illusion of history.", start: 1808.43, end: 1810.29),
                    ReadAlongSentence(text: "Economic history is not a map of the future; it is a study of unprecedented, unpredictable surprises.", start: 1810.71, end: 1816.69),
                    ReadAlongSentence(text: "Think about the most consequential economic events of the last century—the Great Depression, World War II, the dot-com bubble, or the 2008 financial crisis.", start: 1817.19, end: 1825.93),
                    ReadAlongSentence(text: "None of these events were historically precedented when they occurred.", start: 1826.65, end: 1829.51),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If you only use history as a guide to the future, you act like a prophet who is only looking in the rearview mirror.", start: 1829.95, end: 1835.47),
                    ReadAlongSentence(text: "You will successfully predict the previous crisis, but you will be completely blindsided by the next one, because the next crisis will look entirely different.", start: 1835.97, end: 1844.45),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author then pairs this with a brilliant concept from psychology: the \"End of History Illusion.\"", start: 1845.17, end: 1849.87),
                    ReadAlongSentence(text: "If you look back at who you were ten years ago, you will easily recognize how drastically your goals, personality, and priorities have changed.", start: 1850.79, end: 1857.65),
                    ReadAlongSentence(text: "However, when we look forward, we suffer from a massive failure of imagination.", start: 1858.41, end: 1862.95),
                    ReadAlongSentence(text: "We almost always assume that who we are today is the finished product.", start: 1863.73, end: 1867.47),
                    ReadAlongSentence(text: "We assume our current career ambitions, risk tolerance, and lifestyle desires will remain permanently fixed until we retire.", start: 1868.23, end: 1874.23),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This illusion leads to catastrophic financial rigidity.", start: 1874.93, end: 1877.51),
                    ReadAlongSentence(text: "A young professional might commit to an extreme, punishing frugality strategy to retire at thirty-five, only to realize at thirty-five that they actually love their work and want the capital to start a massive business instead.", start: 1879.65, end: 1890.63),
                    ReadAlongSentence(text: "The author warns that because you cannot predict the global economy, and you cannot even predict your own future personality, avoiding extreme financial commitments is the only way to survive.", start: 1891.25, end: 1899.83),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The AI Event Horizon and the Shifting Self", start: 1900.43, end: 1902.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s translate this into the hyper-volatile reality you are navigating right now.", start: 1903.25, end: 1906.99),
                    ReadAlongSentence(text: "Look at the explosion of generative AI, the staggering energy demands of modern Data Centers, and the sudden, decentralized architecture of Crypto.", start: 1907.45, end: 1914.97),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If you try to map the current AI infrastructure super-cycle perfectly onto the 1990s internet boom, you will get crushed.", start: 1915.83, end: 1922.07),
                    ReadAlongSentence(text: "The 1990s did not feature the same complex, interwoven geopolitical supply chains, immediate remote-work workforce distributions, or the instantaneous, algorithmic capital flight we see today.", start: 1922.73, end: 1933.93),
                    ReadAlongSentence(text: "We are living in an era where an unexpected trade war over a tiny semiconductor component can freeze an entire global sector overnight.", start: 1934.75, end: 1941.13),
                    ReadAlongSentence(text: "The world is writing new rules in real-time.", start: 1941.71, end: 1944.33),
                    ReadAlongSentence(text: "History cannot save you here.", start: 1944.79, end: 1946.57),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "More importantly, your relationship to this new economy will evolve.", start: 1947.17, end: 1950.27),
                    ReadAlongSentence(text: "Right now, you might have a high-risk tolerance.", start: 1950.93, end: 1953.19),
                    ReadAlongSentence(text: "You might be perfectly content concentrating your capital into volatile tech ETFs, fully willing to endure brutal 30% swings.", start: 1953.71, end: 1960.5),
                    ReadAlongSentence(text: "But what happens in seven years if you have a family, or decide to move across the country, or suddenly discover a passion for a totally different, lower-paying industry?", start: 1960.9, end: 1968.82),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If your financial architecture is so rigid that it only works if you remain an aggressive, risk-hungry tech investor forever, you are building a prison.", start: 1969.38, end: 1978.62),
                    ReadAlongSentence(text: "True financial mastery in the modern era requires extreme adaptability.", start: 1979.22, end: 1983.52),
                    ReadAlongSentence(text: "You have to build a system that leaves room for the global economy to shock you, and leaves room for you to shock yourself.", start: 1984.08, end: 1990.28),
                    ReadAlongSentence(text: "You must refuse to become a prisoner to your own past predictions.", start: 1990.88, end: 1994.12),
                ]),
            ],
            9: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the invisible trapdoor in the financial world: assuming everyone on the field is playing the exact same sport.", start: 2031.82, end: 2037.88),
                    ReadAlongSentence(text: "Most people fail at wealth creation because they suffer from financial identity theft.", start: 2038.56, end: 2042.9),
                    ReadAlongSentence(text: "They watch a stranger double their net worth in three weeks and immediately feel a sickening wave of FOMO.", start: 2044.08, end: 2049.36),
                    ReadAlongSentence(text: "They assume, subconsciously, that the stranger’s victory is their own missed opportunity.", start: 2049.96, end: 2054.52),
                    ReadAlongSentence(text: "But this is an illusion.", start: 2055.32, end: 2056.22),
                    ReadAlongSentence(text: "The friction arises when you take a financial cue from someone who has radically different risk tolerances, goals, and time horizons than you do.", start: 2056.6, end: 2064.12),
                    ReadAlongSentence(text: "You wouldn't watch a marathon runner sprinting the final 100 yards and decide to adopt that pace for the first mile of your own race.", start: 2064.64, end: 2071.42),
                    ReadAlongSentence(text: "Yet, in the markets, everyday people constantly mimic the moves of institutional sprinters, completely forgetting they are supposed to be running a marathon.", start: 2072.22, end: 2080.21),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Tale of Two Bubbles", start: 2080.93, end: 2081.89),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author tells the story of the late 1990s Dot-Com bubble to illustrate this exact psychological blind spot.", start: 2082.33, end: 2089.21),
                    ReadAlongSentence(text: "Why did otherwise rational, educated people pay utterly unjustifiable prices for internet companies with zero revenue?", start: 2089.99, end: 2097.01),
                    ReadAlongSentence(text: "The common narrative is that people just lost their minds to greed.", start: 2097.43, end: 2100.13),
                    ReadAlongSentence(text: "But the author argues something much more nuanced: the prices actually made perfect sense for the people setting them—the day traders.", start: 2100.67, end: 2107.23),
                    ReadAlongSentence(text: "If a momentum trader acquires a tech stock at $60 with the sole intention of flipping it by lunchtime for $61, they don't care about cash flow, fundamentals, or a ten-year valuation.", start: 2108.09, end: 2117.45),
                    ReadAlongSentence(text: "For their specific, short-term game, the price is entirely rational.", start: 2118.13, end: 2121.15),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The disaster strikes when a long-term investor, looking to fund a retirement two decades away, sees the day trader's momentum and copies the move.", start: 2121.85, end: 2129.55),
                    ReadAlongSentence(text: "The long-term investor is operating under the delusion that the short-term trader knows something they don't.", start: 2130.17, end: 2134.77),
                    ReadAlongSentence(text: "They take their cues from someone playing a fundamentally different game, and when the bubble bursts, the long-term player is left clutching the ashes while the day trader has long since moved on.", start: 2135.35, end: 2144.27),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The AI Illusion", start: 2144.99, end: 2146.07),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, this trap is infinitely more dangerous because the noise is deafening.", start: 2146.53, end: 2150.63),
                    ReadAlongSentence(text: "We no longer just have day traders; we have high-frequency trading networks, deep learning models, and massive institutional capital dictating market momentum.", start: 2151.27, end: 2159.39),
                    ReadAlongSentence(text: "Consider the current explosion in artificial intelligence and the massive capital flowing into data centers and semiconductor infrastructure.", start: 2160.07, end: 2166.35),
                    ReadAlongSentence(text: "When a quantitative fund deploys a complex deep learning LSTM network or uses cluster analysis to detect micro-anomalies in tech valuations, that machine is optimizing for a game measured in days, hours, or even milliseconds.", start: 2166.83, end: 2179.01),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If an everyday investor opens an interface, sees a massive price spike driven by those algorithmic maneuvers, and decides to jump in for their 30-year portfolio, they are committing the ultimate unforced error.", start: 2179.53, end: 2189.58),
                    ReadAlongSentence(text: "They are copying the homework of an entity that is solving an entirely different equation.", start: 2190.22, end: 2194.56),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The same applies to the rapid rotations into clean energy ETFs or reacting to geopolitical trade-war rumors.", start: 2195.14, end: 2201.54),
                    ReadAlongSentence(text: "The headlines will scream about massive daily gains or steep drops, but those headlines never disclose the time horizon of the people taking the profits or cutting their losses.", start: 2202.12, end: 2211.04),
                    ReadAlongSentence(text: "If you are building wealth for a decade from now, the daily noise of someone optimizing for tomorrow's closing bell is worse than useless to you—it is actively destructive.", start: 2211.72, end: 2220.78),
                    ReadAlongSentence(text: "True financial clarity comes from writing down exactly what game you are playing, and then putting blinders on.", start: 2221.38, end: 2225.82),
                    ReadAlongSentence(text: "You have to clearly define your own financial identity and ruthlessly ignore the noise from everyone else.", start: 2226.48, end: 2231.68),
                ]),
            ],
            10: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Sit in any busy coffee shop, open up your laptop, and scroll through the day's financial headlines.", start: 2239.7, end: 2244.96),
                    ReadAlongSentence(text: "Notice how the articles predicting a catastrophic market collapse are always written by people who sound like absolute geniuses.", start: 2245.76, end: 2252.88),
                    ReadAlongSentence(text: "They use complex macroeconomic jargon, cite geopolitical trade wars, and weave intricate data models to prove that the sky is falling.", start: 2253.46, end: 2261.02),
                    ReadAlongSentence(text: "In contrast, the person quietly saying, \"I think the market will probably be higher in ten years,\" sounds like a naive amateur.", start: 2261.44, end: 2268.08),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This is the friction that destroys most portfolios.", start: 2268.88, end: 2271.38),
                    ReadAlongSentence(text: "We are biologically wired to treat pessimism as an intellectual flex.", start: 2272.26, end: 2275.78),
                    ReadAlongSentence(text: "Evolution taught our ancestors that treating a rustle in the bushes as a deadly predator kept them alive, while assuming it was just the wind got them killed.", start: 2276.74, end: 2284.9),
                    ReadAlongSentence(text: "In the financial world, pessimism sounds like someone desperately trying to save your life.", start: 2285.68, end: 2289.8),
                    ReadAlongSentence(text: "Optimism sounds like a cheap, oblivious sales pitch.", start: 2290.32, end: 2292.68),
                    ReadAlongSentence(text: "The reason most people fail at long-term wealth creation is that they let the intellectual seduction of pessimism talk them out of the mathematical reality of human progress.", start: 2293.38, end: 2302.19),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Adaptation Blindspot", start: 2302.79, end: 2304.23),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author highlights a fatal flaw in pessimistic forecasting: it assumes human beings just stand still and blindly take the punishment.", start: 2304.57, end: 2311.43),
                    ReadAlongSentence(text: "When experts predict a crisis, they almost always draw a straight, downward line from today's problem directly into the future.", start: 2311.81, end: 2318.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "What they consistently fail to model is human adaptation.", start: 2319.23, end: 2322.79),
                    ReadAlongSentence(text: "The author points out the profound pessimism that follows major economic crashes or resource shortages.", start: 2323.41, end: 2328.39),
                    ReadAlongSentence(text: "Consider the early 2000s, when the smartest people in the room mathematically \"proved\" we had reached peak oil production and global economies would soon grind to a halt.", start: 2328.89, end: 2338.43),
                    ReadAlongSentence(text: "What the pessimists didn't calculate was that the looming threat of running out of oil created a massive, urgent financial incentive to invent horizontal drilling and fracking.", start: 2339.19, end: 2347.79),
                    ReadAlongSentence(text: "The problem itself funded the solution.", start: 2348.51, end: 2350.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Optimism isn't the delusional belief that everything will be perfect, that crashes won't happen, or that you won't lose money in the short term.", start: 2351.61, end: 2357.83),
                    ReadAlongSentence(text: "True financial optimism is the baseline belief that the odds of a good outcome are in your favor over time, because human beings are incredibly efficient at solving problems when their backs are against the wall.", start: 2358.59, end: 2368.59),
                    ReadAlongSentence(text: "Pessimists extrapolate the disaster; optimists bank on the response.", start: 2369.03, end: 2373.47),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Cortisol Economy", start: 2373.93, end: 2375.15),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, this biological glitch is being ruthlessly exploited.", start: 2375.59, end: 2379.23),
                    ReadAlongSentence(text: "You are not just fighting your own evolutionary wiring; you are fighting algorithms explicitly designed to monetize your anxiety.", start: 2379.97, end: 2386.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the current narrative around the technology sector.", start: 2387.47, end: 2389.73),
                    ReadAlongSentence(text: "On any given day, you can find brilliantly articulated, data-backed reports explaining why the artificial intelligence infrastructure build-out is a massive, unsustainable bubble.", start: 2390.23, end: 2398.77),
                    ReadAlongSentence(text: "You will read deeply researched white papers on how data center energy consumption will collapse the power grid, or how international trade wars will permanently sever the semiconductor supply chain.", start: 2399.21, end: 2408.43),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "These arguments sound incredibly urgent, smart, and terrifying.", start: 2409.17, end: 2412.95),
                    ReadAlongSentence(text: "But they entirely discount the invisible army of engineers and entrepreneurs currently working 80-hour weeks to optimize GPU efficiency, pioneer next-generation cooling systems, and build resilient, localized supply chains.", start: 2413.61, end: 2426.02),
                    ReadAlongSentence(text: "The media will amplify the looming disaster of an AI bottleneck because panic drives clicks and engagement.", start: 2426.64, end: 2432.54),
                    ReadAlongSentence(text: "But betting on that doom means betting against thousands of incredibly smart people who are incentivized by billions of dollars to solve that exact bottleneck.", start: 2433.12, end: 2440.4),
                    ReadAlongSentence(text: "History shows that betting against human ingenuity is a terrible long-term strategy.", start: 2440.88, end: 2445.28),
                    ReadAlongSentence(text: "The smart money knows that pessimism is for the headlines, but optimism is for the portfolio.", start: 2446.12, end: 2451.22),
                ]),
            ],
            11: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Look at the current state of the global market.", start: 2480.06, end: 2481.7),
                    ReadAlongSentence(text: "We are navigating an era of unprecedented chaos—shifting interest rates, volatile geopolitical trade wars, and entire industries being upended overnight by new technologies.", start: 2482.5, end: 2492.34),
                    ReadAlongSentence(text: "In the middle of this storm, human beings are desperate for a map.", start: 2493.22, end: 2495.96),
                    ReadAlongSentence(text: "We crave a predictable world, one where a simple, guaranteed formula leads directly to financial freedom.", start: 2496.66, end: 2502.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This craving is the invisible friction that destroys so many portfolios.", start: 2503.04, end: 2507.16),
                    ReadAlongSentence(text: "When you desperately need an outcome to be true—because you feel behind on retirement, because inflation is eating your savings, or because you just want to escape the 9-to-5 grind—your brain stops processing cold, hard data.", start: 2507.78, end: 2519.56),
                    ReadAlongSentence(text: "Instead, it starts hunting for a comforting narrative.", start: 2520.4, end: 2523.32),
                    ReadAlongSentence(text: "Most people fail at investing not because they lack intelligence, but because they are easily seduced by storytellers who promise them exactly what they want to hear.", start: 2523.74, end: 2531.6),
                    ReadAlongSentence(text: "They want a predictable universe so badly that they willingly accept financial fictions.", start: 2532.24, end: 2536.86),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Hallucination of the Oasis", start: 2537.2, end: 2538.94),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author highlights a profound psychological vulnerability: the more you want something to be true, the more likely you are to overestimate the odds of it actually being true.", start: 2539.6, end: 2548.25),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Think of a wanderer lost in the desert.", start: 2548.97, end: 2550.59),
                    ReadAlongSentence(text: "When a person is dying of thirst, they don't just hope there is a lake over the next sand dune; their brain actually fabricates a mirage.", start: 2551.07, end: 2557.47),
                    ReadAlongSentence(text: "They hallucinate an oasis because their body desperately needs water to survive.", start: 2558.23, end: 2561.85),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The exact same psychological mechanism operates in finance.", start: 2562.51, end: 2565.83),
                    ReadAlongSentence(text: "If a person is 55 years old, severely underfunded for retirement, and terrified of running out of money, they are wandering in a financial desert.", start: 2566.31, end: 2574.39),
                    ReadAlongSentence(text: "When a charismatic fund manager or a loud internet guru pitches them a revolutionary new strategy guaranteeing a 20% annual return, the investor doesn't look at the math.", start: 2575.03, end: 2584.41),
                    ReadAlongSentence(text: "They don't audit the historical failure rate of such promises.", start: 2585.03, end: 2587.39),
                    ReadAlongSentence(text: "They look at the pitch and see an oasis.", start: 2587.81, end: 2590.19),
                    ReadAlongSentence(text: "They believe the story because the alternative—that they have to work for ten more years and drastically cut their standard of living—is too painful to accept.", start: 2590.95, end: 2598.99),
                    ReadAlongSentence(text: "The narrative acts as an anesthetic against reality.", start: 2599.71, end: 2602.05),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Inevitability Trap", start: 2602.51, end: 2603.61),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the financial deserts are crowded, and the mirages are incredibly sophisticated.", start: 2604.05, end: 2608.47),
                    ReadAlongSentence(text: "We see this vividly in the massive narratives surrounding the Clean Energy transition and the Electric Vehicle (EV) revolution.", start: 2609.15, end: 2615.47),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The story being aggressively pushed is that a carbon-neutral world is an absolute, inevitable certainty.", start: 2616.17, end: 2621.75),
                    ReadAlongSentence(text: "Therefore, the narrative suggests, investing in any solar manufacturer or new EV startup is a guaranteed, morally righteous path to generational wealth.", start: 2622.33, end: 2630.95),
                    ReadAlongSentence(text: "The story feels so good.", start: 2631.37, end: 2633.03),
                    ReadAlongSentence(text: "It feels like buying into the dawn of the automotive age in 1910.", start: 2633.47, end: 2636.69),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Because everyday investors desperately want to align their money with their morals—and get rich doing it—they willingly suspend their disbelief.", start: 2638.15, end: 2645.07),
                    ReadAlongSentence(text: "They ignore the cold data: that manufacturing hardware is a brutally low-margin, capital-intensive business.", start: 2645.75, end: 2651.45),
                    ReadAlongSentence(text: "They completely dismiss the historical reality that in massive industrial revolutions, the early pioneers usually go completely bankrupt fighting vicious price wars before the ultimate winners emerge.", start: 2651.91, end: 2663.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The fiction is that a necessary global transition automatically equals a profitable, risk-free investment for you.", start: 2664.45, end: 2670.75),
                    ReadAlongSentence(text: "It doesn't.", start: 2671.47, end: 2671.97),
                    ReadAlongSentence(text: "But when you desperately want to secure your financial future while feeling like you are saving the planet, the \"Green Super-Cycle\" becomes your oasis.", start: 2672.47, end: 2680.35),
                    ReadAlongSentence(text: "You believe the hype not because the financial fundamentals support the valuation, but because you deeply need the story to be true.", start: 2681.26, end: 2687.4),
                    ReadAlongSentence(text: "Protecting your portfolio means realizing that just because an industry changes the world, doesn't mean it will make you rich.", start: 2688.2, end: 2693.38),
                ]),
            ],
            12: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Walk into any bookstore or log onto any financial forum, and you will immediately notice a common delusion: everyone is desperately searching for the \"master key.\"", start: 2751.9, end: 2760.58),
                    ReadAlongSentence(text: "The current state of the global market is a chaotic swirl of conflicting data, and in response, a multi-billion-dollar industry has emerged to sell you the illusion of a single, mathematically perfect formula.", start: 2761.58, end: 2773.1),
                    ReadAlongSentence(text: "The friction that destroys everyday investors is the quiet, nagging belief that if they are struggling, it is simply because they haven't discovered the right algorithm or the correct spreadsheet yet.", start: 2773.6, end: 2782.46),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But personal finance is not physics; there are no universal laws that apply equally to every single person.", start: 2783.1, end: 2788.78),
                    ReadAlongSentence(text: "What works brilliantly for a billionaire hedge fund manager with a forty-year time horizon will completely bankrupt a thirty-year-old teacher saving for a down payment.", start: 2789.54, end: 2797.68),
                    ReadAlongSentence(text: "The failure rate in personal wealth creation has very little to do with poor mathematics.", start: 2798.02, end: 2802.46),
                    ReadAlongSentence(text: "It has everything to do with adopting a strategy that fundamentally clashes with your unique psychological makeup.", start: 2803.18, end: 2809.12),
                    ReadAlongSentence(text: "You cannot borrow someone else's financial philosophy any more than you can borrow their personality.", start: 2809.92, end: 2814.08),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Sleep Test", start: 2814.6, end: 2815.36),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author tells a highly revealing story about his own personal finances to illustrate this exact point.", start: 2815.78, end: 2821.45),
                    ReadAlongSentence(text: "If you were to ask a high-powered supercomputer to design an investment portfolio for a young, high-income financial writer, the machine would output a very specific set of instructions.", start: 2822.05, end: 2830.51),
                    ReadAlongSentence(text: "It would tell him to heavily leverage cheap debt, maximize his risk profile in the markets, and optimize every single dollar for the highest possible yield.", start: 2831.27, end: 2838.51),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Instead, the author does the exact opposite.", start: 2839.17, end: 2841.45),
                    ReadAlongSentence(text: "He owns his house outright, refusing to carry a mortgage, and he keeps an uncomfortably large portion of his net worth sitting quietly in a standard bank account as plain, boring cash.", start: 2841.87, end: 2851.59),
                    ReadAlongSentence(text: "A purely rational economist would look at this and scream.", start: 2852.39, end: 2854.89),
                    ReadAlongSentence(text: "They would point to the spreadsheets proving that the author is losing out on massive compound interest and allowing inflation to slowly eat away at his cash reserves.", start: 2855.67, end: 2863.75),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But the author argues that he is not trying to win a spreadsheet competition.", start: 2864.47, end: 2867.85),
                    ReadAlongSentence(text: "He is trying to win the \"sleep test.\"", start: 2868.39, end: 2870.21),
                    ReadAlongSentence(text: "His personal philosophy is not optimized for maximum financial returns; it is optimized for independence and total peace of mind.", start: 2870.85, end: 2877.77),
                    ReadAlongSentence(text: "He knows his own psychology.", start: 2878.53, end: 2879.79),
                    ReadAlongSentence(text: "He knows that if a market crash wiped out his portfolio while he was heavily in debt, he would panic.", start: 2880.41, end: 2884.83),
                    ReadAlongSentence(text: "By paying off his house and holding cash, he has built a financial fortress that prevents him from ever being forced to make a desperate decision.", start: 2885.47, end: 2893.03),
                    ReadAlongSentence(text: "He chose a strategy that is technically sub-optimal in a spreadsheet, but wildly successful in real life, because it allows his family to sleep soundly at night.", start: 2893.81, end: 2903.13),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Robotic Sky", start: 2904.15, end: 2905.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the pressure to abandon your peace of mind for the sake of optimization is louder and more aggressive than ever.", start: 2905.51, end: 2911.15),
                    ReadAlongSentence(text: "Look at the bleeding edge of the market right now: the explosive emergence of autonomous robotics and the rapidly developing eVTOL (electric vertical takeoff and landing) sector.", start: 2911.67, end: 2920.83),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The narratives surrounding these technologies are intoxicating.", start: 2921.43, end: 2924.23),
                    ReadAlongSentence(text: "Social media feeds are flooded with aggressively smart analysts screaming that if you aren’t heavily exposed to the robotic supply chain or the new aerial mobility infrastructure, you are mathematically dooming your future.", start: 2924.95, end: 2935.91),
                    ReadAlongSentence(text: "They present compelling, undeniable data showing how these sectors will reshape global transportation and labor.", start: 2936.61, end: 2942.13),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But here is where you must apply the author's logic: if putting a massive chunk of your net worth into a pre-revenue flying car startup makes you check your phone fifty times a day in a cold sweat, it is the wrong strategy for you.", start: 2942.63, end: 2953.53),
                    ReadAlongSentence(text: "It does not matter if the math is right.", start: 2954.17, end: 2955.83),
                    ReadAlongSentence(text: "Even if that specific eVTOL company goes on to completely dominate the sky in 2035, the extreme volatility between now and then will shake you out.", start: 2956.21, end: 2964.63),
                    ReadAlongSentence(text: "You cannot reap the rewards of a mathematical home run if your psychological threshold forces you to abandon the game during the third inning.", start: 2965.41, end: 2972.06),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Your financial philosophy must act as a titanium filter against the noise of the \"next big thing.\"", start: 2972.44, end: 2977.32),
                    ReadAlongSentence(text: "True wealth management in the modern era is recognizing that a boring, conservative portfolio that you can stick with during a terrifying market crash will infinitely outperform a genius-level robotics portfolio that causes you to panic-exit at the exact wrong moment.", start: 2978.28, end: 2992.48),
                    ReadAlongSentence(text: "You must define your own psychological breaking point and architect your entire financial life to ensure you never cross it.", start: 2993.1, end: 2999.14),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Final Words for the Book", start: 2999.7, end: 3000.72),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The Psychology of Money reveals the ultimate paradox of finance: the most complex systems in the world are governed by the simplest human emotions.", start: 3001.32, end: 3008.2),
                    ReadAlongSentence(text: "Intelligence, pedigree, and access to sophisticated data algorithms cannot save you from your own ego, fear, or greed.", start: 3008.84, end: 3015.98),
                    ReadAlongSentence(text: "True wealth is never measured by the car in your driveway or the notifications on your screen.", start: 3016.66, end: 3020.92),
                    ReadAlongSentence(text: "It is measured by the invisible, quiet reality of waking up every single morning and knowing that you have total control over your own time.", start: 3021.34, end: 3028.76),
                    ReadAlongSentence(text: "Master your psychology, respect the role of luck, build an unbreakable margin of safety, and you will achieve the only financial goal that actually matters: absolute freedom.", start: 3029.5, end: 3039.24),
                ]),
            ],
        ],
        4: [
            1: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Smart Money\" Myth", start: 7.52, end: 8.76),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Come closer.", start: 9.52, end: 10.26),
                    ReadAlongSentence(text: "Let’s be honest about why you’re nervous.", start: 10.88, end: 12.72),
                    ReadAlongSentence(text: "You think the game is rigged.", start: 13.66, end: 15.02),
                    ReadAlongSentence(text: "You look at the guys in the glass towers with their Bloomberg terminals, high-frequency trading algorithms, and billion-dollar research budgets, and you feel like a minnow swimming with sharks.", start: 15.52, end: 25.56),
                    ReadAlongSentence(text: "You assume that to win, you need to play their game.", start: 26.3, end: 29.08),
                    ReadAlongSentence(text: "But that is exactly why most retail investors get slaughtered—they try to imitate the \"pros\" without realizing that the pros are actually handcuffed.", start: 29.66, end: 38.24),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Institutional Handcuffs", start: 38.74, end: 40.16),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch, the legend who ran the Magellan Fund, used to laugh about this.", start: 40.62, end: 44.36),
                    ReadAlongSentence(text: "He described the \"institutional imperative\" that paralyzes professional fund managers.", start: 45.1, end: 49.77),
                    ReadAlongSentence(text: "Imagine a fund manager at a cocktail party.", start: 50.69, end: 52.75),
                    ReadAlongSentence(text: "He explains that he can’t just buy a stock because it’s profitable; he has to buy what is \"acceptable.\"", start: 53.53, end: 59.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Lynch famously noted that \"You never get fired for losing money on IBM.\"", start: 59.75, end: 64.15),
                    ReadAlongSentence(text: "If a manager buys IBM and it tanks, his boss shrugs—everyone holds IBM.", start: 64.77, end: 70.11),
                    ReadAlongSentence(text: "But if that same manager buys a small, obscure company like a donut chain or a motel franchise, and that tanks?", start: 70.95, end: 77.07),
                    ReadAlongSentence(text: "He’s fired for gambling.", start: 77.51, end: 78.79),
                    ReadAlongSentence(text: "By the time an institution is \"allowed\" to buy a high-growth stock, the company has usually been performing well for years.", start: 79.29, end: 85.89),
                    ReadAlongSentence(text: "The \"Smart Money\" is actually the \"Late Money.\"", start: 86.47, end: 88.95),
                    ReadAlongSentence(text: "They are forced to wait until the coast is clear, leaving the biggest gains on the table for the flexible amateur who saw the lines out the door three years earlier.", start: 89.69, end: 97.27),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The ETF Blindspot", start: 97.83, end: 99.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This dynamic is even more aggressive in the modern era.", start: 100.01, end: 102.67),
                    ReadAlongSentence(text: "Today, the market is dominated by passive ETFs and Index Funds.", start: 103.39, end: 107.87),
                    ReadAlongSentence(text: "These funds operate on rigid rules—they must buy the biggest companies (like Apple or NVIDIA) regardless of valuation, and they cannot touch companies below a certain market cap.", start: 108.41, end: 119.39),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Think about the early days of Zoom or specialized AI tools.", start: 120.23, end: 123.77),
                    ReadAlongSentence(text: "You might use a new piece of software at work every day, loving how it solves a problem.", start: 124.33, end: 129.27),
                    ReadAlongSentence(text: "Meanwhile, Wall Street analysts can’t cover it yet because it’s too small, and the ETFs can’t buy it because it’s not in the S&P 500.", start: 129.79, end: 136.73),
                    ReadAlongSentence(text: "This creates a massive inefficiency.", start: 138.15, end: 140.2),
                    ReadAlongSentence(text: "While the algorithms are fighting over fractions of a penny on Tesla, you have free reign in the under-followed small-cap market.", start: 141.34, end: 147.98),
                    ReadAlongSentence(text: "Your lack of a \"compliance department\" is your greatest competitive advantage.", start: 148.78, end: 152.66),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Casino Fallacy", start: 190.08, end: 191.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most people treat the stock market like a casino, hoping for a lucky spin, but panicking the moment the dealer takes a chip.", start: 191.8, end: 198.26),
                    ReadAlongSentence(text: "They buy high because their neighbor made a killing, and sell low because the news anchor looked worried.", start: 199.18, end: 204.78),
                    ReadAlongSentence(text: "They fail not because they lack intelligence or data, but because they lack stomach.", start: 205.48, end: 210.1),
                    ReadAlongSentence(text: "They haven't asked themselves the only question that matters before opening a brokerage account: \"What will I do when—not if—my portfolio drops 50%?\"", start: 210.92, end: 218.74),
                    ReadAlongSentence(text: "If you don't have an answer, you are already the market's prey.", start: 220.3, end: 223.2),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Stomach Over the Brain", start: 223.7, end: 225.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch calls this \"The Mirror Test.\"", start: 225.7, end: 227.96),
                    ReadAlongSentence(text: "Before buying a single share, you must stand in front of a mirror and ask yourself three questions: \"Do I own a house?", start: 228.74, end: 235.51),
                    ReadAlongSentence(text: "Do I need the money before I can get it back?", start: 236.15, end: 238.39),
                    ReadAlongSentence(text: "Do I have the personal qualities that will bring me success?\"", start: 239.01, end: 242.01),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Lynch tells the story of the frantic calls he’d get during market crashes.", start: 242.59, end: 246.25),
                    ReadAlongSentence(text: "Even when his fund, Magellan, was the best performing in the world, the average investor in his fund actually lost money.", start: 246.81, end: 253.01),
                    ReadAlongSentence(text: "Why? because they bought in when he was on the cover of a magazine and sold out the moment the market dipped.", start: 253.61, end: 259.51),
                    ReadAlongSentence(text: "They treated the stock market like a savings account that pays 15% interest.", start: 260.13, end: 264.39),
                    ReadAlongSentence(text: "It doesn't.", start: 264.85, end: 265.39),
                    ReadAlongSentence(text: "He explains that the most important organ for investing isn't the brain; it's the stomach.", start: 266.11, end: 271.27),
                    ReadAlongSentence(text: "If you are susceptible to selling everything in a panic because \"The Big One\" is coming, you should never buy a stock in the first place.", start: 272.01, end: 278.85),
                    ReadAlongSentence(text: "You are better off in a money market fund than being right about a company but wrong about your own psychology.", start: 279.55, end: 284.73),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Gamification Trap", start: 285.23, end: 286.51),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This \"stomach\" problem has only intensified in the age of instant information and gamified trading apps.", start: 287.07, end: 293.79),
                    ReadAlongSentence(text: "In Lynch's day, you had to call a broker to sell; that friction saved people from themselves.", start: 294.51, end: 299.75),
                    ReadAlongSentence(text: "Today, you can liquidate your life savings from a notification on your watch while waiting for a latte.", start: 300.27, end: 305.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the \"Crypto crashes\" or the meme-stock frenzies.", start: 306.19, end: 309.35),
                    ReadAlongSentence(text: "Investors with high conviction in the technology (like blockchain) often get flushed out by 80% drawdowns because they used leverage or money they needed for next month's rent.", start: 310.15, end: 320.29),
                    ReadAlongSentence(text: "The volatility is the price of admission for the returns.", start: 321.13, end: 323.92),
                    ReadAlongSentence(text: "If you are constantly checking your portfolio app, getting a dopamine hit when it's green and a cortisol spike when it's red, you are failing the Mirror Test every single day.", start: 324.58, end: 334.08),
                    ReadAlongSentence(text: "You are confusing volatility (the price moving around) with risk (permanent loss of capital).", start: 334.74, end: 340.38),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Prediction Addiction", start: 373.04, end: 374.82),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The single biggest waste of time for any investor is trying to predict the economy.", start: 375.68, end: 380.42),
                    ReadAlongSentence(text: "You sit there, paralyzed, watching CNBC, terrified because the Fed might raise rates by a quarter point or because some pundit says a recession is \"imminent\" (they’ve been saying that for six years).", start: 381.24, end: 391.92),
                    ReadAlongSentence(text: "You think you’re being responsible by waiting for the \"right time\" when the skies clear.", start: 392.38, end: 396.36),
                    ReadAlongSentence(text: "But here is the brutal truth: the skies never clear.", start: 397.04, end: 400.4),
                    ReadAlongSentence(text: "There is always something to worry about.", start: 401.36, end: 403.2),
                    ReadAlongSentence(text: "If you spend 13 minutes a year thinking about economics, you've wasted 10 minutes.", start: 403.8, end: 408.7),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Cocktail Party Indicator", start: 409.24, end: 410.76),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch loved to poke fun at the \"The Great Worry.\"", start: 411.28, end: 414.27),
                    ReadAlongSentence(text: "He tells the story of how, in the 1950s, people were terrified of a nuclear war and a depression; in the 1970s, it was oil prices; in the 1980s, it was Japan taking over the world.", start: 414.95, end: 426.73),
                    ReadAlongSentence(text: "There was never a year where a sensible person couldn’t find a dozen logical reasons to sell everything and hide under the bed.", start: 427.55, end: 434.29),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Lynch illustrated this with his \"Cocktail Party Theory.\"", start: 435.07, end: 438.13),
                    ReadAlongSentence(text: "When he’d go to a party during a market bottom, no one wanted to talk about stocks; they talked about dentistry or the weather.", start: 439.05, end: 445.65),
                    ReadAlongSentence(text: "When the market was up 15%, they’d ask him for tips.", start: 446.45, end: 449.69),
                    ReadAlongSentence(text: "When the market was at a dangerous peak, they were giving him tips.", start: 450.17, end: 453.49),
                    ReadAlongSentence(text: "His point was simple: the crowd is always reacting to what has happened, not what will happen.", start: 454.27, end: 460.15),
                    ReadAlongSentence(text: "He famously said, \"If you could predict the economy, you'd be a billionaire.\"", start: 460.67, end: 464.63),
                    ReadAlongSentence(text: "Since you can't, you must ignore the macro and focus entirely on the micro: the specific earnings of the company in front of you.", start: 465.19, end: 471.81),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Doom-Scrolling Tax", start: 472.31, end: 473.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This is even harder today because the \"noise\" has become a deafening roar.", start: 474.61, end: 479.05),
                    ReadAlongSentence(text: "In Lynch's time, you had the evening news.", start: 479.63, end: 481.97),
                    ReadAlongSentence(text: "Today, you have a 24/7 feed of \"doom-scrolling\" on X (Twitter) and YouTube thumbnails screaming \"MARKET COLLAPSE IMMINENT!\"", start: 482.73, end: 490.25),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Think about the COVID-19 crash.", start: 490.97, end: 492.79),
                    ReadAlongSentence(text: "Macro-economists predicted a decade-long depression.", start: 493.29, end: 496.35),
                    ReadAlongSentence(text: "If you listened to the macro noise, you sold everything.", start: 497.41, end: 500.69),
                    ReadAlongSentence(text: "But if you ignored the economy and looked at the micro, you saw that companies like Zoom, Peloton, and Amazon were seeing explosive, unprecedented demand.", start: 501.31, end: 510.16),
                    ReadAlongSentence(text: "The economy was closed, but specific businesses were booming.", start: 510.86, end: 513.96),
                    ReadAlongSentence(text: "The same applies to AI today.", start: 514.68, end: 516.42),
                    ReadAlongSentence(text: "While pundits argue about a \"soft landing\" or \"hard landing\" for the GDP, specific companies are deploying LLMs and revolutionizing productivity regardless of what the Fed does next week.", start: 517.0, end: 529.26),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Wall Street Gatekeeper", start: 554.8, end: 556.08),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You probably think the best stock tips are hidden in a locked room on Wall Street, guarded by men in $5,000 suits whispering about \"proprietary data.\"", start: 556.7, end: 564.9),
                    ReadAlongSentence(text: "So you ignore the most powerful investment tool you own: your eyes.", start: 565.84, end: 569.7),
                    ReadAlongSentence(text: "You walk right past the next Apple or Starbucks every single day, use their products, complain about their competitors, and then go home to buy a stock you’ve never heard of because a stranger on the internet said it was \"ready to pop.\"", start: 570.46, end: 582.1),
                    ReadAlongSentence(text: "This is madness.", start: 582.64, end: 583.58),
                    ReadAlongSentence(text: "The best research isn't on a spreadsheet; it's in your shopping cart.", start: 584.34, end: 587.76),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Pantyhose Advantage", start: 588.34, end: 590.0),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch loved to humiliate the professional class with this concept.", start: 590.72, end: 594.22),
                    ReadAlongSentence(text: "He tells the story of Hanes, the company that made L’eggs pantyhose.", start: 594.68, end: 598.54),
                    ReadAlongSentence(text: "In the 1970s, Wall Street analysts were busy crunching numbers on steel mills and solar energy.", start: 599.12, end: 605.21),
                    ReadAlongSentence(text: "Meanwhile, Lynch’s wife, Carolyn, came home raving about these new pantyhose sold in plastic eggs at the grocery store.", start: 606.05, end: 612.39),
                    ReadAlongSentence(text: "They fit better, they were convenient, and she bought them every week.", start: 613.13, end: 616.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Lynch didn't run a complex discounted cash flow model initially.", start: 617.59, end: 620.93),
                    ReadAlongSentence(text: "He just looked at the checkout line.", start: 621.53, end: 623.27),
                    ReadAlongSentence(text: "He saw women buying them in droves.", start: 623.73, end: 626.01),
                    ReadAlongSentence(text: "He realized that Hanes had a monopoly on the \"supermarket pantyhose\" niche.", start: 626.53, end: 630.55),
                    ReadAlongSentence(text: "While the \"smart money\" was ignoring a boring clothing company, the stock went up six-fold.", start: 631.31, end: 635.69),
                    ReadAlongSentence(text: "He applied the same logic to Dunkin’ Donuts.", start: 636.13, end: 638.65),
                    ReadAlongSentence(text: "He didn't need an annual report to tell him the coffee was good; he just saw that the parking lot was full at 6:00 AM every single morning.", start: 639.23, end: 646.45),
                    ReadAlongSentence(text: "If you like the product, chances are millions of others do too.", start: 647.39, end: 650.95),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"User Experience\" Alpha", start: 651.65, end: 653.57),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the digital age, this \"local knowledge\" advantage has exploded.", start: 654.21, end: 658.49),
                    ReadAlongSentence(text: "You don't just shop at the mall; you work in specialized software environments and live in digital ecosystems.", start: 659.25, end: 665.17),
                    ReadAlongSentence(text: "Think about the rise of Slack or CrowdStrike.", start: 665.57, end: 668.25),
                    ReadAlongSentence(text: "Who knew about these first?", start: 668.99, end: 670.39),
                    ReadAlongSentence(text: "Not the bankers.", start: 670.97, end: 671.77),
                    ReadAlongSentence(text: "It was the IT professionals and office workers who started using them and realized, \"Wow, this is actually essential.\"", start: 672.25, end: 678.67),
                    ReadAlongSentence(text: "Or consider the Ozempic/Wegovy craze.", start: 679.41, end: 681.67),
                    ReadAlongSentence(text: "Long before the stock chart went parabolic, ordinary people in gyms and doctor’s offices were whispering about a \"miracle shot\" for weight loss.", start: 682.27, end: 689.71),
                    ReadAlongSentence(text: "If you were a receptionist at a clinic or just a person struggling with weight, you had the \"insider info\" months before the hedge funds caught on.", start: 690.53, end: 698.53),
                    ReadAlongSentence(text: "Your job, your hobbies, and your subscriptions are a goldmine of data that Wall Street can't access until the quarterly report comes out.", start: 699.37, end: 709.82),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Seduction of \"Sexy\"", start: 753.16, end: 754.4),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You are addicted to \"sexy.\"", start: 755.38, end: 756.6),
                    ReadAlongSentence(text: "You want to own the company that’s curing cancer, mining asteroids, or inventing the next iPhone.", start: 757.3, end: 762.26),
                    ReadAlongSentence(text: "You want a stock ticker you can drop into a conversation at a dinner party that makes you look sophisticated and plugged-in.", start: 762.84, end: 768.82),
                    ReadAlongSentence(text: "But here is the secret that will make you rich while your sophisticated friends go broke: excitement is expensive.", start: 769.44, end: 776.0),
                    ReadAlongSentence(text: "If a company is \"hot,\" it’s already overpriced.", start: 776.6, end: 779.3),
                    ReadAlongSentence(text: "The path to massive wealth is paved with boredom, disgust, and toxic waste.", start: 779.86, end: 784.74),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Funeral Home Moat", start: 785.22, end: 786.56),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch didn’t just tolerate boring companies; he fetishized them.", start: 787.28, end: 790.94),
                    ReadAlongSentence(text: "He tells the story of his absolute dream stock: Service Corporation International (SCI).", start: 791.72, end: 797.51),
                    ReadAlongSentence(text: "What did they do?", start: 798.03, end: 798.63),
                    ReadAlongSentence(text: "They buried people.", start: 799.27, end: 800.25),
                    ReadAlongSentence(text: "They were a funeral home chain.", start: 800.73, end: 802.47),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Lynch loved SCI because it hit every single one of his \"Perfect Stock\" criteria: it had a boring name, it did something disagreeable (nobody likes thinking about death), and rumors about the industry were depressing.", start: 803.01, end: 814.83),
                    ReadAlongSentence(text: "Wall Street analysts refused to cover it because they didn't want to call their clients and say, \"I've got a great deal on coffins.\"", start: 815.49, end: 822.13),
                    ReadAlongSentence(text: "Because the pros ignored it, the stock price stayed low relative to its earnings for years, allowing Lynch to buy in cheap while the company quietly bought up mom-and-pop funeral homes across the country, compounding its value in the shadows.", start: 823.37, end: 836.25),
                    ReadAlongSentence(text: "He jokingly said if he could find a company with a name like \"Bob’s Toxic Waste & Septic Tank Cleaning,\" he’d buy it immediately.", start: 836.91, end: 844.35),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Boredom Arbitrage", start: 845.19, end: 846.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This \"Boredom Arbitrage\" is even more potent today because the \"hype cycle\" moves faster than ever.", start: 847.59, end: 854.01),
                    ReadAlongSentence(text: "When \"AI\" became the buzzword, stocks like NVIDIA and Microsoft skyrocketed instantly.", start: 854.81, end: 860.37),
                    ReadAlongSentence(text: "The premiums were priced in within seconds.", start: 861.15, end: 863.69),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But look at the \"plumbing\" of the modern world.", start: 864.17, end: 866.41),
                    ReadAlongSentence(text: "While everyone was betting on volatile crypto exchanges, companies like Waste Management (WM) or Cintas (CTAS) (uniform rentals) were printing money.", start: 867.19, end: 876.71),
                    ReadAlongSentence(text: "Think about Costco.", start: 877.39, end: 878.27),
                    ReadAlongSentence(text: "It’s a warehouse.", start: 878.95, end: 879.77),
                    ReadAlongSentence(text: "It sells bulk toilet paper.", start: 880.43, end: 882.01),
                    ReadAlongSentence(text: "It is the definition of unsexy.", start: 882.53, end: 884.64),
                    ReadAlongSentence(text: "Yet, it has crushed the performance of most \"disruptive\" tech stocks over the long run because it dominates a niche, has a recurring revenue model (memberships), and is too boring for the \"get rich quick\" crowd to pump and dump.", start: 885.56, end: 898.14),
                    ReadAlongSentence(text: "In the software world, look for the unsexy B2B SaaS companies that handle payroll or compliance—the stuff that has to happen for the economy to function, regardless of whether ChatGPT takes over the world.", start: 898.92, end: 910.1),
                ]),
            ],
            6: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The One-Size-Fits-All Error", start: 930.96, end: 933.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You are judging a fish by its ability to climb a tree.", start: 933.84, end: 936.56),
                    ReadAlongSentence(text: "You buy a utility company and get angry when it doesn't double in six months.", start: 937.12, end: 941.28),
                    ReadAlongSentence(text: "You buy a high-growth tech stock and panic when it drops 20% in a week.", start: 941.84, end: 946.48),
                    ReadAlongSentence(text: "You are losing money because you are applying the same rules to completely different games.", start: 947.0, end: 951.16),
                    ReadAlongSentence(text: "You treat every ticker symbol as a \"stock,\" but that is like treating a racehorse, a dairy cow, and a house cat as just \"animals.\"", start: 951.86, end: 959.18),
                    ReadAlongSentence(text: "If you try to milk the racehorse, you’re going to get kicked.", start: 959.94, end: 962.58),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Taxonomy of Profit", start: 963.22, end: 964.42),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch stopped this madness by creating a strict taxonomy.", start: 964.98, end: 968.2),
                    ReadAlongSentence(text: "Before he bought a single share, he forced the company into one of six boxes: Slow Growers, Stalwarts, Fast Growers, Cyclicals, Asset Plays, or Turnarounds.", start: 968.84, end: 979.37),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of how this saved him with the auto industry.", start: 979.95, end: 983.07),
                    ReadAlongSentence(text: "Most people treated car companies like \"Stalwarts\" (steady reliable growers like Coca-Cola).", start: 983.77, end: 989.15),
                    ReadAlongSentence(text: "Lynch recognized them as \"Cyclicals\"—companies whose fortunes rise and fall with the economy.", start: 989.81, end: 995.47),
                    ReadAlongSentence(text: "When Ford was booming, amateurs bought more, thinking the growth was permanent.", start: 996.27, end: 1000.17),
                    ReadAlongSentence(text: "Lynch sold, knowing the cycle would inevitably turn.", start: 1001.11, end: 1003.77),
                    ReadAlongSentence(text: "He viewed \"Fast Growers\" (like Taco Bell in its early days) as the only ones worth holding through volatility, whereas \"Turnarounds\" (like Chrysler) were pure plays on survival, not growth.", start: 1004.45, end: 1015.51),
                    ReadAlongSentence(text: "If you don't know which category your stock is in, you don't know when to sell.", start: 1016.29, end: 1020.25),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Identity Crisis", start: 1020.97, end: 1022.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern market, misclassification is the primary cause of portfolio death.", start: 1022.49, end: 1027.27),
                    ReadAlongSentence(text: "Look at Zoom or Peloton during the pandemic.", start: 1027.91, end: 1030.19),
                    ReadAlongSentence(text: "Millions of investors mistook them for \"Fast Growers\" (permanent secular trends).", start: 1030.83, end: 1035.47),
                    ReadAlongSentence(text: "In reality, they were \"Cyclicals\" tied to the \"stay-at-home\" cycle.", start: 1035.99, end: 1040.11),
                    ReadAlongSentence(text: "When the world reopened, the cycle turned, and the stocks collapsed.", start: 1040.85, end: 1044.39),
                    ReadAlongSentence(text: "The same applies to Crypto Miners.", start: 1044.93, end: 1046.65),
                    ReadAlongSentence(text: "They are not \"tech growth stocks\"; they are commodity cyclicals tied to the price of Bitcoin.", start: 1047.41, end: 1052.67),
                    ReadAlongSentence(text: "If Bitcoin drops, their earnings vanish.", start: 1053.29, end: 1055.77),
                    ReadAlongSentence(text: "Conversely, Microsoft and Apple have transitioned from Fast Growers to \"Stalwarts.\"", start: 1056.31, end: 1061.17),
                    ReadAlongSentence(text: "They won't make you rich overnight anymore, but they offer recession protection that a small-cap AI startup simply cannot.", start: 1061.93, end: 1068.64),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Match the Strategy", start: 1069.34, end: 1070.16),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Cyclicals (Chips, Energy, Crypto): Sell when P/E is low (earnings are at peak).", start: 1070.78, end: 1076.64),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Fast Growers (AI, SaaS): Hold as long as the earnings growth story is intact.", start: 1077.1, end: 1082.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Stalwarts (Big Tech): Sell if the valuation gets absurd (e.g., 80x earnings).", start: 1082.86, end: 1088.44),
                ]),
            ],
            7: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Price Tag Distraction", start: 1110.8, end: 1112.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You are hypnotized by the wrong number.", start: 1112.66, end: 1114.66),
                    ReadAlongSentence(text: "You wake up, check your phone, and see a stock price.", start: 1115.38, end: 1118.24),
                    ReadAlongSentence(text: "It’s up $5.", start: 1118.76, end: 1119.0),
                    ReadAlongSentence(text: "You feel brilliant.", start: 1119.84, end: 1121.12),
                    ReadAlongSentence(text: "It’s down $10.", start: 1121.44, end: 1122.22),
                    ReadAlongSentence(text: "You feel like a failure.", start: 1122.88, end: 1124.18),
                    ReadAlongSentence(text: "You are letting the market’s mood swings dictate your emotional state.", start: 1124.78, end: 1128.12),
                    ReadAlongSentence(text: "This is because you view a stock as a piece of paper that magically changes value, rather than what it actually is: a claim on a stream of cash.", start: 1128.74, end: 1136.76),
                    ReadAlongSentence(text: "If you don't know exactly how the company makes a dollar of profit, you are walking blindfolded into traffic.", start: 1137.74, end: 1143.48),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Two-Minute Drill", start: 1144.02, end: 1144.94),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch had a simple cure for price-fixation: the \"Two-Minute Drill.\"", start: 1145.4, end: 1149.18),
                    ReadAlongSentence(text: "Before buying, he forced himself to deliver a monologue.", start: 1149.86, end: 1152.75),
                    ReadAlongSentence(text: "If he couldn't explain to a child in two minutes why the company's earnings were going to go up, he wouldn't buy.", start: 1153.31, end: 1158.69),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He loved to show charts where the stock price line wobbled all over the place like a drunk, while the earnings line climbed steadily upward like a staircase.", start: 1159.47, end: 1167.25),
                    ReadAlongSentence(text: "His point?", start: 1167.65, end: 1168.09),
                    ReadAlongSentence(text: "The drunk (price) eventually has to come home to the staircase (earnings).", start: 1168.85, end: 1172.91),
                    ReadAlongSentence(text: "If a company’s earnings grow by 20% a year for a decade, the stock price will eventually follow, regardless of wars, recessions, or bad moods on Wall Street.", start: 1173.35, end: 1182.31),
                    ReadAlongSentence(text: "He famously said, \"If you can’t predict the earnings, you can’t predict the stock.\"", start: 1182.99, end: 1187.07),
                    ReadAlongSentence(text: "He didn't care about the \"story\" unless the story ended in a check being cashed.", start: 1187.93, end: 1191.85),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Profitless Prosperity\" Myth", start: 1192.33, end: 1194.37),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, Silicon Valley has tried to convince you that \"Earnings don't matter\"—that \"Growth\" and \"Users\" and \"Total Addressable Market\" are the new metrics.", start: 1194.99, end: 1204.29),
                    ReadAlongSentence(text: "This is a trap.", start: 1204.93, end: 1206.05),
                    ReadAlongSentence(text: "Look at the SaaS (Software as a Service) boom of 2020-2021.", start: 1206.59, end: 1209.43),
                    ReadAlongSentence(text: "Companies like Snowflake or Asana were trading at 50x or 100x revenue while losing millions of dollars.", start: 1212.13, end: 1219.15),
                    ReadAlongSentence(text: "Investors said, \"It's a new paradigm!\"", start: 1219.71, end: 1222.19),
                    ReadAlongSentence(text: "Then interest rates rose, and the floor fell out.", start: 1222.71, end: 1225.13),
                    ReadAlongSentence(text: "The stocks that survived and thrived (like Microsoft or Alphabet) were the ones with massive, undeniable profits.", start: 1225.77, end: 1232.15),
                    ReadAlongSentence(text: "Even Uber, the poster child for \"growth at all costs,\" only became a stable investment once it proved it could actually generate positive cash flow.", start: 1232.93, end: 1241.14),
                    ReadAlongSentence(text: "The \"earnings engine\" is the only thing that keeps a stock afloat when the hype cycle ends.", start: 1241.9, end: 1246.7),
                ]),
            ],
            8: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Balance Sheet Blindness", start: 1284.64, end: 1286.4),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You are driving a sports car at 150 miles per hour, but you’ve taped over the fuel gauge because \"math is boring.\"", start: 1287.14, end: 1293.38),
                    ReadAlongSentence(text: "You love the speed—the rising stock price, the hype, the revolutionary technology.", start: 1294.14, end: 1298.64),
                    ReadAlongSentence(text: "But you are ignoring the only thing that can kill you instantly: running out of gas.", start: 1299.4, end: 1304.22),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most investors treat the Balance Sheet like a terms-and-conditions document—they scroll right past it.", start: 1305.12, end: 1310.62),
                    ReadAlongSentence(text: "They assume that if a company is \"changing the world,\" the money will sort itself out.", start: 1311.56, end: 1315.64),
                    ReadAlongSentence(text: "This is a fatal error.", start: 1316.22, end: 1317.9),
                    ReadAlongSentence(text: "Companies don't go bankrupt because they lack vision; they go bankrupt because they run out of cash.", start: 1318.58, end: 1323.88),
                    ReadAlongSentence(text: "If you cannot spot the difference between a company that is \"investing in growth\" and one that is bleeding to death, you are not an investor; you are a philanthropist for bad management.", start: 1324.84, end: 1334.68),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Debt Detective", start: 1335.22, end: 1336.26),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch approached the balance sheet not like an accountant, but like a detective at a crime scene.", start: 1336.98, end: 1342.22),
                    ReadAlongSentence(text: "He wasn't looking for \"perfect\" numbers; he was looking for the \"murder weapon\"—usually Debt.", start: 1342.68, end: 1347.63),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of Chrysler in the early 1980s.", start: 1348.55, end: 1351.11),
                    ReadAlongSentence(text: "Everyone thought the company was dead.", start: 1351.63, end: 1353.41),
                    ReadAlongSentence(text: "The stock was trading at miserable lows.", start: 1354.21, end: 1356.49),
                    ReadAlongSentence(text: "But Lynch dug into the debt structure and found a crucial detail that the market missed: Chrysler’s debt was mostly \"funded debt\" (long-term bonds), not \"bank debt\" (loans the bank can call in immediately).", start: 1357.27, end: 1369.89),
                    ReadAlongSentence(text: "This meant Chrysler had time to turn the ship around.", start: 1370.79, end: 1373.71),
                    ReadAlongSentence(text: "The banks couldn't force them into bankruptcy overnight.", start: 1374.41, end: 1376.89),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He also obsessed over Inventory.", start: 1377.65, end: 1379.41),
                    ReadAlongSentence(text: "Lynch would look at a company’s sales growth versus its inventory growth.", start: 1380.37, end: 1384.01),
                    ReadAlongSentence(text: "If sales were up 10% but inventory was up 30%, he ran for the exit.", start: 1384.93, end: 1390.93),
                    ReadAlongSentence(text: "Why?", start: 1391.15, end: 1392.25),
                    ReadAlongSentence(text: "Because it meant the company was stuffing warehouses with products nobody wanted.", start: 1392.99, end: 1396.93),
                    ReadAlongSentence(text: "In the retail world, unsold inventory is like rotting fish—the longer it sits, the more it stinks, and eventually, you have to pay someone to take it away (mark it down to zero).", start: 1397.59, end: 1407.25),
                    ReadAlongSentence(text: "He viewed a buildup of inventory as the single most reliable \"sell signal\" in the market, often appearing months before the stock price collapsed.", start: 1408.19, end: 1415.61),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The ZIRP Zombie Apocalypse", start: 1416.19, end: 1418.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the last decade, we lived through a \"Zero Interest Rate Policy\" (ZIRP) fantasy world where debt was free.", start: 1419.29, end: 1426.59),
                    ReadAlongSentence(text: "This created an entire generation of \"Zombie Companies\"—tech startups and growth stocks that survived only by constantly borrowing cheap money or issuing new shares.", start: 1427.45, end: 1436.57),
                    ReadAlongSentence(text: "They had great revenue growth but terrible balance sheets.", start: 1437.39, end: 1440.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Now that interest rates have normalized, the tide has gone out, and we can see who is swimming naked.", start: 1440.75, end: 1446.11),
                    ReadAlongSentence(text: "Look at the collapse of WeWork or the struggles of Peloton.", start: 1446.73, end: 1449.73),
                    ReadAlongSentence(text: "These companies had incredible \"stories\" and \"revenue growth,\" but their balance sheets were ticking time bombs.", start: 1450.39, end: 1455.87),
                    ReadAlongSentence(text: "They were burning cash faster than they could bring it in.", start: 1456.63, end: 1459.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, \"Financial Forensics\" means looking past the \"Adjusted EBITDA\" (which Charlie Munger famously called \"bullshit earnings\") and looking at Free Cash Flow.", start: 1459.95, end: 1469.31),
                    ReadAlongSentence(text: "In the SaaS (Software as a Service) world, look at the \"Burn Rate.\"", start: 1469.97, end: 1473.4),
                    ReadAlongSentence(text: "If a company has $100 million in the bank but burns $50 million a quarter, they have six months to live.", start: 1474.16, end: 1479.8),
                    ReadAlongSentence(text: "No amount of \"AI integration\" announcements can save a company that cannot pay its server bills.", start: 1480.5, end: 1488.24),
                ]),
            ],
            9: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Empire Builder Complex", start: 1540.36, end: 1541.76),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You love a charismatic CEO.", start: 1542.52, end: 1544.24),
                    ReadAlongSentence(text: "You watch them on TV, radiating confidence, talking about \"synergies\" and \"ecosystems,\" and you think, \"This guy is a visionary.\"", start: 1545.1, end: 1552.64),
                    ReadAlongSentence(text: "You are falling for the oldest trick in the book.", start: 1553.52, end: 1555.38),
                    ReadAlongSentence(text: "Most managers, when left unsupervised with a pile of cash, do not act like responsible stewards; they act like emperors.", start: 1556.22, end: 1563.0),
                    ReadAlongSentence(text: "They get bored with the core business that made them rich and start looking for excitement.", start: 1563.86, end: 1568.32),
                    ReadAlongSentence(text: "They want to buy a movie studio, a sports team, or a competitor they don't understand, just to make their empire bigger.", start: 1568.9, end: 1575.46),
                    ReadAlongSentence(text: "And they use your money to do it.", start: 1576.1, end: 1577.56),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Diworsification Disease", start: 1578.3, end: 1580.05),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Peter Lynch had a name for this disease: \"Diworsification.\"", start: 1580.65, end: 1583.91),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of companies that were printing money in a boring, profitable niche (like making razors or cigarettes) and then decided to \"diversify\" by buying completely unrelated businesses—like a razor company buying a turkey farm.", start: 1584.67, end: 1597.55),
                    ReadAlongSentence(text: "Lynch viewed a high dividend not just as a payout, but as a \"discipline.\"", start: 1598.35, end: 1602.37),
                    ReadAlongSentence(text: "If a company commits to paying a dividend, the CEO can't waste that cash on a foolish acquisition.", start: 1603.33, end: 1608.81),
                    ReadAlongSentence(text: "The money is gone; it’s in your pocket.", start: 1609.31, end: 1611.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He loved the \"dull\" management teams that simply raised the dividend every year.", start: 1612.03, end: 1616.23),
                    ReadAlongSentence(text: "It was a signal that the business was real.", start: 1616.79, end: 1618.75),
                    ReadAlongSentence(text: "He famously said that while companies can fake earnings with accounting tricks, \"dividends don't lie.\"", start: 1619.43, end: 1625.05),
                    ReadAlongSentence(text: "You either have the cash to pay them, or you don't.", start: 1625.57, end: 1627.97),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Buyback Charade", start: 1628.61, end: 1629.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern tech world, \"Diworsification\" has a new face: \"Moonshots.\"", start: 1630.11, end: 1634.27),
                    ReadAlongSentence(text: "Look at Meta (Facebook) in 2021-2022.", start: 1634.73, end: 1635.99),
                    ReadAlongSentence(text: "They were generating billions in ad revenue, but instead of returning it to shareholders, they burned billions trying to build the \"Metaverse.\"", start: 1638.41, end: 1645.77),
                    ReadAlongSentence(text: "The stock collapsed.", start: 1646.61, end: 1647.77),
                    ReadAlongSentence(text: "It was only when Mark Zuckerberg cut costs and initiated a dividend in 2024 that the market truly forgave him.", start: 1648.25, end: 1655.45),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the \"Dividend\" has a quieter, more tax-efficient cousin: the Stock Buyback.", start: 1656.01, end: 1660.77),
                    ReadAlongSentence(text: "Companies like Apple don't just pay dividends; they use their massive cash piles to buy their own shares, reducing the share count and making your remaining shares more valuable.", start: 1661.31, end: 1671.06),
                    ReadAlongSentence(text: "However, you must watch out for the \"fake buyback\"—where a company buys back stock just to offset the millions of shares they gave to employees as \"Stock-Based Compensation.\"", start: 1672.02, end: 1681.28),
                    ReadAlongSentence(text: "That isn't returning capital; it's just treading water.", start: 1682.5, end: 1686.98),
                ]),
            ],
            10: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Watering the Weeds", start: 1716.96, end: 1718.04),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You are likely guilty of the most destructive habit in investing: \"Cutting the flowers and watering the weeds.\"", start: 1718.74, end: 1724.08),
                    ReadAlongSentence(text: "You buy a stock, and it goes up 40%.", start: 1724.78, end: 1726.4),
                    ReadAlongSentence(text: "You get nervous.", start: 1727.74, end: 1728.54),
                    ReadAlongSentence(text: "You think, \"I better sell and lock in the profit before it disappears.\"", start: 1729.34, end: 1732.9),
                    ReadAlongSentence(text: "Then you look at your other stock that is down 40%.", start: 1733.64, end: 1735.4),
                    ReadAlongSentence(text: "You think, \"I can’t sell this one at a loss; I’ll wait for it to come back.\"", start: 1736.8, end: 1740.94),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "So, you sell the winner and keep the loser.", start: 1741.6, end: 1744.16),
                    ReadAlongSentence(text: "You have just penalized success and rewarded failure.", start: 1744.98, end: 1748.12),
                    ReadAlongSentence(text: "Over time, this leaves you with a portfolio full of stagnant \"weeds\" and zero \"flowers.\"", start: 1748.82, end: 1753.98),
                    ReadAlongSentence(text: "You are managing your emotions, not your money.", start: 1754.88, end: 1757.24),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Concentration Edge", start: 1757.78, end: 1758.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch viewed portfolio management as gardening.", start: 1759.49, end: 1762.45),
                    ReadAlongSentence(text: "He argued that there is no magic number of stocks to own, but there is a magic rule: only own what you can follow.", start: 1763.05, end: 1769.33),
                    ReadAlongSentence(text: "He mocked the idea of \"diversification\" for its own sake, calling it \"diworsification.\"", start: 1769.89, end: 1774.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If you have a distinct \"edge\" in only one company, own one.", start: 1775.65, end: 1779.09),
                    ReadAlongSentence(text: "If you find five great situations, own five.", start: 1779.65, end: 1782.23),
                    ReadAlongSentence(text: "But don't buy a 10th stock just to \"spread risk\" if you don't know anything about it.", start: 1782.99, end: 1787.49),
                    ReadAlongSentence(text: "Lynch’s strategy was to constantly rotate capital based on the \"story,\" not the price.", start: 1788.11, end: 1792.93),
                    ReadAlongSentence(text: "If a \"Stalwart\" (steady grower) went up 50% and got expensive, he would sell it to buy a \"Fast Grower\" or a \"Turnaround\" that was just starting its journey.", start: 1793.75, end: 1802.47),
                    ReadAlongSentence(text: "He didn't sell because the price was up; he sold because the opportunity had shifted to a better category.", start: 1803.27, end: 1808.75),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Fake Diversification\" Trap", start: 1809.37, end: 1812.53),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern ETF era, investors have fooled themselves into thinking they are diversified when they are actually just \"closet indexers.\"", start: 1812.97, end: 1821.15),
                    ReadAlongSentence(text: "You might own an S&P 500 ETF, a \"Tech Growth\" ETF, and a \"US Momentum\" ETF.", start: 1821.85, end: 1828.99),
                    ReadAlongSentence(text: "You think you have three distinct assets.", start: 1829.69, end: 1831.93),
                    ReadAlongSentence(text: "In reality, all three are heavily weighted in NVIDIA, Microsoft, and Apple.", start: 1832.43, end: 1837.15),
                    ReadAlongSentence(text: "You haven't diversified; you’ve just tripled your exposure to the same five companies.", start: 1837.99, end: 1842.85),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Similarly, \"Crypto Diversification\" is often a myth.", start: 1843.55, end: 1846.87),
                    ReadAlongSentence(text: "Buying 20 different \"altcoins\" isn't diversification if they all crash 90% the moment Bitcoin sneezes.", start: 1847.49, end: 1854.32),
                    ReadAlongSentence(text: "True allocation today means understanding correlation.", start: 1854.94, end: 1858.54),
                    ReadAlongSentence(text: "If everything in your portfolio turns green on the same day, you aren't diversified; you're just lucky.", start: 1859.2, end: 1864.72),
                    ReadAlongSentence(text: "A properly designed portfolio should have parts that zig when others zag—like holding cash or short-term treasuries to deploy when the \"Fast Growers\" crash.", start: 1865.58, end: 1876.32),
                ]),
            ],
            11: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Loyalty Penalty", start: 1898.86, end: 1899.88),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You treat your stocks like a marriage, sticking with them \"for better or worse\" long after the love is gone.", start: 1900.72, end: 1906.28),
                    ReadAlongSentence(text: "You bought a company because it had a great new product three years ago.", start: 1906.74, end: 1910.16),
                    ReadAlongSentence(text: "Today, competitors have flooded the market, the CEO quit, and profit margins are shrinking.", start: 1911.16, end: 1916.4),
                    ReadAlongSentence(text: "Yet you still hold on, paralyzed by nostalgia.", start: 1916.96, end: 1919.76),
                    ReadAlongSentence(text: "You are investing in a memory, not a business.", start: 1920.58, end: 1923.56),
                    ReadAlongSentence(text: "The most dangerous phrase in your vocabulary is \"I’ll just hold it for the long term,\" because \"long term\" is often just a euphemism for \"I’m too lazy to check if the thesis is broken.\"", start: 1924.44, end: 1935.3),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Life-Cycle Audit", start: 1936.04, end: 1937.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch didn't \"buy and hold\"; he \"bought and watched.\"", start: 1937.78, end: 1940.72),
                    ReadAlongSentence(text: "He treated his portfolio like a constantly evolving narrative.", start: 1941.1, end: 1944.26),
                    ReadAlongSentence(text: "He tells the story of Holiday Inn.", start: 1944.76, end: 1946.87),
                    ReadAlongSentence(text: "In the 1950s and 60s, it was a classic \"Fast Grower.\"", start: 1947.47, end: 1951.31),
                    ReadAlongSentence(text: "You could travel across America and see them popping up at every exit.", start: 1951.93, end: 1955.49),
                    ReadAlongSentence(text: "The stock was a rocket ship.", start: 1956.05, end: 1957.83),
                    ReadAlongSentence(text: "But by the mid-70s, the growth phase was mathematically over—they were everywhere.", start: 1958.27, end: 1963.15),
                    ReadAlongSentence(text: "There was no more room to build.", start: 1963.91, end: 1965.57),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Lynch realized the \"story\" had changed.", start: 1966.13, end: 1968.67),
                    ReadAlongSentence(text: "The company wasn't dying, but it had morphed from a sprinter into a slow jogger.", start: 1969.37, end: 1973.59),
                    ReadAlongSentence(text: "The investors who kept expecting \"Fast Grower\" returns from a saturated \"Stalwart\" got crushed.", start: 1974.11, end: 1979.69),
                    ReadAlongSentence(text: "He instituted a \"Two-Minute Drill\" re-check every few months.", start: 1980.59, end: 1984.07),
                    ReadAlongSentence(text: "If the story had drifted—like a company moving from \"high growth\" to \"cyclical\"—he didn't hesitate to sell, even if he liked the stock.", start: 1984.67, end: 1991.87),
                    ReadAlongSentence(text: "He knew that when the story ends, you have to leave the theater.", start: 1992.69, end: 1996.15),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Disruption Clock", start: 1996.61, end: 1997.63),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern world, \"stories\" rot faster than ever.", start: 1998.35, end: 2001.45),
                    ReadAlongSentence(text: "Technology accelerates the lifecycle of companies.", start: 2002.29, end: 2005.35),
                    ReadAlongSentence(text: "Think about BlackBerry.", start: 2006.07, end: 2007.37),
                    ReadAlongSentence(text: "For years, it was the standard for business communication.", start: 2007.95, end: 2010.77),
                    ReadAlongSentence(text: "It was a \"Fast Grower.\"", start: 2011.47, end: 2012.69),
                    ReadAlongSentence(text: "Then the iPhone launched.", start: 2013.25, end: 2014.65),
                    ReadAlongSentence(text: "The story didn't just change; it evaporated overnight.", start: 2015.37, end: 2018.31),
                    ReadAlongSentence(text: "Investors who re-evaluated the \"moat\" (physical keyboards vs. touchscreens) got out.", start: 2018.73, end: 2025.13),
                    ReadAlongSentence(text: "Those who relied on past glory (\"Everyone uses BBM!\") lost everything.", start: 2025.63, end: 2030.39),
                    ReadAlongSentence(text: "The same happened with Peloton.", start: 2031.13, end: 2032.63),
                    ReadAlongSentence(text: "The \"story\" was: \"Everyone is working out at home forever.\"", start: 2033.29, end: 2036.69),
                    ReadAlongSentence(text: "Then gyms reopened.", start: 2037.35, end: 2038.53),
                    ReadAlongSentence(text: "The story broke.", start: 2038.93, end: 2039.85),
                    ReadAlongSentence(text: "If you didn't re-evaluate immediately when vaccines rolled out, you rode the stock all the way down.", start: 2040.59, end: 2045.96),
                    ReadAlongSentence(text: "Today, you must watch for \"AI Disruption.\"", start: 2046.46, end: 2049.32),
                    ReadAlongSentence(text: "Is your \"Stalwart\" software company about to be automated away by a Large Language Model?", start: 2050.26, end: 2054.82),
                    ReadAlongSentence(text: "If the fundamental \"why\" of your investment is threatened by a new technology, you must sell before the earnings report confirms the damage.", start: 2055.6, end: 2063.0),
                ]),
            ],
            12: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Emotional Inversion", start: 2095.76, end: 2097.32),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Buying a stock is like falling in love—it’s exciting, full of promise, and driven by dopamine.", start: 2098.26, end: 2104.12),
                    ReadAlongSentence(text: "Selling a stock is like a divorce—it’s painful, confusing, and driven by fear.", start: 2104.92, end: 2109.54),
                    ReadAlongSentence(text: "Most investors are terrible at \"the breakup.\"", start: 2110.34, end: 2112.32),
                    ReadAlongSentence(text: "You sell your winners too early because you’re terrified the profit will vanish (locking in a small gain), and you hold your losers too long because you can’t admit you were wrong (praying for a rebound).", start: 2113.12, end: 2122.72),
                    ReadAlongSentence(text: "You are emotionally inverted: you are loyal to the things that hurt you and fickle with the things that help you.", start: 2123.24, end: 2128.38),
                    ReadAlongSentence(text: "You need a prenup for your portfolio.", start: 2128.98, end: 2130.72),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Cyclical Peak", start: 2131.32, end: 2132.4),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Peter Lynch didn’t believe in \"target prices.\"", start: 2132.88, end: 2135.14),
                    ReadAlongSentence(text: "He believed in \"Category Signals.\"", start: 2135.62, end: 2137.46),
                    ReadAlongSentence(text: "He realized that the signal to sell a fast-growing restaurant chain is completely different from the signal to sell a boring chemical company.", start: 2138.06, end: 2144.9),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of the Cyclical Trap.", start: 2145.34, end: 2147.7),
                    ReadAlongSentence(text: "Amateur investors love to buy Cyclicals (like auto companies or steel mills) when the P/E ratio is low, thinking they are getting a bargain.", start: 2148.38, end: 2156.88),
                    ReadAlongSentence(text: "Lynch whispered the exact opposite: \"Sell the Cyclical when the P/E is low.\"", start: 2157.38, end: 2161.67),
                    ReadAlongSentence(text: "Why?", start: 2162.37, end: 2162.67),
                    ReadAlongSentence(text: "Because for a Cyclical, a low P/E means earnings are at a record high, the economy is booming, and everything is perfect.", start: 2163.59, end: 2171.13),
                    ReadAlongSentence(text: "This is the top.", start: 2172.33, end: 2173.31),
                    ReadAlongSentence(text: "The only place to go is down.", start: 2173.99, end: 2175.83),
                    ReadAlongSentence(text: "Conversely, he advised holding Fast Growers (like a young Walmart or Taco Bell) even if the P/E looked high, provided the growth story was still intact.", start: 2176.55, end: 2185.39),
                    ReadAlongSentence(text: "As long as they were opening new stores and same-store sales were rising, he held on.", start: 2186.15, end: 2191.03),
                    ReadAlongSentence(text: "He didn't sell because the stock went up; he sold only when the company stopped growing or the valuation became mathematically impossible (like a Stalwart trading at 50x earnings).", start: 2191.81, end: 2201.85),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Algorithmic Front-Run", start: 2202.71, end: 2204.15),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In today’s hyper-speed market, \"The Exit\" is even more critical because algorithms punish missed expectations instantly.", start: 2204.69, end: 2212.15),
                    ReadAlongSentence(text: "Look at the Semiconductor Industry (NVIDIA, AMD).", start: 2212.99, end: 2216.33),
                    ReadAlongSentence(text: "These are the ultimate modern Cyclicals.", start: 2217.19, end: 2219.45),
                    ReadAlongSentence(text: "When demand for AI chips is insatiable, their P/E ratios compress because earnings explode.", start: 2220.21, end: 2226.27),
                    ReadAlongSentence(text: "That is precisely the danger zone.", start: 2226.91, end: 2228.69),
                    ReadAlongSentence(text: "If you wait for the headlines to say \"Chip Shortage Over,\" the stock will have already dropped 40%.", start: 2229.39, end: 2233.87),
                    ReadAlongSentence(text: "The market \"front-runs\" the cycle.", start: 2235.65, end: 2238.01),
                    ReadAlongSentence(text: "Similarly, look at Crypto.", start: 2238.57, end: 2240.07),
                    ReadAlongSentence(text: "The \"Sell the News\" phenomenon is real.", start: 2240.81, end: 2243.51),
                    ReadAlongSentence(text: "When the Bitcoin ETF was finally approved in early 2024, the price dropped.", start: 2244.01, end: 2249.11),
                    ReadAlongSentence(text: "Why?", start: 2249.51, end: 2249.79),
                    ReadAlongSentence(text: "Because the anticipation was the trade.", start: 2250.15, end: 2252.63),
                    ReadAlongSentence(text: "Once the event happened, the smart money exited into the liquidity provided by the retail crowd buying the headline.", start: 2253.11, end: 2258.87),
                    ReadAlongSentence(text: "And for the \"COVID Winners\" (Zoom, DocuSign): The sell signal wasn't the price; it was the return to the office.", start: 2259.69, end: 2266.11),
                    ReadAlongSentence(text: "The moment the behavioral trend shifted, the \"Fast Grower\" thesis died, and the exit protocol should have triggered immediately, regardless of the loss.", start: 2266.97, end: 2275.39),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Final Words", start: 2275.43, end: 2276.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Wall Street has spent billions constructing an illusion designed to intimidate you, desperate to make you believe that beating the market requires a team of analysts, expensive terminals, or complex deep learning models predicting price movements.", start: 2276.67, end: 2289.91),
                    ReadAlongSentence(text: "In reality, their massive size and rigid institutional compliance rules are their fatal flaws, forcing them to buy late and locking them out of the most lucrative early-stage growth.", start: 2290.69, end: 2301.36),
                    ReadAlongSentence(text: "By stripping away the macroeconomic noise and ignoring the seduction of \"sexy\" trends, you’ve discovered that your greatest competitive moat is your own daily life.", start: 2301.94, end: 2310.52),
                    ReadAlongSentence(text: "The \"Smart Money\" is handcuffed, but you—the observant amateur—have the agility to spot the next massive winner in your shopping cart, your software stack, or your local neighborhood long before the index funds are allowed to buy in.", start: 2311.18, end: 2323.62),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Tomorrow morning, when the opening bell rings and the financial networks scream about the next imminent crisis, you are no longer the market's prey.", start: 2324.16, end: 2331.42),
                    ReadAlongSentence(text: "You now operate with a ruthless, resilient system: you know how to leverage your local knowledge, run the financial forensics on an earnings engine, and execute strict exit protocols based on a company's true category rather than its stock price.", start: 2332.36, end: 2345.08),
                    ReadAlongSentence(text: "You are no longer playing their gamified, high-frequency casino; you are playing the quiet, patient game of business ownership.", start: 2345.58, end: 2352.28),
                    ReadAlongSentence(text: "So, trust the balance sheet, and just look around you—the edge has been yours the whole time, and now you finally know how to master it.", start: 2352.9, end: 2361.02),
                ]),
            ],
        ],
        5: [
            1: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Sanitized\" Trap", start: 8.22, end: 9.42),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the uncomfortable truth: if you are making investment decisions based solely on annual reports or CNBC headlines, you are already the \"sucker at the table.\"", start: 10.08, end: 19.46),
                    ReadAlongSentence(text: "Why?", start: 20.1, end: 20.38),
                    ReadAlongSentence(text: "Because that information has been sanitized by lawyers, polished by PR firms, and digested by millions of algorithms before you ever see it.", start: 21.04, end: 28.6),
                    ReadAlongSentence(text: "Most investors fail because they analyze a stock like a consumer reading a menu.", start: 29.14, end: 33.56),
                    ReadAlongSentence(text: "They look at the price and the description, assuming what is listed is exactly what will be served.", start: 34.44, end: 39.46),
                    ReadAlongSentence(text: "But the real story—the one that drives 10x returns or prevents catastrophic losses—is never on the menu.", start: 39.96, end: 46.22),
                    ReadAlongSentence(text: "It’s in the kitchen.", start: 47.1, end: 48.03),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Gossip Network", start: 48.57, end: 49.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Philip Fisher didn’t trust the menu.", start: 50.53, end: 52.23),
                    ReadAlongSentence(text: "He coined the term \"Scuttlebutt\"—an old naval term for the gossip around the water cooler.", start: 52.89, end: 57.89),
                    ReadAlongSentence(text: "Fisher’s genius wasn't in analyzing balance sheets, but in acting like a detective.", start: 58.55, end: 62.99),
                    ReadAlongSentence(text: "He believed that the most honest information about a company (Company A) never came from Company A itself.", start: 63.51, end: 74.41),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Instead, Fisher would go to Company B—their fiercest competitor—and ask, \"What is Company A doing that worries you?\"", start: 74.85, end: 81.81),
                    ReadAlongSentence(text: "He would talk to suppliers, customers, and even former employees.", start: 82.49, end: 85.75),
                    ReadAlongSentence(text: "He found that while a CEO might lie about their growth, a competitor will never lie about who they are losing customers to.", start: 86.39, end: 92.63),
                    ReadAlongSentence(text: "This triangulation of \"gossip\" creates a 3D picture of reality that a spreadsheet never could.", start: 93.15, end: 98.59),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Digital Forensics", start: 99.19, end: 100.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Fisher had to rely on telephone calls and lunch meetings; you have a supercomputer in your pocket.", start: 100.71, end: 105.65),
                    ReadAlongSentence(text: "Today, \"Scuttlebutt\" is digital forensics.", start: 106.25, end: 108.61),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Employee Sentiment: Don’t just read the ESG report.", start: 109.17, end: 112.31),
                    ReadAlongSentence(text: "Go to Glassdoor or Blind.", start: 113.03, end: 114.89),
                    ReadAlongSentence(text: "Are the engineers at that AI startup complaining about \"spaghetti code\" and high turnover?", start: 115.61, end: 120.39),
                    ReadAlongSentence(text: "That’s a sell signal no earnings call will reveal.", start: 121.13, end: 123.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Customer Reality: If you’re looking at a consumer brand, ignore the projected sales deck.", start: 124.21, end: 129.25),
                    ReadAlongSentence(text: "Go to Reddit or Twitter/X.", start: 130.01, end: 131.97),
                    ReadAlongSentence(text: "Are early adopters raving about the product, or are they complaining about shipping delays?", start: 133.09, end: 137.65),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Supply Chain Checks: In the age of global logistics, tracking import data or supplier contracts can tell you if a company is actually ramping up production before they announce it.", start: 138.49, end: 149.8),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Better Mousetrap\" Fallacy", start: 193.96, end: 195.42),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the most expensive mistake you will ever make: assuming the best product wins.", start: 196.34, end: 200.58),
                    ReadAlongSentence(text: "You find a tech company with faster chips, cleaner code, or a revolutionary drug.", start: 201.2, end: 205.58),
                    ReadAlongSentence(text: "You pile in, convinced the world will beat a path to their door.", start: 206.1, end: 209.3),
                    ReadAlongSentence(text: "One year later, the stock is flat, and a competitor with inferior tech is eating their lunch.", start: 210.0, end: 215.06),
                    ReadAlongSentence(text: "Why?", start: 215.68, end: 215.96),
                    ReadAlongSentence(text: "You fell for the \"Engineer’s Delusion.\"", start: 216.48, end: 218.32),
                    ReadAlongSentence(text: "You audited the engine (the innovation) but ignored the transmission (the sales force).", start: 218.86, end: 223.24),
                    ReadAlongSentence(text: "An engine without a transmission just makes noise; it doesn't move the car.", start: 223.96, end: 227.86),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Invisible Army", start: 228.62, end: 229.78),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Philip Fisher refused to invest in \"lab experiments.\"", start: 230.7, end: 233.46),
                    ReadAlongSentence(text: "He tells the story of visiting companies where the R&D department was treated like royalty—pristine labs, unlimited budgets, geniuses in white coats.", start: 234.06, end: 242.27),
                    ReadAlongSentence(text: "But when he asked about the sales organization, the executives would wave it off as a necessary evil.", start: 243.23, end: 248.19),
                    ReadAlongSentence(text: "Fisher would immediately walk away.", start: 249.13, end: 250.75),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He knew that without a ruthless, efficient mechanism to educate the customer, innovation is just an expensive hobby.", start: 251.47, end: 257.83),
                    ReadAlongSentence(text: "He looked for companies that treated their salespeople with the same reverence as their scientists.", start: 258.45, end: 262.89),
                    ReadAlongSentence(text: "Fisher realized that a \"profit squeeze\" rarely comes from high manufacturing costs; it comes from an inefficient sales team that burns cash trying to find customers.", start: 263.57, end: 272.75),
                    ReadAlongSentence(text: "The \"Common Stock\" winner wasn't just an inventor; it was a master storyteller.", start: 273.63, end: 278.17),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Distribution Moat", start: 279.05, end: 280.13),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the digital age, the most effective salesperson often isn’t a human in a suit; it’s the code itself.", start: 280.93, end: 286.35),
                    ReadAlongSentence(text: "Fisher’s obsession with the \"sales organization\" has evolved into what we now call Product-Led Growth (PLG).", start: 287.21, end: 293.35),
                    ReadAlongSentence(text: "Look at the battle between Slack and HipChat.", start: 294.37, end: 296.53),
                    ReadAlongSentence(text: "HipChat had the first-mover advantage, but Slack didn't just build a chat app; they engineered a viral sales loop directly into the user experience.", start: 297.11, end: 305.29),
                    ReadAlongSentence(text: "Fisher would tell you today that if a user needs a manual or a sales call just to start using the software, the engine is already stalling.", start: 306.13, end: 313.33),
                    ReadAlongSentence(text: "The product must sell itself before the sales team even picks up the phone.", start: 313.97, end: 317.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This distinction is currently deciding the winners in the AI gold rush.", start: 318.41, end: 322.03),
                    ReadAlongSentence(text: "Right now, thousands of startups are wrapping the exact same underlying models (LLMs) and claiming they have a revolutionary engine.", start: 322.59, end: 330.55),
                    ReadAlongSentence(text: "They don't.", start: 331.15, end: 331.65),
                    ReadAlongSentence(text: "The moat today isn't the algorithm, which is rapidly becoming a commodity; it’s the workflow and the community.", start: 333.43, end: 339.19),
                    ReadAlongSentence(text: "A crypto project might have groundbreaking sharding technology, but if their Discord server is a ghost town or their documentation is impenetrable, the 'engine' is worthless.", start: 339.89, end: 349.86),
                    ReadAlongSentence(text: "You must look for companies that obsess over the integration of their tech into daily life, not just the tech itself.", start: 350.52, end: 356.4),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Visionary\" Trap", start: 400.12, end: 401.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You watch the keynote.", start: 401.8, end: 402.94),
                    ReadAlongSentence(text: "The CEO strides across the stage in a leather jacket, promising to revolutionize the industry with a single algorithm.", start: 403.5, end: 409.88),
                    ReadAlongSentence(text: "You are hooked.", start: 410.58, end: 411.42),
                    ReadAlongSentence(text: "You buy the stock.", start: 411.92, end: 412.8),
                    ReadAlongSentence(text: "Six months later, you are down 40%.", start: 413.44, end: 414.98),
                    ReadAlongSentence(text: "Why?", start: 416.54, end: 416.84),
                    ReadAlongSentence(text: "Because you bought the sales pitch, not the operator.", start: 417.46, end: 420.38),
                    ReadAlongSentence(text: "You fell for the \"Charisma Trap.\"", start: 420.82, end: 422.28),
                    ReadAlongSentence(text: "Most investors fail here because they assess a captain only when the sea is calm.", start: 422.96, end: 427.04),
                    ReadAlongSentence(text: "But a CEO’s true DNA isn't revealed in the CNBC interview when the stock is at an all-time high; it is revealed in the silence that follows a disaster.", start: 427.7, end: 436.42),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Clam\" Test", start: 436.94, end: 438.1),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Philip Fisher had a ruthless litmus test for management: The \"Clam\" Factor.", start: 438.76, end: 442.71),
                    ReadAlongSentence(text: "He tells the story of management teams that were the darlings of Wall Street—friendly, accessible, and constantly issuing press releases—as long as the charts were green.", start: 443.43, end: 452.15),
                    ReadAlongSentence(text: "But the moment a factory burned down or a product failed, the phone lines went dead.", start: 452.79, end: 457.37),
                    ReadAlongSentence(text: "They \"clammed up.\"", start: 457.89, end: 458.79),
                    ReadAlongSentence(text: "Fisher instantly sold these stocks.", start: 459.45, end: 461.29),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He realized that a management team that hides from its shareholders during a crisis lacks the fundamental integrity to build long-term wealth.", start: 461.93, end: 469.45),
                    ReadAlongSentence(text: "He hunted for the rare leaders who were more talkative when losing money than when making it.", start: 470.15, end: 474.29),
                    ReadAlongSentence(text: "For Fisher, candor in a crisis was the only true indicator of a company’s survival instinct.", start: 474.83, end: 479.85),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Era of the \"Twitter Meltdown\"", start: 480.39, end: 482.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, the \"Clam\" has evolved into the \"Deflector.\"", start: 482.83, end: 486.47),
                    ReadAlongSentence(text: "We live in the age of the Cult CEO, where leaders often use social media to bypass scrutiny.", start: 487.27, end: 492.79),
                    ReadAlongSentence(text: "Look at the crypto collapse of FTX.", start: 493.65, end: 495.81),
                    ReadAlongSentence(text: "Investors were blinded by the effective altruism and the media persona, missing the complete lack of internal controls.", start: 496.53, end: 503.31),
                    ReadAlongSentence(text: "The red flag wasn't silence; it was the noise of distraction.", start: 503.91, end: 507.15),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, you must analyze how a CEO handles \"technical debt\" and remote culture.", start: 507.83, end: 512.51),
                    ReadAlongSentence(text: "When a tech giant misses a quarter, does the CEO take the blame for over-hiring, or do they blame \"lazy remote workers\" and demand a return to the office?", start: 513.21, end: 521.37),
                    ReadAlongSentence(text: "The latter is a modern \"Clam\"—a leader refusing to own their strategic failure.", start: 521.89, end: 526.23),
                    ReadAlongSentence(text: "True \"Management DNA\" in the 2020s looks like Jensen Huang at NVIDIA or Satya Nadella at Microsoft, who dissect their own failures publicly before the market can do it for them.", start: 526.91, end: 536.82),
                    ReadAlongSentence(text: "They treat the shareholders as partners, not an audience to be managed.", start: 537.64, end: 541.02),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Limit Order\" Tragedy", start: 587.96, end: 589.58),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is how you lose a fortune while trying to save lunch money.", start: 590.36, end: 593.68),
                    ReadAlongSentence(text: "You find the perfect company.", start: 594.38, end: 596.06),
                    ReadAlongSentence(text: "You’ve done the \"Scuttlebutt.\"", start: 596.66, end: 597.74),
                    ReadAlongSentence(text: "You know it’s the next big thing.", start: 598.24, end: 599.86),
                    ReadAlongSentence(text: "The stock is trading at $50.50.", start: 600.5, end: 601.74),
                    ReadAlongSentence(text: "You, trying to be a \"smart\" trader, put in a limit order at $50.00.", start: 603.1, end: 606.42),
                    ReadAlongSentence(text: "You want that psychological win of getting a bargain.", start: 608.74, end: 611.44),
                    ReadAlongSentence(text: "The stock dips to $50.05, then turns around and runs to $500.", start: 611.94, end: 616.06),
                    ReadAlongSentence(text: "You missed a 1,000% return because you were haggling over 50 cents.", start: 617.62, end: 621.66),
                    ReadAlongSentence(text: "Most investors fail not because they pick the wrong stock, but because they treat a generational asset like a used car, refusing to buy unless the sticker price is slashed.", start: 622.3, end: 632.07),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Eighths and Quarters\" Trap", start: 632.91, end: 634.75),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Philip Fisher saw this destroy more wealth than any bear market.", start: 635.33, end: 638.79),
                    ReadAlongSentence(text: "He tells the story of an investor who identified a small, high-growth manufacturing company.", start: 639.29, end: 644.27),
                    ReadAlongSentence(text: "The stock was trading around $35.50.", start: 645.29, end: 646.59),
                    ReadAlongSentence(text: "The investor decided the \"fair value\" was exactly $35.00.", start: 648.57, end: 651.49),
                    ReadAlongSentence(text: "He refused to pay the extra 50 cents—back then, stocks traded in \"eighths and quarters.\"", start: 653.63, end: 658.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He placed his limit order and waited.", start: 659.35, end: 661.21),
                    ReadAlongSentence(text: "The stock hovered, touched $35.25, and then the earnings report came out.", start: 661.97, end: 665.83),
                    ReadAlongSentence(text: "It skyrocketed.", start: 666.63, end: 667.71),
                    ReadAlongSentence(text: "Decades later, that company had split multiple times and was worth millions.", start: 668.41, end: 672.93),
                    ReadAlongSentence(text: "The investor had been \"right\" about everything—the product, the management, the growth—except the price.", start: 673.67, end: 679.49),
                    ReadAlongSentence(text: "Fisher’s rule became absolute: If the company is truly a \"Common Stock\" compounder, the current price is almost irrelevant in the long run.", start: 680.01, end: 687.95),
                    ReadAlongSentence(text: "Buying \"at the market\" is the only way to ensure you actually get a seat on the rocket.", start: 688.67, end: 692.45),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Algorithm Food", start: 693.11, end: 694.01),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In Fisher’s day, you were competing with other humans.", start: 694.67, end: 697.39),
                    ReadAlongSentence(text: "Today, you are competing with High-Frequency Trading (HFT) algorithms that can see your limit order and front-run it.", start: 697.95, end: 704.31),
                    ReadAlongSentence(text: "If you are trying to \"time\" an entry into a volatile asset like Bitcoin or a high-beta AI stock like NVIDIA, you are playing a losing game.", start: 704.89, end: 713.35),
                    ReadAlongSentence(text: "These assets don't move in straight lines; they move in violent steps.", start: 714.09, end: 718.33),
                    ReadAlongSentence(text: "If you wait for the \"perfect pullback\" in a parabolic trend (like the AI boom), you will likely be left on the platform.", start: 718.91, end: 725.39),
                    ReadAlongSentence(text: "The modern market moves too fast for \"sniper\" precision on price.", start: 725.99, end: 729.79),
                    ReadAlongSentence(text: "The only precision that matters is \"sniper\" precision on quality.", start: 730.7, end: 735.8),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Taking Profits\" Fallacy", start: 782.68, end: 784.36),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This is the most painful lesson you will ever learn: you will likely make more money from the one stock you didn't sell than from all the brilliant trades you did.", start: 785.1, end: 793.16),
                    ReadAlongSentence(text: "The amateur investor feels an itch when a stock goes up 50%.", start: 793.72, end: 796.38),
                    ReadAlongSentence(text: "They think, \"I should take some chips off the table.\"", start: 797.9, end: 800.32),
                    ReadAlongSentence(text: "They sell the winner and put that money into a \"cheaper\" stock that hasn't moved yet.", start: 800.76, end: 804.44),
                    ReadAlongSentence(text: "This is called \"watering the weeds and cutting the flowers.\"", start: 805.16, end: 808.08),
                    ReadAlongSentence(text: "You are systematically killing your compounders to feed your losers.", start: 808.8, end: 812.12),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Accidental Billionaire", start: 812.74, end: 814.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Philip Fisher noticed something strange about the wealthiest families he advised.", start: 814.88, end: 818.76),
                    ReadAlongSentence(text: "They didn't get rich by being smart traders; they got rich because they were \"trapped.\"", start: 819.42, end: 823.38),
                    ReadAlongSentence(text: "In Fisher's time, capital gains taxes were incredibly high—sometimes over 25-30% on paper profits.", start: 824.29, end: 831.57),
                    ReadAlongSentence(text: "He tells the story of investors who bought a great company, watched it double, and wanted to sell.", start: 832.15, end: 837.23),
                    ReadAlongSentence(text: "But when they calculated the tax bill, they realized they would lose a third of their wealth to the IRS.", start: 837.79, end: 843.23),
                    ReadAlongSentence(text: "So, they gritted their teeth and held.", start: 843.85, end: 846.09),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Ten years later, that \"forced holding\" had turned a double into a 50-bagger.", start: 846.71, end: 850.55),
                    ReadAlongSentence(text: "The tax code had accidentally immunized them against their own stupidity.", start: 851.17, end: 854.99),
                    ReadAlongSentence(text: "Fisher realized that the only time to sell a company is when the business changes (Core 1, 2, or 3 breaks), never because the price has gone up.", start: 855.57, end: 863.59),
                    ReadAlongSentence(text: "If the job of the company is to grow, your job is to do nothing.", start: 864.41, end: 868.01),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Volatility Tax", start: 868.59, end: 869.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the crypto and tech era, the \"tax\" isn't just from the IRS; it's the volatility.", start: 870.41, end: 875.47),
                    ReadAlongSentence(text: "Look at Amazon or Bitcoin.", start: 876.33, end: 877.99),
                    ReadAlongSentence(text: "To capture the 10,000% gains, you had to sit through multiple drawdowns of 50%, 70%, even 90%.", start: 878.55, end: 884.97),
                    ReadAlongSentence(text: "If you sold Bitcoin in 2013 because it \"doubled too fast,\" you missed the defining asset class of the decade.", start: 886.25, end: 892.91),
                    ReadAlongSentence(text: "The same applies to early Tesla investors.", start: 893.71, end: 896.11),
                    ReadAlongSentence(text: "The \"Forever Hold\" isn't about stubbornness; it's about recognizing that true disruption takes decades, not quarters, to play out.", start: 896.65, end: 904.17),
                    ReadAlongSentence(text: "If you own an ETF like QQQ, you are effectively outsourcing this \"holding\" discipline—the index automatically holds the winners and drops the losers.", start: 904.81, end: 914.26),
                    ReadAlongSentence(text: "But if you are picking individual stocks, you must be the algorithm that refuses to sell just because the ride gets bumpy.", start: 914.88, end: 921.06),
                ]),
            ],
            6: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Macro\" Illusion", start: 960.48, end: 961.82),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is why you panic-sold at the bottom: You listened to a \"Macro Tourist.\"", start: 962.4, end: 967.1),
                    ReadAlongSentence(text: "You let a stranger on television, who has never analyzed the specific company you own, convince you that the entire economy is collapsing.", start: 967.76, end: 974.98),
                    ReadAlongSentence(text: "You looked at the \"market\" instead of the business.", start: 975.82, end: 978.0),
                    ReadAlongSentence(text: "You obsessed over interest rates, election polls, and GDP forecasts—variables you cannot control and definitely cannot predict.", start: 978.6, end: 986.38),
                    ReadAlongSentence(text: "Most investors fail because they treat the stock market like a voting machine, trying to guess what other people will do, rather than a weighing machine that measures what the company is doing.", start: 987.08, end: 996.36),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Dividend\" Trap", start: 997.22, end: 998.34),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Philip Fisher saw investors constantly seduced by the wrong metrics.", start: 998.82, end: 1002.52),
                    ReadAlongSentence(text: "One of his most famous \"Don'ts\" was: \"Don't buy a stock just because the annual report has a nice tone.\"", start: 1003.29, end: 1009.09),
                    ReadAlongSentence(text: "But his deeper lesson was about ignoring the crowd’s obsession with \"safety.\"", start: 1009.59, end: 1012.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of investors who would pass on a high-growth technology company because it didn’t pay a dividend.", start: 1013.67, end: 1019.41),
                    ReadAlongSentence(text: "They wanted the \"safe,\" tangible check in the mail.", start: 1020.05, end: 1022.71),
                    ReadAlongSentence(text: "They flocked to stagnant companies that paid 5% yields but whose stock price slowly bled to death over decades.", start: 1023.51, end: 1029.13),
                    ReadAlongSentence(text: "Fisher realized that \"income\" is often a mask for a dying business.", start: 1029.75, end: 1033.35),
                    ReadAlongSentence(text: "A company that pays out all its profits has admitted it has no more ideas on how to grow.", start: 1034.15, end: 1038.81),
                    ReadAlongSentence(text: "The \"safe\" crowd was actually taking the biggest risk of all: the risk of obsolescence.", start: 1039.67, end: 1044.81),
                    ReadAlongSentence(text: "He taught that true safety isn't in a dividend check; it's in a profit margin that is expanding.", start: 1045.59, end: 1050.19),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Algorithm of Fear", start: 1050.69, end: 1052.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the noise isn't just a quarterly report; it’s a 24/7 algorithmic assault.", start: 1052.55, end: 1057.81),
                    ReadAlongSentence(text: "If you open Twitter/X or turn on CNBC, you are bombarded with \"Recession Imminent\" or \"Crypto is Dead\" headlines.", start: 1058.47, end: 1065.11),
                    ReadAlongSentence(text: "These platforms are designed to maximize engagement, and fear drives engagement.", start: 1065.79, end: 1070.65),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Fed\" Obsession: In 2023, every \"expert\" predicted a recession.", start: 1071.15, end: 1076.37),
                    ReadAlongSentence(text: "If you sold your tech stocks (like Meta or NVIDIA) because you were scared of the Fed raising rates, you missed one of the greatest rallies in history.", start: 1077.15, end: 1084.09),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Narrative\" vs.", start: 1084.81, end: 1085.99),
                    ReadAlongSentence(text: "Numbers: Look at Netflix in 2022.", start: 1087.33, end: 1089.11),
                    ReadAlongSentence(text: "The narrative was \"streaming is over.\"", start: 1090.99, end: 1093.19),
                    ReadAlongSentence(text: "The stock crashed.", start: 1093.63, end: 1094.73),
                    ReadAlongSentence(text: "But the numbers (subscribers, revenue per user) showed the engine was still running.", start: 1095.56, end: 1100.32),
                    ReadAlongSentence(text: "If you listened to the noise, you sold.", start: 1101.16, end: 1103.32),
                    ReadAlongSentence(text: "If you looked at the \"Engine\" (Core 2), you bought.", start: 1103.9, end: 1107.84),
                ]),
            ],
        ],
        6: [
            1: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The House Always Wins", start: 10.4, end: 11.94),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Listen closely.", start: 12.48, end: 13.5),
                    ReadAlongSentence(text: "The reason most intelligent people fail at building wealth isn’t that they pick the wrong stocks.", start: 14.0, end: 19.2),
                    ReadAlongSentence(text: "It’s that they are playing the wrong game entirely.", start: 19.82, end: 22.78),
                    ReadAlongSentence(text: "You’ve been trained to believe that \"investing\" means outsmarting the person on the other side of the screen—finding that hidden gem before the crowd does.", start: 23.34, end: 32.4),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But here is the dirty secret the finance industry spends billions to hide: The stock market is a closed system.", start: 32.86, end: 40.1),
                    ReadAlongSentence(text: "It’s a giant pie.", start: 40.62, end: 41.96),
                    ReadAlongSentence(text: "If you take a bigger slice, someone else must take a smaller one.", start: 42.48, end: 45.64),
                    ReadAlongSentence(text: "But standing between you and that pie is a massive industry of croupiers, dealers, and fixers.", start: 45.9, end: 51.96),
                    ReadAlongSentence(text: "They don't care if the pie grows or shrinks, as long as they get their commission for cutting the slices.", start: 52.4, end: 57.22),
                    ReadAlongSentence(text: "Before we even talk about strategy, we have to stop the bleeding.", start: 57.7, end: 61.52),
                    ReadAlongSentence(text: "You aren't losing to the market; you are losing to the \"helpers.\"", start: 61.9, end: 64.82),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Parable: The Gotrocks Family", start: 65.42, end: 67.48),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In our source material, the author illustrates this with a brilliant metaphor: The Parable of the Gotrocks.", start: 67.94, end: 73.5),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine a wealthy family, the Gotrocks, who own 100% of the stock market.", start: 74.06, end: 79.16),
                    ReadAlongSentence(text: "Every year, they reap the rewards of corporate America—dividends and earnings growth.", start: 79.5, end: 84.44),
                    ReadAlongSentence(text: "They grow wealthier simply by sitting still.", start: 84.82, end: 87.34),
                    ReadAlongSentence(text: "But then, a few smooth-talking \"Helpers\" (brokers) arrive.", start: 87.66, end: 91.88),
                    ReadAlongSentence(text: "They convince cousin Jimmy that he can earn more if he sells his shares to cousin Sally.", start: 92.24, end: 96.72),
                    ReadAlongSentence(text: "The Helpers take a fee for the transaction.", start: 97.22, end: 99.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Soon, the whole family is frantically swapping shares, hiring \"Managers\" to pick the best shares and \"Consultants\" to pick the best Managers.", start: 99.78, end: 108.4),
                    ReadAlongSentence(text: "The result?", start: 108.84, end: 109.42),
                    ReadAlongSentence(text: "The family’s total wealth begins to shrink.", start: 109.84, end: 112.27),
                    ReadAlongSentence(text: "They are still owning the same companies, but now they are paying 20% of their profits to the Helpers.", start: 112.67, end: 118.75),
                    ReadAlongSentence(text: "The lesson is ruthless in its simplicity: In investing, you get what you don't pay for.", start: 119.15, end: 124.89),
                    ReadAlongSentence(text: "The Helpers add zero value; they subtract it.", start: 125.69, end: 129.01),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Trap: The Gamification of Speculation", start: 129.43, end: 132.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the \"Helpers\" don't just look like guys in suits on Wall Street; they look like fun, colorful apps on your phone.", start: 133.13, end: 140.29),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern version of the Gotrocks tragedy is happening right now in sectors like Crypto, AI, or Clean Energy.", start: 140.73, end: 147.99),
                    ReadAlongSentence(text: "You see a \"commission-free\" trading app and think you’ve beaten the system.", start: 148.57, end: 152.67),
                    ReadAlongSentence(text: "You haven't.", start: 153.17, end: 153.69),
                    ReadAlongSentence(text: "When you trade the latest hot AI stock or chase a meme coin, you are generating data (Payment for Order Flow) that the app sells to high-frequency traders.", start: 154.15, end: 163.91),
                    ReadAlongSentence(text: "You are the product.", start: 164.41, end: 165.69),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Every time you click \"trade\" to chase a cybersecurity trend or dump a stock because of a Trade War headline, you are effectively paying a toll.", start: 166.19, end: 174.65),
                    ReadAlongSentence(text: "The friction has moved from expensive broker fees to invisible spreads and behavioral nudges designed to make you trade more.", start: 175.05, end: 182.39),
                    ReadAlongSentence(text: "The \"Helpers\" have just digitized their skimming operation.", start: 182.87, end: 188.93),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Optical Illusion of Wealth", start: 226.81, end: 228.39),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a dangerous optical illusion that blinds almost everyone who opens a brokerage app.", start: 228.75, end: 234.37),
                    ReadAlongSentence(text: "You see a green line going up, and you think you are \"winning.\"", start: 234.79, end: 237.89),
                    ReadAlongSentence(text: "You see a red line going down, and you think you are \"losing.\"", start: 238.33, end: 241.75),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This is the friction that destroys portfolios.", start: 242.19, end: 244.73),
                    ReadAlongSentence(text: "You have been conditioned to believe that the price of a stock is the same thing as the value of the business.", start: 245.45, end: 251.51),
                    ReadAlongSentence(text: "They are not.", start: 251.95, end: 252.61),
                    ReadAlongSentence(text: "In fact, in the short term, they are often total opposites.", start: 253.13, end: 256.99),
                    ReadAlongSentence(text: "Most investors fail because they are playing a game of psychological warfare against millions of strangers, trying to guess what they will pay for a stock tomorrow, rather than focusing on what the company actually does.", start: 257.39, end: 269.07),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The Tale of Two Games", start: 269.55, end: 271.83),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, channeling the wisdom of his mentor, tells us that the stock market is actually two separate games played on the same field.", start: 273.15, end: 280.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Game One is \"The Real Market.\"", start: 281.17, end: 283.13),
                    ReadAlongSentence(text: "This is the boring, slow game where companies—let’s say, a beverage giant or a manufacturer—sell products, pay rent, and distribute their profits to you as dividends.", start: 283.63, end: 293.97),
                    ReadAlongSentence(text: "This game is driven by hard math: earnings growth and dividend yields.", start: 294.33, end: 298.53),
                    ReadAlongSentence(text: "It is the \"Weighing Machine.\"", start: 298.97, end: 300.77),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Game Two is \"The Expectations Market.\"", start: 301.15, end: 304.07),
                    ReadAlongSentence(text: "This is the loud, frantic game where investors bet on how much other investors will pay for those earnings in the future.", start: 304.61, end: 311.45),
                    ReadAlongSentence(text: "This is the \"Voting Machine.\"", start: 311.83, end: 313.55),
                    ReadAlongSentence(text: "The author illustrates this with the historic bubbles of the past: companies whose earnings (The Real Market) were solid, but whose stock prices (The Expectations Market) detached from reality, soared into the stratosphere, and inevitably crashed back to earth.", start: 313.97, end: 329.26),
                    ReadAlongSentence(text: "The lesson?", start: 329.72, end: 330.34),
                    ReadAlongSentence(text: "The \"Real Market\" always wins in the end.", start: 330.78, end: 333.4),
                    ReadAlongSentence(text: "Speculation is just noise that cancels itself out over time.", start: 333.92, end: 337.22),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The AI Hall of Mirrors", start: 337.48, end: 340.3),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, this distinction is more critical—and harder to see—than ever.", start: 340.76, end: 345.14),
                    ReadAlongSentence(text: "Look at the current explosion in Artificial Intelligence and Data Centers.", start: 345.68, end: 349.58),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Real Market\" for AI is tangible: companies are building massive server farms, laying fiber optic cables, and selling software.", start: 350.08, end: 358.54),
                    ReadAlongSentence(text: "There is real earnings growth here.", start: 359.0, end: 360.84),
                    ReadAlongSentence(text: "But the \"Expectations Market\" has turned this into a casino.", start: 361.16, end: 364.3),
                    ReadAlongSentence(text: "You see obscure tech stocks doubling overnight not because their profits doubled, but because the narrative changed.", start: 364.9, end: 371.7),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This applies perfectly to the crypto ecosystem or the \"clean energy\" boom.", start: 372.18, end: 377.3),
                    ReadAlongSentence(text: "Often, the business of clean energy is growing steadily (solar panel installations are up), but the stocks are volatile wrecks because speculators piled in, drove the P/E ratios to the moon, and then fled.", start: 377.9, end: 389.54),
                    ReadAlongSentence(text: "If you cannot distinguish the business (the solar panel sales) from the speculation (the stock price), you will panic when the price drops, even if the business is healthier than ever.", start: 390.14, end: 400.04),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Alpha Delusion", start: 427.96, end: 429.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the hardest pill to swallow.", start: 429.7, end: 431.72),
                    ReadAlongSentence(text: "You have been told that if you study hard enough, read enough charts, and listen to enough podcasts, you can consistently beat the market.", start: 432.34, end: 439.48),
                    ReadAlongSentence(text: "You believe that you can be the \"Alpha\"—the one who wins while others lose.", start: 440.06, end: 444.78),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But the market is not a classroom where everyone can get an \"A\" if they study.", start: 445.24, end: 449.06),
                    ReadAlongSentence(text: "It is a poker table.", start: 449.62, end: 450.7),
                    ReadAlongSentence(text: "For you to win a dollar of \"excess\" return, someone else must lose a dollar.", start: 451.08, end: 455.94),
                    ReadAlongSentence(text: "And that \"someone else\" isn't a clueless amateur anymore.", start: 456.44, end: 459.3),
                    ReadAlongSentence(text: "It is a Goldman Sachs algorithm, a sovereign wealth fund, or a Nobel Laureate.", start: 459.72, end: 465.08),
                    ReadAlongSentence(text: "When you click \"buy\" on a hunch, that means someone else is selling, right?", start: 465.56, end: 469.8),
                    ReadAlongSentence(text: "You have to ask: \"Who is on the other side of this trade, and why do they think I’m wrong?\"", start: 470.36, end: 475.16),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The Relentless Arithmetic", start: 475.52, end: 477.84),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author strips away the magic and leaves us with cold, hard arithmetic.", start: 478.36, end: 482.54),
                    ReadAlongSentence(text: "He presents the \"Cost Matters Hypothesis.\"", start: 483.0, end: 485.46),
                    ReadAlongSentence(text: "Imagine the market returns 10% this year.", start: 486.32, end: 489.08),
                    ReadAlongSentence(text: "All investors, as a group, earn 10% before costs.", start: 489.7, end: 493.36),
                    ReadAlongSentence(text: "But the financial system—the croupiers, the managers, the brokers—charges 2% to play the game.", start: 493.9, end: 499.82),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This means the average investor only takes home 8%.", start: 500.28, end: 502.88),
                    ReadAlongSentence(text: "For you to get 12%, someone else must get 6%.", start: 504.1, end: 506.68),
                    ReadAlongSentence(text: "It is a mathematical certainty.", start: 507.84, end: 509.56),
                    ReadAlongSentence(text: "The author describes the industry as a \"Giant Scam\" where the managers convince you they can find the winning stocks.", start: 510.06, end: 516.6),
                    ReadAlongSentence(text: "But the data shows that over 15 or 20 years, almost no manager consistently wins.", start: 517.06, end: 522.7),
                    ReadAlongSentence(text: "They are just flipping coins, and eventually, their luck runs out.", start: 523.18, end: 526.94),
                    ReadAlongSentence(text: "The only winner is the house.", start: 527.38, end: 529.48),
                    ReadAlongSentence(text: "The author acknowledges that yes, there are \"stars\"—the Warren Buffetts and Peter Lynchs of the world.", start: 530.0, end: 536.25),
                    ReadAlongSentence(text: "But here is the catch: For every Buffett, there are a thousand managers who thought they were Buffett and failed.", start: 536.89, end: 543.19),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The Rise of the Machine", start: 543.61, end: 546.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the author's day, you were competing against men in trading pits.", start: 546.67, end: 550.41),
                    ReadAlongSentence(text: "Today, you are competing against silicon.", start: 551.01, end: 553.31),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern context, \"Alpha\" has been eaten by code.", start: 553.71, end: 556.93),
                    ReadAlongSentence(text: "High-frequency trading (HFT) firms use microwave towers to execute trades in microseconds, front-running news before it even hits your screen.", start: 557.25, end: 566.15),
                    ReadAlongSentence(text: "In the crypto markets, \"MEV bots\" (Maximal Extractable Value) automatically drain value from retail traders.", start: 566.65, end: 573.77),
                    ReadAlongSentence(text: "Even in the \"Value\" space, AI agents are scanning 10-Ks faster than you can open the file.", start: 574.33, end: 579.69),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "When you try to trade in and out of hot sectors like AI or Semiconductors, you are bringing a knife to a nuclear gunfight.", start: 580.05, end: 587.15),
                    ReadAlongSentence(text: "The \"Smart Money\" isn't just smart; it's faster, richer, and more ruthless than you.", start: 587.55, end: 592.35),
                    ReadAlongSentence(text: "The only way to win a rigged game is to refuse to play by their rules.", start: 593.05, end: 599.49),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Silent Heist", start: 652.89, end: 653.93),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a thief in your portfolio, and he is invisible.", start: 654.27, end: 657.71),
                    ReadAlongSentence(text: "You spend hours researching whether \"Clean Energy\" or \"AI\" will boom next year, agonizing over getting a 10% return versus an 8% return.", start: 658.17, end: 667.23),
                    ReadAlongSentence(text: "But while you are distracted by the upside, the \"Silent Heist\" is happening on the downside.", start: 667.63, end: 672.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The financial industry has mastered the art of presenting fees as \"small numbers.\"", start: 673.11, end: 677.75),
                    ReadAlongSentence(text: "They say, \"It’s only 2%.\"", start: 678.09, end: 679.27),
                    ReadAlongSentence(text: "You think, \"2% is nothing.", start: 680.77, end: 682.87),
                    ReadAlongSentence(text: "I’ll still keep 98%.\"", start: 683.35, end: 684.01),
                    ReadAlongSentence(text: "This is the single most expensive math error a human being can make.", start: 685.81, end: 689.75),
                    ReadAlongSentence(text: "That \"tiny\" fee is not a one-time toll; it is a recurring cancer that metastasizes over time, consuming the majority of your wealth before you even retire.", start: 690.15, end: 701.07),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The Fourth Quartile Tragedy", start: 701.49, end: 703.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author illustrates this with a terrifying bit of \"Humble Arithmetic.\"", start: 704.25, end: 708.51),
                    ReadAlongSentence(text: "Imagine you invest a nest egg over an investment lifetime (about 50 years).", start: 709.25, end: 713.81),
                    ReadAlongSentence(text: "The market is generous, giving you a steady 7% or 8% annual return.", start: 714.33, end: 720.03),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In Scenario A, you pay minimal costs.", start: 720.41, end: 723.11),
                    ReadAlongSentence(text: "The \"Miracle of Compounding Returns\" works entirely for you.", start: 723.61, end: 727.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In Scenario B, you pay a \"modest\" 2.5% in total costs (management fees, transaction costs, and sales loads).", start: 728.15, end: 736.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The result?", start: 737.25, end: 737.75),
                    ReadAlongSentence(text: "You don't lose 2.5% of your fortune.", start: 738.21, end: 741.33),
                    ReadAlongSentence(text: "You lose nearly 65% of it.", start: 741.73, end: 744.41),
                    ReadAlongSentence(text: "Yes, you heard that right, nearly 65%!", start: 744.87, end: 746.53),
                    ReadAlongSentence(text: "The financial system—the \"croupiers\"—ends up taking two-thirds of the pie, leaving you, the one who took all the risk and put up all the capital, with the crumbs.", start: 748.19, end: 757.58),
                    ReadAlongSentence(text: "The author’s lesson is stark: In investing, you get what you don't pay for.", start: 758.06, end: 762.2),
                    ReadAlongSentence(text: "Costs are the only variable you can control with 100% certainty.", start: 762.86, end: 767.46),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"Thematic\" Trap", start: 768.06, end: 770.92),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, the \"2% Manager\" has been replaced by the \"Thematic ETF.\"", start: 771.58, end: 776.82),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Wall Street knows you want to invest in \"The Future\"—AI, Data Centers, Cybersecurity, or Remote Work.", start: 777.4, end: 784.24),
                    ReadAlongSentence(text: "So, they package these exciting concepts into niche ETFs.", start: 784.78, end: 788.72),
                    ReadAlongSentence(text: "Unlike a boring S&P 500 fund (which might charge 0.03%), these \"specialized\" funds often carry Expense Ratios of 0.75% or higher.", start: 789.1, end: 801.62),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Furthermore, in the world of Crypto, the costs are hidden in the \"Gas\" and the \"Spread.\"", start: 802.08, end: 806.74),
                    ReadAlongSentence(text: "You might buy a meme coin thinking it's free, but the bid-ask spread (the difference between the buy and sell price) might be 1% instantly.", start: 807.24, end: 815.62),
                    ReadAlongSentence(text: "If you trade in and out of that coin ten times a year, you have voluntarily paid a 10% tax on your own money.", start: 816.16, end: 823.44),
                    ReadAlongSentence(text: "The modern \"Silent Heist\" isn't a check you write to a broker; it is the friction of hyper-activity in a gamified app.", start: 823.88, end: 831.26),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Government’s Invisible Equity", start: 863.8, end: 865.96),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a silent partner in your portfolio who contributes zero capital, takes zero risk, yet claims up to 37% of your profits.", start: 866.42, end: 874.66),
                    ReadAlongSentence(text: "You know him as Uncle Sam.", start: 875.16, end: 876.62),
                    ReadAlongSentence(text: "The friction here is a dangerous mental accounting error: you see a stock go up 20% and think you have made 20%.", start: 877.24, end: 883.7),
                    ReadAlongSentence(text: "You haven't.", start: 883.94, end: 885.44),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most investors treat taxes as an afterthought, something to worry about in April.", start: 885.92, end: 890.44),
                    ReadAlongSentence(text: "But in the mathematics of wealth, taxes are a compound interest penalty.", start: 890.96, end: 895.3),
                    ReadAlongSentence(text: "Every time you sell a winner to buy a new stock, you trigger a \"taxable event.\"", start: 895.94, end: 900.42),
                    ReadAlongSentence(text: "You are voluntarily severing the arm of your compound interest curve.", start: 900.96, end: 904.3),
                    ReadAlongSentence(text: "You aren't just paying a bill; you are removing capital that could have been working for you for the next 30 years.", start: 904.78, end: 910.07),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The Tale of the \"Statue\" vs. The Trader", start: 910.47, end: 914.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author illuminates this with a concept we can call the \"Tax Efficiency Gap.\"", start: 915.07, end: 919.67),
                    ReadAlongSentence(text: "He compares two investors.", start: 920.27, end: 921.77),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Investor A owns an actively managed mutual fund.", start: 922.19, end: 925.63),
                    ReadAlongSentence(text: "The manager is frantic, constantly selling \"overvalued\" stocks to buy \"undervalued\" ones.", start: 926.07, end: 931.83),
                    ReadAlongSentence(text: "This fund has a turnover rate of 100%—meaning the entire portfolio is replaced every year.", start: 932.29, end: 938.95),
                    ReadAlongSentence(text: "This generates massive short-term capital gains distributions, which are taxed at the highest income rates.", start: 939.59, end: 945.45),
                    ReadAlongSentence(text: "Investor A is bleeding money every year, even if he never sells a single share of the fund itself.", start: 945.97, end: 951.75),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Investor B owns a broad market index fund.", start: 952.43, end: 955.47),
                    ReadAlongSentence(text: "The fund manager does... nothing.", start: 955.99, end: 958.73),
                    ReadAlongSentence(text: "He is a statue.", start: 959.11, end: 960.21),
                    ReadAlongSentence(text: "He only sells if a company goes bankrupt or leaves the index.", start: 960.81, end: 964.07),
                    ReadAlongSentence(text: "Because there is almost zero turnover, there are almost zero capital gains taxes.", start: 964.67, end: 969.87),
                    ReadAlongSentence(text: "Investor B’s money compounds tax-deferred, growing like an IRA, simply because the vehicle is efficient.", start: 970.29, end: 976.93),
                    ReadAlongSentence(text: "The lesson?", start: 977.39, end: 978.03),
                    ReadAlongSentence(text: "In investing, laziness is tax-efficient; activity is tax-punitive.", start: 978.65, end: 983.01),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The Crypto & ETF \"Shell Game\"", start: 983.39, end: 987.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the tax leak has turned into a flood, driven by the gamification of \"swapping.\"", start: 987.65, end: 993.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the modern Crypto investor.", start: 993.87, end: 995.79),
                    ReadAlongSentence(text: "You swap Ethereum for Solana, then Solana for a \"Memecoin,\" then back to a Stablecoin.", start: 996.37, end: 1001.72),
                    ReadAlongSentence(text: "In your mind, you are just moving chips on a table.", start: 1002.1, end: 1005.32),
                    ReadAlongSentence(text: "In the eyes of the IRS, every single swap is a sale and a purchase.", start: 1005.84, end: 1010.58),
                    ReadAlongSentence(text: "You might trigger five taxable events in an hour.", start: 1011.02, end: 1014.0),
                    ReadAlongSentence(text: "You could easily owe more in taxes than you have in cash if the market crashes after your trades.", start: 1014.64, end: 1019.92),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The same applies to the \"Sector Rotation\" game in stocks.", start: 1020.32, end: 1023.48),
                    ReadAlongSentence(text: "You sell your \"Clean Energy\" ETF because it's down to buy a \"Data Center\" ETF because it's hot.", start: 1023.84, end: 1031.3),
                    ReadAlongSentence(text: "You are converting potential long-term capital gains (taxed at ~15-20%) into short-term gains (taxed at ~37%).", start: 1031.72, end: 1039.2),
                    ReadAlongSentence(text: "You are sprinting up an escalator that is moving down.", start: 1040.82, end: 1043.54),
                ]),
            ],
            6: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Rearview Mirror Trap", start: 1050.32, end: 1051.62),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a fatal flaw in human psychology that the financial industry exploits with ruthless efficiency: We believe that what just happened is what will happen.", start: 1052.38, end: 1062.76),
                    ReadAlongSentence(text: "When you see a fund with a \"5-Star Rating\" or a \"Top Performer 2024\" badge, your brain screams \"Safety!\" and \"Excellence!\"", start: 1063.3, end: 1070.9),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But in finance, the rearview mirror is broken.", start: 1071.3, end: 1074.18),
                    ReadAlongSentence(text: "Buying a fund because it performed well last year is like betting on a roulette number because it just came up three times in a row.", start: 1074.76, end: 1081.92),
                    ReadAlongSentence(text: "You are not buying \"excellence\"; you are buying \"peak valuation.\"", start: 1082.5, end: 1086.56),
                    ReadAlongSentence(text: "You are arriving at the party exactly when the police are banging on the front door.", start: 1087.14, end: 1091.44),
                    ReadAlongSentence(text: "The friction here is that you are chasing heat, but by the time you feel the warmth, the fire is already burning out.", start: 1091.92, end: 1098.26),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The Legend of the \"Comet\"", start: 1098.72, end: 1100.84),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author warns us to distinguish between \"Stars\" (permanent fixtures) and \"Comets\" (balls of gas that burn out).", start: 1101.24, end: 1108.04),
                    ReadAlongSentence(text: "He tells the story of the \"Go-Go Years\" of the 1960s.", start: 1108.5, end: 1112.8),
                    ReadAlongSentence(text: "There was a manager named Gerald Tsai who launched the Manhattan Fund.", start: 1113.22, end: 1116.74),
                    ReadAlongSentence(text: "He was the \"financial wizard\" of his day, the genius who could do no wrong.", start: 1117.38, end: 1121.88),
                    ReadAlongSentence(text: "His fund shot up like a rocket, attracting millions of dollars from investors desperate to get in on the magic.", start: 1122.36, end: 1129.08),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Then, gravity took over.", start: 1129.54, end: 1131.0),
                    ReadAlongSentence(text: "The \"Reversion to the Mean\" kicked in.", start: 1131.36, end: 1133.42),
                    ReadAlongSentence(text: "The Manhattan Fund didn't just underperform; it collapsed, losing 90% of its assets over the next few decades.", start: 1133.84, end: 1140.53),
                    ReadAlongSentence(text: "The author uses this tragedy to illustrate a statistical certainty: \"Yesterday’s winners are tomorrow’s losers.\"", start: 1140.93, end: 1147.27),
                    ReadAlongSentence(text: "The 5-star rating you see today is almost statistically guaranteed to become a 3-star or 1-star rating within five years.", start: 1148.19, end: 1155.49),
                    ReadAlongSentence(text: "The \"Star\" system doesn't predict the future; it merely records the past.", start: 1155.79, end: 1160.09),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"Disruptor\" Delusion", start: 1160.53, end: 1163.61),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Manhattan Fund\" has been reincarnated as the \"Disruptive Innovation\" ETF.", start: 1164.07, end: 1169.21),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Think of the recent obsession with \"star\" managers or the explosion of thematic ETFs focusing on \"AI Robotics\" or \"Crypto Miners.\"", start: 1169.75, end: 1177.95),
                    ReadAlongSentence(text: "These funds post astronomical returns for one or two years.", start: 1178.47, end: 1182.07),
                    ReadAlongSentence(text: "They appear on every CNBC segment.", start: 1182.45, end: 1185.27),
                    ReadAlongSentence(text: "Influencers on Twitter crown the managers as visionaries.", start: 1185.85, end: 1189.39),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But look closer.", start: 1189.83, end: 1190.83),
                    ReadAlongSentence(text: "These funds often concentrate their bets on high-risk, unprofitable tech stocks.", start: 1191.23, end: 1196.41),
                    ReadAlongSentence(text: "When interest rates rise or the hype cycle breaks (as we saw in 2022), the \"Disruptor\" funds crash harder than the market.", start: 1196.93, end: 1204.15),
                    ReadAlongSentence(text: "If you bought in after the 5-star year—which is what 90% of retail investors do—you didn't buy the disruption; you paid for the bag.", start: 1204.69, end: 1212.71),
                    ReadAlongSentence(text: "The \"Siren Song\" today is amplified by algorithms that feed you news about whoever is winning right now, blinding you to the cliff edge they are approaching.", start: 1213.15, end: 1222.97),
                ]),
            ],
            7: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Treasure Hunter’s Curse", start: 1228.39, end: 1229.63),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "We are all born with a fatal flaw in our financial DNA: the belief that we are smarter than the average.", start: 1230.05, end: 1235.67),
                    ReadAlongSentence(text: "The financial industry knows this.", start: 1236.17, end: 1238.07),
                    ReadAlongSentence(text: "They treat the stock market like a vast, sandy beach and sell you a metal detector.", start: 1238.65, end: 1242.89),
                    ReadAlongSentence(text: "They whisper that if you just study the charts hard enough, listen to the right podcasts, or subscribe to the premium newsletter, you will find the buried gold.", start: 1243.29, end: 1252.03),
                    ReadAlongSentence(text: "You spend your days agonizing over whether to back \"Quantum Computing\" or \"Gene Editing,\" convinced that your research will reveal the next Amazon before the rest of the world catches on.", start: 1252.37, end: 1262.77),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The friction here is mathematical, and it is brutal.", start: 1263.27, end: 1265.95),
                    ReadAlongSentence(text: "The stock market is not a beach full of gold; it is a graveyard of mediocrity dotted with a few spectacular supernovas.", start: 1266.29, end: 1273.43),
                    ReadAlongSentence(text: "For every Apple, there are a thousand bankrupt startups.", start: 1273.95, end: 1277.33),
                    ReadAlongSentence(text: "For every Bitcoin, there are ten thousand dead altcoins.", start: 1277.87, end: 1281.45),
                    ReadAlongSentence(text: "Most investors fail because they exhaust themselves trying to find the needle, never realizing that the farm itself was for sale.", start: 1281.87, end: 1289.25),
                    ReadAlongSentence(text: "They take on the risk of the needle (total loss) without ever guaranteeing the reward.", start: 1289.75, end: 1294.57),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The Laziest Man in the Room", start: 1295.05, end: 1297.53),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, solved this problem with a metaphor so simple it insulted the entire financial establishment: \"Don't look for the needle in the haystack.", start: 1297.91, end: 1307.55),
                    ReadAlongSentence(text: "Just buy the haystack!\"", start: 1307.95, end: 1309.07),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of the \"Laziest Man in the Room.\"", start: 1309.61, end: 1312.11),
                    ReadAlongSentence(text: "Imagine two investors.", start: 1312.69, end: 1314.07),
                    ReadAlongSentence(text: "The first is the \"Picker.\"", start: 1314.61, end: 1316.01),
                    ReadAlongSentence(text: "He is frantic.", start: 1316.45, end: 1317.25),
                    ReadAlongSentence(text: "He reads annual reports until 2:00 AM, pays huge fees to managers, and constantly swaps one stock for another, trying to guess which company will survive.", start: 1317.63, end: 1327.63),
                    ReadAlongSentence(text: "The second is the \"Haystack Owner.\"", start: 1327.99, end: 1329.97),
                    ReadAlongSentence(text: "He is boring.", start: 1330.47, end: 1331.55),
                    ReadAlongSentence(text: "He buys a single fund that owns a tiny slice of every public company in America.", start: 1332.11, end: 1337.35),
                    ReadAlongSentence(text: "He goes to sleep.", start: 1337.89, end: 1338.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Over 50 years, a strange thing happens.", start: 1339.19, end: 1342.39),
                    ReadAlongSentence(text: "The Picker misses the one or two stocks that drive all the market's returns—maybe he sold them too early, or maybe he never bought them at all.", start: 1342.93, end: 1351.07),
                    ReadAlongSentence(text: "But the Haystack Owner?", start: 1351.47, end: 1352.49),
                    ReadAlongSentence(text: "He owned the winners the entire time.", start: 1352.96, end: 1355.32),
                    ReadAlongSentence(text: "He didn't have to find them; he simply couldn't miss them.", start: 1355.72, end: 1358.42),
                    ReadAlongSentence(text: "By owning the entire market, he guaranteed that he would capture 100% of the innovation and growth of the corporate economy.", start: 1358.84, end: 1366.32),
                    ReadAlongSentence(text: "He defeated the \"smart\" money by refusing to play their guessing game.", start: 1367.0, end: 1370.48),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"Magnificent Seven\" Paradox", start: 1370.92, end: 1374.04),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the \"Haystack\" strategy is not just a safety net; it is the only logical offense.", start: 1374.56, end: 1380.18),
                    ReadAlongSentence(text: "The market has become incredibly top-heavy, dominated by what we now call the \"Magnificent Seven\" (companies like NVIDIA, Microsoft, Apple, etc.).", start: 1380.74, end: 1390.48),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the last few years, if you tried to be clever and pick \"undervalued\" small-cap stocks, or if you bet heavily on a specific niche like \"Solar Energy\" or \"Electric Vehicles,\" you likely lost money.", start: 1391.22, end: 1403.98),
                    ReadAlongSentence(text: "Why?", start: 1404.56, end: 1404.82),
                    ReadAlongSentence(text: "Because the market's entire return was driven by just those seven massive AI-adjacent companies.", start: 1405.8, end: 1411.68),
                    ReadAlongSentence(text: "If you didn't own them, you didn't win.", start: 1412.22, end: 1414.48),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This applies perfectly to the current \"AI Super Cycle.\"", start: 1414.92, end: 1418.06),
                    ReadAlongSentence(text: "You might be tempted to pick the specific startup making the cooling fans for data centers.", start: 1418.6, end: 1423.16),
                    ReadAlongSentence(text: "That is a gamble.", start: 1423.52, end: 1424.98),
                    ReadAlongSentence(text: "But if you buy the Total Market Index (the Haystack), you automatically own the chip designer (NVIDIA), the cloud provider (Microsoft), and the energy company powering the grid.", start: 1425.52, end: 1435.28),
                    ReadAlongSentence(text: "You capitalize on the trend of AI without betting your life savings on which specific CEO will win the war.", start: 1435.74, end: 1442.3),
                    ReadAlongSentence(text: "You turn the chaotic casino of \"stock picking\" into the reliable utility of \"capitalism capturing.\"", start: 1442.9, end: 1449.3),
                ]),
            ],
            8: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Icarus Delusion", start: 1484.0, end: 1485.42),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a seduction in the stock market that destroys more wealth than any recession: the Parabola.", start: 1485.94, end: 1492.26),
                    ReadAlongSentence(text: "You see a stock chart that looks like a vertical line—shooting straight to the moon—and your brain whispers, \"This is the new normal.\"", start: 1492.68, end: 1499.62),
                    ReadAlongSentence(text: "You convince yourself that the rules have changed, that this company is so revolutionary it has escaped the laws of physics.", start: 1500.04, end: 1506.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The friction here is emotional.", start: 1506.66, end: 1508.42),
                    ReadAlongSentence(text: "We are hardwired to chase momentum.", start: 1508.82, end: 1511.08),
                    ReadAlongSentence(text: "When a stock doubles in a month, we feel a primal urge to jump on board, terrified of missing out.", start: 1511.38, end: 1516.9),
                    ReadAlongSentence(text: "But in finance, what goes up abnormally fast doesn't just come down; it crashes.", start: 1517.36, end: 1522.18),
                    ReadAlongSentence(text: "You aren't buying growth; you are buying the moment before the rubber band snaps.", start: 1522.82, end: 1527.23),
                    ReadAlongSentence(text: "Most people fail because they mistake a temporary manic episode for a permanent shift in reality.", start: 1527.77, end: 1532.97),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The \"Nifty Fifty\" Massacre", start: 1533.33, end: 1535.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, a historian of market folly, tells the story of the \"Nifty Fifty\" mania of the early 1970s.", start: 1536.17, end: 1543.21),
                    ReadAlongSentence(text: "These were the \"AI darlings\" of their day—companies like Polaroid, Xerox, and Avon.", start: 1543.77, end: 1548.95),
                    ReadAlongSentence(text: "They were considered \"one-decision\" stocks: buy them at any price and never sell.", start: 1549.55, end: 1554.51),
                    ReadAlongSentence(text: "They traded at 80 or 90 times their earnings because investors believed their growth was infinite.", start: 1554.93, end: 1560.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Then, the \"Iron Law of Reversion to the Mean\" (RTM) kicked in.", start: 1561.07, end: 1564.97),
                    ReadAlongSentence(text: "Bogle explains RTM as the gravitational force of finance.", start: 1565.55, end: 1569.65),
                    ReadAlongSentence(text: "Corporate returns always gravitate back to the average over time.", start: 1570.21, end: 1573.81),
                    ReadAlongSentence(text: "The \"Nifty Fifty\" didn't just stop going up; they collapsed, losing 80% to 90% of their value.", start: 1574.19, end: 1580.37),
                    ReadAlongSentence(text: "The companies were fine—Xerox didn't go out of business—but their valuations had detached from reality.", start: 1580.91, end: 1587.11),
                    ReadAlongSentence(text: "The lesson?", start: 1587.47, end: 1587.97),
                    ReadAlongSentence(text: "Trees do not grow to the sky.", start: 1588.43, end: 1590.03),
                    ReadAlongSentence(text: "If a stock's price leaves its earnings behind, gravity will eventually pull it back down—usually with violence.", start: 1590.59, end: 1596.85),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"Super Cycle\" Trap", start: 1597.23, end: 1600.67),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Now, the \"Nifty Fifty\" has been replaced by the \"AI Super Cycle.\"", start: 1601.13, end: 1605.49),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Look at the recent explosion in Data Center stocks or the mania around specific \"AI Hardware\" manufacturers.", start: 1606.13, end: 1612.49),
                    ReadAlongSentence(text: "You hear the exact same \"New Paradigm\" arguments: \"This time is different because of Generative AI!\" or \"Crypto is the future of money, so price doesn't matter!\"", start: 1613.01, end: 1622.96),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "We saw this recently with stocks like Super Micro Computer (SMCI) or various \"Altcoins.\"", start: 1623.5, end: 1629.86),
                    ReadAlongSentence(text: "They went vertical, creating instant millionaires on paper.", start: 1630.3, end: 1633.32),
                    ReadAlongSentence(text: "Then, RTM arrived.", start: 1633.82, end: 1635.18),
                    ReadAlongSentence(text: "One bad earnings report, one regulatory headline, and the stock fell 50% in weeks.", start: 1635.62, end: 1641.3),
                    ReadAlongSentence(text: "The \"Law of Gravity\" applies to everyone—even the company building the future.", start: 1641.86, end: 1646.3),
                    ReadAlongSentence(text: "If the P/E ratio is expanding faster than the profits, you are essentially defying gravity without a parachute.", start: 1646.72, end: 1652.98),
                    ReadAlongSentence(text: "When you buy into a \"Trade War\" beneficiary or a \"Remote Work\" darling after it has already tripled, you are not investing; you are volunteering to be the bag holder for the smart money that is already exiting.", start: 1653.4, end: 1666.08),
                ]),
            ],
            9: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"All-Gas\" Suicide Pact", start: 1673.1, end: 1674.98),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a dangerous allergy in the modern investor's mind: an allergy to \"boring.\"", start: 1675.46, end: 1679.88),
                    ReadAlongSentence(text: "You look at your portfolio and think, \"Why would I lend money to the government for a 4% yield when I could own NVIDIA or Bitcoin and make 40%?\"", start: 1680.4, end: 1688.08),
                    ReadAlongSentence(text: "This logic seems flawless in a bull market.", start: 1689.36, end: 1691.5),
                    ReadAlongSentence(text: "You view every dollar not in high-growth stocks as \"wasted capital.\"", start: 1691.92, end: 1696.1),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The friction here is that you are building a race car with a massive engine and absolutely no brakes.", start: 1696.5, end: 1702.58),
                    ReadAlongSentence(text: "You are optimizing for speed, but you are ignoring survivability.", start: 1703.06, end: 1706.94),
                    ReadAlongSentence(text: "Most investors fail not because they don't pick winners, but because they get shaken out of their winners.", start: 1707.56, end: 1713.16),
                    ReadAlongSentence(text: "When the market drops 30%—and it will—the \"All-Gas\" investor panics and sells at the bottom to stop the pain.", start: 1713.56, end: 1720.78),
                    ReadAlongSentence(text: "You don't need bonds to make you rich; you need them to keep you sane when the world is going crazy.", start: 1721.28, end: 1726.45),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The Anchor to Windward", start: 1726.97, end: 1729.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, often used nautical metaphors to explain this unsexy truth.", start: 1729.53, end: 1734.73),
                    ReadAlongSentence(text: "He viewed the stock market as a turbulent ocean.", start: 1735.19, end: 1737.77),
                    ReadAlongSentence(text: "Stocks are the sails; they capture the wind and drive your wealth forward.", start: 1738.25, end: 1742.41),
                    ReadAlongSentence(text: "But the wind is unpredictable.", start: 1742.73, end: 1744.13),
                    ReadAlongSentence(text: "Sometimes it turns into a hurricane.", start: 1744.71, end: 1746.63),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Bogle argued that Bonds act as the \"Anchor to Windward\" (or the ballast in the ship).", start: 1747.19, end: 1752.67),
                    ReadAlongSentence(text: "When the hurricane hits and stock prices are crashing, bonds usually hold their value or even go up (as investors flee to safety).", start: 1753.25, end: 1761.37),
                    ReadAlongSentence(text: "He tells the story of the \"Balanced Investor.\"", start: 1762.13, end: 1765.21),
                    ReadAlongSentence(text: "While the aggressive \"Growth Investor\" is watching his net worth get cut in half during a crash—and is likely puking up his shares in a panic—the Balanced Investor looks at his bonds.", start: 1765.73, end: 1775.93),
                    ReadAlongSentence(text: "They are steady.", start: 1776.31, end: 1776.91),
                    ReadAlongSentence(text: "They offer a psychological cushion that allows him to say, \"I am down, but I am not out.\"", start: 1777.29, end: 1782.75),
                    ReadAlongSentence(text: "The bonds don't drive the return; they ensure you survive the journey long enough to get the return.", start: 1783.39, end: 1788.77),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"Digital Gold\" Fallacy", start: 1789.09, end: 1792.39),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, the \"Anchor\" has been confusingly swapped for \"Digital Gold\" or \"Yield Farming.\"", start: 1792.83, end: 1798.43),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Many young investors today believe that Bitcoin or Ethereum is their \"hedge\" against the system.", start: 1798.89, end: 1804.61),
                    ReadAlongSentence(text: "They think, \"If the stock market crashes, my Crypto will save me.\"", start: 1805.11, end: 1808.99),
                    ReadAlongSentence(text: "But looking at the data from recent tech corrections (like 2022), we see the opposite: Crypto often correlates highly with speculative tech stocks.", start: 1809.81, end: 1819.27),
                    ReadAlongSentence(text: "When AI and Data Center stocks crash, Crypto often crashes harder.", start: 1819.71, end: 1823.87),
                    ReadAlongSentence(text: "That is not an anchor; that is just more sails.", start: 1824.39, end: 1828.21),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Similarly, \"High Yield\" fintech savings accounts or \"Stablecoin\" lending protocols are not bonds.", start: 1828.71, end: 1834.61),
                    ReadAlongSentence(text: "They carry platform risk and regulatory risk.", start: 1835.01, end: 1838.24),
                    ReadAlongSentence(text: "True bonds (like U.S.", start: 1838.6, end: 1839.98),
                    ReadAlongSentence(text: "Treasuries) are the only asset class that historically behaves differently than stocks during a recession.", start: 1840.38, end: 1845.88),
                    ReadAlongSentence(text: "If your portfolio is 100% Tesla, NVIDIA, and Solana, you don't have a portfolio; you have a single, leveraged bet on \"Risk On\" sentiment.", start: 1846.42, end: 1856.3),
                    ReadAlongSentence(text: "When the mood changes, you have nowhere to hide.", start: 1856.74, end: 1859.98),
                ]),
            ],
            10: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Weaponization of Access", start: 1896.98, end: 1898.88),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a paradox in modern finance: You have never had more access, yet you have never been more likely to blow yourself up.", start: 1899.34, end: 1907.66),
                    ReadAlongSentence(text: "In the old days, if you wanted to bet on \"Cybersecurity\" or \"Lithium Mining,\" you had to call a broker, pay a huge commission, and buy specific stocks.", start: 1908.1, end: 1917.12),
                    ReadAlongSentence(text: "The friction saved you.", start: 1917.54, end: 1918.86),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the financial industry has removed the friction.", start: 1919.46, end: 1922.88),
                    ReadAlongSentence(text: "They have turned the stock market into a candy store.", start: 1923.4, end: 1926.12),
                    ReadAlongSentence(text: "There is an ETF (Exchange Traded Fund) for everything—\"Gen Z Consumption,\" \"Space Exploration,\" \"Obesity Drugs.\"", start: 1926.64, end: 1934.3),
                    ReadAlongSentence(text: "You see a headline about a Trade War, and within seconds, you can buy a \"Deglobalization ETF.\"", start: 1934.82, end: 1940.1),
                    ReadAlongSentence(text: "The trap is subtle: You think you are \"diversifying\" because you bought a fund.", start: 1940.62, end: 1944.16),
                    ReadAlongSentence(text: "In reality, you are just speculating on narrow, volatile themes with a product that looks safe but behaves like dynamite.", start: 1944.56, end: 1951.96),
                    ReadAlongSentence(text: "The industry has weaponized access, handing you a bazooka and telling you it’s a water gun.", start: 1952.24, end: 1957.67),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Double-Edged Sword", start: 1958.09, end: 1959.47),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, had a complicated relationship with the ETF.", start: 1959.95, end: 1964.21),
                    ReadAlongSentence(text: "He actually invented the precursor to it—the index fund.", start: 1964.69, end: 1968.49),
                    ReadAlongSentence(text: "But when the first ETFs launched (like the \"Spider\" or SPY), he was horrified.", start: 1968.97, end: 1974.09),
                    ReadAlongSentence(text: "He called them a \"Purist's Nightmare.\"", start: 1974.53, end: 1976.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of the ETF as a tool that was corrupted by its own utility.", start: 1977.09, end: 1982.31),
                    ReadAlongSentence(text: "Bogle compared the traditional index fund to a \"reliable family sedan\"—boring, safe, and gets you to your destination (retirement).", start: 1982.87, end: 1992.13),
                    ReadAlongSentence(text: "He compared the ETF to a \"sawed-off shotgun.\"", start: 1992.51, end: 1995.45),
                    ReadAlongSentence(text: "It is a powerful tool if you are a professional hunter (a trader), but if you leave it lying around the house, you are likely to blow your foot off.", start: 1995.93, end: 2003.13),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "His warning was prophetic.", start: 2003.61, end: 2005.35),
                    ReadAlongSentence(text: "He saw that because ETFs could be traded instantly like stocks, investors would inevitably treat them like stocks.", start: 2005.69, end: 2013.59),
                    ReadAlongSentence(text: "Instead of buying the \"Haystack\" and holding it for 50 years, they would trade the \"Haystack\" at 10:00 AM and sell it at 2:00 PM.", start: 2014.03, end: 2021.53),
                    ReadAlongSentence(text: "He argued that the ETF structure encouraged the worst behavioral sin in investing: the illusion that you can time the market.", start: 2021.97, end: 2029.49),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"Thematic\" Shell Game", start: 2029.91, end: 2032.97),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, the \"Shotgun\" has evolved into a sniper rifle aimed at your wallet.", start: 2033.39, end: 2038.03),
                    ReadAlongSentence(text: "The most dangerous trap today is the \"Thematic ETF.\"", start: 2038.59, end: 2042.09),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Wall Street knows you are smart enough to avoid high-fee mutual funds.", start: 2042.85, end: 2046.69),
                    ReadAlongSentence(text: "So, they repackage active management as \"Thematic ETFs.\"", start: 2047.11, end: 2051.75),
                    ReadAlongSentence(text: "You see funds for \"AI & Robotics,\" \"Clean Energy,\" \"Work From Home,\" or \"Next Gen Internet.\"", start: 2052.21, end: 2058.49),
                    ReadAlongSentence(text: "These funds charge 0.60% or 0.75%—ten times more than a standard S&P 500 ETF.", start: 2058.85, end: 2067.89),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Take the \"AI Data Center\" trend.", start: 2068.31, end: 2070.13),
                    ReadAlongSentence(text: "You might rush to buy a niche ETF that holds cooling system manufacturers and chip designers.", start: 2070.61, end: 2075.98),
                    ReadAlongSentence(text: "But look closely at the holdings.", start: 2076.38, end: 2077.92),
                    ReadAlongSentence(text: "The top three stocks are likely NVIDIA, Microsoft, and Amazon.", start: 2078.28, end: 2082.1),
                    ReadAlongSentence(text: "If you already own a total market fund, you already own these companies.", start: 2082.72, end: 2086.66),
                    ReadAlongSentence(text: "You are paying a \"Thematic Tax\" of 0.75% just to double-count the same stocks you already have in your cheap index fund.", start: 2087.2, end: 2095.78),
                    ReadAlongSentence(text: "The industry has tricked you into paying active fees for passive products by appealing to your desire to be part of the \"next big thing.\"", start: 2096.14, end: 2103.96),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Fee\" Audit (ETFDetailView)", start: 2104.5, end: 2107.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Search for any niche or thematic fund you are watching and locate the Net Yield in the Snapshots.", start: 2107.78, end: 2113.22),
                    ReadAlongSentence(text: "The Instruction: If the number is above 0.20%, stop.", start: 2113.7, end: 2118.18),
                    ReadAlongSentence(text: "Ask yourself: \"Am I paying this premium for better performance, or just for a cool name?\"", start: 2118.68, end: 2123.74),
                    ReadAlongSentence(text: "Compare it to a standard Total Market ETF (usually 0.03%).", start: 2124.12, end: 2127.3),
                    ReadAlongSentence(text: "If the gap is huge, the value proposition is likely zero.", start: 2129.42, end: 2132.78),
                ]),
            ],
            11: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Alchemy of Wall Street", start: 2138.5, end: 2139.92),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a term in finance invented purely to make you feel inadequate: \"Smart Beta.\"", start: 2140.36, end: 2145.24),
                    ReadAlongSentence(text: "It implies, rather rudely, that the standard index fund you own is \"Dumb Beta.\"", start: 2145.72, end: 2150.96),
                    ReadAlongSentence(text: "The friction here is intellectual vanity.", start: 2151.46, end: 2153.74),
                    ReadAlongSentence(text: "Wall Street knows you have accepted that stock-picking is hard, so they have pivoted to a new seduction: \"Don't pick stocks; pick the perfect algorithm.\"", start: 2154.12, end: 2162.3),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "They sell you complex ETFs that claim to \"optimize\" the market.", start: 2162.78, end: 2166.88),
                    ReadAlongSentence(text: "They promise to weight companies not by size, but by \"Quality,\" \"Momentum,\" or \"Volatility.\"", start: 2167.52, end: 2173.46),
                    ReadAlongSentence(text: "It sounds like science.", start: 2173.92, end: 2175.0),
                    ReadAlongSentence(text: "It looks like math.", start: 2175.42, end: 2176.24),
                    ReadAlongSentence(text: "But in reality, it is marketing.", start: 2176.7, end: 2179.16),
                    ReadAlongSentence(text: "It is the modern version of alchemy—trying to turn the lead of market averages into the gold of superior returns without taking on extra risk.", start: 2179.62, end: 2189.64),
                    ReadAlongSentence(text: "Most investors fail here because they confuse a back-tested simulation with future reality.", start: 2190.24, end: 2195.88),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Story: The \"Data Mining\" Mirage", start: 2196.38, end: 2199.02),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, spent his later years battling this specific hydra.", start: 2199.52, end: 2204.6),
                    ReadAlongSentence(text: "When \"Fundamental Indexing\" (the grandfather of Smart Beta) arrived, claiming it could beat the S&P 500 by simply weighting stocks differently, Bogle was the loudest skeptic in the room.", start: 2205.12, end: 2216.86),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of the \"Data Mining\" trap.", start: 2217.22, end: 2219.8),
                    ReadAlongSentence(text: "If you look at the last 50 years of data, you can always find a pattern that beat the market.", start: 2220.4, end: 2225.92),
                    ReadAlongSentence(text: "Maybe it was \"stocks that start with the letter A\" or \"companies with blue logos.\"", start: 2226.46, end: 2231.32),
                    ReadAlongSentence(text: "If you build a fund around that past pattern, it looks like a genius strategy.", start: 2231.82, end: 2236.11),
                    ReadAlongSentence(text: "Bogle warned that these \"Smart\" funds were just active management in a robot mask.", start: 2236.87, end: 2241.45),
                    ReadAlongSentence(text: "They had higher turnover (taxes) and higher fees.", start: 2241.73, end: 2245.13),
                    ReadAlongSentence(text: "He argued that \"Smart Beta\" is just a bet that a specific factor (like Value or Small Cap) will win forever.", start: 2245.55, end: 2252.67),
                    ReadAlongSentence(text: "But markets adapt.", start: 2253.19, end: 2254.67),
                    ReadAlongSentence(text: "The moment a \"secret anomaly\" is packaged into an ETF and sold to millions, the edge disappears.", start: 2255.13, end: 2261.69),
                    ReadAlongSentence(text: "The only thing that remains is the fee.", start: 2262.19, end: 2264.79),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"AI\" Black Box", start: 2265.35, end: 2268.69),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, \"Smart Beta\" has been given a sexy new makeover: Artificial Intelligence.", start: 2269.35, end: 2274.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You see ETFs now that claim to use \"AI and Machine Learning\" to rotate between sectors, or \"Sentiment Analysis\" to trade based on Twitter trends.", start: 2275.29, end: 2284.03),
                    ReadAlongSentence(text: "You might see a \"Data Center Optimization\" ETF that claims to dynamically adjust its holdings based on electricity prices.", start: 2284.49, end: 2292.31),
                    ReadAlongSentence(text: "This is the \"Smart Beta\" trap on steroids.", start: 2292.69, end: 2295.57),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the \"Quant\" strategies in Crypto or the complex \"Buffer ETFs.\"", start: 2295.97, end: 2300.93),
                    ReadAlongSentence(text: "They are selling you a free lunch.", start: 2301.45, end: 2303.23),
                    ReadAlongSentence(text: "But here is the irony: You already have AI.", start: 2303.69, end: 2306.75),
                    ReadAlongSentence(text: "Your app gives you sentiment analysis and deep research.", start: 2307.25, end: 2310.43),
                    ReadAlongSentence(text: "When you buy an \"AI ETF\" with a 0.75% expense ratio, you are often paying a middleman to do exactly what your phone can do for you.", start: 2310.77, end: 2319.49),
                    ReadAlongSentence(text: "The author didn’t write about AI, but his logic cuts through the hype: If an algorithm truly had a guaranteed edge, the creator wouldn't sell it to you for a 0.75% fee; they would keep it secret and become a trillionaire!", start: 2320.11, end: 2334.09),
                ]),
            ],
            12: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Most Expensive Friend You Have", start: 2339.51, end: 2341.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "We often hire financial advisors because we are scared.", start: 2342.39, end: 2345.31),
                    ReadAlongSentence(text: "The stock market feels like a jungle, and we want a guide with a machete to hack through the vines of volatility.", start: 2345.79, end: 2351.99),
                    ReadAlongSentence(text: "The friction is that this guide charges a toll—usually 1% of your assets per year—regardless of whether he leads you to safety or off a cliff.", start: 2352.53, end: 2361.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most people fail here because they view their advisor as a \"Market Beater.\"", start: 2361.69, end: 2365.59),
                    ReadAlongSentence(text: "You hire them to find the best stocks or time the next crash.", start: 2366.03, end: 2369.65),
                    ReadAlongSentence(text: "But the math says this is a fantasy.", start: 2370.07, end: 2372.65),
                    ReadAlongSentence(text: "If an advisor could reliably beat the market by 2% a year, he wouldn't be managing your account for a 1% fee; he would be managing a hedge fund for billions.", start: 2373.13, end: 2382.53),
                    ReadAlongSentence(text: "By hiring a human to do a job that a simple algorithm does better, you are often paying for a \"friend\" who slowly drains your retirement.", start: 2382.79, end: 2390.39),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Croupier\" vs. The Coach", start: 2390.73, end: 2393.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, was ruthless about the \"Croupier\" class—the intermediaries who take a cut of every transaction.", start: 2393.79, end: 2400.3),
                    ReadAlongSentence(text: "He argued that for 99% of investors, a stock-picking advisor is a net negative.", start: 2400.7, end: 2406.06),
                    ReadAlongSentence(text: "The math of the \"Cost Matters Hypothesis\" proves that after fees, the average advised client must underperform the market.", start: 2406.54, end: 2413.88),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "However, Bogle offered a nuanced solution.", start: 2414.4, end: 2417.24),
                    ReadAlongSentence(text: "He didn't say never hire an advisor.", start: 2417.86, end: 2420.28),
                    ReadAlongSentence(text: "He said hire them for the right reason.", start: 2420.84, end: 2422.92),
                    ReadAlongSentence(text: "Do not pay for \"Investment Management\" (picking stocks).", start: 2423.32, end: 2426.66),
                    ReadAlongSentence(text: "Pay for \"Wealth Management\" (asset allocation, tax planning, and estate planning).", start: 2427.08, end: 2431.62),
                    ReadAlongSentence(text: "But most importantly, pay for \"Behavioral Coaching.\"", start: 2432.14, end: 2435.84),
                    ReadAlongSentence(text: "The only value an advisor truly adds is standing between you and the \"Sell\" button during a panic.", start: 2436.62, end: 2442.66),
                    ReadAlongSentence(text: "If your advisor is just an expensive indexer who charges you to own the market, fire them.", start: 2443.14, end: 2448.3),
                    ReadAlongSentence(text: "But if they are a psychologist who stops you from making a fatal mistake, they are worth every penny.", start: 2448.78, end: 2454.38),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"Finfluencer\" & The AI", start: 2455.0, end: 2458.64),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern world, the \"Advisor\" has mutated.", start: 2459.18, end: 2461.92),
                    ReadAlongSentence(text: "You might not have a guy in a suit, but you have a \"Finfluencer\" on TikTok or YouTube screaming about \"The Next 100x Crypto\" or \"Why the Trade War Will Crash the Market.\"", start: 2462.4, end: 2472.74),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "These digital advisors are even more dangerous because they are unregulated and algorithmically incentivized to terrify you.", start: 2473.28, end: 2479.96),
                    ReadAlongSentence(text: "They don't charge a 1% fee; they charge you your attention and your sanity.", start: 2480.38, end: 2484.94),
                    ReadAlongSentence(text: "They push you into high-fee \"Copy Trading\" platforms or pump-and-dump schemes.", start: 2485.62, end: 2489.96),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "On the flip side, we now have \"Robo-Advisors\" and AI.", start: 2490.36, end: 2494.62),
                    ReadAlongSentence(text: "The modern solution isn't necessarily a human; it is often a piece of software.", start: 2495.16, end: 2500.2),
                    ReadAlongSentence(text: "An AI doesn't panic.", start: 2500.64, end: 2501.96),
                    ReadAlongSentence(text: "It doesn't have an ego.", start: 2502.36, end: 2503.72),
                    ReadAlongSentence(text: "It doesn't need to \"churn\" your account to prove it's working.", start: 2504.34, end: 2507.36),
                    ReadAlongSentence(text: "Your own pocket device can now run the same \"Deep Research\" that a junior analyst at Goldman Sachs used to do.", start: 2507.66, end: 2512.98),
                    ReadAlongSentence(text: "The democratization of data means the \"information edge\" your advisor claimed to have is gone.", start: 2513.7, end: 2520.09),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Jargon\" Detector", start: 2520.51, end: 2521.93),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If an advisor suggests a complex product like an \"Indexed Annuity\" or a \"Structured Note,\" open the Chat Tab.", start: 2522.35, end: 2529.05),
                    ReadAlongSentence(text: "The Instruction: Type: \"Explain the fees and downside caps of [Product Name] like I'm 12.\"", start: 2529.61, end: 2535.47),
                    ReadAlongSentence(text: "The AI will strip away the sales language.", start: 2536.45, end: 2538.93),
                    ReadAlongSentence(text: "If the product sounds like a trap after the translation, be careful!", start: 2539.45, end: 2543.41),
                ]),
            ],
            13: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Curse of the \"Do Something\" Instinct", start: 2582.93, end: 2585.37),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a fatal flaw in human evolution that makes you a terrible investor: the biological bias for action.", start: 2585.81, end: 2593.57),
                    ReadAlongSentence(text: "For two hundred thousand years, your ancestors survived because they were hyper-reactive.", start: 2594.19, end: 2600.03),
                    ReadAlongSentence(text: "When a twig snapped in the jungle, the ones who paused to analyze the data were eaten; the ones who sprinted away survived to pass on their genes.", start: 2600.55, end: 2608.51),
                    ReadAlongSentence(text: "You are the descendant of the paranoid and the twitchy.", start: 2608.99, end: 2611.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern financial markets, this survival instinct is a suicide pact.", start: 2612.21, end: 2616.61),
                    ReadAlongSentence(text: "When the S&P 500 drops 20% in a month, or when a headline screams about \"Hyperinflation,\" your amygdala—the lizard brain—hijacks your logic.", start: 2617.13, end: 2626.93),
                    ReadAlongSentence(text: "It screams, \"Don't just stand there, do something!", start: 2627.41, end: 2630.05),
                    ReadAlongSentence(text: "Sell!", start: 2630.41, end: 2631.45),
                    ReadAlongSentence(text: "Hedge!", start: 2631.47, end: 2632.09),
                    ReadAlongSentence(text: "Buy gold!", start: 2632.39, end: 2633.11),
                    ReadAlongSentence(text: "Move to cash!\"", start: 2633.67, end: 2634.59),
                    ReadAlongSentence(text: "You feel a physical, visceral guilt if you are not taking action to \"fix\" the problem.", start: 2635.17, end: 2639.63),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The friction here is that investing is the only domain in human life where effort is negatively correlated with success.", start: 2640.09, end: 2647.39),
                    ReadAlongSentence(text: "In your career, if you work harder, you make more money.", start: 2647.81, end: 2650.47),
                    ReadAlongSentence(text: "In the gym, if you lift more, you get stronger.", start: 2650.9, end: 2653.5),
                    ReadAlongSentence(text: "But in the stock market, the more you \"do\"—the more you trade, tinker, adjust, and react—the more likely you are to destroy your wealth.", start: 2654.02, end: 2662.22),
                    ReadAlongSentence(text: "The \"insider secret\" that the financial industry spends billions to hide is that the most profitable activity you can engage in is often... absolutely nothing.", start: 2662.72, end: 2673.16),
                    ReadAlongSentence(text: "The hardest thing to do in the world is to stand still while everyone around you is running for the exits.", start: 2673.48, end: 2678.88),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Odysseus Contract", start: 2679.42, end: 2680.7),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, was a student of history as much as he was a student of finance.", start: 2681.06, end: 2685.7),
                    ReadAlongSentence(text: "To solve this behavioral trap, he often pointed to the ancient Greek myth of Odysseus and the Sirens.", start: 2686.3, end: 2692.34),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the Odyssey, the hero Odysseus has to sail his ship past the island of the Sirens.", start: 2692.9, end: 2698.12),
                    ReadAlongSentence(text: "He knows that their song is so beautiful, so seductive, that any man who hears it will be compelled to steer his ship into the rocks and drown.", start: 2698.7, end: 2707.08),
                    ReadAlongSentence(text: "Odysseus is smart enough to know that he is not strong enough to resist.", start: 2707.68, end: 2711.5),
                    ReadAlongSentence(text: "He does not rely on his willpower.", start: 2712.0, end: 2713.8),
                    ReadAlongSentence(text: "He does not say, \"I will just listen a little bit and then turn away.\"", start: 2714.22, end: 2717.68),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Instead, he creates a system to save him from himself.", start: 2718.22, end: 2721.6),
                    ReadAlongSentence(text: "He orders his crew to plug their ears with beeswax so they cannot hear the noise.", start: 2722.0, end: 2726.58),
                    ReadAlongSentence(text: "Then, he orders them to tie him tightly to the mast of the ship.", start: 2726.8, end: 2730.14),
                    ReadAlongSentence(text: "He gives them strict instructions: \"No matter how much I scream, beg, or order you to untie me, you must bind me tighter.\"", start: 2730.58, end: 2738.04),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Bogle argued that the Index Fund is the modern investor’s \"mast.\"", start: 2738.54, end: 2743.1),
                    ReadAlongSentence(text: "By buying the entire market and committing to hold it \"forever,\" you are tying yourself to the mast of American capitalism.", start: 2743.5, end: 2750.44),
                    ReadAlongSentence(text: "You are admitting that you cannot predict the squalls of the market or the seductive song of the next \"hot stock.\"", start: 2750.98, end: 2756.98),
                    ReadAlongSentence(text: "The beeswax is your refusal to engage with daily market noise.", start: 2757.46, end: 2761.32),
                    ReadAlongSentence(text: "The strategy is not to outsmart the Sirens; it is to remove your ability to grab the wheel when you are emotionally compromised.", start: 2761.98, end: 2769.22),
                    ReadAlongSentence(text: "The investor who is \"tied to the mast\" of the index survives the crash; the one who thinks he can steer through the rocks always drowns.", start: 2769.6, end: 2777.02),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The Notification Tsunami", start: 2777.48, end: 2781.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the Sirens have upgraded their technology.", start: 2781.74, end: 2784.54),
                    ReadAlongSentence(text: "They don't just sing from an island; they buzz in your pocket 30 times a day.", start: 2785.14, end: 2789.76),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In Bogle’s era, if you wanted to panic-sell during a crash, you had to call a broker.", start: 2790.54, end: 2795.43),
                    ReadAlongSentence(text: "That broker might be at lunch, or he might talk you out of it.", start: 2796.03, end: 2798.95),
                    ReadAlongSentence(text: "There was friction.", start: 2799.55, end: 2800.59),
                    ReadAlongSentence(text: "Today, the financial industry has removed every ounce of friction.", start: 2801.11, end: 2804.83),
                    ReadAlongSentence(text: "You can FaceID and liquidate your life savings in three seconds while waiting for a latte.", start: 2805.21, end: 2810.97),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "We are living through a \"Notification Tsunami.\"", start: 2811.59, end: 2814.13),
                    ReadAlongSentence(text: "You wake up to a red alert: \"Crypto Crash: Bitcoin down 12% in 20 minutes.\"", start: 2814.65, end: 2819.93),
                    ReadAlongSentence(text: "Then a push notification from a news app: \"Fed Chair Warns of 'Pain' Ahead.\"", start: 2820.41, end: 2824.69),
                    ReadAlongSentence(text: "Then you open X (Twitter) and see a respected \"Finfluencer\" posting a chart that looks like a cliff, captioned \"It’s over.\"", start: 2825.13, end: 2831.87),
                    ReadAlongSentence(text: "This constant barrage is weaponized psychology.", start: 2832.37, end: 2835.15),
                    ReadAlongSentence(text: "It keeps your cortisol levels high and your finger hovering over the \"Sell\" button.", start: 2835.71, end: 2839.65),
                    ReadAlongSentence(text: "The modern Siren song is the \"Gamification of Panic.\"", start: 2840.05, end: 2843.37),
                    ReadAlongSentence(text: "Trading apps shower you with confetti when you buy and red flashing lights when you lose, treating your financial future like a dopamine-loop video game.", start: 2843.93, end: 2852.57),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In an age of hyper-reactive AI, your edge isn't speed—it's \"stillness\".", start: 2853.01, end: 2858.63),
                    ReadAlongSentence(text: "Algorithms are designed to fight over the noise of the millisecond; you win by ruthlessly committing to the silence of the decade!", start: 2859.13, end: 2866.77),
                ]),
            ],
        ],
        7: [
            1: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Wall Street Civil War", start: 9.26, end: 11.1),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a secret war happening on Wall Street, and you are the casualty.", start: 11.8, end: 15.82),
                    ReadAlongSentence(text: "Most investors think the stock market is one big casino where everyone is playing the same game.", start: 16.42, end: 21.9),
                    ReadAlongSentence(text: "You aren't.", start: 22.24, end: 22.76),
                    ReadAlongSentence(text: "There are actually two rival tribes fighting for your money, and they speak completely different languages.", start: 23.38, end: 29.64),
                    ReadAlongSentence(text: "If you don't know which tribe you belong to, you will buy for the wrong reason and sell at the wrong time.", start: 30.64, end: 36.62),
                    ReadAlongSentence(text: "The friction is confusion: You buy a stock because \"it's going up\" (Tribe A) but panic when the earnings report is bad (Tribe B).", start: 37.34, end: 44.8),
                    ReadAlongSentence(text: "You are mixing oil and water, and your portfolio is the one catching fire.", start: 45.56, end: 50.14),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Castle vs. The Foundation", start: 50.42, end: 53.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author simplifies this chaos into two distinct philosophies.", start: 53.62, end: 57.87),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "First, there is the \"Firm Foundation\" theory.", start: 58.87, end: 61.91),
                    ReadAlongSentence(text: "Imagine a cynical old appraiser looking at a house.", start: 62.51, end: 65.51),
                    ReadAlongSentence(text: "He doesn't care if the house is pretty.", start: 66.07, end: 68.07),
                    ReadAlongSentence(text: "He cares about the rent it generates, the cash flow, the dividend.", start: 68.77, end: 72.79),
                    ReadAlongSentence(text: "He believes every asset has an intrinsic value—an anchor.", start: 73.43, end: 77.45),
                    ReadAlongSentence(text: "If the price drifts too far above the anchor, he sells.", start: 78.17, end: 81.73),
                    ReadAlongSentence(text: "If it falls below, he buys.", start: 82.15, end: 84.03),
                    ReadAlongSentence(text: "He is playing the long game of math.", start: 84.47, end: 86.65),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Second, there is the \"Castle in the Air\" theory.", start: 87.25, end: 90.59),
                    ReadAlongSentence(text: "This is the psychological game.", start: 91.31, end: 93.33),
                    ReadAlongSentence(text: "The author describes this investor as someone building castles in the clouds.", start: 93.99, end: 98.63),
                    ReadAlongSentence(text: "They don't care about the cash flow; they care about the crowd.", start: 99.41, end: 102.87),
                    ReadAlongSentence(text: "They buy an asset simply because they believe a \"Greater Fool\" will come along tomorrow and pay more for it.", start: 103.63, end: 110.05),
                    ReadAlongSentence(text: "They are surfing the waves of human hope and fear, not analyzing spreadsheets.", start: 110.81, end: 115.65),
                    ReadAlongSentence(text: "The author warns that while \"Castles\" are more fun, they are built on nothing but air, and gravity eventually wins.", start: 116.43, end: 123.77),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The 2026 Hybrid", start: 124.63, end: 126.65),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The lines have blurred, but the danger is higher.", start: 127.55, end: 130.33),
                    ReadAlongSentence(text: "The \"Castle in the Air\" is now turbo-charged by social media.", start: 131.09, end: 134.75),
                    ReadAlongSentence(text: "A meme coin or a hyped AI startup with zero revenue can skyrocket simply because a subreddit or a TikTok trend decided it should.", start: 135.59, end: 144.67),
                    ReadAlongSentence(text: "This is pure \"Castle\" building.", start: 145.33, end: 147.35),
                    ReadAlongSentence(text: "It works until the music stops.", start: 148.09, end: 150.23),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Conversely, the \"Firm Foundation\" has become harder to find because algorithms have priced in \"intrinsic value\" instantly.", start: 151.01, end: 158.65),
                    ReadAlongSentence(text: "You can't easily find an undervalued stock just by reading a balance sheet anymore—an AI bot beat you to it by 0.003 seconds.", start: 159.09, end: 168.03),
                    ReadAlongSentence(text: "The modern \"Wiser\" investor knows that Bitcoin is a Castle (pure psychology, no cash flow) while a Dividend ETF is a Foundation.", start: 168.78, end: 178.38),
                    ReadAlongSentence(text: "You can own both, but you must never confuse them.", start: 179.08, end: 182.1),
                    ReadAlongSentence(text: "If you treat a Castle like a Foundation, you will lose everything waiting for a \"bounce back\" that never comes.", start: 182.88, end: 191.1),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The IQ Trap", start: 228.76, end: 229.98),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the embarrassing truth: High IQ does not protect you from financial stupidity.", start: 230.62, end: 236.16),
                    ReadAlongSentence(text: "In fact, smart people are often more susceptible to bubbles because they are better at rationalizing their madness.", start: 236.92, end: 243.38),
                    ReadAlongSentence(text: "The friction isn't a lack of data; it is a surplus of dopamine.", start: 244.16, end: 247.98),
                    ReadAlongSentence(text: "When you see your neighbor—who you know is less intelligent than you—making a fortune on a \"sure thing,\" your brain breaks.", start: 248.48, end: 255.2),
                    ReadAlongSentence(text: "Envy overrides logic.", start: 255.66, end: 257.36),
                    ReadAlongSentence(text: "You buy at the top not because you believe the math, but because you cannot bear the pain of missing out.", start: 258.02, end: 264.18),
                    ReadAlongSentence(text: "You are not investing; you are hallucinating wealth.", start: 264.74, end: 267.72),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The $50,000 Onion", start: 268.2, end: 269.8),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author inoculates you against this madness by taking you back to 17th-century Holland.", start: 270.22, end: 275.5),
                    ReadAlongSentence(text: "He tells the story of Tulipmania, the original blueprint for every financial disaster since.", start: 276.24, end: 281.98),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "It started innocently.", start: 282.38, end: 283.68),
                    ReadAlongSentence(text: "Tulips were rare and beautiful.", start: 284.1, end: 286.02),
                    ReadAlongSentence(text: "But soon, the \"Castle in the Air\" builders arrived.", start: 286.32, end: 289.1),
                    ReadAlongSentence(text: "Prices detached from reality.", start: 289.56, end: 291.36),
                    ReadAlongSentence(text: "At the peak, a single Semper Augustus bulb sold for the equivalent of a mansion, a carriage, and horses.", start: 292.1, end: 298.72),
                    ReadAlongSentence(text: "The author recounts the tragic comedy of a sailor who mistook a rare bulb for an onion and ate it with his herring—a breakfast that cost a fortune.", start: 299.56, end: 308.06),
                    ReadAlongSentence(text: "When the fever broke, the price collapsed by 99% overnight.", start: 308.72, end: 313.3),
                    ReadAlongSentence(text: "The bulb was still a bulb; only the hallucination had vanished.", start: 314.04, end: 318.04),
                    ReadAlongSentence(text: "The lesson?", start: 318.4, end: 318.92),
                    ReadAlongSentence(text: "An asset's price is what you pay; its value is what it does.", start: 319.54, end: 323.78),
                    ReadAlongSentence(text: "If it does nothing but sit there, it is a speculation, not an investment.", start: 324.36, end: 328.83),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The 2026 \"New Paradigm\"", start: 329.27, end: 331.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Nowadays, we don't buy tulips; we buy \"narratives.\"", start: 332.27, end: 335.39),
                    ReadAlongSentence(text: "The hallucination today wears a lab coat or a hoodie.", start: 335.87, end: 338.87),
                    ReadAlongSentence(text: "It is the AI startup with no product but a $5 billion valuation.", start: 339.27, end: 343.93),
                    ReadAlongSentence(text: "It is the \"Governance Token\" that governs nothing.", start: 344.55, end: 347.25),
                    ReadAlongSentence(text: "It is the meme stock that rallies because an influencer posted a frog emoji.", start: 348.03, end: 352.63),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "[Getty Images]", start: 353.15, end: 353.99),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The mechanism is identical to the 1600s: Innovation + Easy Money + Fear of Missing Out (FOMO).", start: 354.59, end: 361.91),
                    ReadAlongSentence(text: "The modern trap is the phrase, \"This time is different.\"", start: 362.45, end: 365.59),
                    ReadAlongSentence(text: "You will hear, \"But crypto is the future of money!\" or \"AI is the new electricity!\"", start: 365.93, end: 371.29),
                    ReadAlongSentence(text: "The author would remind you: The internet was the future in 1999, but 95% of dot-com companies still went to zero.", start: 371.73, end: 379.73),
                    ReadAlongSentence(text: "Being right about the technology does not mean you are right about the price.", start: 380.55, end: 385.15),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Fortune Teller’s Guild", start: 430.85, end: 432.25),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Humans are desperate for patterns.", start: 433.07, end: 434.97),
                    ReadAlongSentence(text: "If you stare at clouds long enough, you see faces.", start: 435.61, end: 438.53),
                    ReadAlongSentence(text: "If you stare at stock charts long enough, you see money.", start: 439.21, end: 442.45),
                    ReadAlongSentence(text: "This is the friction: You want to believe there is a secret code, a \"Head and Shoulders\" pattern or a \"Golden Cross\" that predicts the future.", start: 442.99, end: 451.15),
                    ReadAlongSentence(text: "You think if you just study the lines on the screen hard enough, you can outsmart the market.", start: 451.89, end: 456.35),
                    ReadAlongSentence(text: "You are wrong.", start: 456.87, end: 457.85),
                    ReadAlongSentence(text: "The market isn't a map; it’s a mirror reflecting your own wishful thinking.", start: 458.17, end: 462.63),
                    ReadAlongSentence(text: "The people selling you these \"systems\" aren't rich from trading; they are rich from selling you the system.", start: 463.41, end: 468.65),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Coin Flip Experiment", start: 469.23, end: 470.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author destroys this entire industry—Technical Analysis—with a humiliating experiment.", start: 471.23, end: 477.78),
                    ReadAlongSentence(text: "He asked his students to create a fake stock chart.", start: 478.22, end: 481.34),
                    ReadAlongSentence(text: "They did this by flipping a coin: Heads meant the stock went up, Tails meant it went down.", start: 481.98, end: 487.08),
                    ReadAlongSentence(text: "They plotted the results on graph paper.", start: 487.76, end: 489.74),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The result?", start: 490.16, end: 490.78),
                    ReadAlongSentence(text: "The chart looked exactly like a real stock.", start: 491.38, end: 494.06),
                    ReadAlongSentence(text: "It had trends, cycles, and \"resistance levels.\"", start: 494.82, end: 497.84),
                    ReadAlongSentence(text: "When the author showed this fake chart to a famous technical analyst, the expert got excited.", start: 498.62, end: 503.72),
                    ReadAlongSentence(text: "He analyzed the \"formations\" and confidently shouted, \"Buy immediately!", start: 504.3, end: 509.08),
                    ReadAlongSentence(text: "This stock is about to break out!\"", start: 509.6, end: 511.56),
                    ReadAlongSentence(text: "The author then gently revealed the truth: \"This isn't a company.", start: 512.2, end: 516.46),
                    ReadAlongSentence(text: "This is a coin flip.\"", start: 517.1, end: 518.2),
                    ReadAlongSentence(text: "The lesson was brutal.", start: 518.68, end: 519.96),
                    ReadAlongSentence(text: "Technical analysts are often just predicting the past.", start: 520.36, end: 523.54),
                    ReadAlongSentence(text: "They are analyzing noise and calling it music.", start: 524.04, end: 526.98),
                    ReadAlongSentence(text: "If past prices predicted future prices, librarians would be the richest people in the world.", start: 527.62, end: 533.52),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Algorithmic Slaughterhouse", start: 534.38, end: 536.18),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The Technical Analysis trap is even deadlier because you aren't competing against a guy with a ruler; you are competing against High-Frequency Trading (HFT) bots.", start: 537.0, end: 546.94),
                    ReadAlongSentence(text: "These AI algorithms analyze every tick, every pattern, and every millisecond of data.", start: 547.44, end: 553.74),
                    ReadAlongSentence(text: "If there was a profitable pattern, the AI found it, exploited it, and erased it before your chart even loaded.", start: 554.5, end: 560.84),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Modern \"technical traders\" on crypto exchanges or forex apps are essentially playing a video game against a supercomputer set to \"God Mode.\"", start: 561.42, end: 570.44),
                    ReadAlongSentence(text: "You might see a \"support level\" at $50,000 for Bitcoin.", start: 570.92, end: 574.68),
                    ReadAlongSentence(text: "The bot sees your \"Stop Loss\" order sitting right below it.", start: 575.18, end: 578.65),
                    ReadAlongSentence(text: "The bot will push the price down just enough to trigger your sale, steal your shares, and then rally the price back up.", start: 579.33, end: 585.81),
                    ReadAlongSentence(text: "You are not the trader; you are the liquidity.", start: 586.45, end: 589.09),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Trap of \"Doing Your Homework\"", start: 630.05, end: 631.87),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the most painful lesson for smart people: You can do everything right and still lose.", start: 632.53, end: 638.49),
                    ReadAlongSentence(text: "You can read every balance sheet, calculate every ratio, and perfectly model a company’s future cash flows.", start: 639.21, end: 646.23),
                    ReadAlongSentence(text: "You can be the \"Warren Buffett\" of your friend group.", start: 646.77, end: 649.17),
                    ReadAlongSentence(text: "But there is a fatal flaw in the logic of \"Fundamental Analysis.\"", start: 649.89, end: 653.33),
                    ReadAlongSentence(text: "You believe that if you find a great company at a fair price, the stock must go up.", start: 653.77, end: 658.15),
                    ReadAlongSentence(text: "The market does not care about your spreadsheet.", start: 658.71, end: 661.21),
                    ReadAlongSentence(text: "The friction is that you are trying to predict the future with tools that only measure the past.", start: 661.61, end: 666.41),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Blindfolded Monkeys", start: 666.83, end: 668.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author exposes this illusion with a famous challenge to the entire financial industry.", start: 668.81, end: 673.97),
                    ReadAlongSentence(text: "He declared that a blindfolded monkey throwing darts at the financial pages of a newspaper could select a portfolio that would do just as well as one carefully selected by experts.", start: 674.47, end: 684.92),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This wasn’t a joke; it was a mathematical gauntlet.", start: 685.54, end: 688.26),
                    ReadAlongSentence(text: "He explains that even the smartest fundamental analysts are often wrong because of \"Random Events.\"", start: 688.82, end: 695.34),
                    ReadAlongSentence(text: "A company might have a perfect balance sheet today, but tomorrow a factory burns down, a CEO gets indicted, or a new law bans their product.", start: 696.2, end: 705.62),
                    ReadAlongSentence(text: "These are \"unknown unknowns.\"", start: 706.38, end: 708.46),
                    ReadAlongSentence(text: "The author tells the story of how analysts loved the \"Nifty Fifty\"—the blue-chip stocks of the 1970s that could \"never fail.\"", start: 709.1, end: 716.42),
                    ReadAlongSentence(text: "Xerox, Polaroid, Avon.", start: 716.96, end: 718.92),
                    ReadAlongSentence(text: "They had great fundamentals.", start: 719.4, end: 720.78),
                    ReadAlongSentence(text: "But the market changed, technology shifted, and those \"safe\" stocks crashed by 80-90%.", start: 721.22, end: 726.7),
                    ReadAlongSentence(text: "The lesson?", start: 728.4, end: 728.94),
                    ReadAlongSentence(text: "Even valid information is useless if the market has already priced it in or if random chaos strikes tomorrow.", start: 729.7, end: 737.0),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The AI Forecasting fallacy", start: 737.68, end: 739.52),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The illusion of \"predicting fundamentals\" has moved to AI.", start: 740.1, end: 743.48),
                    ReadAlongSentence(text: "We now have \"Predictive Analytics\" and \"Big Data\" models that claim to foresee earnings surprises.", start: 744.3, end: 750.06),
                    ReadAlongSentence(text: "But here is the catch: If the AI works, everyone uses it.", start: 750.52, end: 754.86),
                    ReadAlongSentence(text: "If everyone uses it, the advantage disappears instantly.", start: 755.62, end: 759.38),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern \"Fundamental Illusion\" is thinking you can out-analyze a market that is 90% machine-driven.", start: 759.98, end: 766.44),
                    ReadAlongSentence(text: "You might think NVIDIA or the latest Quantum Computing stock is undervalued based on its P/E ratio.", start: 767.24, end: 774.16),
                    ReadAlongSentence(text: "But the market isn't pricing it on P/E; it's pricing it on liquidity flows and macroeconomic sentiment.", start: 774.76, end: 780.99),
                    ReadAlongSentence(text: "You are playing chess while the market is playing a slot machine.", start: 781.49, end: 784.55),
                    ReadAlongSentence(text: "The fundamental data is real, but its predictive power is largely a mirage in the short term.", start: 785.11, end: 790.73),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Ego of the Picker", start: 833.75, end: 835.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the hardest pill to swallow: You are not smarter than the market.", start: 835.75, end: 839.79),
                    ReadAlongSentence(text: "Nobody is.", start: 840.37, end: 841.41),
                    ReadAlongSentence(text: "The friction is your ego.", start: 842.03, end: 843.35),
                    ReadAlongSentence(text: "You believe that because you read a few articles or follow a few experts, you have an \"edge.\"", start: 843.87, end: 849.29),
                    ReadAlongSentence(text: "You think you can spot the next Apple or avoid the next crash before everyone else.", start: 849.79, end: 854.47),
                    ReadAlongSentence(text: "This belief is expensive.", start: 855.07, end: 856.47),
                    ReadAlongSentence(text: "Every time you try to outsmart the market by picking winners and losers, you are fighting a collective intelligence of millions of people, banks, and algorithms that have already priced in every piece of news you just read.", start: 857.25, end: 870.05),
                    ReadAlongSentence(text: "You are betting against the wisdom of the crowd, and the house almost always wins.", start: 870.67, end: 875.45),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The $100 Bill on the Sidewalk", start: 876.05, end: 878.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author illustrates this with a classic economist joke.", start: 879.23, end: 882.41),
                    ReadAlongSentence(text: "Two economists are walking down the street.", start: 882.83, end: 884.87),
                    ReadAlongSentence(text: "One spots a $100 bill lying on the ground.", start: 885.83, end: 888.53),
                    ReadAlongSentence(text: "\"Look!\" he says.", start: 888.99, end: 889.95),
                    ReadAlongSentence(text: "\"A hundred dollars!\"", start: 890.49, end: 891.43),
                    ReadAlongSentence(text: "The other economist doesn't even stop walking.", start: 891.95, end: 894.41),
                    ReadAlongSentence(text: "\"It can't be real,\" he replies.", start: 895.01, end: 896.77),
                    ReadAlongSentence(text: "\"If it were a real $100 bill, someone would have already picked it up.\"", start: 897.63, end: 901.59),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "[image]", start: 902.07, end: 902.47),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This is the essence of the Efficient Market Hypothesis (EMH).", start: 903.13, end: 907.11),
                    ReadAlongSentence(text: "The author explains that news travels so fast—instantly—that prices adjust immediately.", start: 907.77, end: 913.45),
                    ReadAlongSentence(text: "By the time you hear good news about a company, the stock price has already gone up to reflect it.", start: 914.33, end: 919.91),
                    ReadAlongSentence(text: "There are no \"free lunches\" (or $100 bills) lying around waiting for you to find them.", start: 920.75, end: 925.96),
                    ReadAlongSentence(text: "The market is an \"Efficiency Engine\" that devours information and spits out the correct price before you can even click \"Buy.\"", start: 926.72, end: 934.66),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Speed of Light", start: 935.1, end: 936.36),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Now, the Efficiency Engine has gone nuclear.", start: 936.88, end: 939.64),
                    ReadAlongSentence(text: "Information doesn't just travel fast; it travels at the speed of light via fiber optic cables directly into the servers of High-Frequency Trading firms.", start: 940.26, end: 949.68),
                    ReadAlongSentence(text: "If an AI detects a positive sentiment in a CEO's voice during an earnings call, it buys the stock before the CEO finishes the sentence.", start: 950.38, end: 959.32),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern investor who tries to \"beat the market\" is bringing a knife to a laser fight.", start: 960.04, end: 964.72),
                    ReadAlongSentence(text: "You might think you found an \"undiscovered\" gem in the crypto market or a small-cap biotech stock.", start: 965.22, end: 970.62),
                    ReadAlongSentence(text: "You didn't.", start: 971.14, end: 971.66),
                    ReadAlongSentence(text: "You are just the last person to know.", start: 972.46, end: 974.58),
                    ReadAlongSentence(text: "The \"Wiser\" move is to stop trying to beat the engine and instead hitch a ride on it.", start: 975.38, end: 979.9),
                    ReadAlongSentence(text: "If you can't find the needle in the haystack, buy the whole haystack.", start: 980.42, end: 984.2),
                ]),
            ],
            6: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Fake Diversity\" Scam", start: 1024.06, end: 1026.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most investors are walking around with a ticking time bomb in their pockets, and they call it a \"diversified portfolio.\"", start: 1026.96, end: 1033.9),
                    ReadAlongSentence(text: "You think because you own Apple, Microsoft, NVIDIA, and Google, you are safe.", start: 1034.72, end: 1039.5),
                    ReadAlongSentence(text: "You aren't.", start: 1040.14, end: 1040.64),
                    ReadAlongSentence(text: "You just own four different flavors of the exact same risk.", start: 1041.24, end: 1045.0),
                    ReadAlongSentence(text: "If the tech sector catches a cold, your entire financial life gets pneumonia.", start: 1045.62, end: 1050.28),
                    ReadAlongSentence(text: "The friction here is the misunderstanding of correlation.", start: 1050.98, end: 1053.92),
                    ReadAlongSentence(text: "You are not engineering risk; you are piling it up in one corner and hoping gravity doesn't notice.", start: 1054.48, end: 1060.08),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Island of Sun and Rain", start: 1060.58, end: 1062.52),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author explains the cure for this madness—Modern Portfolio Theory—with a simple parable about an island economy.", start: 1063.34, end: 1071.15),
                    ReadAlongSentence(text: "Imagine there are only two companies on this island: a large beach resort and an umbrella manufacturer.", start: 1071.89, end: 1078.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If you invest all your money in the resort, you make a fortune when it's sunny, but you go broke when it rains.", start: 1078.77, end: 1085.15),
                    ReadAlongSentence(text: "It’s a rollercoaster.", start: 1085.59, end: 1086.83),
                    ReadAlongSentence(text: "If you invest only in the umbrella company, you feast during storms but starve during the summer.", start: 1087.31, end: 1093.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Free Lunch\" of economics appears when you buy both.", start: 1094.21, end: 1098.29),
                    ReadAlongSentence(text: "Because their fortunes move in opposite directions (negative correlation), the volatility cancels out.", start: 1098.99, end: 1104.69),
                    ReadAlongSentence(text: "You earn a steady, reliable return regardless of the weather.", start: 1105.27, end: 1108.81),
                    ReadAlongSentence(text: "The author demonstrates that by combining volatile assets that zig when others zag, you can actually reduce your total risk without lowering your expected return.", start: 1109.59, end: 1119.79),
                    ReadAlongSentence(text: "This is the mathematical miracle of diversification.", start: 1120.63, end: 1123.91),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The 2026 Correlation Crisis", start: 1124.31, end: 1126.89),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Now, the \"Island\" is global, and finding assets that don't move together is harder than ever.", start: 1127.57, end: 1133.05),
                    ReadAlongSentence(text: "During a panic, \"all correlations go to one.\"", start: 1133.61, end: 1136.43),
                    ReadAlongSentence(text: "When the market crashes, almost everything—stocks, real estate, even crypto—dumps together.", start: 1136.87, end: 1142.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The mistake today is thinking that Bitcoin is a \"hedge\" against the stock market.", start: 1142.83, end: 1147.77),
                    ReadAlongSentence(text: "It often isn't; it’s just a high-beta tech stock that trades 24/7.", start: 1148.33, end: 1152.13),
                    ReadAlongSentence(text: "True \"Risk Engineering\" in the modern era requires uncomfortable assets.", start: 1153.61, end: 1158.61),
                    ReadAlongSentence(text: "It means holding boring government bonds, perhaps managed futures, or commodities like gold that actually move differently than your AI stocks.", start: 1159.55, end: 1168.76),
                    ReadAlongSentence(text: "If your entire portfolio makes you happy at the same time, you are not diversified.", start: 1169.44, end: 1174.5),
                    ReadAlongSentence(text: "You should always hate at least one thing you own.", start: 1175.12, end: 1179.36),
                ]),
            ],
            7: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"New Coke\" of Finance", start: 1218.2, end: 1219.96),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Wall Street has a massive problem: Simple index funds work too well.", start: 1220.58, end: 1225.3),
                    ReadAlongSentence(text: "They are cheap, effective, and boring.", start: 1226.22, end: 1228.7),
                    ReadAlongSentence(text: "This is a disaster for fund managers who need to buy yachts.", start: 1229.24, end: 1232.86),
                    ReadAlongSentence(text: "Their solution?", start: 1233.3, end: 1234.08),
                    ReadAlongSentence(text: "Re-branding.", start: 1234.5, end: 1235.16),
                    ReadAlongSentence(text: "They realized they couldn't sell \"Active Management\" anymore because the data proved it failed.", start: 1235.68, end: 1240.78),
                    ReadAlongSentence(text: "So, they invented a sexy new term: \"Smart Beta.\"", start: 1241.44, end: 1244.74),
                    ReadAlongSentence(text: "The friction here is marketing.", start: 1245.28, end: 1246.96),
                    ReadAlongSentence(text: "You are being sold a product that claims to be \"smarter\" than the market—offering higher returns with lower risk.", start: 1247.5, end: 1254.36),
                    ReadAlongSentence(text: "It sounds perfect.", start: 1254.92, end: 1256.0),
                    ReadAlongSentence(text: "It is almost always a trap designed to extract higher fees for a slightly tweaked product.", start: 1256.88, end: 1262.94),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Tilt and the Trap", start: 1263.38, end: 1264.92),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author dissects this trend with the precision of a surgeon.", start: 1265.7, end: 1268.92),
                    ReadAlongSentence(text: "He explains that \"Smart Beta\" strategies essentially take a boring index (like the S&P 500) and \"tilt\" it.", start: 1269.4, end: 1276.52),
                    ReadAlongSentence(text: "Instead of buying companies based on size (Market Cap), they buy based on \"Factors\" like Value (cheap stocks), Momentum (rising stocks), or Low Volatility (stable stocks).", start: 1277.4, end: 1289.8),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He admits that historically, some of these factors have outperformed.", start: 1290.36, end: 1294.76),
                    ReadAlongSentence(text: "Small companies and cheap \"value\" stocks had a good run in the 20th century.", start: 1295.38, end: 1300.06),
                    ReadAlongSentence(text: "However, he warns that these anomalies often disappear the moment they are discovered.", start: 1300.54, end: 1305.34),
                    ReadAlongSentence(text: "It’s like a secret fishing spot.", start: 1305.7, end: 1307.64),
                    ReadAlongSentence(text: "Once you publish the coordinates in a magazine (or launch an ETF), the fish vanish.", start: 1308.3, end: 1313.04),
                    ReadAlongSentence(text: "The \"Smart\" strategy often ends up being just a \"More Expensive\" strategy that underperforms the dumb index once you subtract the taxes and trading costs.", start: 1313.74, end: 1323.21),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The 2026 \"Factor Zoo\"", start: 1323.81, end: 1325.97),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Smart\" marketing has evolved into \"Thematic\" and \"AI-Driven\" madness.", start: 1326.81, end: 1331.87),
                    ReadAlongSentence(text: "We now have the \"Factor Zoo\"—hundreds of complex ETFs claiming to exploit obscure market inefficiencies.", start: 1332.71, end: 1339.87),
                    ReadAlongSentence(text: "You might see an \"AI-Powered Sentiment ETF\" or a \"Work-From-Home Alpha Fund.\"", start: 1340.53, end: 1345.99),
                    ReadAlongSentence(text: "These are the grandchildren of Smart Beta.", start: 1346.35, end: 1348.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The danger today is \"Overfitting.\"", start: 1349.25, end: 1352.01),
                    ReadAlongSentence(text: "With supercomputers, I can find a correlation between anything.", start: 1352.57, end: 1356.51),
                    ReadAlongSentence(text: "I can prove that buying stocks with the letter \"Q\" in their name outperforms the market on Tuesdays.", start: 1357.27, end: 1363.23),
                    ReadAlongSentence(text: "An AI can generate a backtest that looks perfect.", start: 1363.97, end: 1367.17),
                    ReadAlongSentence(text: "But it isn't a strategy; it's a coincidence.", start: 1367.95, end: 1370.67),
                    ReadAlongSentence(text: "The modern \"Smart\" fund is often just a closet index fund charging you 0.75% for a service a robot does for 0.03%.", start: 1371.45, end: 1387.13),
                ]),
            ],
            8: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Caveman in the Casino", start: 1427.41, end: 1428.93),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the biological glitch that destroys portfolios: Your brain is 200,000 years old.", start: 1429.71, end: 1436.39),
                    ReadAlongSentence(text: "It was designed to survive on the savannah, not to trade derivatives on a smartphone.", start: 1436.91, end: 1441.79),
                    ReadAlongSentence(text: "When you see a stock crash, your amygdala—the fear center—lights up exactly as if a tiger were chasing you.", start: 1442.33, end: 1448.63),
                    ReadAlongSentence(text: "You panic and sell.", start: 1448.99, end: 1450.47),
                    ReadAlongSentence(text: "When you see a stock soaring, your dopamine centers light up like you just found a fruit tree.", start: 1451.23, end: 1456.33),
                    ReadAlongSentence(text: "You buy.", start: 1456.85, end: 1457.57),
                    ReadAlongSentence(text: "The friction is that successful investing requires you to do the exact opposite of your survival instincts.", start: 1458.21, end: 1464.35),
                    ReadAlongSentence(text: "You are biologically hardwired to buy high (greed) and sell low (fear).", start: 1464.89, end: 1469.05),
                    ReadAlongSentence(text: "You are not a rational economic actor; you are an emotional ape with a bank account.", start: 1469.51, end: 1474.68),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Pain of the Loss", start: 1475.12, end: 1476.36),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author drags this psychological flaw into the light using Behavioral Finance.", start: 1477.28, end: 1482.2),
                    ReadAlongSentence(text: "He explains a concept called Loss Aversion with a brutal truth: The pain of losing $1,000 is twice as intense as the pleasure of gaining $1,000.", start: 1482.64, end: 1491.52),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This imbalance causes a deadly mistake called the \"Disposition Effect.\"", start: 1492.86, end: 1497.06),
                    ReadAlongSentence(text: "Investors tend to sell their winning stocks too early (to \"lock in\" the good feeling) and hold their losing stocks too long (to avoid the pain of admitting a mistake).", start: 1497.6, end: 1508.0),
                    ReadAlongSentence(text: "He tells the story of the investor who refuses to sell a tanking stock, saying, \"I'll sell it when it gets back to even.\"", start: 1508.6, end: 1514.68),
                    ReadAlongSentence(text: "It rarely does.", start: 1514.98, end: 1515.86),
                    ReadAlongSentence(text: "By refusing to \"realize\" the loss, the investor turns a small scratch into a fatal wound, anchoring their ship to a sinking rock just to protect their ego.", start: 1516.6, end: 1526.18),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Dopamine dispenser", start: 1526.92, end: 1528.12),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The financial industry has weaponized your biology against you.", start: 1528.56, end: 1532.02),
                    ReadAlongSentence(text: "Trading apps are no longer tools; they are video games.", start: 1532.7, end: 1536.24),
                    ReadAlongSentence(text: "When you buy a stock, confetti explodes on the screen.", start: 1536.92, end: 1540.26),
                    ReadAlongSentence(text: "When you check your crypto portfolio, the numbers flash in bright green or red, specifically designed to trigger a dopamine loop.", start: 1541.04, end: 1548.86),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern \"Inner Ape\" falls for Confirmation Bias on steroids.", start: 1549.46, end: 1553.18),
                    ReadAlongSentence(text: "If you buy a meme coin that crashes, you don't sell.", start: 1554.08, end: 1557.1),
                    ReadAlongSentence(text: "Instead, you go to a Discord server or a Reddit thread full of other bag-holders who tell you to have \"Diamond Hands.\"", start: 1557.64, end: 1564.08),
                    ReadAlongSentence(text: "They reinforce your delusion that the price must come back up.", start: 1564.56, end: 1567.82),
                    ReadAlongSentence(text: "In the 1970s, you had to call a broker to make a mistake.", start: 1568.6, end: 1571.94),
                    ReadAlongSentence(text: "Today, you can ruin your financial future with a single face-ID unlock while sitting on the toilet.", start: 1572.46, end: 1581.07),
                ]),
            ],
            9: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Parasite in Your Portfolio", start: 1630.67, end: 1632.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the scandal of the century: The financial industry is the only industry on Earth where you get worse service the more you pay for it.", start: 1633.41, end: 1641.11),
                    ReadAlongSentence(text: "If you hire a cheap lawyer, you go to jail.", start: 1641.87, end: 1644.33),
                    ReadAlongSentence(text: "If you hire a cheap heart surgeon, you die.", start: 1645.07, end: 1647.79),
                    ReadAlongSentence(text: "But if you hire an expensive fund manager, you go broke.", start: 1648.57, end: 1651.91),
                    ReadAlongSentence(text: "The friction is that we are trained to believe \"You get what you pay for.\"", start: 1652.59, end: 1656.75),
                    ReadAlongSentence(text: "In investing, you get what you don't pay for.", start: 1657.53, end: 1660.01),
                    ReadAlongSentence(text: "Every dollar you pay in management fees, trading costs, and taxes is a dollar that isn't compounding for your future.", start: 1660.61, end: 1667.73),
                    ReadAlongSentence(text: "You are feeding a system of parasites that produce nothing but excuses for why they failed to beat the average.", start: 1668.35, end: 1674.73),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Ultimate \"Cheat Code\"", start: 1675.43, end: 1676.87),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author presents the \"Index Fund\" not as a compromise, but as a mathematical weapon.", start: 1677.53, end: 1683.1),
                    ReadAlongSentence(text: "He explains that the stock market is a \"positive-sum game\"—corporate profits grow, and everyone can win.", start: 1683.56, end: 1691.04),
                    ReadAlongSentence(text: "But active trading is a \"zero-sum game\"—for every person who beats the market, someone else must lose.", start: 1691.78, end: 1698.82),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Once you add the fees of the \"croupiers\" (brokers and managers), it becomes a \"negative-sum game.\"", start: 1699.58, end: 1705.28),
                    ReadAlongSentence(text: "The author champions the solution: Buy the haystack.", start: 1705.84, end: 1709.06),
                    ReadAlongSentence(text: "Don't look for the needle.", start: 1709.48, end: 1710.6),
                    ReadAlongSentence(text: "By buying a broad-based Index Fund (like the S&P 500), you own a tiny slice of every major business in America.", start: 1711.04, end: 1719.1),
                    ReadAlongSentence(text: "You fire the expensive manager.", start: 1719.72, end: 1721.74),
                    ReadAlongSentence(text: "You eliminate the risk of picking a loser.", start: 1722.16, end: 1724.38),
                    ReadAlongSentence(text: "You guarantee that you will capture the entire return of the market, minus a tiny fee.", start: 1724.9, end: 1730.36),
                    ReadAlongSentence(text: "He proves that over a 20-year period, this \"dumb\" strategy beats 90% of the \"smart\" money.", start: 1730.76, end: 1737.44),
                    ReadAlongSentence(text: "It is the only free lunch on Wall Street.", start: 1738.04, end: 1740.52),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Self-Healing Beast", start: 1741.16, end: 1742.62),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In 2026, the Index Fund is even more powerful because of velocity.", start: 1743.26, end: 1748.24),
                    ReadAlongSentence(text: "The modern S&P 500 is a ruthless, self-cleaning organism.", start: 1749.02, end: 1753.48),
                    ReadAlongSentence(text: "When a company (like an old retail giant) starts to die, the Index automatically demotes it.", start: 1754.1, end: 1759.86),
                    ReadAlongSentence(text: "When a new innovator (like an AI giant) rises, the Index automatically adds it.", start: 1760.68, end: 1766.08),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You don't need to predict if \"Quantum Computing\" will replace \"Generative AI.\"", start: 1766.76, end: 1771.46),
                    ReadAlongSentence(text: "The Index will do it for you.", start: 1771.98, end: 1773.62),
                    ReadAlongSentence(text: "If a new technology takes over the world, it will enter the Index, and you will own it automatically.", start: 1774.56, end: 1780.56),
                    ReadAlongSentence(text: "The modern danger is \"Closet Indexing\"—paying high fees for a \"Tech ETF\" that just owns the same top 5 stocks as the S&P 500 anyway.", start: 1781.22, end: 1791.67),
                    ReadAlongSentence(text: "The \"Wiser\" move is to accept that the Index is the ultimate trend-follower.", start: 1792.19, end: 1796.55),
                    ReadAlongSentence(text: "It never sleeps, it never panics, and it costs almost nothing.", start: 1797.17, end: 1801.11),
                ]),
            ],
            10: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Sleeping Bag Strategy", start: 1850.69, end: 1852.25),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the most expensive mistake smart people make: They treat investing like a static number.", start: 1852.85, end: 1858.61),
                    ReadAlongSentence(text: "They ask, \"What is the best portfolio?\" as if the answer is the same for a 22-year-old software engineer and a 65-year-old retiree.", start: 1859.15, end: 1867.99),
                    ReadAlongSentence(text: "It isn't.", start: 1868.71, end: 1869.17),
                    ReadAlongSentence(text: "The friction is Risk Capacity.", start: 1869.73, end: 1871.99),
                    ReadAlongSentence(text: "A young person can lose 50% of their money and laugh about it because they have 40 years of \"Human Capital\" (future earnings) left to replace it.", start: 1872.73, end: 1881.47),
                    ReadAlongSentence(text: "A retiree who loses 50% faces a catastrophic decline in lifestyle.", start: 1882.19, end: 1887.57),
                    ReadAlongSentence(text: "Most people fail because they are either too conservative when young (sleeping on a pile of cash that inflation is eating) or too aggressive when old (sleeping on a bed of crypto that might vanish overnight).", start: 1888.29, end: 1900.05),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Glide Path", start: 1900.59, end: 1901.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author solves this by introducing the \"Lifecycle Guide\"—a roadmap that shifts as you age.", start: 1902.33, end: 1908.67),
                    ReadAlongSentence(text: "He doesn't just give you a pie chart; he gives you a movie script.", start: 1909.31, end: 1912.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In Act 1 (your 20s and 30s), you are aggressive.", start: 1913.41, end: 1916.99),
                    ReadAlongSentence(text: "You own almost entirely stocks.", start: 1917.49, end: 1919.77),
                    ReadAlongSentence(text: "You want volatility because you are a net buyer—when the market crashes, stocks are on sale for your future self.", start: 1920.49, end: 1927.47),
                    ReadAlongSentence(text: "In Act 2 (your 40s and 50s), the plot thickens.", start: 1928.49, end: 1931.47),
                    ReadAlongSentence(text: "You start adding bonds and real estate.", start: 1931.93, end: 1934.45),
                    ReadAlongSentence(text: "You are no longer just growing wealth; you are protecting it.", start: 1935.11, end: 1938.59),
                    ReadAlongSentence(text: "In Act 3 (your 60s and beyond), the climax arrives.", start: 1939.25, end: 1943.09),
                    ReadAlongSentence(text: "You shift heavily into income-producing assets like bonds and dividend stocks.", start: 1943.75, end: 1948.83),
                    ReadAlongSentence(text: "The goal is no longer \"more money\"; the goal is \"reliable money.\"", start: 1949.61, end: 1953.57),
                    ReadAlongSentence(text: "The author warns that failing to follow this \"Glide Path\" is like trying to land a plane without lowering the landing gear—you might crash right at the end of a perfect flight.", start: 1954.11, end: 1964.18),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The 2026 Longevity Gamble", start: 1964.78, end: 1967.44),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In 2026, the old \"100 minus your age\" rule for stock allocation is dangerous not because you will live to 100, but because you might.", start: 1967.82, end: 1979.26),
                    ReadAlongSentence(text: "The greatest risk to a modern retirement isn't the market crashing; it is Longevity Risk—the mathematical probability that you survive longer than your savings do.", start: 1979.74, end: 1990.22),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Medical advances and lifestyle shifts mean your retirement could easily stretch for 30 or 40 years.", start: 1990.8, end: 1996.98),
                    ReadAlongSentence(text: "If you shift entirely to \"safe\" bonds at age 65, inflation becomes your silent assassin.", start: 1997.68, end: 2004.34),
                    ReadAlongSentence(text: "A 3% inflation rate cuts your purchasing power in half every 24 years.", start: 2005.02, end: 2010.48),
                    ReadAlongSentence(text: "If you live to 90 but planned for 80, you spend your final decade broke.", start: 2011.44, end: 2016.7),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern \"Wiser\" strategy requires you to stay invested in growth assets (stocks) much later in life than your grandparents did.", start: 2017.38, end: 2025.64),
                    ReadAlongSentence(text: "You need your portfolio to keep working because you might be retired for a third of your life.", start: 2026.2, end: 2031.24),
                    ReadAlongSentence(text: "The goal isn't just to reach the finish line; it's to ensure the gas tank doesn't run dry while you are still driving.", start: 2032.08, end: 2040.86),
                ]),
            ],
        ],
        8: [
            1: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the friction: most investors treat the stock market like a casino and their shares like betting chips.", start: 8.7, end: 15.48),
                    ReadAlongSentence(text: "They obsess over the flashing numbers (the price), completely detached from the reality of what those numbers represent.", start: 16.44, end: 23.9),
                    ReadAlongSentence(text: "When the \"chip\" value drops, they panic and fold.", start: 24.74, end: 27.96),
                    ReadAlongSentence(text: "This is the \"Renter’s Mentality\"—you are just renting a position on a chart, hoping to pass it to a greater fool for a profit.", start: 28.72, end: 36.76),
                    ReadAlongSentence(text: "This detachment is the single greatest cause of wealth destruction.", start: 37.36, end: 41.52),
                    ReadAlongSentence(text: "You cannot weather a storm if you don't even know what house you are living in.", start: 42.1, end: 46.37),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Silent Partner\" Letter Buffett flips this dynamic by ignoring the stock market entirely.", start: 46.93, end: 53.11),
                    ReadAlongSentence(text: "In his foundational Owner-Related Business Principles, he tells a simple but radical story: imagine Berkshire Hathaway isn't a publicly traded corporation, but a private family partnership.", start: 53.89, end: 67.09),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He posits that he is the managing partner, and you are the silent partner.", start: 67.63, end: 72.55),
                    ReadAlongSentence(text: "You aren't a \"shareholder\"—a faceless source of capital to be exploited—you are a co-owner.", start: 73.21, end: 79.79),
                    ReadAlongSentence(text: "Buffett famously notes that he treats his investors as if they were his own sisters and aunts.", start: 80.33, end: 86.61),
                    ReadAlongSentence(text: "An owner of a private farm doesn't check the price of their land every day; they check the weather and the crop yield.", start: 87.27, end: 93.81),
                    ReadAlongSentence(text: "Buffett teaches that if you wouldn't be comfortable owning a stock if the market closed down for five years, you shouldn't own it for five minutes.", start: 94.49, end: 102.79),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Gamification Trap", start: 103.33, end: 104.93),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, \"Adopting the Owner's Mindset\" is harder—and more profitable—than ever.", start: 105.33, end: 111.21),
                    ReadAlongSentence(text: "Financial apps have weaponized the \"Renter's Mentality\" through gamification.", start: 111.83, end: 116.99),
                    ReadAlongSentence(text: "When you buy a stock on a modern app and see confetti explode, or panic-sell because a crypto coin dropped 15% in an hour, you are falling into the trap Buffett warned against.", start: 117.71, end: 129.21),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Apply the \"Owner's Mindset\" to the AI boom.", start: 129.73, end: 133.01),
                    ReadAlongSentence(text: "The \"Renter\" buys NVIDIA because the line is going up.", start: 133.89, end: 137.6),
                    ReadAlongSentence(text: "The \"Owner\" buys it because they understand the moat of the CUDA software ecosystem and want to own a proportional share of that cash flow for the next decade.", start: 138.16, end: 148.4),
                    ReadAlongSentence(text: "If you are stressing over quarterly earnings calls, you are likely speculating, not owning.", start: 149.12, end: 154.64),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Profit Mirage", start: 184.06, end: 185.4),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the dangerous secret about financial statements: \"Profit\" is an opinion, but \"Cash\" is a fact.", start: 186.16, end: 193.88),
                    ReadAlongSentence(text: "Most aspiring investors glance at the bottom line of an Income Statement—Net Income—and assume that’s how much money the business actually made.", start: 194.48, end: 205.14),
                    ReadAlongSentence(text: "They are wrong.", start: 205.5, end: 207.16),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "GAAP (Generally Accepted Accounting Principles) is a set of rules designed to make companies comparable, not necessarily truthful about their economic reality.", start: 207.76, end: 218.86),
                    ReadAlongSentence(text: "You can follow every accounting rule perfectly and still go bankrupt while reporting a \"profit.\"", start: 219.4, end: 225.2),
                    ReadAlongSentence(text: "If you are analyzing a business based solely on its Price-to-Earnings (P/E) ratio, you are effectively driving a car by looking only at the speedometer while ignoring the fuel gauge.", start: 225.94, end: 236.96),
                    ReadAlongSentence(text: "You know how fast you're going, but not when the engine is about to die.", start: 237.5, end: 241.29),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Owner Earnings\" Revelation", start: 241.65, end: 244.15),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Buffett solved this by inventing his own metric: \"Owner Earnings.\"", start: 245.01, end: 249.39),
                    ReadAlongSentence(text: "In his letters, he describes a hypothetical business that reports massive profits but requires new machinery every year just to stay open.", start: 250.05, end: 259.31),
                    ReadAlongSentence(text: "To the accountant, buying that machine is just capital expenditure (CapEx) that gets depreciated slowly over years.", start: 259.79, end: 267.61),
                    ReadAlongSentence(text: "To the owner, that money is gone.", start: 268.11, end: 270.57),
                    ReadAlongSentence(text: "It left the bank account.", start: 271.11, end: 272.55),
                    ReadAlongSentence(text: "It cannot be used to pay dividends or expand.", start: 273.09, end: 276.39),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Buffett’s formula is ruthless: Take reported earnings, add back depreciation (a non-cash charge), but then subtract the capital expenditures required to maintain the company's competitive position.", start: 277.03, end: 290.53),
                    ReadAlongSentence(text: "This reveals the \"distributable cash\"—the actual money the owner can take out of the business without hurting it.", start: 291.17, end: 298.41),
                    ReadAlongSentence(text: "He teaches us to look for companies that don't just report accounting profits, but generate \"free cash flow\"—businesses that don't require heavy reinvestment just to survive.", start: 299.09, end: 310.49),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Adjusted EBITDA\" Trap", start: 311.03, end: 313.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In today’s tech-dominated market, this distortion is even worse.", start: 313.79, end: 318.31),
                    ReadAlongSentence(text: "We live in the era of \"Adjusted EBITDA\"—a metric Charlie Munger famously called \"bullshit earnings.\"", start: 318.95, end: 325.83),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Modern tech companies (SaaS, AI, Gig Economy) often report massive losses but claim they are profitable on an \"Adjusted\" basis.", start: 326.65, end: 336.55),
                    ReadAlongSentence(text: "They do this by excluding things like Stock-Based Compensation (paying employees in stock instead of cash).", start: 337.09, end: 343.83),
                    ReadAlongSentence(text: "They pretend this isn't a real expense.", start: 344.39, end: 346.89),
                    ReadAlongSentence(text: "But if you are an owner, it is a real expense—it dilutes your ownership stake.", start: 347.59, end: 353.43),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the recent AI boom.", start: 353.81, end: 355.91),
                    ReadAlongSentence(text: "A company might show high EBITDA, but if they have to spend billions every year on new GPU clusters just to keep their model relevant, their Owner Earnings might be negative.", start: 356.71, end: 367.96),
                    ReadAlongSentence(text: "They are running on a treadmill, running faster and faster just to stay in the same place.", start: 368.46, end: 373.94),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The Capex Check: Open the Cash Flow Statement and compare \"Capital Expenditures\" (under Investing) to \"Depreciation\" (under Operating).", start: 374.9, end: 386.18),
                    ReadAlongSentence(text: "If Capex is consistently higher than Depreciation, the company is burning cash just to stay alive rather than generating wealth for you—proceed with extreme caution.", start: 386.68, end: 398.8),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The \"Real\" P/E: Ignore the standard P/E ratio found on finance sites.", start: 399.4, end: 405.36),
                    ReadAlongSentence(text: "Calculate \"Price to Free Cash Flow\" by dividing Market Cap by (Operating Cash Flow minus Capital Expenditures) to see the true multiple you are paying for the cash the business actually generates.", start: 405.86, end: 419.82),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Good Product\" Fallacy", start: 428.54, end: 430.44),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the friction: most investors think a \"good company\" is one with a great product or a fast-growing market.", start: 431.12, end: 438.76),
                    ReadAlongSentence(text: "They see a revolutionary technology or a popular brand and assume the stock is a winner.", start: 439.42, end: 445.7),
                    ReadAlongSentence(text: "This is the \"Good Product Fallacy.\"", start: 446.62, end: 449.0),
                    ReadAlongSentence(text: "History is littered with companies that changed the world but went bankrupt because they couldn't protect their profits.", start: 449.76, end: 456.46),
                    ReadAlongSentence(text: "If you are buying a stock just because \"everyone is using it,\" you are missing the most critical variable: durability.", start: 457.14, end: 465.14),
                    ReadAlongSentence(text: "A castle with no moat is just a pile of gold waiting to be looted by competitors.", start: 465.7, end: 471.54),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Castle and the Knight", start: 471.98, end: 473.46),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Buffett solves this with his most famous metaphor: the \"Economic Moat.\"", start: 474.48, end: 479.28),
                    ReadAlongSentence(text: "He asks you to imagine a business as a magnificent castle.", start: 479.96, end: 483.6),
                    ReadAlongSentence(text: "Inside the castle is the \"Gold\"—the high returns on invested capital.", start: 484.33, end: 489.23),
                    ReadAlongSentence(text: "But every day, a thousand knights (competitors) ride up to the castle walls, trying to steal that gold.", start: 489.75, end: 496.45),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He distinguishes between two types of businesses: \"Franchises\" and \"Commodities.\"", start: 496.95, end: 502.31),
                    ReadAlongSentence(text: "A Franchise is a castle with a wide, crocodile-filled moat.", start: 502.81, end: 507.45),
                    ReadAlongSentence(text: "It has pricing power—it can raise prices, and customers still pay.", start: 508.03, end: 512.81),
                    ReadAlongSentence(text: "Think of See's Candies, a company Buffett bought.", start: 513.63, end: 516.91),
                    ReadAlongSentence(text: "They could raise the price of a box of chocolates every single year, and people would still buy it for Valentine's Day because no one wants to give their spouse \"discount\" chocolate.", start: 517.55, end: 529.33),
                    ReadAlongSentence(text: "A Commodity business, on the other hand, has no moat.", start: 529.91, end: 533.13),
                    ReadAlongSentence(text: "It must compete solely on price.", start: 533.61, end: 535.63),
                    ReadAlongSentence(text: "If it raises prices by a penny, customers leave.", start: 536.15, end: 539.51),
                    ReadAlongSentence(text: "Buffett teaches that it is far better to buy a wonderful business (Franchise) at a fair price than a fair business (Commodity) at a wonderful price.", start: 540.11, end: 548.97),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Network Effect\" Moat", start: 549.47, end: 551.45),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern economy, moats have evolved from physical brands to digital networks.", start: 551.95, end: 557.27),
                    ReadAlongSentence(text: "The most powerful moat today is the \"Network Effect\"—where a product becomes more valuable as more people use it.", start: 557.81, end: 565.41),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the \"AI War.\"", start: 565.85, end: 567.71),
                    ReadAlongSentence(text: "A standalone AI wrapper app has a weak moat; anyone can copy the code and undercut the price.", start: 568.49, end: 574.95),
                    ReadAlongSentence(text: "But a platform like the Apple App Store or Microsoft's enterprise ecosystem has a massive moat.", start: 575.69, end: 582.41),
                    ReadAlongSentence(text: "If you are a developer, you must be on the App Store because that's where the users are.", start: 582.93, end: 587.75),
                    ReadAlongSentence(text: "If you are a user, you stay because that's where the apps are.", start: 588.39, end: 592.43),
                    ReadAlongSentence(text: "This creates a \"Switching Cost\" so high that users are effectively locked in.", start: 592.97, end: 598.77),
                    ReadAlongSentence(text: "In the age of remote work and digital subscriptions, looking for high \"Switching Costs\" is the modern equivalent of looking for a brand name.", start: 599.31, end: 608.5),
                    ReadAlongSentence(text: "If it takes a company 12 months and $10 million to migrate away from a software provider, that provider has a moat of steel.", start: 609.02, end: 619.34),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Manic Neighbor", start: 674.64, end: 675.62),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You believe the market is an authority figure.", start: 676.12, end: 678.74),
                    ReadAlongSentence(text: "When a stock price collapses by 10% in a single morning, your primal brain assumes the market \"knows\" something you don’t.", start: 679.16, end: 687.72),
                    ReadAlongSentence(text: "You feel foolish, exposed, and desperate to stop the pain.", start: 688.36, end: 692.48),
                    ReadAlongSentence(text: "You assume price equals truth.", start: 693.14, end: 695.68),
                    ReadAlongSentence(text: "But in the short run, the market is not a weighing machine that measures value; it is a voting machine that measures popularity.", start: 696.36, end: 704.34),
                    ReadAlongSentence(text: "If you let the daily ticker dictate your emotional state, you are letting a mob of strangers determine your self-worth.", start: 705.2, end: 712.1),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Legend of Mr. Market", start: 712.6, end: 715.5),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Buffett didn’t invent the solution to this; he inherited it from his mentor, Ben Graham, in the form of a parable that changes everything.", start: 716.04, end: 724.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine you own a small business in partnership with a man named \"Mr.", start: 724.77, end: 729.23),
                    ReadAlongSentence(text: "Market.\"", start: 729.73, end: 730.11),
                    ReadAlongSentence(text: "Every single morning, without fail, Mr.", start: 730.57, end: 733.35),
                    ReadAlongSentence(text: "Market knocks on your office door.", start: 734.21, end: 736.01),
                    ReadAlongSentence(text: "He is a manic-depressive.", start: 736.45, end: 738.33),
                    ReadAlongSentence(text: "Some days, he is euphoric, sees only sunshine, and offers to buy your share of the business for a ludicrously high price.", start: 738.79, end: 747.39),
                    ReadAlongSentence(text: "Other days, he is despondent, sees only ruin, and offers to sell you his share for pennies on the dollar.", start: 748.31, end: 754.45),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author teaches us that Mr.", start: 755.13, end: 757.05),
                    ReadAlongSentence(text: "Market is there to serve you, not to guide you.", start: 758.83, end: 761.57),
                    ReadAlongSentence(text: "His wallet is open, but his wisdom is non-existent.", start: 762.23, end: 766.01),
                    ReadAlongSentence(text: "You have three choices: you can ignore him, you can sell to him when he is manic, or you can buy from him when he is depressed.", start: 766.61, end: 774.59),
                    ReadAlongSentence(text: "The one thing you must never do is fall under his influence.", start: 775.09, end: 779.11),
                    ReadAlongSentence(text: "If you look at a dropping price and think, \"I must be wrong,\" you have allowed the crazy neighbor to run your house.", start: 779.57, end: 786.51),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Algorithm Is the New Mr. Market", start: 787.03, end: 791.79),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the 1950s, Mr.", start: 792.33, end: 793.95),
                    ReadAlongSentence(text: "Market showed up once a day in the morning newspaper.", start: 795.11, end: 798.15),
                    ReadAlongSentence(text: "Today, he lives in your pocket, screaming at you 24/7 through push notifications and red/green candlesticks.", start: 798.73, end: 806.91),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Modern apps have gamified this manic behavior.", start: 807.65, end: 810.71),
                    ReadAlongSentence(text: "They use bright red colors and downward arrows to trigger a cortisol spike (fear) and bright green confetti to trigger dopamine (greed).", start: 811.67, end: 820.92),
                    ReadAlongSentence(text: "In the world of Crypto and 24-hour trading, Mr.", start: 821.56, end: 825.04),
                    ReadAlongSentence(text: "Market never sleeps; he is on a permanent bender.", start: 825.82, end: 829.04),
                    ReadAlongSentence(text: "If you check your portfolio five times a day, you are inviting a manic-depressive into your brain five times a day to scream at you.", start: 829.86, end: 838.42),
                    ReadAlongSentence(text: "The \"wiser\" investor realizes that volatility is not risk—it is the fee you pay for entrance.", start: 839.52, end: 847.04),
                    ReadAlongSentence(text: "If you can decouple your mood from the color of the pixels on your screen, you have an insurmountable advantage over the algorithm-addicted masses.", start: 847.66, end: 856.92),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The CEO’s Secret Addiction", start: 863.68, end: 865.74),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the friction: You assume the CEO works for you.", start: 866.18, end: 870.08),
                    ReadAlongSentence(text: "You assume their primary goal is to make your shares more valuable.", start: 870.62, end: 874.44),
                    ReadAlongSentence(text: "In reality, most CEOs suffer from a \"growth addiction.\"", start: 875.1, end: 878.64),
                    ReadAlongSentence(text: "Their salaries, prestige, and magazine covers are often tied to the size of the company (total revenue), not the value per share.", start: 879.22, end: 887.48),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This creates a conflict of interest.", start: 888.1, end: 890.38),
                    ReadAlongSentence(text: "A CEO will often take the cash the business generates—your cash—and light it on fire by buying a mediocre competitor at a premium price, just to make the empire bigger.", start: 891.06, end: 902.94),
                    ReadAlongSentence(text: "They call it \"strategic synergy.\"", start: 903.5, end: 905.76),
                    ReadAlongSentence(text: "Usually, it’s just ego.", start: 906.5, end: 908.26),
                    ReadAlongSentence(text: "If you don't watch how management spends the money in the bank, you are letting a teenager with a credit card run your household.", start: 908.94, end: 916.74),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"One Dollar\" Ultimatum", start: 917.2, end: 919.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Buffett counters this with a ruthless rule known as the \"One Dollar Test.\"", start: 920.21, end: 925.05),
                    ReadAlongSentence(text: "In his letters, he lays out a simple ultimatum for management: A company should only retain earnings if, for every dollar retained, it creates at least one dollar of market value over time.", start: 925.83, end: 938.39),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of how easy it is for a CEO to \"buy\" growth.", start: 939.23, end: 943.61),
                    ReadAlongSentence(text: "Anyone can grow sales by buying a bad business.", start: 944.21, end: 947.25),
                    ReadAlongSentence(text: "But a true \"Capital Allocator\" (Buffett's highest praise) knows when to shrink.", start: 947.73, end: 953.29),
                    ReadAlongSentence(text: "If the company cannot reinvest cash at a high rate of return, the CEO must have the humility to give it back to the shareholders—either through dividends (a direct check) or share buybacks (increasing your percentage of ownership).", start: 953.93, end: 970.13),
                    ReadAlongSentence(text: "He views a share buyback not as a market signal, but as a way to buy out \"unhappy partners\" at a discount, instantly making the remaining partners richer without them lifting a finger.", start: 971.01, end: 983.03),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Buyback Masquerade", start: 983.55, end: 985.31),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern tech era, the \"Share Buyback\" has been corrupted.", start: 985.75, end: 989.59),
                    ReadAlongSentence(text: "Many Silicon Valley giants announce massive, multi-billion dollar buyback programs to great fanfare.", start: 990.37, end: 998.09),
                    ReadAlongSentence(text: "It sounds like they are returning capital to you.", start: 998.53, end: 1000.89),
                    ReadAlongSentence(text: "Often, they are lying.", start: 1001.25, end: 1002.69),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "They are using those buybacks to offset \"Stock-Based Compensation\" (SBC).", start: 1003.31, end: 1008.43),
                    ReadAlongSentence(text: "They pay their engineers in millions of new shares (diluting you), then use company cash to buy those shares back (undiluting you).", start: 1009.33, end: 1018.17),
                    ReadAlongSentence(text: "The net result?", start: 1018.71, end: 1019.79),
                    ReadAlongSentence(text: "The share count stays flat, but the cash is gone.", start: 1020.33, end: 1023.27),
                    ReadAlongSentence(text: "This is running in place.", start: 1023.67, end: 1025.75),
                    ReadAlongSentence(text: "A \"wiser\" analysis looks at the net change in share count.", start: 1026.17, end: 1030.43),
                    ReadAlongSentence(text: "If a company spends $10 billion on buybacks but the share count doesn't drop, that wasn't a return of capital—it was a disguised employee salary expense.", start: 1031.19, end: 1043.5),
                ]),
            ],
            6: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Boardroom Blind Spot", start: 1101.36, end: 1103.32),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "We treat CEOs like chess grandmasters.", start: 1104.04, end: 1106.88),
                    ReadAlongSentence(text: "We assume that when a leader announces a massive acquisition or a pivot into a new technology, they have run thousands of simulations and found the optimal move.", start: 1107.68, end: 1118.8),
                    ReadAlongSentence(text: "But inside the boardroom, a different, darker game is being played.", start: 1119.48, end: 1123.84),
                    ReadAlongSentence(text: "It isn’t strategy; it’s survival.", start: 1124.38, end: 1126.88),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most corporate leadership is not driven by logic, but by a terrifying fear of being the \"odd one out.\"", start: 1127.48, end: 1134.56),
                    ReadAlongSentence(text: "If Competitor A buys a blockchain startup, Competitor B feels a primal compulsion to buy one too, regardless of the price.", start: 1135.36, end: 1143.82),
                    ReadAlongSentence(text: "If they don't, and blockchain succeeds, they look like fools.", start: 1144.25, end: 1147.79),
                    ReadAlongSentence(text: "If they buy it and it fails, well, \"everyone else did it too.\"", start: 1148.35, end: 1152.25),
                    ReadAlongSentence(text: "This herd mentality is the single greatest destroyer of shareholder capital, yet it parades itself as \"industry standard best practice.\"", start: 1152.79, end: 1161.39),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Institutional Imperative\"", start: 1161.77, end: 1163.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Buffett coined a specific term for this force: the \"Institutional Imperative.\"", start: 1164.07, end: 1169.23),
                    ReadAlongSentence(text: "In his letters, he dissects how decent, intelligent managers turn into irrational copycats the moment they enter a corporate hierarchy.", start: 1169.85, end: 1178.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He compares it to a teenager smoking to look cool.", start: 1179.47, end: 1182.43),
                    ReadAlongSentence(text: "The Imperative dictates that if an investment banker proposes a deal, the CEO will find a way to justify it.", start: 1183.03, end: 1190.81),
                    ReadAlongSentence(text: "If a competitor expands, the CEO will expand.", start: 1191.31, end: 1194.79),
                    ReadAlongSentence(text: "Buffett famously noted that this force is so strong it can make a group of brilliant people do things that any one of them, acting alone, would call insane.", start: 1195.63, end: 1205.73),
                    ReadAlongSentence(text: "He teaches us that the rarest asset in business is not intelligence—it is the courage to say \"no\" when everyone else is shouting \"yes.\"", start: 1206.41, end: 1215.83),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Pivot\" Pandemic", start: 1216.67, end: 1218.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern era, the Institutional Imperative has accelerated into a virus.", start: 1218.87, end: 1223.85),
                    ReadAlongSentence(text: "We see it in the \"Pivot\" culture.", start: 1224.35, end: 1226.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "First, it was the \"Dot-com\" pivot.", start: 1226.53, end: 1228.95),
                    ReadAlongSentence(text: "Then, the \"Blockchain\" pivot.", start: 1229.41, end: 1231.57),
                    ReadAlongSentence(text: "Now, it is the \"AI\" pivot.", start: 1232.13, end: 1234.35),
                    ReadAlongSentence(text: "Companies that sell pet food or furniture have no business declaring themselves \"AI-first\" organizations, yet they launch half-baked chatbots just to boost their stock price for a quarter.", start: 1234.87, end: 1246.86),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Consider the Metaverse hype cycle of 2021.", start: 1247.48, end: 1249.54),
                    ReadAlongSentence(text: "Facebook changed its name to Meta, and suddenly, every Fortune 500 company felt the Imperative to buy virtual real estate.", start: 1251.5, end: 1260.62),
                    ReadAlongSentence(text: "Billions of dollars of shareholder capital were incinerated in months because CEOs were terrified of missing out on a future they didn't even understand.", start: 1261.12, end: 1270.44),
                    ReadAlongSentence(text: "A \"wiser\" investor spots these waves of hysteria.", start: 1270.86, end: 1274.1),
                    ReadAlongSentence(text: "When a CEO uses the latest buzzword 50 times on an earnings call but cannot explain the unit economics, they are not innovating; they are succumbing to the Imperative.", start: 1275.06, end: 1285.96),
                ]),
            ],
        ],
        9: [
            1: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Listen closely.", start: 8.96, end: 9.72),
                    ReadAlongSentence(text: "We are navigating an era of unprecedented financial chaos.", start: 10.08, end: 13.62),
                    ReadAlongSentence(text: "Between inflation silently eating away your purchasing power and the manic volatility ripping through the markets, the average retail investor is wildly under-equipped.", start: 14.38, end: 23.2),
                    ReadAlongSentence(text: "They are stepping onto a battlefield armed with a toy hammer.", start: 23.8, end: 27.06),
                    ReadAlongSentence(text: "The prevailing myth—the grand illusion keeping the middle class stuck in mediocrity—is that the traditional financial industry exists to help you build wealth.", start: 27.48, end: 36.3),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "It doesn't.", start: 36.72, end: 37.54),
                    ReadAlongSentence(text: "The system is a brilliantly engineered machine designed to siphon your capital.", start: 38.08, end: 42.62),
                    ReadAlongSentence(text: "When you walk into a traditional brokerage, you aren't meeting a wealth-building partner.", start: 43.06, end: 47.18),
                    ReadAlongSentence(text: "Your stockbroker is typically paid a fee simply to sell you an investment product.", start: 47.52, end: 51.92),
                    ReadAlongSentence(text: "They do not get paid to actually make you money.", start: 52.42, end: 54.84),
                    ReadAlongSentence(text: "And if you think you can hide in a standard mutual fund, the math is brutally unforgiving.", start: 55.44, end: 60.69),
                    ReadAlongSentence(text: "After the management companies extract their exorbitant fees and expenses, the vast majority of mutual funds consistently fail to beat the market averages over time.", start: 61.13, end: 70.35),
                    ReadAlongSentence(text: "You are paying premium prices for guaranteed mediocrity.", start: 71.05, end: 74.23),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Truth About the Tooth Fairy", start: 74.73, end: 76.45),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Joel Greenblatt strips away this glossy facade with one blunt, cynical truth: when it comes to Wall Street, there ain’t no tooth fairy.", start: 76.95, end: 84.75),
                    ReadAlongSentence(text: "Once you leave the comfort of your home and step into the market, no one is going to tuck you in, no one is looking out for your best interests, and money is certainly not going to magically appear under your pillow.", start: 85.53, end: 95.63),
                    ReadAlongSentence(text: "You are entirely on your own.", start: 96.27, end: 98.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "To survive this, you need an ironclad anchor.", start: 98.65, end: 101.33),
                    ReadAlongSentence(text: "Greenblatt illustrates the ease of destroying capital by recounting a childhood mistake: taking his hard-earned savings and buying a 10-foot-tall weather balloon from a mail-order catalog.", start: 102.07, end: 112.45),
                    ReadAlongSentence(text: "After managing to inflate it, the balloon immediately floated away and popped on a tree down the street.", start: 113.09, end: 118.77),
                    ReadAlongSentence(text: "It is a perfect metaphor for what happens when you throw capital at flashy, useless assets instead of saving for the future.", start: 119.27, end: 125.87),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "To prevent your wealth from floating away, you must establish an absolute, non-negotiable baseline.", start: 126.53, end: 132.31),
                    ReadAlongSentence(text: "That baseline is the 10-year U.S. government bond.", start: 132.81, end: 136.85),
                    ReadAlongSentence(text: "If you lend your money to the U.S. government, they guarantee your interest rate and the return of your capital with essentially no risk.", start: 137.35, end: 145.39),
                    ReadAlongSentence(text: "If that risk-free rate is 6%, then any other individual or business asking for your money must expect to pay you significantly more than 6%.", start: 145.91, end: 153.89),
                    ReadAlongSentence(text: "If an investment cannot violently clear that risk-free hurdle, taking on the added risk is pointless; you are practically throwing money away.", start: 155.27, end: 163.27),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The AI Gold Rush and Dusty Garages", start: 163.91, end: 166.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Fast forward to today's market, and we are watching the exact same wealth-destruction play out, just with sleeker marketing.", start: 167.09, end: 173.57),
                    ReadAlongSentence(text: "Instead of mail-order weather balloons, retail investors are being lured by TikTok gurus hawking the latest dog-themed meme coins, or they are sinking capital into unproven AI startups that are nothing more than dusty garages with a flashy \".ai\" domain name.", start: 174.07, end: 188.78),
                    ReadAlongSentence(text: "The noise surrounding electric vehicles, remote-work infrastructure, and massive data center build-outs is deafening.", start: 189.32, end: 195.52),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But the math of the universe hasn't changed one bit.", start: 196.26, end: 199.2),
                    ReadAlongSentence(text: "When you look at an overhyped tech ETF or a highly-leveraged crypto protocol, you have to ruthlessly apply the baseline.", start: 199.64, end: 206.62),
                    ReadAlongSentence(text: "Does this asset definitively offer a return that crushes the risk-free rate of a government bond?", start: 206.92, end: 212.42),
                    ReadAlongSentence(text: "If you are paying 2% management fees to a hedge fund that underperforms a basic Treasury bill, you are being robbed in broad daylight.", start: 213.02, end: 220.54),
                    ReadAlongSentence(text: "The modern financial machine thrives on this complexity to hide the fact that they are feeding off your capital.", start: 221.12, end: 226.96),
                    ReadAlongSentence(text: "The only way to find the gold beneath the gloss is to reject the noise entirely and demand a massive premium for your risk.", start: 227.48, end: 233.94),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the realms of computer science and finance, we are trained to search for elegant algorithms and rational models to predict behavior.", start: 240.74, end: 247.8),
                    ReadAlongSentence(text: "We desperately want to believe the financial system is a perfectly calibrated machine.", start: 248.22, end: 253.0),
                    ReadAlongSentence(text: "It is a fatal miscalculation.", start: 253.48, end: 255.18),
                    ReadAlongSentence(text: "The average retail investor stares at a screen, watches a ticker flash green and red, and assumes those numbers represent the absolute, fundamental truth of a company's worth in real-time.", start: 255.56, end: 266.14),
                    ReadAlongSentence(text: "This is exactly why the herd gets slaughtered.", start: 266.48, end: 268.9),
                    ReadAlongSentence(text: "When inflation surges or volatility rips through the system, they scramble, treating the stock market like a hyper-efficient calculator.", start: 269.38, end: 276.9),
                    ReadAlongSentence(text: "They are chasing the manic highs and panicking during the chaotic lows, convinced the market knows something they don't.", start: 277.36, end: 283.36),
                    ReadAlongSentence(text: "It doesn't.", start: 283.86, end: 284.5),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Meet Your Manic Partner", start: 284.92, end: 286.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Joel Greenblatt shatters this illusion using a brilliant concept originally conceived by Benjamin Graham: imagine you are a partner in a business with a deeply unstable, wildly emotional guy named Mr.", start: 286.86, end: 298.82),
                    ReadAlongSentence(text: "Market.", start: 298.94, end: 300.12),
                    ReadAlongSentence(text: "Every single day, Mr.", start: 300.56, end: 302.14),
                    ReadAlongSentence(text: "Market knocks on your door and offers to acquire your half of the business, or part with his half, at a specific price.", start: 303.8, end: 310.26),
                    ReadAlongSentence(text: "Some days, he is absolutely euphoric, convinced the business is invincible, and he names an absurdly high price.", start: 310.8, end: 317.36),
                    ReadAlongSentence(text: "Other days, he is profoundly depressed, terrified of the future, and offers to part with his stake for pennies on the dollar.", start: 318.04, end: 324.46),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Greenblatt notes that in a single year, a massive company like General Motors might be valued at $30 billion one month, and $60 billion just a few months later.", start: 324.94, end: 333.9),
                    ReadAlongSentence(text: "Did the intrinsic value of GM’s factories, inventory, and global operations magically double in 90 days?", start: 334.42, end: 340.78),
                    ReadAlongSentence(text: "Absolutely not.", start: 341.12, end: 342.28),
                    ReadAlongSentence(text: "The business didn't change; Mr.", start: 342.8, end: 344.92),
                    ReadAlongSentence(text: "Market's mood changed.", start: 345.38, end: 346.6),
                    ReadAlongSentence(text: "Your entire edge comes from exploiting these depressive panics to acquire pieces of a business with a massive \"margin of safety\"—securing your stake at a steep discount to true value.", start: 347.02, end: 356.76),
                    ReadAlongSentence(text: "And while Mr.", start: 357.32, end: 358.2),
                    ReadAlongSentence(text: "Market is an emotional basket case in the short term, over the long haul, facts and reality take over.", start: 358.62, end: 364.78),
                    ReadAlongSentence(text: "Greenblatt promises that if you wait him out—usually within two to three years—Mr.", start: 365.56, end: 370.35),
                    ReadAlongSentence(text: "Market will eventually sober up and pay a fair price for that value.", start: 370.81, end: 374.53),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: Bidding on Dusty Garages in the Digital Age", start: 375.19, end: 378.99),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let's look at the absolute circus happening today.", start: 379.61, end: 382.37),
                    ReadAlongSentence(text: "The financial media and online forums are relentlessly hyping the inevitable future of EVTOL flying cars and speculative crypto protocols.", start: 382.93, end: 392.11),
                    ReadAlongSentence(text: "Mr.", start: 392.77, end: 393.13),
                    ReadAlongSentence(text: "Market hears this noise, gets swept up in the mania, and suddenly prices a fundamentally unprofitable electric vehicle startup—essentially a dusty garage with a sleek 3D rendering—as if it has already conquered the global auto industry.", start: 393.61, end: 408.09),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Conversely, when a minor supply chain glitch hits or trade war headlines spook the algorithmic trading bots, Mr.", start: 408.87, end: 415.27),
                    ReadAlongSentence(text: "Market panics.", start: 416.01, end: 416.83),
                    ReadAlongSentence(text: "He instantly slashes the valuations of cash-gushing, world-class clean energy infrastructure firms or established robotics leaders by 40%.", start: 417.23, end: 425.35),
                    ReadAlongSentence(text: "The speed of the modern digital market only amplifies this manic-depression.", start: 426.77, end: 430.97),
                    ReadAlongSentence(text: "Whether it's the 24/7 hype cycle of decentralized finance or the flood of capital into thematic remote-work ETFs, the herd is reacting strictly to mood swings, not to math.", start: 431.51, end: 442.91),
                    ReadAlongSentence(text: "The secret isn't outsmarting the technology; it’s recognizing that the manic-depressive pricing engine hasn't changed a bit.", start: 443.47, end: 449.93),
                    ReadAlongSentence(text: "You must wait patiently in the shadows for the inevitable panic, snatch up the gold beneath the gloss, and let time force the market back to reality.", start: 450.39, end: 458.63),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let me pull back the curtain on the greatest psychological trap in modern finance.", start: 500.15, end: 504.37),
                    ReadAlongSentence(text: "In today’s hyper-connected, digital world, the financial industry has successfully gamified the accumulation of wealth.", start: 504.89, end: 511.47),
                    ReadAlongSentence(text: "We swipe on glass screens, we tap glowing buttons, and we watch confetti explode when a trade executes.", start: 512.21, end: 517.75),
                    ReadAlongSentence(text: "This frictionless environment has created a fatal, widespread delusion.", start: 518.33, end: 522.11),
                    ReadAlongSentence(text: "People now treat stocks as nothing more than blinking ticker symbols or digital casino chips.", start: 522.71, end: 528.01),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "They bet on a ticker because a social media influencer promised it was the next revolutionary disruption, entirely disconnected from what that ticker actually represents in the physical world.", start: 528.79, end: 539.23),
                    ReadAlongSentence(text: "They stare at the jagged lines on a chart, completely blind to the fact that they are looking at real companies with factories, supply chains, employees, and cash registers.", start: 539.63, end: 549.31),
                    ReadAlongSentence(text: "This massive disconnect is why the herd is constantly slaughtered when the market shifts.", start: 550.11, end: 554.51),
                    ReadAlongSentence(text: "They panic when the line goes down and chase blindly when the line goes up because they have forgotten the foundational truth of the entire system: a stock is not a magical lottery ticket.", start: 555.33, end: 565.39),
                    ReadAlongSentence(text: "It is a legally binding ownership percentage in a living, breathing, cash-generating enterprise.", start: 565.95, end: 571.29),
                    ReadAlongSentence(text: "Until you rewire your brain to see the factory behind the flashing red and green numbers, you will always be a victim of the casino.", start: 571.71, end: 578.71),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Math of the Schoolyard Hustle", start: 579.57, end: 581.13),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Joel Greenblatt cuts through Wall Street’s intentional complexity by ignoring complicated financial jargon and telling a simple story about a sixth-grade hustler named Jason.", start: 581.69, end: 590.74),
                    ReadAlongSentence(text: "Jason runs a tight, highly profitable operation in his schoolyard.", start: 591.3, end: 595.16),
                    ReadAlongSentence(text: "He buys packs of gum for 25 cents.", start: 595.62, end: 597.98),
                    ReadAlongSentence(text: "With five sticks to a pack, Jason ruthlessly unloads individual sticks to his trapped classmates for 25 cents each.", start: 598.4, end: 605.8),
                    ReadAlongSentence(text: "He pulls in $1.25 per pack, leaving him with $1 of pure, unadulterated profit every time he empties a wrapper.", start: 606.44, end: 613.28),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Now, imagine Jason grows up and scales this operation into a wildly successful corporate chain called \"Jason’s Gum Shops\".", start: 614.06, end: 621.28),
                    ReadAlongSentence(text: "He eventually wants to raise capital for himself, so he decides to divide his business into 1 million equal shares.", start: 621.76, end: 628.3),
                    ReadAlongSentence(text: "He offers these shares to you for $12 apiece, valuing the entire business at $12 million.", start: 628.9, end: 634.54),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "How do you know if $12 is a brilliant bargain or a massive rip-off?", start: 635.22, end: 639.18),
                    ReadAlongSentence(text: "You ignore the stock price in isolation and look under the hood at the engine.", start: 639.62, end: 643.5),
                    ReadAlongSentence(text: "Jason’s chain generated $10 million in sales last year.", start: 644.08, end: 647.64),
                    ReadAlongSentence(text: "But sales aren't cash in your pocket.", start: 648.08, end: 649.86),
                    ReadAlongSentence(text: "After paying $6 million for the actual gum , spending another $2 million on rent, employee wages, and electricity , and handing over 40% in taxes to the government , Jason’s Gum Shops produced exactly $1.2 million in cold, hard net income.", start: 650.24, end: 664.68),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Because Jason divided the business into 1 million shares, each individual share is entitled to exactly $1.20 of that profit.", start: 665.3, end: 672.72),
                    ReadAlongSentence(text: "If you pay $12 for a share that earns $1.20, your return on that investment in the first year is exactly 10%.", start: 673.32, end: 679.52),
                    ReadAlongSentence(text: "Greenblatt calls this the \"Earnings Yield\".", start: 680.9, end: 683.38),
                    ReadAlongSentence(text: "It is the ultimate truth serum.", start: 684.04, end: 685.6),
                    ReadAlongSentence(text: "You then compare this 10% yield against the 6% return you could get risk-free from a 10-year U.S. government bond to decide if the risk is worth your capital.", start: 686.18, end: 696.32),
                    ReadAlongSentence(text: "You aren't guessing where a stock chart is headed; you are calculating exactly how much cash your specific slice of the business generates relative to the price tag.", start: 696.9, end: 705.74),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: Piercing the Silicon Mirage", start: 706.24, end: 709.42),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s drag this math out of the gum shop and into the modern arena.", start: 710.34, end: 713.76),
                    ReadAlongSentence(text: "Right now, the market is absolutely obsessed with the infrastructure of tomorrow.", start: 714.28, end: 718.4),
                    ReadAlongSentence(text: "We are witnessing massive waves of capital flowing into next-generation data centers, autonomous logistics networks, and clean energy conglomerates.", start: 718.86, end: 728.02),
                    ReadAlongSentence(text: "The financial media will scream that a cloud-computing firm trading at $300 a share is a \"must-own\" asset simply because the digital revolution is inevitable.", start: 728.72, end: 738.48),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But as a disciplined insider, you must brutally strip away the narrative and interrogate the engine.", start: 738.92, end: 744.26),
                    ReadAlongSentence(text: "Let’s say this highly-hyped data center company has divided itself into 100 million shares, and last year it generated $50 million in actual profit.", start: 744.66, end: 753.4),
                    ReadAlongSentence(text: "That means each share earned exactly $0.50.", start: 753.96, end: 756.14),
                    ReadAlongSentence(text: "If Mr.", start: 757.84, end: 758.6),
                    ReadAlongSentence(text: "Market is asking you to pay $300 for one of those shares, your Earnings Yield is a microscopic 0.16%.", start: 759.16, end: 765.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Think about the sheer insanity of that math.", start: 767.08, end: 769.4),
                    ReadAlongSentence(text: "You are taking on the massive, unpredictable risk of a highly competitive, capital-intensive technology sector to earn a fraction of a single percent in real cash generation.", start: 769.96, end: 780.48),
                    ReadAlongSentence(text: "Meanwhile, a boring, guaranteed government bond is paying out significantly more.", start: 780.97, end: 785.47),
                    ReadAlongSentence(text: "The crowd is so blinded by the story of remote work and cloud expansion that they are willingly stepping into a mathematical death trap.", start: 786.09, end: 793.27),
                    ReadAlongSentence(text: "Mastering Earnings Yield gives you financial X-ray vision.", start: 793.81, end: 797.19),
                    ReadAlongSentence(text: "It allows you to look at a hyped EV manufacturer, a new decentralized finance protocol, or a boring industrial supply company, and immediately calculate the actual cash reality underneath the gloss.", start: 797.87, end: 810.87),
                    ReadAlongSentence(text: "It forces you to ask: \"Am I acquiring a cash-generating engine, or am I just overpaying for a cool story?\"", start: 811.63, end: 817.63),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is how you wire this cash-focused discipline into your routine tomorrow:", start: 818.37, end: 823.45),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most retail investors fail because they step onto a battlefield where they are mathematically guaranteed to lose.", start: 880.65, end: 886.75),
                    ReadAlongSentence(text: "When two companies announce a corporate merger, the target's stock price instantly jumps to just below the final acquisition price.", start: 887.21, end: 894.09),
                    ReadAlongSentence(text: "The tiny gap left over is the \"arbitrage spread.\"", start: 894.87, end: 897.73),
                    ReadAlongSentence(text: "Amateurs and overconfident professionals alike crowd into this space, risking massive amounts of capital to capture a tiny, fleeting percentage.", start: 898.35, end: 906.09),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Chasing this spread today is the equivalent of picking up pennies in front of an algorithmic steamroller.", start: 906.63, end: 911.73),
                    ReadAlongSentence(text: "In a chaotic market environment defined by intense regulatory scrutiny and high-frequency trading, traditional risk arbitrage is a fool's errand.", start: 912.43, end: 920.83),
                    ReadAlongSentence(text: "You are competing against armies of specialized lawyers and heavily armed institutions.", start: 921.37, end: 926.21),
                    ReadAlongSentence(text: "If the deal goes through, your reward is a tiny sliver of profit.", start: 927.05, end: 930.75),
                    ReadAlongSentence(text: "But if the deal breaks due to a financing glitch, a regulatory block, or a macro-economic shock, the stock collapses and your capital is obliterated.", start: 931.39, end: 941.15),
                    ReadAlongSentence(text: "It is an asymmetrical trap.", start: 941.71, end: 943.31),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Sinkhole and the Sweetener", start: 943.67, end: 945.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author learned this lesson the hard way during the acquisition of Florida Cypress Gardens by Harcourt Brace Jovanovich.", start: 945.83, end: 951.81),
                    ReadAlongSentence(text: "It looked like a flawless, guaranteed deal.", start: 952.27, end: 954.51),
                    ReadAlongSentence(text: "The financing was secure, the shareholder votes were locked up, and the synergy was obvious.", start: 954.95, end: 960.07),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Then, the earth literally opened up.", start: 960.53, end: 962.87),
                    ReadAlongSentence(text: "A massive sinkhole swallowed the theme park's main pavilion just weeks before the closing date.", start: 963.39, end: 968.27),
                    ReadAlongSentence(text: "The deal was thrown into jeopardy, and the author found himself staring at a potential $6.42 loss just to capture an 80-cent profit.", start: 968.75, end: 976.35),
                    ReadAlongSentence(text: "The lesson was brutal and clear: \"Don't try this at home.\"", start: 976.95, end: 980.03),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The brilliant alternative is to completely ignore the merger spread and focus exclusively on \"Merger Securities.\"", start: 980.47, end: 987.43),
                    ReadAlongSentence(text: "Sometimes, to win a bidding war, an acquiring company exhausts its cash and common stock, forcing it to pay target shareholders with strange \"sweeteners\".", start: 988.03, end: 996.79),
                    ReadAlongSentence(text: "These can take the form of preferred stock, warrants, or complex contingent value rights (CVRs).", start: 997.37, end: 1002.91),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "When these bizarre securities are distributed, absolute chaos ensues.", start: 1003.55, end: 1007.63),
                    ReadAlongSentence(text: "The author paints a picture of an investor who owned an agriculture stock, suddenly receiving complex 9% bonds due in 2010.", start: 1008.19, end: 1015.49),
                    ReadAlongSentence(text: "They do not want them.", start: 1016.93, end: 1018.13),
                    ReadAlongSentence(text: "More importantly, the massive institutional funds cannot keep them.", start: 1018.89, end: 1022.79),
                    ReadAlongSentence(text: "Because a mutual fund manager is strictly mandated to own equities, their compliance department legally forbids them from retaining bizarre debt instruments or warrants.", start: 1023.27, end: 1031.94),
                    ReadAlongSentence(text: "Both the amateur and the professional have the exact same reaction: they blindly unload the new securities as fast as humanly possible, entirely ignoring their fundamental value.", start: 1032.5, end: 1042.98),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Algorithmic Blind Spot", start: 1043.52, end: 1045.16),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, this dynamic is exacerbated by the sheer velocity of automated passive investing.", start: 1045.7, end: 1051.16),
                    ReadAlongSentence(text: "Consider a massive, traditional infrastructure company getting acquired by a dominant force in the Data Center and Artificial Intelligence space.", start: 1051.56, end: 1060.14),
                    ReadAlongSentence(text: "To close the deal, the acquirer pays in cash, plus a complex \"warrant\" tied to the future completion of a new Clean Energy microgrid.", start: 1060.88, end: 1069.56),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "When the deal finalizes, the traditional infrastructure ETFs and conservative dividend funds receive millions of these Clean Energy warrants.", start: 1070.14, end: 1078.1),
                    ReadAlongSentence(text: "The tracking algorithms driving these ETFs are incapable of processing this anomaly.", start: 1078.64, end: 1083.48),
                    ReadAlongSentence(text: "The warrants do not fit the sector mandate, they lack historical volatility data, and they pay no current yield.", start: 1083.92, end: 1089.6),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The machine's only programmed response is to immediately purge the unrecognized asset from the portfolio.", start: 1090.12, end: 1095.9),
                    ReadAlongSentence(text: "This creates a spectacular, localized crash in the price of the warrants.", start: 1096.58, end: 1100.86),
                    ReadAlongSentence(text: "While the financial media hyperventilates over the size of the overall merger, you are waiting in the shadows.", start: 1101.36, end: 1107.74),
                    ReadAlongSentence(text: "You can scoop up these orphaned instruments for pennies on the dollar, capitalizing entirely on the fact that an algorithm was forced to throw them in the trash.", start: 1108.58, end: 1119.42),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Have you ever noticed how the smartest people in the room often make the most disastrous financial decisions?", start: 1183.58, end: 1189.08),
                    ReadAlongSentence(text: "The friction comes from a fundamental misunderstanding: we treat finance like it is physics.", start: 1189.54, end: 1194.5),
                    ReadAlongSentence(text: "We believe it operates on immutable laws, formulas, and perfectly rational answers.", start: 1195.1, end: 1200.26),
                    ReadAlongSentence(text: "We assume that if we just build a complex enough system—perhaps engineering intricate data architecture to process market trends and chart the future—we can perfectly conquer the market.", start: 1200.92, end: 1211.2),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But human beings aren't code.", start: 1211.62, end: 1213.36),
                    ReadAlongSentence(text: "We fail because we optimize for a spreadsheet instead of optimizing for a peaceful night's sleep.", start: 1213.84, end: 1219.24),
                    ReadAlongSentence(text: "When you design a flawless financial plan on a quiet Sunday afternoon, you are acting rationally.", start: 1219.76, end: 1225.22),
                    ReadAlongSentence(text: "When the market drops 15% on a Tuesday morning and your heart starts pounding, rationality evaporates.", start: 1225.94, end: 1232.08),
                    ReadAlongSentence(text: "The perfectly calculated plan shatters against the reality of human emotion.", start: 1232.64, end: 1236.64),
                    ReadAlongSentence(text: "The secret the industry tries to hide is that trying to be completely, coldly rational is actually a trap.", start: 1237.04, end: 1243.22),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Fever of the Era", start: 1243.68, end: 1245.08),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author tells a compelling story about how our personal history dictates our financial reality.", start: 1245.7, end: 1251.05),
                    ReadAlongSentence(text: "Imagine two different people.", start: 1251.83, end: 1253.29),
                    ReadAlongSentence(text: "One was born in 1950 and watched the stock market go essentially nowhere during their formative years in the 1970s.", start: 1254.01, end: 1260.77),
                    ReadAlongSentence(text: "The other was born in 1970 and came of age during the unstoppable roaring bull market of the 1990s.", start: 1261.23, end: 1267.41),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "If you ask both of them about risk, you will get two entirely opposite answers.", start: 1267.93, end: 1272.61),
                    ReadAlongSentence(text: "And the fascinating part?", start: 1273.03, end: 1274.29),
                    ReadAlongSentence(text: "No one is crazy.", start: 1274.73, end: 1275.93),
                    ReadAlongSentence(text: "The author points out that every financial decision makes perfect sense to the person making it at that exact moment, heavily filtered through the tiny sliver of economic history they personally experienced.", start: 1276.37, end: 1286.77),
                    ReadAlongSentence(text: "We are all viewing money through a highly distorted, individualized lens.", start: 1287.43, end: 1291.41),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Because our lenses are so biased, the author argues that aiming for strict rationality is a vulnerability.", start: 1292.15, end: 1298.43),
                    ReadAlongSentence(text: "A purely rational investor might look at historical data and decide to leverage themselves to the absolute limit because the expected return is mathematically positive.", start: 1299.09, end: 1308.05),
                    ReadAlongSentence(text: "But a reasonable investor knows that if a sudden dip causes a margin call, or simply triggers enough anxiety to force a panic exit, the math is entirely useless.", start: 1308.73, end: 1318.27),
                    ReadAlongSentence(text: "You must aim for a strategy that is reasonable enough to let you stay in the game long-term, even if it isn't flawlessly rational on paper.", start: 1318.97, end: 1326.79),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Trading the Algorithm for the Human", start: 1327.19, end: 1329.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s drag this into the reality of right now.", start: 1329.43, end: 1331.71),
                    ReadAlongSentence(text: "We are living in an era of overwhelming technological acceleration.", start: 1332.49, end: 1336.51),
                    ReadAlongSentence(text: "AI infrastructure is booming, data centers are eating massive amounts of capital, and markets swing wildly based on geopolitical murmurs or the sudden movement of a single crypto whale.", start: 1337.23, end: 1347.97),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, you hold an unprecedented amount of analytical power right in your pocket.", start: 1348.57, end: 1353.05),
                    ReadAlongSentence(text: "You can deploy an autonomous Deep Research Agent to parse a decade of dense 10-K filings in minutes, and it might tell you exactly what you need to know about a company.", start: 1353.49, end: 1363.09),
                    ReadAlongSentence(text: "The AI feels no fear.", start: 1363.63, end: 1365.33),
                    ReadAlongSentence(text: "It doesn't sweat.", start: 1365.81, end: 1366.75),
                    ReadAlongSentence(text: "It only sees pure expected value and cold, hard rationality.", start: 1367.29, end: 1371.55),
                    ReadAlongSentence(text: "But you are the one who has to stare at the screen when a sudden supply chain shock causes those exact companies to plummet 20% in a week.", start: 1372.09, end: 1380.0),
                    ReadAlongSentence(text: "When you look at your phone and see those red numbers flashing across your live widget, the psychological pain immediately overrides the AI's logical blueprint.", start: 1380.48, end: 1389.36),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In today's world of frictionless, hyper-fast mobile finance, the ultimate edge isn't just having the most sophisticated data or the fastest alert system.", start: 1389.84, end: 1398.44),
                    ReadAlongSentence(text: "It is building a strategy that actively accommodates your own human flaws.", start: 1398.88, end: 1402.92),
                    ReadAlongSentence(text: "If maintaining a theoretically \"perfect\" portfolio keeps you staring at the ceiling at 2 AM, it is a catastrophic strategy for you.", start: 1403.36, end: 1410.84),
                    ReadAlongSentence(text: "Wealth isn't built by the person with the smartest data; it is built by the person who creates a framework reasonable enough to survive their own worst impulses.", start: 1411.46, end: 1420.06),
                ]),
            ],
        ],
        10: [
            1: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the uncomfortable truth most retail investors never figure out: the market is a giant, ruthlessly efficient weighing machine of everyone else's opinions.", start: 8.22, end: 17.32),
                    ReadAlongSentence(text: "You log on, read the morning headlines, and see a universally praised trend.", start: 17.82, end: 22.46),
                    ReadAlongSentence(text: "It feels safe to agree.", start: 22.48, end: 23.98),
                    ReadAlongSentence(text: "It feels logical.", start: 24.68, end: 26.1),
                    ReadAlongSentence(text: "But here is the friction: if everyone already knows a piece of information, it is already baked into the price.", start: 26.78, end: 33.0),
                    ReadAlongSentence(text: "You cannot gain an edge by knowing what everyone else knows and thinking how everyone else thinks.", start: 33.74, end: 38.14),
                    ReadAlongSentence(text: "When you agree with the consensus, you are guaranteeing yourself average returns.", start: 38.64, end: 42.34),
                    ReadAlongSentence(text: "And in the financial world, average returns—after taxes, fees, and inflation—equate to a slow, silent bleed of your wealth.", start: 42.84, end: 51.12),
                    ReadAlongSentence(text: "To actually win, you have to be willing to be profoundly uncomfortable.", start: 51.76, end: 55.94),
                    ReadAlongSentence(text: "You have to stand outside the crowded room.", start: 56.56, end: 58.73),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Second-Level Thinker", start: 59.35, end: 60.51),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In The Most Important Thing, Howard Marks illustrates this with a simple, devastating concept that separates the amateurs from the masters.", start: 61.33, end: 68.73),
                    ReadAlongSentence(text: "He calls it \"Second-Level Thinking.\"", start: 69.41, end: 71.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine a widely celebrated tech company that just announced record profits.", start: 72.53, end: 76.65),
                    ReadAlongSentence(text: "The first-level thinker looks at the news and says, \"This is a great company with massive growth; let's allocate capital.\"", start: 77.23, end: 83.45),
                    ReadAlongSentence(text: "It is simple, reactive, and entirely wrong.", start: 84.05, end: 86.77),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Marks asks us to look deeper.", start: 87.55, end: 89.33),
                    ReadAlongSentence(text: "The second-level thinker looks at the exact same company and says, \"It is a good company, but everyone thinks it is a great company, and it is priced as if it is a perfect company.", start: 89.93, end: 98.91),
                    ReadAlongSentence(text: "Therefore, it is overpriced and mathematically dangerous.\"", start: 99.63, end: 102.91),
                    ReadAlongSentence(text: "The story here isn't about finding a good business; it's about understanding the gap between perception and reality.", start: 103.77, end: 109.75),
                    ReadAlongSentence(text: "First-level thinking relies on intuition; second-level thinking relies on complex, divergent logic.", start: 110.73, end: 117.33),
                    ReadAlongSentence(text: "You have to constantly ask: Who doesn't know this yet?", start: 117.91, end: 121.07),
                    ReadAlongSentence(text: "And what is the crowd getting wrong?", start: 121.75, end: 123.45),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The AI Echo Chamber", start: 124.15, end: 125.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s drag this into today's reality.", start: 126.23, end: 128.07),
                    ReadAlongSentence(text: "Open any financial feed, and you will see alerts like \"Tech Stocks Rally on Strong AI Earnings\" screaming at you.", start: 129.11, end: 135.53),
                    ReadAlongSentence(text: "First-level thinking looks at the massive cloud infrastructure providers or the leading GPU designers and assumes they are the only path to the future.", start: 136.33, end: 144.17),
                    ReadAlongSentence(text: "The crowd is entirely obsessed with the obvious giants.", start: 144.87, end: 147.91),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But a second-level thinker realizes those obvious trades are already saturated by the masses.", start: 148.49, end: 154.21),
                    ReadAlongSentence(text: "Instead of fighting for scraps at the top, they go deeper into the data.", start: 155.03, end: 158.39),
                    ReadAlongSentence(text: "They might run a sophisticated cluster analysis algorithm across thousands of equities, deliberately searching for the hidden, undervalued companies that actually power the revolution—the obscure utility companies providing the massive energy required for those data centers, or the specialized manufacturers building server cooling systems.", start: 159.35, end: 177.96),
                    ReadAlongSentence(text: "The crowd is staring directly at the shiny software; the second-level thinker is quietly mining the numbers to accumulate the unglamorous infrastructure the software desperately depends on.", start: 178.84, end: 189.06),
                    ReadAlongSentence(text: "The edge isn't in predicting the obvious wave; the edge is finding the neglected assets the wave will eventually lift.", start: 189.68, end: 198.56),
                ]),
            ],
            2: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most people walk into the financial markets believing a very dangerous academic lie: that the market is a perfectly calibrated machine.", start: 235.52, end: 243.06),
                    ReadAlongSentence(text: "They assume that because millions of supercomputers, analysts, and institutional algorithms are constantly crunching data, the price you see on the screen is exactly what an asset is worth at that exact second.", start: 243.6, end: 254.76),
                    ReadAlongSentence(text: "This creates a paralyzing friction.", start: 255.72, end: 257.62),
                    ReadAlongSentence(text: "If the market is perfectly efficient, why bother analyzing anything at all?", start: 258.78, end: 262.72),
                    ReadAlongSentence(text: "You might as well just index your money and walk away.", start: 263.42, end: 265.72),
                    ReadAlongSentence(text: "Or worse, when a stock is plunging, retail investors assume the \"smart money\" must know some catastrophic secret, so they panic and follow the crowd out the door.", start: 266.5, end: 275.34),
                    ReadAlongSentence(text: "They fail because they outsource their conviction to the current price tag, completely forgetting that the price tag is ultimately set by deeply flawed, highly emotional human beings.", start: 276.24, end: 285.6),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Hundred-Dollar Bill on the Sidewalk", start: 286.24, end: 288.1),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In The Most Important Thing, Howard Marks destroys this myth of perfect efficiency with a classic industry joke.", start: 288.78, end: 295.23),
                    ReadAlongSentence(text: "A strict academic finance professor and his student are walking down the street.", start: 295.91, end: 300.27),
                    ReadAlongSentence(text: "The student looks down, points, and says, \"Look, a hundred-dollar bill on the sidewalk!\"", start: 300.91, end: 306.03),
                    ReadAlongSentence(text: "The professor doesn't even break his stride to look.", start: 307.05, end: 309.23),
                    ReadAlongSentence(text: "\"Don't bother,\" he replies.", start: 309.79, end: 311.07),
                    ReadAlongSentence(text: "\"If it were a real hundred-dollar bill, someone else would have already picked it up.\"", start: 311.99, end: 315.67),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The professor is blinded by his own rigid theory.", start: 316.33, end: 319.09),
                    ReadAlongSentence(text: "Marks uses this to illustrate a profound truth: the market is usually efficient, but it is not always efficient.", start: 319.91, end: 326.51),
                    ReadAlongSentence(text: "Because it is driven by human fear and human greed, the pendulum of sentiment swings much too far in both directions.", start: 327.09, end: 333.81),
                    ReadAlongSentence(text: "In moments of panic, investors indiscriminately dump brilliant businesses at bargain prices.", start: 334.55, end: 339.67),
                    ReadAlongSentence(text: "In moments of euphoric mania, they pay absurd premiums for absolute garbage.", start: 340.45, end: 344.75),
                    ReadAlongSentence(text: "Your entire job as a strategist is to wander the sidewalks during these rare moments of emotional extremism and calmly pick up the hundred-dollar bills that everyone else is too terrified or too distracted to claim.", start: 345.47, end: 356.01),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Index Fund Avalanche", start: 356.67, end: 358.23),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s apply this to the madness of the modern tape.", start: 358.73, end: 361.25),
                    ReadAlongSentence(text: "Today, massive market failures are happening in plain sight, entirely manufactured by the rise of passive ETFs and algorithmic trading.", start: 361.69, end: 369.67),
                    ReadAlongSentence(text: "When a trillion dollars blindly flows into an S&P 500 index fund, that capital is forced to automatically allocate into the largest tech companies, regardless of their actual underlying valuation or fundamental reality.", start: 370.53, end: 383.37),
                    ReadAlongSentence(text: "This creates a self-fulfilling momentum bubble at the very top.", start: 384.29, end: 387.85),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But here is the secret: this passive avalanche leaves the rest of the market completely starved of capital and attention.", start: 388.43, end: 395.99),
                    ReadAlongSentence(text: "Boring, highly profitable mid-cap companies—perhaps a regional logistics firm or a niche industrial supplier—are completely ignored simply because they aren't part of the passive mega-trend.", start: 396.71, end: 407.29),
                    ReadAlongSentence(text: "Add in the wild, narrative-driven swings of Crypto, where billions in market cap are shifted by a single late-night tweet, and you have a landscape absolutely ripe with inefficiency.", start: 408.01, end: 418.48),
                    ReadAlongSentence(text: "The market routinely fails to price neglected assets correctly.", start: 419.4, end: 422.98),
                    ReadAlongSentence(text: "That failure is your precise entry point.", start: 424.04, end: 429.02),
                ]),
            ],
            3: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most people conflate a great company with a great investment.", start: 477.8, end: 480.86),
                    ReadAlongSentence(text: "It is the most expensive mistake in finance.", start: 481.68, end: 483.9),
                    ReadAlongSentence(text: "You see a business with a brilliant CEO, flawless products, and massive revenue growth, and your brain instantly short-circuits to, \"I need to own a piece of this.\"", start: 484.28, end: 494.08),
                    ReadAlongSentence(text: "But you are forgetting the invisible, unforgiving second variable.", start: 494.96, end: 498.3),
                    ReadAlongSentence(text: "A world-class company can be a toxic, wealth-destroying asset if the price tag is wrong.", start: 499.06, end: 504.06),
                    ReadAlongSentence(text: "This friction happens because we are biologically wired to seek out quality and safety, but we are rarely trained to calculate the mathematical relationship between cost and intrinsic worth.", start: 504.76, end: 515.16),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Nifty Fifty Mirage", start: 515.76, end: 517.34),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In The Most Important Thing, Howard Marks illustrates this trap by pointing back to the \"Nifty Fifty\" era of the late 1960s.", start: 518.34, end: 525.42),
                    ReadAlongSentence(text: "The author tells the story of a time when institutional investors became blindly obsessed with fifty dominant, seemingly invincible corporations—companies like IBM, Xerox, and Kodak.", start: 526.3, end: 537.41),
                    ReadAlongSentence(text: "The consensus was that these businesses were so exceptionally good, the price you paid for them simply didn't matter.", start: 538.15, end: 544.51),
                    ReadAlongSentence(text: "They were \"one-decision\" assets: you acquire them and never let go.", start: 545.17, end: 548.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But Marks points out the catastrophic flaw in that logic.", start: 549.37, end: 552.35),
                    ReadAlongSentence(text: "Because everyone universally agreed they were flawless, their prices were bid up to astronomical, euphoric multiples.", start: 552.95, end: 559.75),
                    ReadAlongSentence(text: "When the reality of the 1970s market crash hit, those investors were decimated.", start: 560.37, end: 564.89),
                    ReadAlongSentence(text: "The companies themselves mostly survived, and many continued to grow their underlying revenues, but the investors still lost fortunes.", start: 565.37, end: 572.85),
                    ReadAlongSentence(text: "Why?", start: 573.33, end: 573.63),
                    ReadAlongSentence(text: "Because, as Marks coldly reminds us, there is no such thing as a good asset regardless of price.", start: 574.09, end: 580.05),
                    ReadAlongSentence(text: "Value is what the business generates in cash; price is what you surrender to get it.", start: 580.77, end: 585.77),
                    ReadAlongSentence(text: "When price aggressively disconnects from value, the risk of permanent loss becomes absolute.", start: 586.49, end: 592.07),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Price of the AI Future", start: 592.45, end: 594.31),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Look out the window at today's landscape.", start: 595.11, end: 596.87),
                    ReadAlongSentence(text: "We are living through an exact replica of this divergence with Artificial Intelligence and the massive build-out of data centers.", start: 597.39, end: 604.35),
                    ReadAlongSentence(text: "You don't need a PhD to know that AI is fundamentally rewiring the global economy.", start: 604.93, end: 609.31),
                    ReadAlongSentence(text: "The narrative is undeniable.", start: 609.99, end: 611.49),
                    ReadAlongSentence(text: "But when an AI infrastructure stock is trading at eighty times its forward revenue, the market is pricing in a future that requires absolute, uninterrupted perfection for the next two decades.", start: 612.23, end: 622.31),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Even if that company radically succeeds and dominates the cloud sector, your personal return on investment might be zero or deeply negative because you already paid for all of that future success upfront.", start: 623.09, end: 634.37),
                    ReadAlongSentence(text: "The modern trap is finding a genuinely disruptive, world-changing technology, but paying a price that mathematically guarantees a loss.", start: 635.17, end: 645.72),
                ]),
            ],
            4: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The financial industry has brainwashed you with a mathematical lie.", start: 694.38, end: 698.06),
                    ReadAlongSentence(text: "They desperately want you to believe that \"risk\" simply means a bouncy chart.", start: 698.76, end: 703.9),
                    ReadAlongSentence(text: "If an asset's price swings wildly from day to day, they label it dangerous.", start: 704.56, end: 708.84),
                    ReadAlongSentence(text: "If it moves in a slow, predictable, almost flat line, they label it safe.", start: 709.44, end: 713.9),
                    ReadAlongSentence(text: "This is exactly why most retail investors fail: they are completely terrified of turbulence.", start: 714.56, end: 720.02),
                    ReadAlongSentence(text: "When they hit an air pocket and their portfolio drops 20% in a week, they vomit up their positions in sheer panic.", start: 720.64, end: 727.36),
                    ReadAlongSentence(text: "They believe they are strictly managing risk, but they are actually just converting temporary paper turbulence into a permanent, unrecoverable destruction of their own wealth.", start: 728.04, end: 736.98),
                    ReadAlongSentence(text: "They survive the bumpy flight by jumping out of the plane.", start: 737.94, end: 740.52),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Mirage of the Sharpe Ratio", start: 741.06, end: 742.64),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In The Most Important Thing, Howard Marks completely dismantles this academic definition of risk.", start: 743.34, end: 749.41),
                    ReadAlongSentence(text: "The author tells the story of how finance professors and Wall Street institutions fell deeply in love with \"volatility\" as a metric simply because it can be easily measured and plugged into an elegant spreadsheet.", start: 750.07, end: 761.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But Marks argues that true risk cannot be quantified by past price wiggles.", start: 762.23, end: 766.49),
                    ReadAlongSentence(text: "Risk, in the real world, is one thing and one thing only: the probability of a permanent loss of capital.", start: 767.07, end: 773.15),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine driving over two bridges.", start: 774.07, end: 775.93),
                    ReadAlongSentence(text: "Bridge A is a shaky, wooden suspension bridge that sways violently in the wind, but its engineering is fundamentally sound and it will definitely get you across the gorge.", start: 776.53, end: 785.65),
                    ReadAlongSentence(text: "Bridge B is a remarkably smooth, freshly paved concrete highway that abruptly ends in a sheer drop off a cliff.", start: 786.35, end: 792.55),
                    ReadAlongSentence(text: "Academic finance tells you the wooden bridge is \"risky\" because it moves.", start: 793.17, end: 797.53),
                    ReadAlongSentence(text: "Marks tells you the smooth highway is the ultimate danger because it leads to a permanent zero.", start: 798.21, end: 802.89),
                    ReadAlongSentence(text: "Volatility is simply the emotional toll you pay to cross the bridge; permanent loss is failing to reach the other side.", start: 803.73, end: 809.95),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Surviving the Crypto Winter", start: 810.61, end: 812.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Look at the brutal reality of the modern cryptocurrency markets, specifically foundational assets like Bitcoin.", start: 812.71, end: 818.55),
                    ReadAlongSentence(text: "If you measure risk purely by volatility, it appears to be one of the most terrifying assets in human history, routinely suffering 60% to 80% drawdowns.", start: 819.25, end: 829.39),
                    ReadAlongSentence(text: "The first-level thinker screams that it is too dangerous to touch.", start: 830.05, end: 833.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But what about the traditional investor who acquired \"safe\" long-term government bonds in 2020?", start: 834.33, end: 839.03),
                    ReadAlongSentence(text: "Those bonds barely bounced around day-to-day, but thanks to explosive inflation and rapidly rising interest rates, they inflicted a slow, silent, and permanent destruction of purchasing power.", start: 840.41, end: 851.91),
                    ReadAlongSentence(text: "The bondholders experienced almost zero volatility, yet suffered a catastrophic loss of real wealth.", start: 852.56, end: 858.74),
                    ReadAlongSentence(text: "Today, the greatest danger isn't acquiring something that bounces violently; it's acquiring a structurally flawed asset—like a dying legacy tech company or an overpriced bond—that goes down slowly and simply never comes back.", start: 859.72, end: 873.76),
                ]),
            ],
            5: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is the silent trap most investors fall into: they treat risk like a binding contract.", start: 910.08, end: 915.1),
                    ReadAlongSentence(text: "They look at a highly speculative asset and tell themselves, \"If I am just brave enough to stomach the danger, the market mathematically owes me a massive payout.\"", start: 915.66, end: 924.98),
                    ReadAlongSentence(text: "They view risk as a tollbooth—you pay with your peace of mind, and in exchange, you get handed a higher return.", start: 925.9, end: 932.64),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But the market does not reward bravery, and it certainly does not owe you a premium just because you took a reckless gamble.", start: 933.38, end: 939.58),
                    ReadAlongSentence(text: "If exposing your capital to a high probability of destruction actually guaranteed a higher return, it wouldn't be risky in the first place—it would just be a high-yield savings account.", start: 940.16, end: 949.76),
                    ReadAlongSentence(text: "The friction here is that people conflate expected return with guaranteed outcome.", start: 950.46, end: 954.7),
                    ReadAlongSentence(text: "They engineer their portfolios assuming the best-case scenario is a certainty, completely forgetting that risk isn't a volume knob you turn up to get richer.", start: 955.34, end: 963.28),
                    ReadAlongSentence(text: "It is the very real, mathematical probability that your capital gets permanently wiped out.", start: 964.04, end: 969.19),
                    ReadAlongSentence(text: "You do not get paid for taking risk.", start: 969.79, end: 972.05),
                    ReadAlongSentence(text: "You only get paid if the risk happens to spare you.", start: 972.61, end: 975.01),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Widening Bell Curve", start: 975.81, end: 976.99),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Howard Marks aggressively corrects this fatal misunderstanding.", start: 977.71, end: 981.37),
                    ReadAlongSentence(text: "He tells us to throw away the straight line and visualize risk as a bell curve of possible outcomes.", start: 982.19, end: 987.45),
                    ReadAlongSentence(text: "As you take on more risk, the expected return might move slightly higher, but the bell curve dramatically flattens and widens.", start: 988.07, end: 994.71),
                    ReadAlongSentence(text: "Most importantly, the left tail of that curve stretches deep into the territory of permanent, catastrophic loss.", start: 995.23, end: 1001.97),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author stresses that superior investors do not succeed by possessing a magical crystal ball that predicts the future.", start: 1002.89, end: 1010.07),
                    ReadAlongSentence(text: "They succeed through absolute \"risk control.\"", start: 1010.85, end: 1013.37),
                    ReadAlongSentence(text: "They actively construct portfolios that can survive scenarios they didn't see coming.", start: 1014.17, end: 1018.29),
                    ReadAlongSentence(text: "Marks leverages the concept of alternative histories—the invisible timelines of what could have happened.", start: 1018.91, end: 1024.69),
                    ReadAlongSentence(text: "Just because you drove a car blindfolded and didn't crash doesn't mean it was a brilliant strategy; it means you got lucky in this specific timeline.", start: 1025.09, end: 1032.95),
                    ReadAlongSentence(text: "The master investor demands a massive \"risk premium\" upfront—acquiring an asset at a heavily discounted price—to insure against the inevitable moments when the worst possible alternative history suddenly becomes reality.", start: 1033.53, end: 1045.39),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Geopolitical Blind Spot", start: 1046.19, end: 1048.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Look at the current euphoria surrounding the Artificial Intelligence super-cycle.", start: 1048.73, end: 1052.33),
                    ReadAlongSentence(text: "Retail capital is flooding into a handful of GPU manufacturers and cloud providers, pricing them for absolute perfection.", start: 1053.19, end: 1059.41),
                    ReadAlongSentence(text: "The crowd assumes the only risk is temporary turbulence.", start: 1060.15, end: 1063.23),
                    ReadAlongSentence(text: "But they are entirely blind to the catastrophic left tail of the curve.", start: 1063.59, end: 1067.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "What happens if a sudden geopolitical trade war blockades the specific semiconductor foundries that manufacture 90% of these advanced chips?", start: 1067.77, end: 1076.61),
                    ReadAlongSentence(text: "What if a global regulatory framework instantly criminalizes the massive data scraping techniques required to train these language models?", start: 1077.31, end: 1084.81),
                    ReadAlongSentence(text: "If your portfolio only survives if the perfect, uninterrupted AI future plays out, you haven't controlled your risk; you have simply closed your eyes.", start: 1085.6, end: 1094.64),
                    ReadAlongSentence(text: "Insuring against the unknown means recognizing that black swans are entirely unpredictable by definition.", start: 1095.42, end: 1101.42),
                    ReadAlongSentence(text: "You must structure your capital allocation so that a geopolitical shock or a sudden regulatory hammer in the tech sector doesn't permanently wipe you out.", start: 1102.08, end: 1110.92),
                    ReadAlongSentence(text: "You don't build a storm bunker because you know exactly when the tornado is coming; you build it because you acknowledge you cannot control the weather.", start: 1111.66, end: 1122.28),
                ]),
            ],
            6: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Humans are desperately uncomfortable with uncertainty, which is why the financial industry makes billions selling the illusion of foresight.", start: 1148.76, end: 1155.66),
                    ReadAlongSentence(text: "You turn on the television, and a very confident analyst in a tailored suit tells you exactly where the S&P 500 will be in six months, or precisely what month the Federal Reserve will pivot.", start: 1156.42, end: 1168.24),
                    ReadAlongSentence(text: "The friction here is that macroeconomic forecasting is essentially a coin toss dressed up as science.", start: 1169.0, end: 1174.82),
                    ReadAlongSentence(text: "Amateurs fail because they build their entire financial architecture on a rigid prediction of a future they cannot possibly know.", start: 1175.62, end: 1182.08),
                    ReadAlongSentence(text: "When their prediction inevitably misses the mark, their portfolio shatters.", start: 1182.74, end: 1186.9),
                    ReadAlongSentence(text: "They waste all their analytical energy trying to guess what will happen next, instead of doing the much harder work of figuring out what is happening right now.", start: 1187.5, end: 1195.1),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Temperature of the Room", start: 1195.82, end: 1197.56),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In The Most Important Thing, Howard Marks aggressively dismisses the value of macro-forecasting.", start: 1198.32, end: 1203.92),
                    ReadAlongSentence(text: "He offers a liberating, ruthlessly pragmatic alternative: we never know where we are going, but we ought to know exactly where we are.", start: 1204.46, end: 1212.51),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine you are deciding how to dress for the day.", start: 1213.51, end: 1215.99),
                    ReadAlongSentence(text: "You don't need a meteorologist to swear on their life that it will rain at exactly 2:15 PM next Tuesday.", start: 1216.49, end: 1221.95),
                    ReadAlongSentence(text: "You just need the situational awareness to look out the window and check the thermometer today.", start: 1222.53, end: 1227.07),
                    ReadAlongSentence(text: "If the sky is bruised and the air is heavy, you carry an umbrella.", start: 1227.75, end: 1231.37),
                    ReadAlongSentence(text: "Marks uses the metaphor of the pendulum—a cycle that swings inevitably from extreme optimism and underpriced risk, to extreme pessimism and overpriced risk.", start: 1231.81, end: 1241.61),
                    ReadAlongSentence(text: "You do not need to predict the exact day the pendulum will reverse course; you simply need to measure how far it has swung.", start: 1242.33, end: 1248.55),
                    ReadAlongSentence(text: "When credit is cheap, deals are absurdly leveraged, and your neighbor is suddenly an expert on initial public offerings, the pendulum has swung to dangerous euphoria.", start: 1249.07, end: 1257.91),
                    ReadAlongSentence(text: "You don't predict the crash; you simply acknowledge the temperature of the room and adjust your exposure because the environment is mathematically hostile.", start: 1258.49, end: 1266.27),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Zero-Interest Hangover", start: 1266.85, end: 1268.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Let’s map this reality onto the modern tape.", start: 1269.39, end: 1271.99),
                    ReadAlongSentence(text: "For over a decade, we surfed a bizarre, artificial tide of zero-percent interest rates.", start: 1272.37, end: 1277.67),
                    ReadAlongSentence(text: "Money was practically free.", start: 1278.21, end: 1279.99),
                    ReadAlongSentence(text: "That specific macro tide lifted absolutely everything—from profitless tech startups to speculative NFTs.", start: 1280.65, end: 1288.57),
                    ReadAlongSentence(text: "A whole generation of investors mistook a rising macro tide for their own financial genius.", start: 1289.31, end: 1294.27),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But then the pendulum violently swung.", start: 1295.01, end: 1296.87),
                    ReadAlongSentence(text: "Central banks cranked rates at a historic pace to fight inflation, and the tide rapidly went out.", start: 1297.51, end: 1302.73),
                    ReadAlongSentence(text: "The companies that relied entirely on cheap debt to survive were suddenly swimming naked.", start: 1303.41, end: 1308.15),
                    ReadAlongSentence(text: "Today, we are surfing a new tide defined by the massive, capital-intensive infrastructure build-out for Artificial Intelligence and a shifting geopolitical supply chain.", start: 1308.81, end: 1319.55),
                    ReadAlongSentence(text: "The first-level thinker is still sitting around trying to predict if the Fed will adjust rates by 25 basis points next quarter.", start: 1320.13, end: 1326.11),
                    ReadAlongSentence(text: "The master strategist isn't guessing; they are simply observing that the cost of capital has fundamentally changed.", start: 1326.93, end: 1333.0),
                    ReadAlongSentence(text: "They are quietly rotating away from legacy businesses dependent on cheap debt, favoring companies with fortified balance sheets that can self-fund their own data center expansions.", start: 1333.52, end: 1347.66),
                ]),
            ],
            7: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Gravity of the Crowd", start: 1393.24, end: 1394.72),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The greatest threat to your financial survival is not the Federal Reserve, a market crash, or a geopolitical crisis.", start: 1395.56, end: 1402.66),
                    ReadAlongSentence(text: "It is your own biology.", start: 1403.56, end: 1404.82),
                    ReadAlongSentence(text: "We are herd animals, hardwired over millennia to find safety in numbers.", start: 1405.54, end: 1409.96),
                    ReadAlongSentence(text: "If you saw the rest of your tribe running in terror, your instincts demanded you run too, without stopping to ask why.", start: 1410.92, end: 1417.36),
                    ReadAlongSentence(text: "That instinct kept your ancestors alive, but in the modern financial markets, it is a wealth-destroying disease.", start: 1417.98, end: 1424.44),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The friction here is that the math of wealth creation requires you to act completely unnaturally.", start: 1425.18, end: 1430.52),
                    ReadAlongSentence(text: "When the market plunges into a sea of red, the financial pain registers in your brain exactly like physical pain.", start: 1431.32, end: 1436.84),
                    ReadAlongSentence(text: "Your amygdala—the fear center of your brain—hijacks your logic and screams for you to escape.", start: 1437.4, end: 1443.14),
                    ReadAlongSentence(text: "Conversely, when everyone around you is getting rich on a speculative bubble, the fear of missing out acts as an irresistible gravitational pull.", start: 1443.78, end: 1451.77),
                    ReadAlongSentence(text: "Most investors fail not because they lack intelligence or data, but because they lack the emotional shock absorbers required to withstand the gravity of a panicking crowd.", start: 1452.59, end: 1462.15),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Pendulum of Expectations", start: 1462.71, end: 1464.55),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, understood that investing is ultimately an exercise in psychological endurance.", start: 1465.03, end: 1471.45),
                    ReadAlongSentence(text: "To combat this emotional gravity, he introduced the metaphor of the \"Emotional Pendulum.\"", start: 1471.99, end: 1477.15),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Bogle teaches us to look at the history of the stock market as a tale of two different realities.", start: 1478.13, end: 1483.05),
                    ReadAlongSentence(text: "The first reality is the business itself—the \"Real Market.\"", start: 1483.57, end: 1487.01),
                    ReadAlongSentence(text: "This is the actual dividend yield and earnings growth of the corporations you own.", start: 1487.73, end: 1491.89),
                    ReadAlongSentence(text: "This reality is remarkably stable; it slowly and steadily marches upward over the decades.", start: 1492.59, end: 1498.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The second reality is the \"Expectations Market.\"", start: 1498.93, end: 1502.05),
                    ReadAlongSentence(text: "This is the speculative return, driven entirely by what people are willing to pay for those earnings.", start: 1503.01, end: 1508.09),
                    ReadAlongSentence(text: "This is the pendulum.", start: 1509.05, end: 1510.49),
                    ReadAlongSentence(text: "It swings wildly from irrational exuberance (when investors view the future through rose-colored glasses) to unjustified pessimism (when they believe the sky is falling).", start: 1511.17, end: 1520.67),
                    ReadAlongSentence(text: "Bogle tells us that while the pendulum swings violently from side to side, generating terrifying headlines and euphoric manias, it always, eventually, rests at the center—anchored to the true economic value of the businesses.", start: 1521.33, end: 1534.43),
                    ReadAlongSentence(text: "The insider secret is realizing that the swings of the pendulum are an illusion.", start: 1535.05, end: 1538.87),
                    ReadAlongSentence(text: "If you anchor your emotions to the \"Real Market,\" the wild swings of the crowd lose their power over you.", start: 1539.77, end: 1545.19),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The Weaponized Panic Machine", start: 1545.95, end: 1549.39),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In Bogle's era, the pendulum swung slowly.", start: 1550.15, end: 1552.79),
                    ReadAlongSentence(text: "You had to wait for the morning newspaper to feel the panic.", start: 1553.67, end: 1556.21),
                    ReadAlongSentence(text: "Today, emotional gravity has been weaponized by technology, and the pendulum swings at the speed of light.", start: 1556.77, end: 1562.85),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "We live in a financial ecosystem engineered to harvest your attention by spiking your cortisol.", start: 1563.77, end: 1568.79),
                    ReadAlongSentence(text: "Consider a sudden escalation in a Trade War or a rumored regulatory crackdown on Crypto.", start: 1569.49, end: 1574.89),
                    ReadAlongSentence(text: "Within seconds, algorithms push catastrophic headlines to your lock screen.", start: 1575.63, end: 1579.96),
                    ReadAlongSentence(text: "Social media \"finfluencers\" broadcast emergency updates with apocalyptic thumbnails.", start: 1580.44, end: 1585.7),
                    ReadAlongSentence(text: "The screens on your zero-commission trading apps flash aggressively in red, triggering a physiological stress response.", start: 1586.22, end: 1592.06),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "This applies perfectly to the hyper-volatile sectors of today.", start: 1592.8, end: 1596.04),
                    ReadAlongSentence(text: "Look at Data Center and AI infrastructure companies.", start: 1596.78, end: 1599.3),
                    ReadAlongSentence(text: "The underlying businesses are growing steadily—building facilities and laying cables.", start: 1600.0, end: 1604.78),
                    ReadAlongSentence(text: "That is the Real Market.", start: 1605.5, end: 1607.0),
                    ReadAlongSentence(text: "But the stocks swing 30% in a single week based on a whispered rumor about a delayed microchip.", start: 1607.6, end: 1613.18),
                    ReadAlongSentence(text: "When you let the gamified alerts and the 24/7 news cycle dictate your mood, you are tying your emotional state to a pendulum being violently pushed by high-frequency trading bots and engagement-hungry media companies.", start: 1613.76, end: 1625.02),
                    ReadAlongSentence(text: "Your only true edge in the modern era is emotional detachment.", start: 1625.72, end: 1629.36),
                    ReadAlongSentence(text: "You win by building a psychological fortress that the noise cannot penetrate.", start: 1630.06, end: 1634.94),
                ]),
            ],
            8: [
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a paradox in investing that breaks the brains of most beginners: The safer an investment feels, the more dangerous it actually is.", start: 1642.06, end: 1650.78),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In normal life, consensus is a great filter.", start: 1651.38, end: 1654.2),
                    ReadAlongSentence(text: "If a thousand people say a restaurant is terrible, you don’t eat there.", start: 1655.1, end: 1658.76),
                    ReadAlongSentence(text: "If everyone agrees a specific car is reliable, you buy it.", start: 1659.28, end: 1663.08),
                    ReadAlongSentence(text: "But the stock market is a mirror universe.", start: 1663.74, end: 1666.28),
                    ReadAlongSentence(text: "By the time everyone agrees that a specific technology or company is the undeniable future, the price of that asset has already been bid up to the stratosphere.", start: 1667.12, end: 1675.98),
                    ReadAlongSentence(text: "The friction here is that you want to buy the \"obvious\" winner, but you forget that the stock market operates as an auction.", start: 1676.42, end: 1682.16),
                    ReadAlongSentence(text: "When you buy what is universally loved, you pay a massive premium.", start: 1682.72, end: 1686.98),
                    ReadAlongSentence(text: "I call this the \"Comfort Tax.\"", start: 1687.58, end: 1689.34),
                    ReadAlongSentence(text: "Most people fail because they think they are buying a great business, when in reality, they are just buying a great consensus—and paying top dollar for it.", start: 1690.16, end: 1697.72),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Standing in Front of the Pendulum", start: 1698.42, end: 1699.78),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, understood this psychological warfare intimately.", start: 1700.26, end: 1704.55),
                    ReadAlongSentence(text: "He frequently leaned on the metaphor of the pendulum to describe the manic-depressive nature of the stock market.", start: 1705.29, end: 1710.99),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells us that the investment markets swing like a giant pendulum.", start: 1711.43, end: 1714.79),
                    ReadAlongSentence(text: "At the exact center of the arc lies intrinsic value—the boring, mathematical reality of corporate earnings and dividends.", start: 1715.51, end: 1722.85),
                    ReadAlongSentence(text: "But the pendulum rarely rests there.", start: 1723.37, end: 1725.13),
                    ReadAlongSentence(text: "It is constantly swinging outward toward the extremes of irrational exuberance, fueled by greed, and then violently crashing back toward the extremes of unjustified pessimism, fueled by terror.", start: 1725.77, end: 1736.35),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Bogle reminds us of the tragic story of Sir Isaac Newton, one of the smartest humans to ever live.", start: 1737.13, end: 1742.83),
                    ReadAlongSentence(text: "Newton invested in the South Sea Company during a massive speculative bubble.", start: 1743.57, end: 1747.43),
                    ReadAlongSentence(text: "He initially made a fortune, exited, but then—watching his friends get richer as the pendulum swung further into euphoria—he abandoned his logic, jumped back in at the peak, and lost his life savings.", start: 1748.41, end: 1760.13),
                    ReadAlongSentence(text: "Newton famously lamented, \"I can calculate the motions of the heavenly bodies, but not the madness of the people.\"", start: 1761.19, end: 1767.75),
                    ReadAlongSentence(text: "Bogle’s lesson is that intelligence cannot save you from the pendulum.", start: 1768.47, end: 1772.17),
                    ReadAlongSentence(text: "Only aggressive disagreement can.", start: 1772.93, end: 1774.69),
                    ReadAlongSentence(text: "When the pendulum is at its highest, most euphoric arc, you must stubbornly disagree with the optimism.", start: 1775.29, end: 1781.29),
                    ReadAlongSentence(text: "When it swings to the darkest depths of despair, you must stubbornly disagree with the doom.", start: 1781.89, end: 1786.61),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The Algorithmic Echo Chamber", start: 1787.19, end: 1790.45),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, disagreeing with the crowd is ten times harder because the crowd now lives in your pocket, amplified by algorithmic echo chambers.", start: 1791.23, end: 1799.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Think about the recent frenzies surrounding Crypto \"super-cycles\" or the parabolic rise of AI and Data Center infrastructure.", start: 1799.83, end: 1806.67),
                    ReadAlongSentence(text: "The modern pendulum isn't just pushed by human emotion; it is accelerated by social media feeds, Reddit communities, and gamified apps that curate a reality where everyone is making money except you.", start: 1807.39, end: 1818.75),
                    ReadAlongSentence(text: "When you open an app and see a wall of green, and every influencer is predicting a \"new paradigm\" for Clean Energy or Remote Work tech, the algorithmic consensus feels like an undeniable fact.", start: 1819.41, end: 1829.77),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The trap is that the modern financial ecosystem punishes contrarians.", start: 1830.49, end: 1834.69),
                    ReadAlongSentence(text: "If you disagree with a meme-stock rally, you are ridiculed.", start: 1835.27, end: 1838.96),
                    ReadAlongSentence(text: "If you doubt the immediate profitability of a massive AI rollout, you are called a dinosaur.", start: 1839.48, end: 1845.4),
                    ReadAlongSentence(text: "The modern pendulum swings faster and hits harder.", start: 1846.0, end: 1848.88),
                    ReadAlongSentence(text: "To survive it, you have to realize that when your curated feed is uniformly euphoric about a sector, the pendulum has reached its maximum extension.", start: 1849.42, end: 1857.82),
                    ReadAlongSentence(text: "The risk is highest exactly when the crowd feels the safest.", start: 1858.46, end: 1862.0),
                    ReadAlongSentence(text: "You must learn to view overwhelming consensus not as a green light, but as a blinding siren warning you to step back.", start: 1862.66, end: 1869.64),
                ]),
            ],
            9: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Glamour Trap", start: 1908.48, end: 1909.26),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a dangerous assumption that a \"world-changing company\" automatically makes for a \"great investment.\"", start: 1909.66, end: 1914.96),
                    ReadAlongSentence(text: "The friction here is that the stock market does not reward you for identifying what is brilliant; it rewards you for identifying what is mispriced.", start: 1915.88, end: 1923.14),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most people fail because their ego demands they invest in the glamorous, the revolutionary, and the shiny.", start: 1923.82, end: 1929.5),
                    ReadAlongSentence(text: "They want to brag at dinner parties about owning the company curing a disease or building the fastest microchip.", start: 1930.28, end: 1935.88),
                    ReadAlongSentence(text: "It is incredibly tempting to build complex data mining models, running sophisticated cluster analyses to hunt for perfectly mispriced anomalies hiding in the shadows.", start: 1936.68, end: 1945.86),
                    ReadAlongSentence(text: "But the brutal truth of the market is that glamour is expensive.", start: 1946.76, end: 1949.98),
                    ReadAlongSentence(text: "The crowd bids up the price of \"revolutionary\" companies until the math guarantees a mediocre return.", start: 1950.9, end: 1957.08),
                    ReadAlongSentence(text: "True wealth isn't found in the spotlight; it is scavenged in the neglected, boring, and unsexy corners of the market that everyone else is too impatient to analyze.", start: 1957.86, end: 1966.57),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Triumph of the Tortoise", start: 1967.21, end: 1968.97),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, solved this puzzle by dissecting exactly where stock market money comes from.", start: 1969.59, end: 1975.25),
                    ReadAlongSentence(text: "He revealed that your total return is made of two entirely different beasts: \"Speculative Return\" and \"Fundamental Return.\"", start: 1976.01, end: 1982.29),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Speculative Return is the hype.", start: 1983.05, end: 1985.01),
                    ReadAlongSentence(text: "It is the change in the Price-to-Earnings (P/E) ratio based on human emotion.", start: 1985.63, end: 1989.75),
                    ReadAlongSentence(text: "It is the hare—leaping forward one year, collapsing in a panic the next.", start: 1990.39, end: 1994.91),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Fundamental Return is the neglected value.", start: 1995.67, end: 1997.99),
                    ReadAlongSentence(text: "It consists of just two boring numbers: the initial dividend yield and the company's actual earnings growth.", start: 1998.93, end: 2005.01),
                    ReadAlongSentence(text: "This is the tortoise.", start: 2005.59, end: 2006.95),
                    ReadAlongSentence(text: "It is unsexy.", start: 2007.47, end: 2009.27),
                    ReadAlongSentence(text: "It doesn't generate breaking news alerts.", start: 2010.05, end: 2011.91),
                    ReadAlongSentence(text: "But Bogle points out a staggering historical fact: over the long span of market history, Speculative Return effectively cancels itself out to zero.", start: 2012.43, end: 2021.09),
                    ReadAlongSentence(text: "The booms and busts net out.", start: 2021.77, end: 2023.47),
                    ReadAlongSentence(text: "Therefore, virtually 100% of the wealth created in the stock market over the last century came from the tortoise—the quiet, neglected, compounding cash flows of boring businesses.", start: 2024.11, end: 2034.65),
                    ReadAlongSentence(text: "The insider secret is to stop obsessing over the unpredictable hare of speculation and start scavenging for the relentless tortoise of fundamental value.", start: 2035.29, end: 2043.63),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The Unsexy Backbone", start: 2044.21, end: 2047.37),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In today’s hyper-financialized world, the obsession with the \"hare\" has reached a fever pitch.", start: 2047.99, end: 2053.21),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Look at the current landscape.", start: 2053.87, end: 2055.13),
                    ReadAlongSentence(text: "Millions of investors are throwing capital into purely speculative assets like Crypto meme coins, which have zero earnings, zero dividends, and zero fundamental value.", start: 2056.09, end: 2066.09),
                    ReadAlongSentence(text: "It is 100% Speculative Return—a pure gamble on the next person's willingness to pay more.", start: 2066.67, end: 2072.24),
                    ReadAlongSentence(text: "Or look at the AI frenzy.", start: 2072.92, end: 2074.22),
                    ReadAlongSentence(text: "Everyone is desperately trying to identify the next flashy software startup that will disrupt the world.", start: 2075.2, end: 2080.9),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "But where is the neglected value?", start: 2081.56, end: 2083.04),
                    ReadAlongSentence(text: "It is in the unsexy backbone.", start: 2083.88, end: 2085.86),
                    ReadAlongSentence(text: "While the crowd fights over the AI software companies trading at 100 times their earnings, the neglected value is in the boring industrial utility companies that have to supply the massive electrical power to the new Data Centers.", start: 2086.58, end: 2098.64),
                    ReadAlongSentence(text: "It is in the unglamorous copper miners providing the wiring for the Clean Energy grid.", start: 2099.4, end: 2103.88),
                    ReadAlongSentence(text: "These companies often pay steady dividends and grow their earnings predictably, but they don't get trending hashtags.", start: 2104.6, end: 2111.02),
                    ReadAlongSentence(text: "In a market obsessed with disrupting the future, your greatest edge is finding the quiet, highly profitable companies that are simply selling the shovels for the gold rush.", start: 2111.72, end: 2120.58),
                ]),
            ],
            10: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Myth of the Hustle", start: 2128.6, end: 2129.84),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a toxic lie baked into our culture that dictates how we measure success: we worship the \"hustle.\"", start: 2130.54, end: 2136.5),
                    ReadAlongSentence(text: "From the moment you enter the workforce, you are trained that activity equals progress.", start: 2137.34, end: 2141.78),
                    ReadAlongSentence(text: "If you want to get promoted, you work longer hours.", start: 2142.3, end: 2145.1),
                    ReadAlongSentence(text: "If you want to grow a business, you launch more products.", start: 2145.6, end: 2148.24),
                    ReadAlongSentence(text: "We are conditioned to believe that motion is the only antidote to failure.", start: 2148.86, end: 2152.84),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "When you bring this \"hustle\" mentality into the financial markets, it becomes a weapon of mass wealth destruction.", start: 2153.28, end: 2159.34),
                    ReadAlongSentence(text: "The friction here is that your brain equates \"doing nothing\" with laziness and negligence.", start: 2160.04, end: 2165.98),
                    ReadAlongSentence(text: "When the market opens, you feel an overwhelming compulsion to scour the news, run screeners, and execute trades.", start: 2166.64, end: 2173.58),
                    ReadAlongSentence(text: "You feel like you must have an opinion on every macroeconomic event, every earnings report, and every geopolitical crisis.", start: 2174.28, end: 2181.64),
                    ReadAlongSentence(text: "Most people fail at investing because they treat it like a 9-to-5 job where they are paid piecework.", start: 2182.7, end: 2188.04),
                    ReadAlongSentence(text: "They believe that if they are not actively managing, tweaking, and reacting, they are falling behind.", start: 2188.6, end: 2194.44),
                    ReadAlongSentence(text: "The hardest insider secret to accept is that the stock market is the only domain on earth where extreme, bordering-on-lazy inactivity is the ultimate competitive advantage.", start: 2195.08, end: 2204.91),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Umpire Without a Whistle", start: 2205.51, end: 2206.89),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author addresses this psychological trap by borrowing a masterclass concept from Warren Buffett, who in turn borrowed it from the greatest baseball hitter of all time, Ted Williams.", start: 2207.45, end: 2217.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In his book The Science of Hitting, Ted Williams carved the strike zone into 77 distinct cells.", start: 2218.53, end: 2224.73),
                    ReadAlongSentence(text: "He calculated that if he only swung at pitches in his absolute \"sweet spot\" (the center cells), he would bat .400.", start: 2225.45, end: 2231.25),
                    ReadAlongSentence(text: "If he reached for pitches on the lower outside corner, his average would plummet to .230.", start: 2232.49, end: 2236.37),
                    ReadAlongSentence(text: "His secret was not a faster swing; it was the ruthless discipline of inaction.", start: 2237.93, end: 2242.13),
                    ReadAlongSentence(text: "He aggressively waited for the \"fat pitch.\"", start: 2242.77, end: 2244.75),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author translates this to the financial world with one massive, beautiful advantage: In the stock market, there are no \"called strikes.\"", start: 2245.41, end: 2253.33),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Imagine standing at home plate.", start: 2253.97, end: 2255.93),
                    ReadAlongSentence(text: "The pitcher is Wall Street.", start: 2256.63, end: 2258.19),
                    ReadAlongSentence(text: "He throws a pitch called \"Brazilian Tech Startups.\"", start: 2258.87, end: 2261.57),
                    ReadAlongSentence(text: "It zips by.", start: 2262.07, end: 2262.73),
                    ReadAlongSentence(text: "You don't understand it.", start: 2263.35, end: 2264.31),
                    ReadAlongSentence(text: "In baseball, the umpire yells \"Strike one!\"", start: 2265.01, end: 2268.61),
                    ReadAlongSentence(text: "But in the stock market, the umpire is silent.", start: 2269.63, end: 2273.01),
                    ReadAlongSentence(text: "The pitcher throws \"European Bank Mergers.\"", start: 2273.69, end: 2275.77),
                    ReadAlongSentence(text: "You let it pass.", start: 2276.23, end: 2276.99),
                    ReadAlongSentence(text: "No penalty.", start: 2277.49, end: 2277.95),
                    ReadAlongSentence(text: "You can stand at the plate for five years, bat resting comfortably on your shoulder, watching tens of thousands of pitches sail by.", start: 2278.73, end: 2286.01),
                    ReadAlongSentence(text: "You only lose the game when your ego forces you to swing at a pitch you don't understand just because the crowd is cheering.", start: 2286.77, end: 2292.77),
                    ReadAlongSentence(text: "The true master acknowledges exactly what they don't know, builds a tiny circle of competence, and practices \"patient opportunism\"—waiting years, if necessary, for the single, undeniable fat pitch where the odds are overwhelmingly in their favor.", start: 2293.49, end: 2307.69),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The 24/7 Pitching Machine", start: 2308.43, end: 2311.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the discipline of inaction is exponentially harder because you are no longer standing in a quiet baseball stadium; you are trapped inside a neon-lit, 24/7 pitching machine that never unplugs.", start: 2312.23, end: 2324.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The pitches are coming at 100 miles per hour, directly to your lock screen.", start: 2324.87, end: 2328.27),
                    ReadAlongSentence(text: "A new Crypto protocol launches, and your feed explodes with stories of teenagers becoming millionaires overnight.", start: 2328.77, end: 2335.03),
                    ReadAlongSentence(text: "The machine throws a \"Generative AI\" pitch.", start: 2335.77, end: 2338.13),
                    ReadAlongSentence(text: "Then a \"Space Exploration\" pitch.", start: 2338.65, end: 2340.55),
                    ReadAlongSentence(text: "Then a \"Work-from-Home\" disruptor pitch.", start: 2341.41, end: 2344.11),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The gamification of modern finance is designed to make you feel stupid for keeping your bat on your shoulder.", start: 2344.79, end: 2349.71),
                    ReadAlongSentence(text: "When a meme stock surges 400% in a week, the algorithmic echo chamber mocks your discipline.", start: 2350.27, end: 2355.87),
                    ReadAlongSentence(text: "The modern trap is the belief that because you have access to every global market, you must participate in every global market.", start: 2356.39, end: 2363.6),
                    ReadAlongSentence(text: "But think about the recent wreckage of the \"Metaverse\" trend or the SPAC boom.", start: 2364.26, end: 2368.18),
                    ReadAlongSentence(text: "The investors who felt the compulsion to swing at those pitches—because they couldn't bear the FOMO—crushed their portfolios.", start: 2368.94, end: 2375.58),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern superpower is looking at a wildly lucrative trend, admitting, \"I have absolutely no idea how this technology makes money,\" and going back to your things.", start: 2376.14, end: 2385.02),
                    ReadAlongSentence(text: "You do not have to conquer every sector.", start: 2385.76, end: 2387.76),
                    ReadAlongSentence(text: "You do not have to have an opinion on the Trade War's impact on microchips.", start: 2388.48, end: 2391.88),
                    ReadAlongSentence(text: "Your edge is letting 99% of the modern noise fly right past you, saving your capital for the rare, boring, undeniable pitch that lands perfectly in your tiny zone of understanding.", start: 2392.74, end: 2403.42),
                ]),
            ],
            11: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Genius Delusion", start: 2446.5, end: 2447.94),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "There is a psychological trap in the financial world that quietly bankrupts the smartest people in the room: the asymmetry of ego.", start: 2448.46, end: 2455.76),
                    ReadAlongSentence(text: "When we lose money, we immediately blame external forces—a sudden market crash, a corrupt CEO, or just bad luck.", start: 2456.52, end: 2464.1),
                    ReadAlongSentence(text: "But when we make money, we look in the mirror and see a financial genius.", start: 2464.62, end: 2468.18),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The friction here is that our brains are desperate to find cause and effect where there is only randomness.", start: 2469.04, end: 2473.92),
                    ReadAlongSentence(text: "We fail at investing because we confuse a good outcome with a good process.", start: 2474.66, end: 2478.92),
                    ReadAlongSentence(text: "You can make a brilliant, mathematically sound decision and still lose your shirt because of a freak geopolitical event.", start: 2479.64, end: 2485.86),
                    ReadAlongSentence(text: "Conversely, you can make a brain-dead, reckless gamble and become a millionaire because you happened to be in the right place at the right time.", start: 2486.58, end: 2494.38),
                    ReadAlongSentence(text: "The secret that Wall Street tries to bury is that a terrifying percentage of success is dictated by pure, unadulterated luck.", start: 2494.98, end: 2503.08),
                    ReadAlongSentence(text: "If you cannot separate your skill from your luck, arrogance will eventually convince you to bet the house on a coin toss you are mathematically guaranteed to lose.", start: 2503.78, end: 2512.17),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The National Coin-Flipping Tournament", start: 2512.77, end: 2515.49),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "To illustrate the absurdity of confusing luck with skill, imagine a national coin-flipping tournament.", start: 2516.29, end: 2522.01),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Every single day, 330 million Americans wake up and flip a quarter.", start: 2522.45, end: 2527.71),
                    ReadAlongSentence(text: "If you guess heads or tails correctly, you advance to the next round.", start: 2528.69, end: 2532.07),
                    ReadAlongSentence(text: "If you guess wrong, you are eliminated.", start: 2532.65, end: 2535.09),
                    ReadAlongSentence(text: "By the law of probability, after about 20 days, there will be roughly 315 people who have guessed correctly 20 times in a row.", start: 2535.71, end: 2544.61),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Here is where the delusion kicks in.", start: 2545.41, end: 2547.25),
                    ReadAlongSentence(text: "Those 315 people will genuinely believe they have a \"gift.\"", start: 2547.99, end: 2551.73),
                    ReadAlongSentence(text: "They will start writing books titled The Art of the Toss.", start: 2552.39, end: 2555.43),
                    ReadAlongSentence(text: "They will sell premium newsletter subscriptions detailing their proprietary \"wrist-flick algorithms\" and atmospheric pressure analyses.", start: 2556.23, end: 2563.39),
                    ReadAlongSentence(text: "They will wear tailored suits and go on financial news networks to explain their genius.", start: 2564.13, end: 2568.87),
                    ReadAlongSentence(text: "But the brutal math dictates that someone had to win.", start: 2569.71, end: 2572.63),
                    ReadAlongSentence(text: "It wasn't skill; it was a statistical inevitability.", start: 2573.43, end: 2576.91),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The lesson is to acknowledge \"alternative histories.\"", start: 2577.55, end: 2579.79),
                    ReadAlongSentence(text: "For every wildly successful investor you see, there are a thousand invisible alternative realities where that exact same strategy wiped them out due to a single bad break.", start: 2580.43, end: 2590.05),
                    ReadAlongSentence(text: "To survive the coin toss, you don't need a better wrist flick.", start: 2590.61, end: 2593.47),
                    ReadAlongSentence(text: "You need a \"margin of safety\"—a structural defense in your portfolio that ensures when you inevitably guess wrong, you don't get permanently eliminated from the game.", start: 2594.05, end: 2601.99),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The Algorithm's Blind Spot", start: 2602.51, end: 2605.49),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the delusion of skill has been amplified by the sheer processing power we have at our fingertips.", start: 2606.05, end: 2611.73),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You can feed ten years of pristine market data into a deep learning architecture, carefully tuning an LSTM or training an XGBoost model to find the perfect predictive pattern.", start: 2612.31, end: 2623.53),
                    ReadAlongSentence(text: "The backtesting looks flawless.", start: 2624.05, end: 2625.69),
                    ReadAlongSentence(text: "The precision and recall metrics suggest you have solved the market.", start: 2626.21, end: 2629.51),
                    ReadAlongSentence(text: "But here is the fatal flaw: models only train on the history that happened.", start: 2630.05, end: 2634.67),
                    ReadAlongSentence(text: "They cannot train on the history that almost happened.", start: 2635.23, end: 2637.99),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Your model cannot predict a sudden supply chain embargo on microchips, an overnight Trade War tariff, or a global pandemic that freezes the economy.", start: 2638.43, end: 2645.99),
                    ReadAlongSentence(text: "When a highly leveraged bet on a Clean Energy ETF skyrockets, the investor praises their flawless algorithmic strategy.", start: 2647.01, end: 2654.14),
                    ReadAlongSentence(text: "They completely ignore the alternative history where a single political vote swung the other way and bankrupted the sector.", start: 2654.92, end: 2660.86),
                    ReadAlongSentence(text: "In modern finance, we build incredibly complex tools to predict the future, forgetting that the future is heavily dictated by random, unquantifiable variables.", start: 2661.5, end: 2671.26),
                    ReadAlongSentence(text: "If your strategy relies on absolute precision rather than a massive margin of safety, you are just a coin flipper with a supercomputer.", start: 2672.0, end: 2681.24),
                ]),
            ],
            12: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Highlight Reel\" Trap", start: 2718.86, end: 2720.32),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "We are obsessed with the knockout punch.", start: 2721.28, end: 2723.34),
                    ReadAlongSentence(text: "In every other arena of life, we are taught that greatness is the result of spectacular, aggressive action.", start: 2724.18, end: 2730.38),
                    ReadAlongSentence(text: "We want to be the investor who spotted the next world-changing tech giant at two dollars a share, or the one who timed the exact bottom of a market crash.", start: 2731.2, end: 2739.62),
                    ReadAlongSentence(text: "The friction here is that your ego wants a \"highlight reel,\" but your bank account needs a \"boring reality.\"", start: 2740.2, end: 2745.26),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most people fail at investing because they play a \"Winner's Game.\"", start: 2745.84, end: 2748.76),
                    ReadAlongSentence(text: "They try to hit the impossible cross-court shot, betting their capital on high-risk, high-reward plays that require perfect timing and superhuman foresight.", start: 2749.46, end: 2758.3),
                    ReadAlongSentence(text: "They focus so much on the potential \"win\" that they ignore the devastating math of the \"loss.\"", start: 2759.16, end: 2763.88),
                    ReadAlongSentence(text: "In the markets, as in life, trying to be a hero usually just makes you a casualty.", start: 2764.7, end: 2769.3),
                    ReadAlongSentence(text: "The insider secret is that wealth is not built by being right; it is built by refusing to be catastrophically wrong.", start: 2769.84, end: 2776.55),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Amateur's Tennis Match", start: 2777.13, end: 2778.35),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, explains this shift in mindset by borrowing a powerful observation from Simon Ramo’s book, Extraordinary Tennis for the Ordinary Player.", start: 2778.95, end: 2788.37),
                    ReadAlongSentence(text: "Ramo noticed a fundamental difference between how professionals play tennis and how amateurs play it.", start: 2788.97, end: 2794.23),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In professional tennis, it is a \"Winner's Game.\"", start: 2794.77, end: 2797.43),
                    ReadAlongSentence(text: "Players are so skilled that they must hit powerful, precise \"winners\" to beat their opponents.", start: 2798.27, end: 2803.25),
                    ReadAlongSentence(text: "But in amateur tennis, the game is entirely different.", start: 2803.95, end: 2807.05),
                    ReadAlongSentence(text: "Amateurs don't win by hitting great shots; they win because their opponent eventually hits the ball into the net or out of bounds.", start: 2807.63, end: 2814.23),
                    ReadAlongSentence(text: "It is a \"Loser's Game,\" where the person who makes the fewest unforced errors—the one who simply keeps the ball in play—is the one who walks away with the trophy.", start: 2814.73, end: 2823.87),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Bogle argues that for 99% of us, the stock market is an amateur tennis match.", start: 2824.55, end: 2829.31),
                    ReadAlongSentence(text: "You are not competing against a wall; you are competing against the costs of trading, the taxes of turnover, and the emotional volatility of your own brain.", start: 2830.07, end: 2838.77),
                    ReadAlongSentence(text: "Every time you try to \"beat the market\" with a speculative bet, you are attempting a high-risk power shot.", start: 2839.51, end: 2844.99),
                    ReadAlongSentence(text: "Most of the time, you hit it into the net.", start: 2845.73, end: 2847.87),
                    ReadAlongSentence(text: "The author’s solution is to stop trying to hit winners.", start: 2848.49, end: 2851.65),
                    ReadAlongSentence(text: "If you simply own the entire market through a low-cost index fund, you are effectively keeping the ball in play while everyone else exhausts themselves making unforced errors.", start: 2852.39, end: 2861.67),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The High-Speed Net", start: 2862.63, end: 2865.19),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the \"net\" is higher, and the game is played at a much faster pace.", start: 2865.69, end: 2870.29),
                    ReadAlongSentence(text: "The challenge isn't the assets themselves—whether it's AI, Data Centers, or Crypto—it’s how we trade them.", start: 2871.17, end: 2878.07),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The modern \"unforced error\" isn't buying a specific technology; it's the high-frequency tinkering that happens because of 24/7 access.", start: 2878.55, end: 2886.48),
                    ReadAlongSentence(text: "When you look at high-volatility sectors like Crypto or AI-driven tech, the temptation is to \"play the swings.\"", start: 2887.02, end: 2893.44),
                    ReadAlongSentence(text: "You see a 10% dip and try to time a perfect exit, or you see a vertical spike and try to leverage your position.", start: 2894.02, end: 2900.22),
                    ReadAlongSentence(text: "These are the amateur's \"power shots.\"", start: 2900.82, end: 2902.54),
                    ReadAlongSentence(text: "They feel like active management, but they often result in hitting the ball straight into the net of taxes, slippage, and bad timing.", start: 2903.1, end: 2910.12),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In a world of \"0DTE\" options and instant liquidity, your greatest edge is your defensive posture.", start: 2910.7, end: 2917.1),
                    ReadAlongSentence(text: "Whether you are holding a total market index or a specific digital asset, the person who wins is the one who refuses to be shaken out by short-term noise.", start: 2917.68, end: 2926.7),
                    ReadAlongSentence(text: "Defensive investing today means realizing that the person who simply refuses to blow up their portfolio through over-trading or excessive fees is the one who stays on the court long enough to see the \"winners\" fail.", start: 2927.4, end: 2937.78),
                ]),
            ],
            13: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Symmetrical Trap", start: 2944.0, end: 2945.06),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most investors are trapped in a \"fair fight\" with the market, and in a fair fight, the house eventually wins.", start: 2945.84, end: 2952.04),
                    ReadAlongSentence(text: "The friction here is the belief that to get higher returns, you must accept equally high risks.", start: 2952.96, end: 2957.76),
                    ReadAlongSentence(text: "We are taught that if you want a 20% gain, you must be comfortable with a 20% loss.", start: 2958.36, end: 2963.68),
                    ReadAlongSentence(text: "This is \"Symmetrical Investing,\" and it is a recipe for exhaustion.", start: 2964.4, end: 2968.7),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "People fail because they treat their portfolio like a mirror—when the market goes up, they go up; when it crashes, they crash just as hard.", start: 2969.38, end: 2977.92),
                    ReadAlongSentence(text: "They lack \"convexity.\"", start: 2978.62, end: 2979.84),
                    ReadAlongSentence(text: "They are constantly one bad month away from wiping out a year of progress.", start: 2980.44, end: 2984.02),
                    ReadAlongSentence(text: "The insider secret is that the elite don't play fair.", start: 2984.56, end: 2987.64),
                    ReadAlongSentence(text: "They aren't looking for a 50/50 gamble; they are looking for \"Asymmetry.\"", start: 2988.28, end: 2992.62),
                    ReadAlongSentence(text: "They want trades where the ceiling is the moon, but the floor is made of reinforced concrete.", start: 2993.62, end: 2998.42),
                    ReadAlongSentence(text: "If you are participating in 100% of the market's pain just to get 100% of its gain, you aren't an investor; you’re a passenger.", start: 2999.12, end: 3006.58),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Weighted Coin", start: 3007.3, end: 3008.26),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, spent his career proving that the \"Alpha\" everyone chases—the ability to beat the market—is often just a ghost.", start: 3008.99, end: 3017.49),
                    ReadAlongSentence(text: "But he highlights a specific, rare form of value-add: the ability to tilt the odds.", start: 3018.59, end: 3024.03),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "He tells the story of the \"Gross Return\" vs. the \"Net Return.\"", start: 3024.69, end: 3029.03),
                    ReadAlongSentence(text: "Imagine a game where you and the market both start with $100.", start: 3029.97, end: 3032.19),
                    ReadAlongSentence(text: "The market goes up 10%, then down 10%.", start: 3033.83, end: 3036.15),
                    ReadAlongSentence(text: "The market is back at $99.", start: 3037.43, end: 3038.43),
                    ReadAlongSentence(text: "But if you have high fees, taxes, and bad timing, you might go up 8% and down 12%.", start: 3039.99, end: 3045.39),
                    ReadAlongSentence(text: "You are at $95.", start: 3046.53, end: 3046.79),
                    ReadAlongSentence(text: "You have \"Negative Asymmetry.\"", start: 3048.83, end: 3050.99),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Bogle’s solution was to use the \"Index\" as the ultimate defensive shield.", start: 3051.77, end: 3055.71),
                    ReadAlongSentence(text: "He argued that by ruthlessly cutting costs and taxes, you create a natural asymmetry.", start: 3056.13, end: 3061.41),
                    ReadAlongSentence(text: "While the active trader loses 2% of their wealth every year to the \"Croupiers\" (brokers and managers), the indexer keeps that 2%.", start: 3062.03, end: 3069.27),
                    ReadAlongSentence(text: "Over decades, that 2% acts as a structural cushion.", start: 3070.77, end: 3074.03),
                    ReadAlongSentence(text: "You participate in the full upside of the \"Real Market,\" but your \"Net\" downside is significantly less than the frantic gambler's.", start: 3074.71, end: 3081.83),
                    ReadAlongSentence(text: "True skill isn't picking the winning horse; it’s making sure you don't pay the bookie so much that even a win makes you broke.", start: 3082.51, end: 3088.53),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The \"Infrastructure\" Edge", start: 3089.09, end: 3091.77),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "In the modern landscape, asymmetry is found by shifting your focus from the \"front-end\" hype to the \"back-end\" necessity.", start: 3092.53, end: 3098.95),
                    ReadAlongSentence(text: "Everyone is currently obsessed with picking the winning AI model or the fastest-growing clean energy startup.", start: 3099.99, end: 3105.97),
                    ReadAlongSentence(text: "These are symmetric bets: if the specific technology fails or gets disrupted, the investment can vanish.", start: 3106.77, end: 3113.57),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "True asymmetry today lies in the infrastructure that must exist regardless of which individual company wins the race.", start: 3114.27, end: 3121.55),
                    ReadAlongSentence(text: "For instance, rather than gambling on a single AI software firm, the asymmetric move is looking at the power grid and data center real estate that the entire industry relies upon.", start: 3122.19, end: 3132.09),
                    ReadAlongSentence(text: "If AI flourishes, these utilities are essential; if the hype cools, these assets still possess high intrinsic value and physical utility.", start: 3132.81, end: 3141.59),
                    ReadAlongSentence(text: "This creates a \"heads I win, tails I don't lose much\" scenario.", start: 3142.43, end: 3146.52),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Similarly, in sectors like Crypto or remote work tech, the goal is to avoid betting on the \"flash in the pan.\"", start: 3147.08, end: 3153.76),
                    ReadAlongSentence(text: "Instead, you look for the protocols or service providers that have become the standard pipes of the system.", start: 3154.5, end: 3159.76),
                    ReadAlongSentence(text: "By using your technical background—leveraging your understanding of system architecture and data mining—you can identify these \"bottleneck\" companies.", start: 3160.48, end: 3168.7),
                    ReadAlongSentence(text: "You aren't guessing which app people will use; you are investing in the infrastructure they are forced to use.", start: 3169.2, end: 3174.36),
                    ReadAlongSentence(text: "This is how you capture the massive upside of innovation while anchoring your floor in tangible, indispensable value.", start: 3175.02, end: 3182.44),
                ]),
            ],
            14: [
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The \"Just This Once\" Fallacy", start: 3214.76, end: 3216.3),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You have survived the gauntlet.", start: 3217.24, end: 3219.26),
                    ReadAlongSentence(text: "You understand the math of the market, the parasite of fees, and the illusion of the stock-picking guru.", start: 3219.8, end: 3225.08),
                    ReadAlongSentence(text: "You have built a fortress.", start: 3225.9, end: 3227.82),
                    ReadAlongSentence(text: "Yet, there is one final friction point where the smartest investors on earth still manage to destroy their own wealth: the finish line.", start: 3228.48, end: 3235.3),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most people fail here because they become victims of their own boredom.", start: 3235.94, end: 3239.16),
                    ReadAlongSentence(text: "The brutal reality of compounding wealth is that it is extraordinarily monotonous.", start: 3239.86, end: 3244.02),
                    ReadAlongSentence(text: "Once your system is set, there is nothing left to \"do.\"", start: 3244.74, end: 3247.4),
                    ReadAlongSentence(text: "But human beings hate doing nothing.", start: 3248.26, end: 3250.04),
                    ReadAlongSentence(text: "Eventually, your ego will whisper a dangerous lie: \"Just this once.\"", start: 3250.96, end: 3255.58),
                    ReadAlongSentence(text: "You will see a friend double their net worth on a speculative gamble, or you will read a terrifying macroeconomic headline, and you will convince yourself that the rules you learned no longer apply to this one specific, unique situation.", start: 3256.54, end: 3269.48),
                    ReadAlongSentence(text: "You will break your own system just to feel the thrill of participation.", start: 3270.22, end: 3273.9),
                    ReadAlongSentence(text: "The insider secret is that wealth is not lost because an investor lacked knowledge; it is lost because they lacked the endurance to tolerate a lifetime of boredom.", start: 3274.8, end: 3283.38),
                    ReadAlongSentence(text: "The final checkmate is protecting your portfolio from the greatest threat it will ever face: you.", start: 3283.97, end: 3289.07),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Grand Master’s Blunder", start: 3289.73, end: 3291.35),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "The author, John Bogle, viewed the successful index investor as a chess Grand Master who has already mathematically won the game, but who still has to play out the final moves.", start: 3291.99, end: 3302.09),
                    ReadAlongSentence(text: "The only way the Grand Master loses is if they get arrogant, lose focus, and make a careless, unforced blunder.", start: 3302.83, end: 3309.05),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "To prevent this, Bogle created a final checklist of psychological pitfalls.", start: 3310.01, end: 3314.37),
                    ReadAlongSentence(text: "He tells the story of the \"New Era\" delusion—the recurring historical fantasy where investors convince themselves that because technology has changed, the fundamental rules of corporate profits have somehow vanished.", start: 3314.87, end: 3328.23),
                    ReadAlongSentence(text: "He warned against the \"Rearview Mirror\" trap, where investors blindly chase the sector that performed best last year, mathematically guaranteeing they pay peak prices.", start: 3329.05, end: 3338.17),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Most importantly, Bogle preached the philosophy of \"Stay the Course.\"", start: 3338.71, end: 3342.03),
                    ReadAlongSentence(text: "He argued that the ultimate investing superpower is an iron-clad commitment to your original plan, regardless of market weather.", start: 3342.65, end: 3349.31),
                    ReadAlongSentence(text: "The successful investor does not pivot when the market crashes, nor do they leverage up when the market soars.", start: 3350.05, end: 3355.97),
                    ReadAlongSentence(text: "They simply pull all the principles together—low costs, broad diversification, and zero emotion—and they lock the door.", start: 3356.73, end: 3364.35),
                    ReadAlongSentence(text: "The game is won by the player who refuses to make the final, fatal blunder.", start: 3365.13, end: 3369.77),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "The Modern Context: The Algorithmic Siren Song", start: 3370.45, end: 3373.71),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Today, the \"Just this once\" fallacy is no longer a quiet whisper; it is a deafening roar amplified by algorithms.", start: 3374.33, end: 3381.81),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Every time you open your phone, the financial machine is trying to force you into a blunder.", start: 3382.49, end: 3387.07),
                    ReadAlongSentence(text: "It presents you with \"New Era\" narratives that feel impossible to ignore.", start: 3387.99, end: 3392.31),
                    ReadAlongSentence(text: "A breakthrough in Generative AI, a sudden regulatory shift in Crypto, or a geopolitical Trade War—each event is packaged by financial media as an unprecedented emergency requiring your immediate action.", start: 3393.09, end: 3406.59),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "You will see new \"Thematic ETFs\" launched precisely at the peak of a trend’s hype, charging premium fees for the privilege of owning what is already popular.", start: 3407.57, end: 3416.85),
                    ReadAlongSentence(text: "The modern checkmate requires you to view this entire digital ecosystem not as a source of actionable intelligence, but as a psychological testing ground.", start: 3417.45, end: 3426.37),
                    ReadAlongSentence(text: "When everyone on your timeline is screaming that a specific Data Center stock or Clean Energy token is \"going to the moon,\" your discipline must be a brick wall.", start: 3426.85, end: 3435.74),
                    ReadAlongSentence(text: "The ultimate modern edge is looking at the most exciting, paradigm-shifting technological revolution in human history, and having the sheer audacity to say, \"That is fascinating, but I am not touching my portfolio.\" *", start: 3436.52, end: 3448.74),
                ]),
                ReadAlongBlock(isHeading: true, sentences: [
                    ReadAlongSentence(text: "Final Words: The Ultimate Edge", start: 3449.64, end: 3452.18),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "As we close this journey through the principles of common sense investing, remember what you actually possess.", start: 3452.82, end: 3458.26),
                    ReadAlongSentence(text: "You are not just using an app; you are wielding the mathematical truth of the markets.", start: 3458.8, end: 3463.32),
                    ReadAlongSentence(text: "The financial industry will always try to sell you complexity, because complexity is profitable for them.", start: 3464.28, end: 3469.72),
                    ReadAlongSentence(text: "But simplicity is profitable for you.", start: 3470.54, end: 3472.74),
                ]),
                ReadAlongBlock(isHeading: false, sentences: [
                    ReadAlongSentence(text: "Your journey through these 14 Cores was designed to strip away the noise.", start: 3473.42, end: 3477.34),
                    ReadAlongSentence(text: "You now know that the \"croupiers\" in suits and the \"influencers\" on screens are playing a different game than you are.", start: 3478.0, end: 3484.34),
                    ReadAlongSentence(text: "Let them chase the wind.", start: 3484.98, end: 3486.1),
                    ReadAlongSentence(text: "Let them pay the taxes, the fees, and the emotional toll of the casino.", start: 3486.8, end: 3491.22),
                    ReadAlongSentence(text: "Your money is quietly, ruthlessly capturing the growth of human progress.", start: 3492.02, end: 3496.28),
                    ReadAlongSentence(text: "Trust the math, ignore the crowd, and above all else, stay the course.", start: 3496.98, end: 3501.4),
                ]),
            ],
        ],
    ]
